// ── Impostazioni email (reply-to configurabile da admin) ──────────────
async function getEmailReplyTo() {
  if (_cache.emailReplyTo !== undefined) return _cache.emailReplyTo;
  try {
    const docs = await fsGetAll('settings');
    const found = docs.find(d => d.id === 'email');
    _cache.emailReplyTo = found?.replyTo || '';
  } catch(e) { _cache.emailReplyTo = ''; }
  return _cache.emailReplyTo;
}

// Valori di default per l'export Ebay (corriere/costo spedizione, tempo di
// spedizione, Migliore Offerta) — salvati una volta, richiamati e mostrati
// (modificabili) ogni volta al momento dell'export, così Franco può
// cambiarli in autonomia senza bisogno di intervenire sul codice
async function getEbaySettings() {
  if (_cache.ebaySettings !== undefined) return _cache.ebaySettings;
  try {
    const docs = await fsGetAll('settings');
    const found = docs.find(d => d.id === 'ebay_export');
    _cache.ebaySettings = found || {};
  } catch(e) { _cache.ebaySettings = {}; }
  return _cache.ebaySettings;
}

async function loadEbaySettingsFields() {
  const s = await getEbaySettings();
  document.getElementById('ebay-settings-shipping-service').value = s.shippingService || '';
  document.getElementById('ebay-settings-shipping-cost').value = s.shippingCost ?? '';
  document.getElementById('ebay-settings-dispatch-days').value = s.dispatchDays || '';
  document.getElementById('ebay-settings-best-offer').checked = s.bestOfferEnabled || false;
  document.getElementById('ebay-settings-best-offer-accept-pct').value = s.bestOfferAcceptPct ?? '';
  document.getElementById('ebay-settings-best-offer-min-pct').value = s.bestOfferMinPct ?? '';
  toggleEbaySettingsBestOfferFields();
}

function toggleEbaySettingsBestOfferFields() {
  const checked = document.getElementById('ebay-settings-best-offer').checked;
  document.getElementById('ebay-settings-best-offer-fields').style.display = checked ? 'grid' : 'none';
}

async function saveEbaySettings() {
  const settings = {
    id: 'ebay_export',
    shippingService: document.getElementById('ebay-settings-shipping-service').value.trim(),
    shippingCost: parseFloat(document.getElementById('ebay-settings-shipping-cost').value) || 0,
    dispatchDays: parseInt(document.getElementById('ebay-settings-dispatch-days').value) || 4,
    bestOfferEnabled: document.getElementById('ebay-settings-best-offer').checked,
    bestOfferAcceptPct: parseInt(document.getElementById('ebay-settings-best-offer-accept-pct').value) || null,
    bestOfferMinPct: parseInt(document.getElementById('ebay-settings-best-offer-min-pct').value) || null,
  };
  await fsSave('settings', settings);
  _cache.ebaySettings = settings;
  toast(currentLang === 'it' ? '✅ Impostazioni Ebay salvate!' : '✅ Ebay settings saved!', 'success');
}

async function saveEmailReplyTo(value) {
  await fsSave('settings', { id: 'email', replyTo: value });
  _cache.emailReplyTo = value;
}

// ============================================================
//  CONSENSO NEWSLETTER (GDPR)
// ------------------------------------------------------------
//  hasNewsletterConsent() è l'unico punto di verità: un utente riceve la
//  newsletter SOLO se newsletterConsent === true. Il campo undefined
//  ("mai chiesto", tutti gli utenti registrati prima della v5.597) vale
//  come NO — il silenzio non è consenso.
// ============================================================
// ============================================================
//  DISISCRIZIONE A UN CLIC (link profondo dalla newsletter)
// ------------------------------------------------------------
//  Il link in calce a ogni newsletter (?unsubscribe=1) porta qui. Se la
//  sessione non è attiva, l'intento resta in sospeso: il sito chiede
//  l'accesso e, appena ottenuto, ci arriva da solo. Il login NON è un
//  ostacolo burocratico: senza, chiunque conoscesse l'indirizzo potrebbe
//  disiscrivere un altro.
// ============================================================
// L'intento NON può vivere solo in una variabile in memoria: un ricaricamento
// qualsiasi (un refresh, un ritorno indietro, un redirect) lo cancellerebbe in
// silenzio e l'utente atterrerebbe sulla Home senza capire perché. Lo teniamo in
// sessionStorage: sopravvive ai ricaricamenti, muore alla chiusura della scheda.
const PENDING_UNSUB_KEY = 'pending_unsubscribe'; // '1' (link vecchio) oppure l'id del destinatario

// Il link accetta tre forme:
//   #unsubscribe=<id>  → forma attuale: dice ANCHE a chi era indirizzata l'e-mail
//   #unsubscribe       → forma della v5.620, senza destinatario
//   ?unsubscribe=1     → forma della v5.616, senza destinatario
// Le due vecchie restano riconosciute per non rompere le e-mail gia' partite: in
// quel caso non sappiamo chi fosse il destinatario e si agisce su chi e'
// autenticato, che e' il comportamento di prima.
// Il frammento non viene mai trasmesso al server: nessun redirect puo' toglierlo.
function checkUnsubscribeLink() {
  try {
    const hash = (window.location.hash || '').toLowerCase();
    const rawHash = window.location.hash || '';
    let target = null;
    if (hash.startsWith('#unsubscribe')) {
      const eq = rawHash.indexOf('=');
      target = eq >= 0 ? decodeURIComponent(rawHash.slice(eq + 1)) : '1';
    } else if (new URLSearchParams(window.location.search).get('unsubscribe') === '1') {
      target = '1';
    }
    if (target) {
      console.log('[unsubscribe] richiesta rilevata, destinatario:', target === '1' ? '(non indicato)' : target);
      sessionStorage.setItem(PENDING_UNSUB_KEY, target);
      history.replaceState(null, '', window.location.pathname);
    }
    resumePendingUnsubscribe();
  } catch(e) { console.warn('[unsubscribe] checkUnsubscribeLink', e.message); }
}

function pendingUnsubTarget() {
  try { return sessionStorage.getItem(PENDING_UNSUB_KEY); } catch(e) { return null; }
}

function resumePendingUnsubscribe() {
  const target = pendingUnsubTarget();
  if (!target) return false;
  if (!currentUser) {
    console.log('[unsubscribe] non autenticato: chiedo l\'accesso, intento conservato');
    openAuth('login');
    return true;
  }
  console.log('[unsubscribe] apro la pagina di disiscrizione');
  showPage('unsubscribe');
  return true;
}

// La chiave resta in sessionStorage finche' la pagina non ha finito il suo lavoro
// (o l'utente non se ne va): serve a renderUnsubscribePage per sapere a chi era
// indirizzata l'e-mail, e va tolta solo quando l'operazione e' conclusa.
function clearPendingUnsubscribe() {
  try { sessionStorage.removeItem(PENDING_UNSUB_KEY); } catch(e) {}
}

async function renderUnsubscribePage() {
  const el = document.getElementById('unsubscribe-content');
  if (!el || !currentUser) return;
  const L = currentLang === 'it';
  const target = pendingUnsubTarget();            // id destinatario, '1' (link vecchio), o null
  const hasTarget = target && target !== '1';
  const home = `<div style="margin-top:1.25rem;"><a href="#" onclick="showPage('home');return false;" style="color:var(--muted);font-size:0.88rem;">${L ? 'Torna alla Home' : 'Back to Home'}</a></div>`;

  // --- Il link era per un ALTRO account: non si tocca nulla ------------------
  // Nessun dettaglio sul destinatario ne' sullo scopo del link: chi non e' il
  // destinatario non ha motivo di sapere ne' l'uno ne' l'altro.
  if (hasTarget && String(currentUser.id) !== String(target)) {
    el.innerHTML = `
      <div style="font-size:3rem;margin-bottom:0.75rem;">⚠️</div>
      <h1 class="section-title" style="margin-bottom:0.75rem;">${L ? 'Link non valido per questo account' : 'Link not valid for this account'}</h1>
      <p style="color:var(--muted);line-height:1.6;margin-bottom:1.5rem;">
        ${L ? `Il link che hai aperto non è associato all'utenza attualmente connessa (<strong style="color:var(--text);">${esc(currentUser.username)}</strong>), quindi non è stato eseguito.<br><br>Se il link riguardava un altro account, esci e rientra con quello.`
             : `The link you opened is not associated with the currently signed-in account (<strong style="color:var(--text);">${esc(currentUser.username)}</strong>), so it has not been executed.<br><br>If the link was for a different account, sign out and sign in with that one.`}
      </p>
      <button class="btn-secondary" style="font-size:0.95rem;padding:0.6rem 1.5rem;" onclick="logout()">
        ${L ? '🚪 Esci' : '🚪 Sign out'}
      </button>${home}`;
    return;
  }

  // --- Admin: non riceve la newsletter, non c'e' nulla da disiscrivere -------
  if (currentUser.isAdmin) {
    el.innerHTML = `
      <div style="font-size:3rem;margin-bottom:0.75rem;">🛠️</div>
      <h1 class="section-title" style="margin-bottom:0.75rem;">${L ? 'Sei entrato come amministratore' : 'You are signed in as administrator'}</h1>
      <p style="color:var(--muted);line-height:1.6;margin-bottom:1.5rem;">
        ${L ? "L'account amministratore non riceve la newsletter, quindi non c'è nulla da disiscrivere.<br><br>Se stavi provando il link di un altro utente, esci e rientra con quell'account."
             : 'The administrator account does not receive the newsletter, so there is nothing to unsubscribe.<br><br>If you were testing another user\'s link, sign out and sign in with that account.'}
      </p>${home}`;
    return;
  }

  // --- DISISCRIZIONE IMMEDIATA ----------------------------------------------
  // Nessuna schermata di conferma: aprire quel link SIGNIFICA volersi
  // disiscrivere, e chiederglielo una seconda volta sarebbe un ostacolo, non una
  // cautela. E' sicuro perche' la pagina richiede comunque il login: uno scanner
  // antivirus o un anteprima di posta che aprisse il link non e' autenticato, e
  // quindi non puo' disiscrivere nessuno.
  // clearPendingUnsubscribe() e' cruciale: senza, dopo un "Riattiva" la pagina si
  // ridisegnerebbe, ritroverebbe l'intento in sospeso e disiscriverebbe di nuovo,
  // annullando la riattivazione appena fatta.
  if (target && hasNewsletterConsent(currentUser)) {
    el.innerHTML = `<p style="color:var(--muted);padding:2rem 0;">${L ? 'Un attimo…' : 'One moment…'}</p>`;
    const ok = await _setNewsletterConsent(false, 'unsubscribe-link');
    clearPendingUnsubscribe();
    if (!ok) {
      el.innerHTML = `
        <div style="font-size:3rem;margin-bottom:0.75rem;">⚠️</div>
        <h1 class="section-title" style="margin-bottom:0.75rem;">${L ? 'Disiscrizione non riuscita' : 'Unsubscribe failed'}</h1>
        <p style="color:var(--muted);line-height:1.6;margin-bottom:1.5rem;">
          ${L ? 'Qualcosa è andato storto e la modifica non è stata salvata. Riprova fra poco, oppure disattivala dal tuo profilo, sezione "Preferenze e-mail".'
               : 'Something went wrong and the change was not saved. Try again shortly, or turn it off from your profile, "E-mail preferences" section.'}
        </p>${home}`;
      return;
    }
  } else if (target) {
    clearPendingUnsubscribe(); // era gia' disiscritto: niente da fare
  }

  // --- Riattivata (dopo aver premuto "Riattiva la newsletter") --------------
  if (hasNewsletterConsent(currentUser)) {
    el.innerHTML = `
      <div style="font-size:3rem;margin-bottom:0.75rem;">📧</div>
      <h1 class="section-title" style="margin-bottom:0.75rem;">${L ? 'Iscrizione riattivata' : 'Subscription re-enabled'}</h1>
      <p style="color:var(--muted);line-height:1.6;margin-bottom:1.5rem;">
        ${L ? 'Tornerai a ricevere le novità sull\'Inventario Sgorbions.<br>Puoi disattivarla quando vuoi dal tuo profilo, sezione "Preferenze e-mail".'
             : 'You will receive updates on the Sgorbions Inventory again.<br>You can turn it off anytime from your profile, "E-mail preferences" section.'}
      </p>${home}`;
    return;
  }

  // --- Esito normale: disiscritto -------------------------------------------
  el.innerHTML = `
    <div style="font-size:3rem;margin-bottom:0.75rem;">✅</div>
    <h1 class="section-title" style="margin-bottom:0.75rem;white-space:nowrap;font-size:clamp(1.05rem, 4.6vw, 2rem);">${L ? 'Non sei più iscritto alla newsletter' : 'You are no longer subscribed to the newsletter'}</h1>
    <p style="color:var(--muted);line-height:1.6;margin-bottom:1.5rem;">
      ${L ? 'Non riceverai altre comunicazioni sulle novità dell\'Inventario Sgorbions.<br>Se hai già cambiato idea, puoi riattivarla subito qui sotto — o comunque sia potrai farlo in qualunque momento dal tuo profilo, sezione "Preferenze e-mail".'
           : 'You will receive no further updates on the Sgorbions Inventory.<br>If you have already changed your mind, you can re-enable it right below — or you can do so at any time from your profile, "E-mail preferences" section.'}
    </p>
    <button class="btn-secondary" style="font-size:0.95rem;padding:0.6rem 1.5rem;" onclick="doResubscribeFromLink()">
      ${L ? '📧 Riattiva la newsletter' : '📧 Re-enable the newsletter'}
    </button>
    <p style="color:var(--muted);font-size:0.82rem;line-height:1.5;margin:1.25rem auto 0;max-width:34rem;opacity:0.85;">
      ${L ? 'Le e-mail di servizio (benvenuto, risposte ai tuoi post e ai tuoi messaggi) continueranno comunque ad arrivarti: non sono newsletter.'
           : 'Service e-mails (welcome, replies to your posts and messages) will still reach you: they are not newsletters.'}
    </p>${home}`;
}

// L'unico clic. Origine 'unsubscribe-link', così nella tabella admin si distingue
// da una revoca fatta dal profilo: sono due percorsi diversi e sapere quale sia
// stato usato è un'informazione, non un dettaglio.

async function doResubscribeFromLink() {
  if (!currentUser) return;
  const ok = await _setNewsletterConsent(true, 'unsubscribe-link');
  if (ok) clearPendingUnsubscribe();
  renderUnsubscribePage();
}

// Punto unico di scrittura del consenso: prima la stessa logica era ripetuta in
// saveNewsletterConsent() e setNewsletterConsentFromPrompt(), e ora sarebbe stata
// ripetuta una terza e una quarta volta.
async function _setNewsletterConsent(value, source, opts = {}) {
  const L = currentLang === 'it';
  const prev = currentUser.newsletterConsent;
  currentUser.newsletterConsent = !!value;
  currentUser.newsletterConsentDate = new Date().toISOString();
  currentUser.newsletterConsentSource = source;
  LOCAL.set('currentUser', currentUser);
  try {
    await fsSave('users', currentUser);
  } catch(e) {
    console.error('_setNewsletterConsent', e);
    currentUser.newsletterConsent = prev; // ripristino: la scrittura non è andata
    LOCAL.set('currentUser', currentUser);
    toast(L ? 'Salvataggio non riuscito, riprova' : 'Save failed, please retry', 'error');
    return false;
  }
  // EVENTO su ogni passaggio a "no" che non sia una ripetizione (prev !== false).
  // Due casi distinti, e la descrizione li tiene separati perché non sono la
  // stessa cosa:
  //   - prev === true      → REVOCA: aveva la newsletter, l'ha disattivata.
  //   - prev === undefined → RIFIUTO: gli abbiamo chiesto e ha detto di no.
  // Il secondo caso è comunque una scelta esplicita, informata e libera — non un
  // silenzio — e come tale merita di essere registrata (Franco, v5.618).
  // Il "No, grazie" in fase di registrazione resta invece fuori: passa per un'altra
  // strada (il consenso è scritto direttamente sul nuovo utente) ed è già coperto
  // dall'evento 'new_user' che quella registrazione genera comunque.
  if (value === false && prev !== false) {
    const via = source === 'unsubscribe-link'
      ? 'link in calce alla newsletter'
      : (source === 'profile' ? 'toggle nel profilo'
      : (source === 'prompt' ? 'prompt al primo accesso' : source));
    const testo = (prev === true)
      ? `L'utente ${bold(currentUser.username)} si è disiscritto dalla newsletter (${via})`
      : `L'utente ${bold(currentUser.username)} ha rifiutato la newsletter (${via})`;
    logEvent('newsletter_off', testo);
  }

  // opts.silent: il chiamante ha un messaggio suo. È il caso del prompt
  // una-tantum, dove un "no" non è una REVOCA ma una prima risposta — dirgli
  // "ci dispiace che tu abbia disattivato" sarebbe stonato.
  if (!opts.silent) {
    toast(value
      ? (L ? "Hai attivato l'iscrizione alla newsletter figurinesgorbions.it 😊<br>Complimenti e grazie!"
           : "You've subscribed to the figurinesgorbions.it newsletter 😊<br>Thank you!")
      : (L ? "Ci dispiace che tu abbia disattivato la newsletter! 😢<br>Potrai riattivarla quando vuoi.<br>Ricorda che è l'unico modo per rimanere aggiornato sull'Inventario Sgorbions via e-mail."
           : "We're sorry to see you unsubscribe! 😢<br>You can turn it back on whenever you like.<br>Remember it's the only way to stay up to date on the Sgorbions Inventory by e-mail."),
      'success', null, value ? 5000 : 7000);
  }
  return true;
}

function hasNewsletterConsent(user) {
  return user?.newsletterConsent === true;
}

// Chiede il consenso a chi non l'ha mai espresso (campo undefined): tutti gli
// utenti registrati prima della v5.597, e i nuovi utenti Google (che non
// passano dal form di registrazione, quindi non vedono la casella).
// Non viene mai chiesto all'admin, né durante un'impersonificazione.
function maybeAskNewsletterConsent() {
  if (!currentUser || currentUser.isAdmin) return;
  if (typeof isImpersonating === 'function' && isImpersonating()) return;
  if (currentUser.newsletterConsent !== undefined) return; // già chiesto: sì o no che sia
  const modal = document.getElementById('newsletter-consent-modal');
  if (modal) modal.classList.remove('hidden');
}

// Risposta al prompt. Registra SEMPRE la scelta (anche il "no"), con data e
// origine: il GDPR chiede di poter dimostrare il consenso, e registrare anche
// il rifiuto evita di riproporre il modal a ogni accesso.
async function setNewsletterConsentFromPrompt(value) {
  const modal = document.getElementById('newsletter-consent-modal');
  if (modal) modal.classList.add('hidden');
  if (!currentUser) return;
  const L = currentLang === 'it';
  const ok = await _setNewsletterConsent(value, 'prompt', { silent: true });
  if (!ok) return;
  // Messaggi propri: il "sì" coincide con quello dell'attivazione, il "no" no —
  // qui non c'è nessuna disattivazione da rimpiangere, è una prima risposta.
  if (value) {
    toast(L
      ? "Hai attivato l'iscrizione alla newsletter figurinesgorbions.it 😊<br>Complimenti e grazie!"
      : "You've subscribed to the figurinesgorbions.it newsletter 😊<br>Thank you!",
      'success', null, 5000);
  } else {
    toast(L
      ? 'Nessuna newsletter: rispetteremo la tua scelta. 😢<br>Potrai attivarla quando vuoi dal tuo profilo.'
      : "No newsletter: we'll respect your choice. 😢<br>You can enable it anytime from your profile.",
      'success', null, 5000);
  }
}

// Toggle nel profilo: dà o revoca il consenso in qualsiasi momento.
async function saveNewsletterConsent() {
  if (!currentUser) return;
  const cb = document.getElementById('profile-newsletter-toggle');
  const enabling = cb?.checked || false;
  const L = currentLang === 'it';

  // Conferma solo allo SPEGNIMENTO. È una spunta piccola in mezzo al profilo:
  // si preme per sbaglio, e l'utente se ne accorgerebbe solo settimane dopo, non
  // ricevendo più nulla. All'accensione invece nessuna conferma — un'iscrizione
  // fatta per errore si annulla in un clic, e chiedere "sei sicuro di volerti
  // iscrivere?" suonerebbe come un tentativo di scoraggiarlo.
  if (!enabling) {
    const ok = confirm(L
      ? 'Vuoi davvero disattivare la newsletter?\n\nNon riceverai più le novità sull\'Inventario Sgorbions.\nPotrai riattivarla quando vuoi da qui.\n\nLe e-mail di servizio (benvenuto, risposte ai tuoi post e ai tuoi messaggi) continueranno comunque ad arrivarti: non sono newsletter.'
      : 'Do you really want to turn off the newsletter?\n\nYou will no longer receive updates on the Sgorbions Inventory.\nYou can turn it back on from here whenever you like.\n\nService e-mails (welcome, replies to your posts and messages) will still reach you: they are not newsletters.');
    if (!ok) { if (cb) cb.checked = true; return; } // annullato: la spunta torna accesa
  }

  const ok = await _setNewsletterConsent(enabling, 'profile');
  if (!ok && cb) cb.checked = !enabling; // scrittura fallita: la spunta torna com'era
}

// Lingua del DESTINATARIO di un'e-mail. Non si può usare currentLang: quella è
// la lingua dell'admin che sta inviando, non di chi riceve — un admin che scrive
// con il sito in italiano manderebbe un piè di pagina italiano anche a un inglese.
// Ordine di preferenza:
//   1. user.lang — salvato alla registrazione (dalla v5.615). È il dato migliore:
//      è la lingua che quella persona stava effettivamente usando.
//   2. nationalityCode — ripiego per gli utenti registrati prima, che user.lang
//      non ce l'hanno. Stessa regola che il sito applica al login.
//   3. italiano — se non c'è né l'uno né l'altro. Il sito è italiano di origine
//      (dominio .it) ed è lo stesso ripiego di _detectBrowserLang.
function userLangFor(user) {
  if (user?.lang === 'it' || user?.lang === 'en') return user.lang;
  if (user?.nationalityCode) return user.nationalityCode === 'it' ? 'it' : 'en';
  return 'it';
}

// Link profondo di disiscrizione: porta direttamente alla pagina dedicata, dove
// basta un clic. Se la sessione non è attiva il sito chiede prima l'accesso e poi
// ci arriva da solo (l'intento resta in sospeso, vedi _pendingUnsubscribe) — il
// login è indispensabile: senza, chiunque conoscesse l'indirizzo potrebbe
// disiscrivere qualcun altro.
// Frammento, non query: il frammento non viene MAI trasmesso al server, quindi
// nessun redirect (http→https, apex→www, inoltro del dominio) può eliminarlo
// per strada. La forma con ?unsubscribe=1 resta comunque riconosciuta, per le
// e-mail già inviate.
// Il link porta con se' l'ID DEL DESTINATARIO. Senza, direbbe soltanto "qualcuno
// vuole disiscriversi" e la pagina agirebbe su chiunque fosse autenticato in quel
// browser: l'admin che apre il link di una newsletter mandata a Mario
// disiscriverebbe SE STESSO, e Mario resterebbe iscritto.
// L'id NON e' una credenziale e non autorizza nulla: la pagina richiede comunque
// il login e verifica che l'utente autenticato SIA quel destinatario. Serve solo
// a riconoscere il bersaglio giusto e a dirlo chiaramente quando non coincide.
// La query serve SOLO a scavalcare la cache del browser; il carico utile sta nel
// frammento. Perche' entrambi:
//   - il FRAMMENTO (#unsubscribe=<id>) non viene mai trasmesso al server, quindi
//     nessun redirect puo' toglierlo: e' il posto sicuro per l'identita';
//   - ma il frammento NON fa parte della chiave di cache. "figurinesgorbions.it/"
//     e "figurinesgorbions.it/#unsubscribe=123" sono per il browser la stessa
//     risorsa. Chi ha visitato il sito di recente si vedrebbe servire l'index.html
//     vecchio (GitHub Pages lo manda con max-age=600), che a sua volta punta a un
//     app.js vecchio: il link aprirebbe una versione superata del sito.
//   - la QUERY invece fa parte della chiave di cache. Mettendoci la versione,
//     dopo ogni rilascio il primo clic e' per forza un miss: index.html viene
//     riscaricato fresco.
// Divisione dei ruoli: la query e' sacrificabile (se un redirect la mangia non
// perdiamo nulla, solo il vantaggio sulla cache), il frammento e' il dato vero.
const UNSUBSCRIBE_URL = (userId) =>
  'https://figurinesgorbions.it/?nl=' + encodeURIComponent(JS_VERSION) +
  '#unsubscribe=' + encodeURIComponent(userId || '');

const NEWSLETTER_FOOTER = (lang, userId) => (lang === 'en')
  ? '\n\n———\n' +
    'You are receiving this e-mail because you consented to the figurinesgorbions.it newsletter.\n' +
    'To unsubscribe, open this link and confirm with one click:\n' +
    UNSUBSCRIBE_URL(userId)
  : '\n\n———\n' +
    'Ricevi questa e-mail perché hai acconsentito alla newsletter di figurinesgorbions.it.\n' +
    'Per disiscriverti, apri questo link e conferma con un clic:\n' +
    UNSUBSCRIBE_URL(userId);

// Limite mensile del piano gratuito EmailJS. Era cablato come "200" in più punti;
// tenerlo in un solo posto evita che un domani ne resti indietro uno.
const EMAILJS_MONTHLY_LIMIT = 200;

async function sendEmail(toEmail, username, subject, messaggio, options = {}) {
  // Log always, regardless of EmailJS outcome
  if (typeof emailjs === 'undefined') { console.warn('EmailJS not loaded'); await logEmail(toEmail, subject, options.source || 'other', messaggio, 'failed'); return { ok: false, error: 'EmailJS non caricato' }; }
  try {
    const replyTo = await getEmailReplyTo();
    // Solo la newsletter porta in calce il rimando alla revoca del consenso:
    // le e-mail transazionali (benvenuto, risposte) non sono marketing e non
    // hanno una disiscrizione da offrire.
    // options.lang è la lingua del DESTINATARIO, non quella dell'admin.
    // In sua assenza si ripiega sull'italiano (vedi userLangFor).
    const bodyToSend = (options.source === 'newsletter')
      ? messaggio + NEWSLETTER_FOOTER(options.lang || 'it', options.userId)
      : messaggio;
    const payload = {
      email: toEmail,
      username: username,
      subject: subject,
      messaggio: bodyToSend
    };
    if (replyTo) payload.reply_to = replyTo;
    if (options.bcc) payload.bcc = options.bcc;
    await emailjs.send(EMAILJS_SERVICE, EMAILJS_TEMPLATE, payload);
    console.log('Email inviata a', toEmail);
    await logEmail(toEmail, subject, options.source || 'other', messaggio, 'sent');
    // Il contatore si incrementa QUI, non nei chiamanti. Prima era sparso fra
    // loro, e due percorsi se l'erano dimenticato: la risposta a un messaggio dai
    // Contatti e il ciclo di sendNewsletterEmail(). Contando nell'unico punto da
    // cui l'e-mail esce davvero, il conteggio non può più divergere dal log —
    // che è scritto un rigo sopra, dalla stessa condizione di successo.
    await incrementEmailCounter(1);
    return { ok: true };
  } catch(e) {
    console.error('Errore invio email', e);
    const rawMsg = e?.text || e?.message || String(e);
    let friendly = rawMsg;
    if (/authentication failed|535/i.test(rawMsg)) {
      friendly = currentLang === 'it'
        ? 'Autenticazione SMTP fallita — controlla le credenziali email su EmailJS (la password potrebbe essere cambiata)'
        : 'SMTP authentication failed — check email credentials on EmailJS (password may have changed)';
    }
    await logEmail(toEmail, subject, options.source || 'other', messaggio, 'failed');
    return { ok: false, error: friendly };
  }
}

async function sendWelcomeEmail(user) {
  await sendEmail(
    user.email,
    user.username,
    'Benvenuto su figurinesgorbions.it! 👾',
    'Benvenuto nella community Sgorbions di figurinesgorbions.it!\n\nIl tuo account è stato creato con successo. Inizia subito a esplorare l\'Inventario e a costruire la tua lista!'
  );
}

async function sendReplyNotificationEmail(postAuthorId, postTitle, replyAuthor, replyText) {
  const users = getData('users', []);
  const postAuthor = users.find(u => u.id === postAuthorId);
  if (!postAuthor || !postAuthor.email) return;
  // Don't notify if replying to own post
  if (postAuthor.id === currentUser.id) return;
  await sendEmail(
    postAuthor.email,
    postAuthor.username,
    'Qualcuno ha risposto al tuo post! 💬',
    replyAuthor + ' ha risposto al tuo post "' + postTitle + '":\n\n"' + replyText + '"\n\nVai a vedere la risposta su figurinesgorbions.it'
  );
}

let _emailArchiveFilter = 'newsletter';

function switchEmailArchiveTab(filter) {
  _emailArchiveFilter = filter;
  document.querySelectorAll('.email-archive-tab-btn').forEach(btn => {
    const active = btn.getAttribute('data-archive') === filter;
    btn.style.borderBottomColor = active ? 'var(--accent)' : 'transparent';
    btn.style.color = active ? 'var(--accent)' : 'var(--muted)';
    btn.style.fontWeight = active ? '600' : '400';
  });
  renderEmailLog();
}

// targetId: id del contenitore dove disegnare la tabella
// filterSource: 'all' | 'newsletter' | 'messages' — se omesso usa _emailArchiveFilter (pannello E-mail)
// Cancellazione di una riga dal registro delle comunicazioni.
// ATTENZIONE: le tabelle mescolano DUE raccolte — le e-mail vere (email_log) e le
// newsletter recapitate come messaggio interno (contact_messages con
// isAnnouncement). Il pulsante deve quindi sapere da dove togliere: passare la
// raccolta sbagliata significherebbe non cancellare nulla, in silenzio.
async function deleteLogRow(coll, id) {
  if (!confirm(currentLang === 'it'
    ? 'Eliminare questa riga dal registro?'
    : 'Delete this row from the log?')) return;
  try {
    await fsDelete(coll, id);
    if (coll === 'contact_messages' && _cache.contact_messages) {
      _cache.contact_messages = _cache.contact_messages.filter(m => m.id !== id);
    }
    // email_log non e' in cache: le tabelle lo rileggono da Firestore a ogni
    // disegno, quindi basta ridisegnare.
    renderEmailLog();
    renderNewsletterLog('newsletter-email-log');
    toast(currentLang === 'it' ? 'Riga eliminata' : 'Row deleted', 'success');
  } catch(e) {
    console.error('deleteLogRow', e);
    toast(currentLang === 'it' ? 'Eliminazione non riuscita' : 'Delete failed', 'error');
  }
}

// Il pulsante, uguale in tutte e tre le viste.
function logDeleteBtn(coll, id) {
  return '<button class="tbl-btn tbl-btn-del" style="margin-right:0;" onclick="event.stopPropagation();deleteLogRow(\'' + coll + '\',\'' + id + '\')" title="' + (currentLang === 'it' ? 'Elimina questa riga' : 'Delete this row') + '">🗑️</button>';
}

async function renderEmailLogInto(targetId, filterSource) {
  const el = document.getElementById(targetId);
  if (!el) return;
  el.innerHTML = '<p style="color:var(--muted);font-style:italic;">' + (currentLang === 'it' ? 'Caricamento...' : 'Loading...') + '</p>';
  try {
    let logs = await fsGetAll('email_log');
    if (filterSource !== 'all') {
      logs = logs.filter(e => e.source === filterSource);
    }
    logs.sort((a,b) => new Date(b.date) - new Date(a.date));
    if (!logs.length) { el.innerHTML = '<p style="color:var(--muted);font-style:italic;">' + (currentLang === 'it' ? 'Nessuna e-mail registrata.' : 'No emails recorded.') + '</p>'; return; }
    const display = logs.slice(0, 50);
    const note = logs.length > 50 ? `<p style="font-size:0.78rem;color:var(--muted);margin-bottom:0.5rem;">${currentLang === 'it' ? 'Mostrate le ultime 50 di ' + logs.length : 'Showing last 50 of ' + logs.length}</p>` : '';
    const sourceLabel = (s) => s === 'newsletter' ? '📬 Newsletter' : s === 'pwdreset' ? '🔑 ' + (currentLang === 'it' ? 'Reset password' : 'Password reset') : '↩️ ' + (currentLang === 'it' ? 'Messaggio ricevuto' : 'Received message');
    const showSourceCol = filterSource === 'all';
    const rows = display.map((e, idx) => {
      const rowId = targetId + '-row-' + idx;
      const detailId = targetId + '-detail-' + idx;
      const statusIcon = e.status === 'failed' ? '<span title="Invio fallito" style="color:#ff6464;">❌ </span>' : '<span style="color:var(--success);">✓ </span>';
      const mainRow = '<tr style="cursor:pointer;" onclick="toggleEmailDetail(\'' + detailId + '\')">' +
        '<td style="white-space:nowrap;font-size:0.88rem;padding:0.4rem 0.75rem;">' + statusIcon + new Date(e.date).toLocaleDateString('it-IT') + ' ' + new Date(e.date).toLocaleTimeString('it-IT',{hour:'2-digit',minute:'2-digit'}) + '</td>' +
        '<td style="font-size:0.88rem;padding:0.4rem 0.75rem;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;">' + e.to + '</td>' +
        '<td style="font-size:0.88rem;padding:0.4rem 0.75rem;">' + e.subject + '</td>' +
        (showSourceCol ? '<td style="font-size:0.85rem;color:var(--muted);padding:0.4rem 0.75rem;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;">' + sourceLabel(e.source) + '</td>' : '') +
        '<td style="padding:0.4rem 0.5rem;white-space:nowrap;overflow:hidden;text-align:center;">' + logDeleteBtn('email_log', e.id) + '</td>' +
        '</tr>';
      const colspan = showSourceCol ? 5 : 4;
      const bodyHtml = e.body
        ? '<div style="white-space:pre-line;font-size:0.88rem;line-height:1.6;color:var(--text);padding:0.5rem 0;">' + e.body.replace(/[<]/g,'&lt;').replace(/[>]/g,'&gt;') + '</div>'
        : e.source === 'pwdreset'
          ? '<p style="color:var(--muted);font-style:italic;font-size:0.85rem;">' + (currentLang === 'it' ? 'Contenuto non disponibile: questa e-mail è generata e inviata direttamente da Firebase Authentication, non dal nostro sistema.' : 'Content not available: this e-mail is generated and sent directly by Firebase Authentication, not by our system.') + '</p>'
          : '<p style="color:var(--muted);font-style:italic;font-size:0.85rem;">' + (currentLang === 'it' ? 'Corpo non disponibile (email inviata prima di questa funzionalità)' : 'Body not available (email sent before this feature)') + '</p>';
      const detailRow = '<tr id="' + detailId + '" style="display:none;"><td colspan="' + colspan + '" style="padding:0.75rem 1rem;background:var(--card2);border-bottom:1px solid var(--border);">' +
        '<div style="font-size:0.78rem;color:var(--muted);margin-bottom:0.4rem;"><strong>' + (currentLang === 'it' ? 'Da:' : 'From:') + '</strong> figurinesgorbions.it &nbsp;|&nbsp; <strong>' + (currentLang === 'it' ? 'A:' : 'To:') + '</strong> ' + e.to + '</div>' +
        '<div style="font-size:0.78rem;color:var(--muted);margin-bottom:0.75rem;"><strong>' + (currentLang === 'it' ? 'Oggetto:' : 'Subject:') + '</strong> ' + e.subject + '</div>' +
        bodyHtml +
        '</td></tr>';
      return mainRow + detailRow;
    }).join('');
    el.innerHTML = note + '<div style="overflow-x:auto;"><table class="data-table" style="border-spacing:0;table-layout:fixed;width:100%;min-width:850px;"><thead><tr>' +
      '<th style="padding:0.4rem 0.75rem;width:170px;">' + (currentLang === 'it' ? 'Data invio' : 'Sent date') + '</th>' +
      '<th style="padding:0.4rem 0.75rem;width:220px;">' + (currentLang === 'it' ? 'Destinatario' : 'Recipient') + '</th>' +
      '<th style="padding:0.4rem 0.75rem;">' + (currentLang === 'it' ? 'Soggetto' : 'Subject') + '</th>' +
      (showSourceCol ? '<th style="padding:0.4rem 0.75rem;width:130px;">' + (currentLang === 'it' ? 'Origine' : 'Source') + '</th>' : '') +
      '<th style="padding:0.4rem 0.75rem;width:90px;"></th>' +
      '</tr></thead><tbody>' + rows + '</tbody></table></div>';
  } catch(err) { el.innerHTML = '<p style="color:var(--muted);">' + (currentLang === 'it' ? 'Errore caricamento log.' : 'Error loading log.') + '</p>'; }
}

function toggleEmailDetail(detailId) {
  const row = document.getElementById(detailId);
  if (!row) return;
  const allDetails = row.closest('table').querySelectorAll('tr[id*="-detail-"]');
  allDetails.forEach(r => { if (r.id !== detailId) r.style.display = 'none'; });
  const isOpen = row.style.display !== 'none';
  row.style.display = isOpen ? 'none' : '';
  // Aggiorna l'indicatore ▶/▼ nella riga principale
  const mainRow = row.previousElementSibling;
  if (mainRow) {
    const firstCell = mainRow.querySelector('td');
    if (firstCell) firstCell.innerHTML = firstCell.innerHTML.replace(isOpen ? '▼' : '▶', isOpen ? '▶' : '▼');
  }
}

// Log unificato della Newsletter: sia le e-mail inviate (da email_log,
// source=newsletter) sia i messaggi inviati come annuncio (da
// contact_messages, isAnnouncement:true), con un'icona che distingue il
// mezzo di invio. Usato sia nel tab Newsletter di Comunicazioni sia nella
// pagina di composizione, perché mostrino sempre lo stesso identico elenco
async function renderNewsletterLog(targetId) {
  const el = document.getElementById(targetId);
  if (!el) return;
  el.innerHTML = '<p style="color:var(--muted);font-style:italic;">' + (currentLang === 'it' ? 'Caricamento...' : 'Loading...') + '</p>';
  try {
    // Il destinatario si mostra con nome utente e bandierina, come nel resto del
    // pannello. L'indirizzo e-mail invece NON e' un dato neutro: stamparlo accanto
    // a una newsletter recapitata come MESSAGGIO interno sarebbe fuorviante,
    // perche' a quell'indirizzo non e' stato mandato nulla. Lo si usa solo per
    // ritrovare l'utente, e lo si stampa solo quando l'invio e' avvenuto davvero
    // per e-mail.
    const perEmail = new Map(
      getData('users', []).map(u => [(u.email || '').toLowerCase(), u])
    );
    // id e coll servono al pulsante di cancellazione: senza, il .map() li perdeva
    // e non ci sarebbe stato modo di sapere COSA cancellare e DOVE.
    const emailLogs = (await fsGetAll('email_log')).filter(e => e.source === 'newsletter').map(e => ({
      id: e.id, coll: 'email_log',
      date: e.date, to: e.to, subject: e.subject, body: e.body, method: 'email', status: e.status,
      user: perEmail.get((e.to || '').toLowerCase()) || null
    }));
    const msgLogs = getData('contact_messages', []).filter(m => m.isAnnouncement).map(m => ({
      id: m.id, coll: 'contact_messages',
      date: m.repliedAt || m.date, to: m.email, subject: m.subject, body: m.message, method: 'message', status: 'ok',
      // il record dell'annuncio porta gia' il nome utente; la nazionalita' si
      // ritrova per indirizzo, che pero' non verra' mostrato.
      user: perEmail.get((m.email || '').toLowerCase()) || (m.name ? { username: m.name } : null)
    }));
    const combined = [...emailLogs, ...msgLogs].sort((a,b) => new Date(b.date) - new Date(a.date));
    if (!combined.length) { el.innerHTML = '<p style="color:var(--muted);font-style:italic;">' + (currentLang === 'it' ? 'Nessuna newsletter inviata.' : 'No newsletter sent.') + '</p>'; return; }
    const display = combined.slice(0, 50);
    const note = combined.length > 50 ? `<p style="font-size:0.78rem;color:var(--muted);margin-bottom:0.5rem;">${currentLang === 'it' ? 'Mostrate le ultime 50 di ' + combined.length : 'Showing last 50 of ' + combined.length}</p>` : '';
    const methodLabel = (e) => e.method === 'email' ? '✉️ E-mail' : '💬 ' + (currentLang === 'it' ? 'Messaggio' : 'Message');

    // DUE COLONNE distinte, non due righe impilate: l'utente (bandierina + nome)
    // e l'indirizzo e-mail.
    // L'indirizzo si stampa SOLO se l'invio e' avvenuto davvero per e-mail. Per un
    // messaggio interno la cella resta VUOTA — non un trattino, non l'indirizzo:
    // scrivere li' un indirizzo a cui non e' stato mandato nulla farebbe credere
    // il contrario, e questo pannello serve anche a dimostrare cosa e' stato
    // spedito e a chi.
    const cellaUtente = (e) => {
      const u = e.user;
      if (!u?.username) return '<span style="color:var(--muted);">—</span>';
      const bandiera = u.nationalityCode
        ? `<img src="${flagUrl(u.nationalityCode)}" title="${esc(u.nationalityName || '')}" style="width:20px;height:15px;object-fit:cover;border-radius:2px;vertical-align:middle;margin-right:0.45rem;">`
        : '';
      return bandiera + `<span style="vertical-align:middle;">${esc(u.username)}</span>`;
    };
    const cellaEmail = (e) => (e.method === 'email' && e.to)
      ? esc(e.to)
      : '<span style="color:var(--muted);">—</span>';
    const rows = display.map((e, idx) => {
      const detailId = targetId + '-detail-' + idx;
      const statusIcon = e.status === 'failed' ? '<span title="Invio fallito" style="color:#ff6464;">❌ </span>' : '<span style="color:var(--success);">✓ </span>';
      const mainRow = '<tr style="cursor:pointer;" onclick="toggleEmailDetail(\'' + detailId + '\')">' +
        '<td style="white-space:nowrap;font-size:0.88rem;padding:0.4rem 0.75rem;">' + statusIcon + new Date(e.date).toLocaleDateString('it-IT') + ' ' + new Date(e.date).toLocaleTimeString('it-IT',{hour:'2-digit',minute:'2-digit'}) + '</td>' +
        '<td style="font-size:0.88rem;padding:0.4rem 0.75rem;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;">' + cellaUtente(e) + '</td>' +
        '<td style="font-size:0.88rem;padding:0.4rem 0.75rem;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;">' + cellaEmail(e) + '</td>' +
        '<td style="font-size:0.88rem;padding:0.4rem 0.75rem;overflow:hidden;text-overflow:ellipsis;">' + esc(e.subject || '') + '</td>' +
        '<td style="font-size:0.85rem;color:var(--muted);padding:0.4rem 0.75rem;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;">' + methodLabel(e) + '</td>' +
        '<td style="padding:0.4rem 0.5rem;white-space:nowrap;overflow:hidden;text-align:center;">' + logDeleteBtn(e.coll, e.id) + '</td>' +
        '</tr>';
      const bodyHtml = e.body
        ? '<div style="white-space:pre-line;font-size:0.88rem;line-height:1.6;color:var(--text);padding:0.5rem 0;">' + e.body.replace(/[<]/g,'&lt;').replace(/[>]/g,'&gt;') + '</div>'
        : '<p style="color:var(--muted);font-style:italic;font-size:0.85rem;">' + (currentLang === 'it' ? 'Corpo non disponibile' : 'Body not available') + '</p>';
      const detailRow = '<tr id="' + detailId + '" style="display:none;"><td colspan="6" style="padding:0.75rem 1rem;background:var(--card2);border-bottom:1px solid var(--border);">' +
        // Anche qui: per un messaggio interno il "A:" non e' un indirizzo e-mail —
        // e' il destinatario dentro il sito. Mostrare l'indirizzo farebbe credere
        // che gli sia stata scritta un'e-mail, che non e' successo.
        '<div style="font-size:0.78rem;color:var(--muted);margin-bottom:0.4rem;"><strong>' + (currentLang === 'it' ? 'Da:' : 'From:') + '</strong> figurinesgorbions.it &nbsp;|&nbsp; <strong>' + (currentLang === 'it' ? 'A:' : 'To:') + '</strong> ' + esc(e.method === 'email' ? (e.to || '') : (e.user?.username || '—')) + '</div>' +
        '<div style="font-size:0.78rem;color:var(--muted);margin-bottom:0.75rem;"><strong>' + (currentLang === 'it' ? 'Oggetto:' : 'Subject:') + '</strong> ' + esc(e.subject || '') + '</div>' +
        bodyHtml +
        '</td></tr>';
      return mainRow + detailRow;
    }).join('');
    el.innerHTML = note + '<div style="overflow-x:auto;"><table class="data-table" style="border-spacing:0;table-layout:fixed;width:100%;min-width:990px;"><thead><tr>' +
      '<th style="padding:0.4rem 0.75rem;width:150px;">' + (currentLang === 'it' ? 'Data invio' : 'Sent date') + '</th>' +
      '<th style="padding:0.4rem 0.75rem;width:170px;">' + (currentLang === 'it' ? 'Utente' : 'User') + '</th>' +
      '<th style="padding:0.4rem 0.75rem;width:210px;">' + (currentLang === 'it' ? 'E-mail' : 'E-mail') + '</th>' +
      '<th style="padding:0.4rem 0.75rem;">' + (currentLang === 'it' ? 'Soggetto' : 'Subject') + '</th>' +
      '<th style="padding:0.4rem 0.75rem;width:130px;">' + (currentLang === 'it' ? 'Mezzo' : 'Method') + '</th>' +
      '<th style="padding:0.4rem 0.75rem;width:90px;"></th>' +
      '</tr></thead><tbody>' + rows + '</tbody></table></div>';
  } catch(err) { el.innerHTML = '<p style="color:var(--muted);">' + (currentLang === 'it' ? 'Errore caricamento log.' : 'Error loading log.') + '</p>'; }
}

async function renderEmailLog() {
  if (_emailArchiveFilter === 'messages') return renderSentMessagesLog('admin-email-log');
  if (_emailArchiveFilter === 'newsletter') return renderNewsletterLog('admin-email-log');
  return renderEmailLogInto('admin-email-log', _emailArchiveFilter);
}

// Log unificato dei messaggi inviati (non e-mail): sia le risposte alle
// richieste degli utenti sia gli annunci newsletter inviati come
// messaggio, presi direttamente da contact_messages (che traccia sempre
// il testo, e-mail inviata o meno), con una colonna Origine che li
// distingue
async function renderSentMessagesLog(targetId) {
  const el = document.getElementById(targetId);
  if (!el) return;
  const msgs = getData('contact_messages', []).filter(m => m.replied).sort((a,b) => new Date(b.repliedAt || b.date) - new Date(a.repliedAt || a.date));
  if (!msgs.length) { el.innerHTML = '<p style="color:var(--muted);font-style:italic;">' + (currentLang === 'it' ? 'Nessun messaggio inviato.' : 'No messages sent.') + '</p>'; return; }
  const display = msgs.slice(0, 50);
  const note = msgs.length > 50 ? `<p style="font-size:0.78rem;color:var(--muted);margin-bottom:0.5rem;">${currentLang === 'it' ? 'Mostrati gli ultimi 50 di ' + msgs.length : 'Showing last 50 of ' + msgs.length}</p>` : '';
  const originLabel = (m) => m.isAnnouncement ? '📬 Newsletter' : '↩️ ' + (currentLang === 'it' ? 'Messaggio ricevuto' : 'Received message');
  const rows = display.map((m, idx) => {
    const detailId = targetId + '-detail-' + idx;
    const dateVal = m.repliedAt || m.date;
    const mainRow = '<tr style="cursor:pointer;" onclick="toggleEmailDetail(\'' + detailId + '\')">' +
      '<td style="white-space:nowrap;font-size:0.88rem;padding:0.4rem 0.75rem;">' + new Date(dateVal).toLocaleDateString('it-IT') + ' ' + new Date(dateVal).toLocaleTimeString('it-IT',{hour:'2-digit',minute:'2-digit'}) + '</td>' +
      '<td style="font-size:0.88rem;padding:0.4rem 0.75rem;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;">' + m.email + '</td>' +
      '<td style="font-size:0.88rem;padding:0.4rem 0.75rem;">' + (m.subject || '') + '</td>' +
      '<td style="font-size:0.85rem;color:var(--muted);padding:0.4rem 0.75rem;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;">' + originLabel(m) + '</td>' +
      '<td style="padding:0.4rem 0.5rem;white-space:nowrap;overflow:hidden;text-align:center;">' + logDeleteBtn('contact_messages', m.id) + '</td>' +
      '</tr>';
    const bodyText = m.isAnnouncement ? m.message : (m.replyText || '');
    const bodyHtml = '<div style="white-space:pre-line;font-size:0.88rem;line-height:1.6;color:var(--text);padding:0.5rem 0;">' + bodyText.replace(/[<]/g,'&lt;').replace(/[>]/g,'&gt;') + '</div>';
    const detailRow = '<tr id="' + detailId + '" style="display:none;"><td colspan="5" style="padding:0.75rem 1rem;background:var(--card2);border-bottom:1px solid var(--border);">' +
      '<div style="font-size:0.78rem;color:var(--muted);margin-bottom:0.4rem;"><strong>' + (currentLang === 'it' ? 'Da:' : 'From:') + '</strong> figurinesgorbions.it &nbsp;|&nbsp; <strong>' + (currentLang === 'it' ? 'A:' : 'To:') + '</strong> ' + m.email + '</div>' +
      '<div style="font-size:0.78rem;color:var(--muted);margin-bottom:0.75rem;"><strong>' + (currentLang === 'it' ? 'Oggetto:' : 'Subject:') + '</strong> ' + (m.subject || '') + '</div>' +
      bodyHtml +
      '</td></tr>';
    return mainRow + detailRow;
  }).join('');
  el.innerHTML = note + '<div style="overflow-x:auto;"><table class="data-table" style="border-spacing:0;table-layout:fixed;width:100%;min-width:850px;"><thead><tr>' +
    '<th style="padding:0.4rem 0.75rem;width:170px;">' + (currentLang === 'it' ? 'Data invio' : 'Sent date') + '</th>' +
    '<th style="padding:0.4rem 0.75rem;width:220px;">' + (currentLang === 'it' ? 'Destinatario' : 'Recipient') + '</th>' +
    '<th style="padding:0.4rem 0.75rem;">' + (currentLang === 'it' ? 'Soggetto' : 'Subject') + '</th>' +
    '<th style="padding:0.4rem 0.75rem;width:130px;">' + (currentLang === 'it' ? 'Origine' : 'Source') + '</th>' +
    '<th style="padding:0.4rem 0.75rem;width:90px;"></th>' +
    '</tr></thead><tbody>' + rows + '</tbody></table></div>';
}

async function loadReplyToField() {
  const input = document.getElementById('newsletter-reply-to');
  if (!input) return;
  input.value = await getEmailReplyTo();
}

async function saveReplyToField() {
  const input = document.getElementById('newsletter-reply-to');
  if (!input) return;
  const value = input.value.trim();
  await saveEmailReplyTo(value);
  toast(currentLang === 'it' ? '✅ Indirizzo salvato!' : '✅ Address saved!', 'success');
}

// Stato dell'ordinamento della tabella destinatari. col=null → ordine
// originale (quello di getData), nessuna freccia mostrata.
let _nlSort = { col: null, dir: 'asc' };

// Rigenerare la tabella distrugge le caselle spuntate: prima di riordinare le
// fotografiamo e poi le rimettiamo, altrimenti l'admin che seleziona dieci
// utenti e poi clicca su un'intestazione perde la selezione senza capire perché.
function _snapshotNewsletterSelection() {
  const grab = (cls) => new Set([...document.querySelectorAll('.' + cls)].filter(cb => cb.checked).map(cb => cb.dataset.id));
  return { sel: grab('newsletter-user-cb'), email: grab('newsletter-user-email-cb'), msg: grab('newsletter-user-msg-cb') };
}
function _restoreNewsletterSelection(snap) {
  if (!snap) return;
  const put = (cls, set) => document.querySelectorAll('.' + cls).forEach(cb => {
    if (cb.disabled) return; // una casella E-mail disabilitata (nessun consenso) resta spenta
    cb.checked = set.has(cb.dataset.id);
  });
  put('newsletter-user-cb', snap.sel);
  put('newsletter-user-email-cb', snap.email);
  put('newsletter-user-msg-cb', snap.msg);
}

function sortNewsletterUsers(col) {
  if (_nlSort.col === col) _nlSort.dir = (_nlSort.dir === 'asc') ? 'desc' : 'asc';
  else _nlSort = { col, dir: 'asc' };
  const snap = _snapshotNewsletterSelection();
  renderNewsletterUsers();
  _restoreNewsletterSelection(snap);
}

function renderNewsletterUsers() {
  renderNewsletterLog('newsletter-email-log');
  const el = document.getElementById('newsletter-users-list');
  const sumEl = document.getElementById('newsletter-consent-summary');
  if (!el) return;
  const L = currentLang === 'it';
  let users = getData('users', []).filter(u => !u.isAdmin && u.email);
  if (!users.length) {
    el.innerHTML = '<p style="color:var(--muted);font-size:0.88rem;padding:0.75rem;">' + (L ? 'Nessun utente registrato.' : 'No registered users.') + '</p>';
    if (sumEl) sumEl.innerHTML = '';
    return;
  }

  // Riepilogo consensi, fuori dall'area di scorrimento: resta sempre visibile
  const yes   = users.filter(u => u.newsletterConsent === true).length;
  const no    = users.filter(u => u.newsletterConsent === false).length;
  const never = users.length - yes - no; // undefined: mai chiesto
  if (sumEl) {
    const n = (v) => `<strong style="color:var(--text);">${v}</strong>`;
    sumEl.innerHTML = L
      ? `<div style="line-height:1.7;">· ${n(yes)} con consenso<br>· ${n(no)} senza<br>· ${n(never)} mai chiesto.</div>
         <p style="margin:0.6rem 0 0 0;line-height:1.5;">A chi non ha dato il consenso la casella E-mail è disattivata — puoi comunque raggiungerlo con un Messaggio interno.</p>`
      : `<div style="line-height:1.7;">· ${n(yes)} consented<br>· ${n(no)} declined<br>· ${n(never)} never asked.</div>
         <p style="margin:0.6rem 0 0 0;line-height:1.5;">The E-mail box is disabled for those without consent — you can still reach them with an internal Message.</p>`;
  }

  // Ordinamento. Il consenso non è alfabetico: ha un ordine suo, dal più al meno
  // raggiungibile (sì → mai chiesto → no), che è l'informazione utile all'admin.
  if (_nlSort.col) {
    const consentRank = (u) => u.newsletterConsent === true ? 0 : (u.newsletterConsent === undefined ? 1 : 2);
    const key = (u) => {
      switch (_nlSort.col) {
        case 'username': return (u.username || '').toLowerCase();
        case 'email':    return (u.email || '').toLowerCase();
        case 'nat':      return (u.nationalityName || '\uffff').toLowerCase(); // senza nazionalità in fondo
        case 'consent':  return consentRank(u);
        default:         return '';
      }
    };
    const mul = (_nlSort.dir === 'asc') ? 1 : -1;
    users = [...users].sort((a, b) => {
      const ka = key(a), kb = key(b);
      if (typeof ka === 'number') return (ka - kb) * mul;
      return ka.localeCompare(kb, L ? 'it' : 'en') * mul;
    });
  }

  const arrow = (col) => _nlSort.col === col ? (_nlSort.dir === 'asc' ? ' ▲' : ' ▼') : '';
  const th  = 'padding:0.4rem 0.75rem;position:sticky;top:0;z-index:1;background:var(--card2);';
  const thS = th + 'cursor:pointer;user-select:none;'; // intestazione ordinabile
  // table-layout:fixed — le larghezze dichiarate sotto vengono rispettate e lo
  // spazio restante è diviso tra Utente ed E-mail. Senza, il browser dimensiona
  // in base al contenuto e un indirizzo e-mail lungo allargherebbe la tabella
  // oltre il contenitore, riportando lo scorrimento orizzontale.
  el.innerHTML = `<table class="data-table compact" style="border-spacing:0;table-layout:fixed;width:100%;">
    <thead><tr>
      <th style="${th}width:36px;"></th>
      <th style="${thS}width:22%;" onclick="sortNewsletterUsers('username')" title="${L ? 'Ordina per utente' : 'Sort by user'}">${L ? 'Utente' : 'User'}${arrow('username')}</th>
      <th style="${thS}" onclick="sortNewsletterUsers('email')" title="${L ? 'Ordina per e-mail' : 'Sort by e-mail'}">E-mail${arrow('email')}</th>
      <th style="${thS}width:56px;text-align:center;" onclick="sortNewsletterUsers('nat')" title="${L ? 'Ordina per nazionalità' : 'Sort by nationality'}">${L ? 'Naz.' : 'Nat.'}${arrow('nat')}</th>
      <th style="${thS}width:130px;" onclick="sortNewsletterUsers('consent')" title="${L ? 'Ordina per consenso' : 'Sort by consent'}">${L ? 'Consenso' : 'Consent'}${arrow('consent')}</th>
      <th style="${th}width:70px;text-align:center;">${L ? 'Invia e-mail' : 'Send e-mail'}</th>
      <th style="${th}width:80px;text-align:center;">${L ? 'Invia messaggio' : 'Send message'}</th>
    </tr></thead>
    <tbody>` + users.map(u => {
      const ok = hasNewsletterConsent(u);
      return `<tr style="opacity:${ok ? '1' : '0.75'};">
        <td style="text-align:center;">
          <input type="checkbox" class="newsletter-user-cb" data-id="${u.id}" data-email="${u.email}" data-username="${u.username}" style="width:16px;height:16px;cursor:pointer;">
        </td>
        <td style="overflow-wrap:anywhere;${ok ? 'color:var(--accent);' : ''}">${u.username}</td>
        <td style="color:var(--muted);overflow-wrap:anywhere;">${u.email}</td>
        <td style="text-align:center;">${u.nationalityCode ? `<img src="${flagUrl(u.nationalityCode)}" title="${u.nationalityName || ''}" style="width:18px;height:12px;object-fit:cover;border-radius:2px;vertical-align:middle;">` : '<span style="color:var(--muted);">—</span>'}</td>
        <td>${consentCell(u)}</td>
        <td style="text-align:center;" title="${ok ? '' : (L ? 'Nessun consenso: e-mail non inviabile' : 'No consent: e-mail cannot be sent')}">
          <input type="checkbox" class="newsletter-user-email-cb" data-id="${u.id}" ${ok ? 'checked' : 'disabled'} style="width:16px;height:16px;cursor:${ok ? 'pointer' : 'not-allowed'};">
        </td>
        <td style="text-align:center;">
          <input type="checkbox" class="newsletter-user-msg-cb" data-id="${u.id}" style="width:16px;height:16px;cursor:pointer;">
        </td>
      </tr>`;
    }).join('') + `</tbody></table>`;

  function consentCell(u) {
    const when = u.newsletterConsentDate ? new Date(u.newsletterConsentDate).toLocaleDateString(L ? 'it-IT' : 'en-GB') : '';
    const src  = u.newsletterConsentSource || '';
    const tip  = when ? `${L ? 'Il' : 'On'} ${when}${src ? ' (' + src + ')' : ''}` : (L ? 'Consenso mai richiesto' : 'Consent never requested');
    if (u.newsletterConsent === true)  return `<span title="${tip}" style="color:var(--accent);">✅ ${L ? 'Sì' : 'Yes'}</span>`;
    if (u.newsletterConsent === false) return `<span title="${tip}" style="color:#ff6464;">⛔ ${L ? 'No' : 'No'}</span>`;
    return `<span title="${tip}" style="color:#ffb400;">— ${L ? 'Mai chiesto' : 'Never asked'}</span>`;
  }
}

function selectAllNewsletterUsers(select) {
  document.querySelectorAll('.newsletter-user-cb').forEach(cb => cb.checked = select);
}

// Crea un messaggio-annuncio per un utente (usato dalla Newsletter come
// alternativa/aggiunta all'e-mail): non è la risposta a qualcosa scritto
// dall'utente, ma un annuncio dello staff — salvato come contact_messages
// con isAnnouncement:true, così l'utente lo vede nella sezione "I miei
// messaggi con lo staff" del proprio profilo, senza la scritta "in attesa
// di risposta" che avrebbe senso solo per una vera richiesta dell'utente
async function sendNewsletterMessage(user, subject, body) {
  const msg = {
    id: 'msg_' + Date.now() + '_' + Math.random().toString(36).slice(2, 8),
    name: user.username,
    email: user.email,
    subject: subject,
    message: body,
    date: new Date().toISOString(),
    read: true,
    replied: true,
    repliedAt: new Date().toISOString(),
    isAnnouncement: true,
    userReadReply: false
  };
  await fsSave('contact_messages', msg);
  if (_cache.contact_messages) _cache.contact_messages.push(msg);
}

async function sendNewsletterFromAdmin() {
  const subject = document.getElementById('newsletter-subject').value.trim();
  const body = document.getElementById('newsletter-body').value.trim();
  if (!subject || !body) { toast('Compila oggetto e messaggio', 'error'); return; }
  const selected = [...document.querySelectorAll('.newsletter-user-cb:checked')];
  if (!selected.length) { toast((currentLang === 'it' ? 'Seleziona almeno un utente' : 'Select at least one user'), 'error'); return; }
  if (!confirm((currentLang === 'it' ? 'Inviare la newsletter a ' : 'Send newsletter to ') + selected.length + (currentLang === 'it' ? ' utenti?' : ' users?'))) return;
  const adminUser = getData('users', []).find(u => u.isAdmin);
  const bcc = adminUser?.email || null;
  let emailCount = 0, msgCount = 0, blockedCount = 0;
  const allUsers = getData('users', []);
  for (const cb of selected) {
    const wantsEmail = document.querySelector(`.newsletter-user-email-cb[data-id="${cb.dataset.id}"]`)?.checked;
    const wantsMsg = document.querySelector(`.newsletter-user-msg-cb[data-id="${cb.dataset.id}"]`)?.checked;
    // Guardia sul consenso: ricontrollata qui e non solo nella UI. Se la
    // casella fosse riabilitata a mano (o il dato cambiasse nel frattempo),
    // l'e-mail non parte comunque.
    const u = allUsers.find(x => x.id === cb.dataset.id);
    if (wantsEmail && !hasNewsletterConsent(u)) {
      blockedCount++;
      console.warn('Newsletter non inviata a', cb.dataset.email, '— nessun consenso');
    } else if (wantsEmail) {
      await sendEmail(cb.dataset.email, cb.dataset.username, subject, body, { bcc, source: 'newsletter', lang: userLangFor(u), userId: u?.id }); emailCount++;
    }
    if (wantsMsg) { await sendNewsletterMessage({ username: cb.dataset.username, email: cb.dataset.email }, subject, body); msgCount++; }
  }
  const blockedNote = blockedCount ? (currentLang === 'it' ? ` — ${blockedCount} e-mail non inviate (nessun consenso)` : ` — ${blockedCount} e-mails not sent (no consent)`) : '';
  toast((currentLang === 'it' ? `Newsletter inviata: ${emailCount} e-mail, ${msgCount} messaggi! 📧${blockedNote}` : `Newsletter sent: ${emailCount} e-mails, ${msgCount} messages! 📧${blockedNote}`), 'success');
  document.getElementById('newsletter-subject').value = '';
  document.getElementById('newsletter-body').value = '';
  renderNewsletterLog('newsletter-email-log');
}

async function sendNewsletterEmail(subject, messaggio) {
  // Filtro sul consenso: chi non l'ha dato (o non ha ancora risposto al
  // prompt) non riceve la newsletter, mai.
  const users = getData('users', []).filter(u => !u.isAdmin && u.email && hasNewsletterConsent(u));
  // BCC dinamico: legge l'email dell'admin dal database ad ogni invio,
  // così riflette sempre quella attuale (modificabile dal Profilo).
  const adminUser = getData('users', []).find(u => u.isAdmin);
  const bcc = adminUser?.email || null;
  for (const user of users) {
    await sendEmail(user.email, user.username, subject, messaggio, { bcc, source: 'newsletter', lang: userLangFor(user), userId: user.id });
  }
  toast((currentLang === 'it' ? 'Newsletter inviata a ' : 'Newsletter sent to ') + users.length + (currentLang === 'it' ? ' utenti!' : ' users!'), 'success');
}

