// Lingua del browser (navigator.language: informazione già presente nel
// browser, nessuna richiesta di rete verso terzi — vedi Privacy Policy).
// Se il browser non dichiara nulla, il default è l'italiano.
function _detectBrowserLang() {
  const b = (navigator.language || navigator.userLanguage || '').toLowerCase();
  if (!b) return 'it';
  return b.startsWith('it') ? 'it' : 'en';
}

// ATTENZIONE all'ordine: il rilevamento va fatto QUI, alla prima assegnazione.
// Farlo più tardi (com'era in loadAllData) è inutile — setLang(), chiamato nel
// blocco INIT prima di initFirebase(), scrive già LOCAL('lang'), quindi il
// controllo "!LOCAL.get('lang')" là in fondo risultava sempre falso e il
// rilevamento non veniva MAI eseguito.
let currentLang = LOCAL.get('lang') || _detectBrowserLang();

function t(key) { return (i18n[currentLang] || i18n.en)[key] || (i18n.en)[key] || key; }

function applyI18n() {
  document.querySelectorAll('[data-i18n]').forEach(el => {
    el.textContent = t(el.dataset.i18n);
  });
  document.querySelectorAll('[data-i18n-html]').forEach(el => {
    el.innerHTML = t(el.dataset.i18nHtml);
  });
  document.querySelectorAll('[data-i18n-placeholder]').forEach(el => {
    el.placeholder = t(el.dataset.i18nPlaceholder);
  });
  document.querySelectorAll('[data-i18n-title]').forEach(el => {
    el.title = t(el.dataset.i18nTitle);
  });
}

function setLang(lang, byUser = false) {
  currentLang = lang;
  LOCAL.set('lang', lang);
  if (byUser && currentUser) {
    LOCAL.set('lang_set_by_user_' + currentUser.id, true);
    // Persistiamo la scelta anche sul documento utente: localStorage vive solo su
    // questo dispositivo, ma per scrivergli un'e-mail nella sua lingua il dato
    // deve stare nel database. Scrittura non bloccante: cambiare lingua a mano è
    // un gesto raro, e se fallisce non c'è nulla da interrompere.
    if (currentUser.lang !== lang) {
      currentUser.lang = lang;
      LOCAL.set('currentUser', currentUser);
      fsSave('users', currentUser).catch(e => console.warn('Lingua utente non salvata', e.message));
    }
  }
  // Update flag button
  const btn = document.getElementById('lang-current-btn');
  if (btn) {
    const flags = { en: 'gb', it: 'it' };
    btn.src = flagUrl(flags[lang] || 'gb');
  }
  document.querySelectorAll('.lang-btn').forEach(b => {
    b.classList.toggle('active', (lang === 'en' && b.textContent === '🇬🇧') || (lang === 'it' && b.textContent === '🇮🇹'));
  });
  const eyebrow = document.getElementById('classifica-eyebrow');
  if (eyebrow) eyebrow.textContent = lang === 'it' ? 'Migliori Collezionisti' : 'Top Collectors';
  // Blocchi di contenuto lungo (es. Privacy Policy) troppo estesi per il
  // dizionario data-i18n: due versioni statiche, mostriamo solo quella giusta
  document.querySelectorAll('.lang-block-it').forEach(el => el.style.display = lang === 'it' ? '' : 'none');
  document.querySelectorAll('.lang-block-en').forEach(el => el.style.display = lang === 'en' ? '' : 'none');
  applyI18n();
  renderAll();
}

// ============================================================
//  APP STATE
// ============================================================
let currentUser = LOCAL.get('currentUser') || null;
let _realAdmin = null; // traccia l'admin originale durante l'impersonificazione (vedi isImpersonating)
let currentSeriesId = null;
let _noPhotoFilter = false; // filtro figurine senza foto
// Il filtro sul TIPO di oggetto (set base, variazioni, change...) risponde alla
// domanda "che cosa e' questo?". Non rispondeva a quella che un collezionista si fa
// davvero: "cosa mi manca?". Da qui il secondo filtro, che e' una DIMENSIONE
// INDIPENDENTE: "variazione ufficiale" e "mi manca" non sono alternative, si
// COMBINANO ("le variazioni ufficiali che mi mancano"). Per questo vive in una
// variabile propria e in una riga propria, e non fra le opzioni del tipo.
let _ownedFilter = 'all'; // 'all' | 'owned' (ce l'ho) | 'missing' (mi manca)
let _itemTypeFilter = 'base'; // 'base' | 'variation' | 'unofficialVariation' | 'change' | 'all' — sempre uno solo attivo
let _ebayFilter = false; // indipendente da _itemTypeFilter: si combina in AND, non è esclusivo con "Solo base"/ecc.
let _noOfficialVariationFilter = false; // indipendente da _itemTypeFilter come _ebayFilter, ma impone SEMPRE anche "solo base" (non solo AND con il filtro tipo scelto) — mostra solo figurine base senza nessuna Variazione ufficiale collegata
let _retroViewMode = 'destra-piena'; // 'sotto' | 'destra' | 'dinamico' | 'fronte-grande' | 'destra-piena' — come viene mostrato il Retro rispetto al fronte nella griglia Figurine, visibile a tutti

// v5.827 — ETICHETTA DELLE CARD FIGURINA, SOLO SU TELEFONO.
// 'number' = sulla card compare il solo numero; 'full' = numero e nome (com'e' sul desktop).
// Vale ESCLUSIVAMENTE sotto la soglia mobile: _figLabelOnlyNumber() ha la guardia di viewport,
// quindi il desktop rende sempre numero+nome qualunque cosa ci sia salvato. La scelta e'
// ricordata dal browser (localStorage), a differenza di _retroViewMode che non si salva.
let _figLabelMode = 'full';   // v5.848 — default: nomi MOSTRATI (prima 'number')
try { const _m = localStorage.getItem('sgorbions_fig_label_mode'); if (_m === 'number' || _m === 'full') _figLabelMode = _m; } catch(e) {}
function _isMobileViewport() { return window.matchMedia('(max-width: 860px)').matches; }
function _figLabelOnlyNumber() { return _isMobileViewport() && _figLabelMode === 'number'; }

// v5.856 — descrizione della serie richiudibile, solo su telefono.
function _setupSeriesDescToggle(desc) {
  const p = document.getElementById('detail-desc');
  const btn = document.getElementById('detail-desc-toggle');
  if (!p || !btn) return;
  const lunga = _isMobileViewport() && (desc || '').trim().length > 140;
  if (!lunga) {
    p.classList.remove('desc-collapsed');
    btn.style.display = 'none';
    return;
  }
  p.classList.add('desc-collapsed');
  btn.style.display = '';
  btn.textContent = currentLang === 'it' ? 'Mostra tutto' : 'Show more';
}
function toggleSeriesDesc() {
  const p = document.getElementById('detail-desc');
  const btn = document.getElementById('detail-desc-toggle');
  if (!p || !btn) return;
  const chiusa = p.classList.toggle('desc-collapsed');
  btn.textContent = chiusa
    ? (currentLang === 'it' ? 'Mostra tutto' : 'Show more')
    : (currentLang === 'it' ? 'Mostra meno' : 'Show less');
}
function setFigLabelMode(mode) {
  _figLabelMode = (mode === 'full') ? 'full' : 'number';
  try { localStorage.setItem('sgorbions_fig_label_mode', _figLabelMode); } catch(e) {}
  try { renderItems(); } catch(e) { console.error('renderItems (setFigLabelMode)', e); }
}
function toggleFigLabelMode() { setFigLabelMode(_figLabelMode === 'number' ? 'full' : 'number'); }
// La serie ha i numeri? Flag "Non ha numeri" della scheda serie (s.noNumbers).
function _serieHaNumeri() {
  const s = getData('series', []).find(x => x.id === currentSeriesId);
  return !(s && s.noNumbers);
}
// Specchietti "Retro per categoria" (v5.762): stato apertura (chiusi al caricamento) e filtro
let _retroCatTopOpen = false;      // riquadro in alto (Retro base): chiuso di default
let _retroCatResultsOpen = false;  // riquadro risultati: chiuso di default
let _retroCategoryFilter = null;   // filtro categoria attivo (null = off; '' = senza categoria); solo sezione Retro
let _retroResultCatVals = [];      // valori categoria reali dei box cliccabili dei risultati, per l'onclick via indice
// v5.809 — Specchietti "Change per Tipo di change" (sezione Figurine), gemelli di quelli dei Retro.
let _changeTypeTopOpen = false;      // riquadro in alto (panoramica Change): chiuso di default
let _changeTypeResultsOpen = false;  // riquadro risultati: chiuso di default
let _changeTypeFilter = null;        // filtro Tipo di change attivo (null = off); solo sezione Figurine
let _changeTypeResultVals = [];      // valori Tipo di change dei box cliccabili dei risultati, per l'onclick via indice
let _previousPage = 'home'; // pagina da cui si è arrivati, usata dal pulsante "← Torna" nel profilo
let editingSeriesImg = null;
let editingFigImg = null;
let editingFigEbayImg = null;
let editingFigEbayImgFileSave = null;
let _returnToErroriAfterSave = false;

function closeFigModal() {
  closeModal('add-fig-modal');
  if (_returnToErroriAfterSave) {
    _returnToErroriAfterSave = false;
    showPage('profile');
    adminTab('errori');
  }
}

function switchFigModalTab(tab) {
  const genDiv = document.getElementById('fig-tab-generale');
  const ebayDiv = document.getElementById('fig-tab-ebay');
  const genBtn = document.getElementById('fig-tab-btn-generale');
  const ebayBtn = document.getElementById('fig-tab-btn-ebay');
  if (genDiv) genDiv.style.display = tab === 'generale' ? '' : 'none';
  if (ebayDiv) ebayDiv.style.display = tab === 'ebay' ? '' : 'none';
  if (genBtn) { genBtn.style.borderBottomColor = tab === 'generale' ? 'var(--accent)' : 'transparent'; genBtn.style.color = tab === 'generale' ? 'var(--accent)' : 'var(--muted)'; }
  if (ebayBtn) { ebayBtn.style.borderBottomColor = tab === 'ebay' ? 'var(--accent)' : 'transparent'; ebayBtn.style.color = tab === 'ebay' ? 'var(--accent)' : 'var(--muted)'; }
}


// Admin seeding is handled in loadAllData() after Firebase is ready

// ============================================================
//  NAVIGATION
// ============================================================
function showAdminTab(tab) {
  // Show page-profile but hide profile content, show only admin panel
  document.querySelectorAll('.page').forEach(p => p.classList.remove('active'));
  const profilePage = document.getElementById('page-profile');
  if (profilePage) profilePage.classList.add('active');
  const sd = document.getElementById('series-detail');
  if (sd) sd.style.display = 'none';
  // Hide profile content, show admin panel
  const profileContent = document.getElementById('profile-content');
  if (profileContent) profileContent.style.display = 'none';
  const panel = document.getElementById('admin-panel');
  if (panel) panel.style.display = 'block';
  window.scrollTo({ top: 0, behavior: 'smooth' });
  adminTab(tab);
}

function showPage(page) {
  const protectedPages = ['catalog', 'blog', 'classifica', 'wantlist', 'profile', 'newsletter', 'wishlist', 'unsubscribe'];
  if (protectedPages.includes(page) && !currentUser) {
    openAuth('login');
    return;
  }
  // Traccia la pagina da cui si arriva, per poter tornare indietro dal profilo
  // (es. pulsante "← Torna a Inventario") invece di andare sempre alla Home
  const currentActiveEl = document.querySelector('.page.active');
  if (currentActiveEl && currentActiveEl.id !== 'page-' + page) {
    _previousPage = currentActiveEl.id.replace('page-', '');
  }
  document.querySelectorAll('.page').forEach(p => p.classList.remove('active'));
  document.getElementById('series-detail').style.display = 'none';
  const el = document.getElementById('page-' + page);
  if (el) { el.classList.add('active'); }
  document.querySelectorAll('.nav-links a').forEach(a => {
    a.classList.toggle('active', a.dataset.page === page);
  });
  window.scrollTo({ top: 0, behavior: 'smooth' });
  if (page === 'catalog') renderCatalog();
  if (page === 'blog') renderBlog();
  if (page === 'profile') {
    const pc = document.getElementById('profile-content');
    if (pc) pc.style.display = '';
    const ap = document.getElementById('admin-panel');
    if (ap) ap.style.display = currentUser?.isAdmin ? 'block' : 'none';
    renderProfile();
  }
  if (page === 'home') { renderHomeStats(); renderHomeSeries(); }
  if (page === 'wantlist') renderWantlist();
  if (page === 'newsletter') { renderNewsletterUsers(); renderEmailLog(); }
  if (page === 'wishlist') renderWishlist();
  if (page === 'unsubscribe') renderUnsubscribePage();
  if (page === 'classifica') renderClassifica();
  if (page === 'admin') adminTab('users');
  if (page === 'contact' && currentUser) {
    const emailInput = document.getElementById('contact-email');
    if (emailInput && !emailInput.value) emailInput.value = currentUser.email;
  }
  initReveal();
}

// ============================================================
//  AUTH
// ============================================================
// openAuth moved to top
async function _findUserByAuthUid(uid) {
  // Prima controlla la cache locale (es. per l'admin, che ha l'intera collezione già in cache)
  const cached = getData('users', []).find(x => x.authUid === uid);
  if (cached) return cached;
  // Query mirata: con le regole di sicurezza attive, un utente può leggere solo
  // il documento il cui campo authUid corrisponde al proprio uid autenticato
  try {
    const { collection, query, where, getDocs } = window._fb;
    const q = query(collection(db, 'users'), where('authUid', '==', uid));
    const snap = await getDocs(q);
    if (snap.empty) return null;
    const docSnap = snap.docs[0];
    const user = { ...docSnap.data(), id: docSnap.id };
    // Aggiorna la cache solo se era già una lista realmente popolata (es. per
    // l'admin). Altrimenti NON creiamo qui una lista con un solo utente: 
    // verrebbe scambiata per l'elenco completo (è successo, ed è un bug
    // fastidioso da scovare). Chi ha bisogno della lista completa la carica
    // esplicitamente con _loadAdminOnlyData().
    if (Array.isArray(_cache.users)) {
      const idx = _cache.users.findIndex(x => x.id === user.id);
      if (idx >= 0) _cache.users[idx] = user; else _cache.users.push(user);
    }
    return user;
  } catch(e) {
    console.error('_findUserByAuthUid query failed', e);
    return null;
  }
}

// Rilegge da Firestore i dati che il pannello admin mostra, e ridisegna.
// SERVIVA: il sito non ha NESSUN ascoltatore in tempo reale (onSnapshot: zero). I
// dati dell'admin si leggono UNA VOLTA SOLA, all'accesso, e poi restano fermi in
// cache. Non e' che "ci mettono un po'" a comparire, come sembrava a Franco: non
// comparivano affatto, finche' non si ricaricava la pagina.
// Rilegge SOLO le quattro raccolte del pannello (users, contact_messages,
// segnalazioni, eventi) tramite _loadAdminOnlyData, che esisteva gia'. Non tocca
// figurine, serie, owned: sono migliaia di documenti, e Franco ha gia' sbattuto
// contro la quota giornaliera di Firestore.
async function refreshAdminData() {
  if (!currentUser?.isAdmin) return;
  const btn = document.getElementById('admin-refresh-btn');
  const info = document.getElementById('admin-refresh-info');
  // il doppio clic raddoppierebbe le letture: il pulsante si spegne mentre lavora
  if (btn?.disabled) return;
  if (btn) btn.disabled = true;
  if (info) info.textContent = currentLang === 'it' ? 'Lettura in corso...' : 'Loading...';
  try {
    await _loadAdminOnlyData();
    // ridisegno tutto cio' che dipende da quelle quattro raccolte
    try { renderAdminUsers(); } catch(e) { console.error('renderAdminUsers', e); }
    try { renderAdminContacts(); } catch(e) {}
    try { renderAdminSegnalazioni(); } catch(e) {}
    try { renderAdminEventi(); } catch(e) {}
    // i badge veri: updateAdminBadges() NON esiste — me l'ero inventata.
    try { updateMsgBadge(); } catch(e) {}
    try { updateBellBadge(); } catch(e) {}
    try { updateWishlistBadge(); } catch(e) {}
    const ora = new Date().toLocaleTimeString(currentLang === 'it' ? 'it-IT' : 'en-US');
    if (info) info.textContent = (currentLang === 'it' ? 'Aggiornato alle ' : 'Updated at ') + ora;
  } catch(e) {
    console.error('refreshAdminData', e);
    // un errore silenzioso qui sarebbe il peggio: l'admin crederebbe di vedere dati
    // freschi mentre guarda quelli vecchi. Stessa lezione della v5.682.
    if (info) info.textContent = currentLang === 'it'
      ? '\u26A0\uFE0F Aggiornamento NON riuscito: stai vedendo i dati di prima.'
      : '\u26A0\uFE0F Refresh FAILED: you are seeing the previous data.';
  } finally {
    if (btn) btn.disabled = false;
  }
}

async function _loadAdminOnlyData() {
  // Dati riservati all'admin, da ricaricare esplicitamente ogni volta che un
  // admin effettua il login dal modulo (non solo al caricamento iniziale
  // della pagina, gestito da loadAllData). In parallelo, non in sequenza,
  // per non sommare i tempi di rete di quattro richieste una dopo l'altra.
  const [users, contactMessages, segnalazioni, eventi] = await Promise.all([
    fsGetAll('users'),
    fsGetAll('contact_messages'),
    fsGetAll('segnalazioni'),
    fsGetAll('eventi')
  ]);
  _cache.users = users;
  _cache.contact_messages = contactMessages;
  _cache.segnalazioni = segnalazioni;
  _cache.eventi = eventi;
  updateMsgBadge();

  // Manutenzione: cancella i messaggi dei non registrati oltre i 6 mesi. Gira qui
  // perche' e' l'unico momento disponibile — il sito e' statico e non ha un
  // processo notturno. Non e' atteso (niente await): se fosse lento non deve
  // rallentare l'apertura del pannello.
  purgeOldContactMessages();
  purgeOldEventi();
  purgeOldSegnalazioni();
}

async function doLogin() {
  const emailInput = document.getElementById('login-email').value.trim();
  const p = document.getElementById('login-password').value;
  const authErr = document.getElementById('auth-error');
  if (authErr) authErr.style.display = 'none';
  const showErr = (msg) => { const ae = document.getElementById('auth-error'); if (ae) { ae.style.display = ''; ae.textContent = msg; } else toast(msg, 'error'); };
  if (!emailInput || !p) { showErr(currentLang === 'it' ? 'Inserisci e-mail e password' : 'Enter e-mail and password'); return; }

  const { signInWithEmailAndPassword } = window._fbAuth;
  let cred;
  try {
    cred = await signInWithEmailAndPassword(fbAuth, emailInput, p);
  } catch(err) {
    console.error('Firebase Auth login', err);
    const networkCodes = ['auth/network-request-failed', 'auth/timeout', 'auth/too-many-requests'];
    if (networkCodes.includes(err.code)) {
      showErr(currentLang === 'it'
        ? '⏳ Connessione lenta o instabile: il login non è riuscito a completarsi in tempo. Non è un problema di password — riprova.'
        : '⏳ Slow or unstable connection: login didn\u2019t complete in time. This is not a password issue — please retry.');
    } else {
      showErr(currentLang === 'it' ? 'E-mail o password errati' : 'Wrong e-mail or password');
    }
    return;
  }

  const user = await _findUserByAuthUid(cred.user.uid);
  if (!user) {
    console.error('Login riuscito su Firebase Auth ma nessun profilo trovato per authUid', cred.user.uid);
    showErr(currentLang === 'it' ? 'Accesso riuscito ma profilo non trovato: contatta l\'amministratore' : 'Signed in but no profile found: please contact the administrator');
    return;
  }

  user.lastLogin = new Date().toISOString();
  currentUser = user;
  LOCAL.set('currentUser', user);
  // Al login la Nazionalità reimposta la lingua, ma solo se: (a) l'utente non ha
  // scelto esplicitamente una lingua cliccando la bandierina, e (b) una
  // nazionalità c'è davvero. Se è vuota si tiene la lingua in uso — prima veniva
  // trattata come "non italiano" e forzava l'inglese.
  if (!LOCAL.get('lang_set_by_user_' + user.id) && user.nationalityCode) {
    setLang(user.nationalityCode === 'it' ? 'it' : 'en');
    applyI18n();
  }
  fsSave('users', user); // lastLogin: non blocca il login, non serve attenderlo
  if (!user.isAdmin) logEvent('login', 'Login effettuato da: ' + bold(user.username), { read: true, authUid: user.authUid || null });
  else await _loadAdminOnlyData();
  await loadAllOwnedFromFirebase();
  closeModal('auth-modal');
  updateNavUser();
  loadWishlist();
  const welcomeEl = document.getElementById('hero-welcome-msg');
  if (welcomeEl) {
    welcomeEl.style.display = '';
    welcomeEl.textContent = (currentLang === 'it' ? 'Bentornato, ' : 'Welcome back, ') + user.username + '! 👾';
    setTimeout(() => { welcomeEl.style.display = 'none'; }, 4000);
  }
  // Chi era arrivato dal link di disiscrizione e ha dovuto accedere viene portato
  // dove voleva andare, invece di essere scaricato sulla Home.
  if (resumePendingUnsubscribe()) return;
  maybeAskNewsletterConsent(); // utenti pre-v5.597: consenso mai chiesto
}
function _generateUniqueUsername(base) {
  const profiles = getData('public_profiles', []);
  let clean = (base || 'collezionista').replace(/[^a-zA-Z0-9_]/g, '').slice(0, 20) || 'collezionista';
  let candidate = clean;
  let n = 1;
  while (profiles.find(x => x.username === candidate)) {
    n++;
    candidate = clean + n;
  }
  return candidate;
}

async function signInWithGoogle() {
  if (!fbAuth || !window._fbAuth) { toast(currentLang === 'it' ? 'Connessione a Firebase in corso, riprova tra poco' : 'Connecting to Firebase, please retry shortly', 'error'); return; }
  const { GoogleAuthProvider, signInWithPopup } = window._fbAuth;
  let cred;
  try {
    cred = await signInWithPopup(fbAuth, new GoogleAuthProvider());
  } catch(err) {
    console.error('signInWithGoogle', err);
    if (err.code === 'auth/popup-closed-by-user' || err.code === 'auth/cancelled-popup-request') return; // l'utente ha chiuso il popup, nessun errore da mostrare
    toast(currentLang === 'it' ? 'Accesso con Google non riuscito, riprova' : 'Google sign-in failed, please retry', 'error');
    return;
  }

  let user = await _findUserByAuthUid(cred.user.uid);

  let isNewUser = false;
  if (user) {
    // Utente già esistente: procedo come un login
    user.lastLogin = new Date().toISOString();
  } else {
    isNewUser = true;
    // Stesso requisito del form di registrazione: conferma di avere
    // almeno 16 anni, obbligatoria anche per chi si registra con Google
    const ageConfirmed = confirm(currentLang === 'it'
      ? 'Per registrarti devi confermare di avere almeno 16 anni. Confermi?'
      : 'To register you must confirm you are at least 16 years old. Do you confirm?');
    if (!ageConfirmed) {
      try { const { fbDeleteAuthUser } = window._fbAuth; await fbDeleteAuthUser(cred.user); } catch(e) { console.warn('cleanup unconfirmed google account failed', e.message); }
      toast(currentLang === 'it' ? 'Registrazione annullata' : 'Registration cancelled', 'error');
      return;
    }
    // Primo accesso con questo account Google: creo un nuovo utente
    const baseName = cred.user.displayName || (cred.user.email || '').split('@')[0];
    const username = _generateUniqueUsername(baseName);
    // nationalityCode è sempre vuoto (Google non la fornisce): la lingua è quindi
    // quella che la persona sta usando in questo momento sul sito.
    const newUser = { id: Date.now().toString(), authUid: cred.user.uid, username, email: cred.user.email || '', isAdmin: false, joined: new Date().toISOString(), lastLogin: new Date().toISOString(), nationalityCode: '', nationalityName: '', ageConfirmed16: true, ageConfirmedAt: new Date().toISOString(), lang: currentLang };
    const saved = await fsSave('users', newUser);
    _cache.users = _cache.users || [];
    _cache.users.push(saved);
    user = saved;
    sendWelcomeEmail(saved);
    logEvent('new_user', 'Nuovo utente registrato con Google: ' + bold(username), { authUid: newUser.authUid || null });
  }

  currentUser = user;
  LOCAL.set('currentUser', user);
  // Stessa regola del login e-mail/password. Nota: un nuovo utente Google ha
  // sempre nationalityCode vuoto (Google non la fornisce), quindi non subisce
  // mai un cambio di lingua alla registrazione — prima invece finiva sempre in
  // inglese, qualunque lingua stesse usando.
  if (!LOCAL.get('lang_set_by_user_' + user.id) && user.nationalityCode) {
    setLang(user.nationalityCode === 'it' ? 'it' : 'en');
    applyI18n();
  }
  if (!isNewUser) fsSave('users', user); // lastLogin: non blocca, non serve attenderlo (per un nuovo utente è già stato salvato sopra)
  if (!isNewUser && !user.isAdmin) logEvent('login', 'Login effettuato da: ' + bold(user.username), { read: true, authUid: user.authUid || null });
  if (!isNewUser && user.isAdmin) await _loadAdminOnlyData();
  await loadAllOwnedFromFirebase();
  closeModal('auth-modal');
  updateNavUser();
  loadWishlist();
  const welcomeEl = document.getElementById('hero-welcome-msg');
  if (welcomeEl) {
    welcomeEl.style.display = '';
    welcomeEl.textContent = (currentLang === 'it' ? 'Bentornato, ' : 'Welcome back, ') + user.username + '! 👾';
    setTimeout(() => { welcomeEl.style.display = 'none'; }, 4000);
  }
  // Nuovo utente Google: chiediamo esplicitamente se vuole personalizzare il nome utente
  // (generato automaticamente da nome e cognome dell'account Google) — molti non
  // scoprirebbero mai da soli che è possibile cambiarlo dal profilo
  if (isNewUser) {
    // Il consenso newsletter non è chiesto qui: il nuovo utente Google non passa
    // dal form di registrazione, quindi il campo resta undefined e il prompt gli
    // viene mostrato subito dopo il modal del nome utente (vedi saveNewUsername).
    // Se chiude quel modal senza salvare, lo vedrà al prossimo accesso: in nessun
    // caso il consenso viene dato per scontato.
    openUsernameModal(true);
  } else {
    if (resumePendingUnsubscribe()) return;
    maybeAskNewsletterConsent();
  }
}

async function doRegister() {
  const u = document.getElementById('reg-username').value.trim();
  const e = document.getElementById('reg-email').value.trim();
  const p = document.getElementById('reg-password').value;
  const regErr = document.getElementById('reg-error');
  if (regErr) regErr.style.display = 'none';
  if (!u || !e || !p) { if (regErr) { regErr.style.display = ''; regErr.textContent = 'Compila tutti i campi'; return; } toast((currentLang === 'it' ? 'Compila tutti i campi' : 'Please fill in all fields'), 'error'); return; }
  if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(e)) { if (regErr) { regErr.style.display = ''; regErr.textContent = 'Inserisci un indirizzo e-mail valido'; return; } toast('Inserisci un indirizzo e-mail valido', 'error'); return; }
  if (p.length < 6) { const re = document.getElementById('reg-error'); if (re) { re.style.display = ''; re.textContent = 'La password deve avere almeno 6 caratteri'; return; } toast('La password deve avere almeno 6 caratteri', 'error'); return; }
  const ageConfirmed = document.getElementById('reg-age-confirm')?.checked;
  if (!ageConfirmed) {
    const msg = currentLang === 'it' ? 'Devi confermare di avere almeno 16 anni per registrarti' : 'You must confirm you are at least 16 years old to register';
    if (regErr) { regErr.style.display = ''; regErr.textContent = msg; } else toast(msg, 'error');
    return;
  }
  // Consenso newsletter: la risposta è obbligatoria (tendina a tre valori, di
  // default "— Seleziona —"), ma il "No" è una risposta perfettamente valida e
  // non impedisce la registrazione. Blocchiamo solo chi non ha risposto affatto.
  const nlChoice = document.getElementById('reg-newsletter-consent')?.value || '';
  if (!nlChoice) {
    const msg = currentLang === 'it'
      ? 'Scegli se vuoi ricevere la newsletter — puoi tranquillamente rispondere "No", la registrazione funziona lo stesso'
      : 'Please choose whether you want the newsletter — you can safely answer "No", registration works anyway';
    if (regErr) { regErr.style.display = ''; regErr.textContent = msg; } else toast(msg, 'error');
    return;
  }
  let profiles = getData('public_profiles', []);
  if (profiles.find(x => x.username === u)) { const msg = currentLang === 'it' ? 'Nome utente già in uso' : 'Username already taken'; const re = document.getElementById('reg-error'); if (re) { re.style.display = ''; re.textContent = msg; return; } toast(msg, 'error'); return; }
  const natCode = document.getElementById('reg-nationality-code')?.value || '';
  const natName = document.getElementById('reg-nationality-name')?.value || '';
  let authUid = null;
  const submitBtn = document.getElementById('reg-submit-btn');
  const waitNotice = document.getElementById('reg-wait-notice');
  if (submitBtn) submitBtn.disabled = true;
  if (waitNotice) waitNotice.style.display = '';
  try {
    const { createUserWithEmailAndPassword } = window._fbAuth;
    const cred = await createUserWithEmailAndPassword(fbAuth, e, p);
    authUid = cred.user.uid;
  } catch(err) {
    console.error('Firebase Auth registration', err);
    let msg = currentLang === 'it' ? 'Registrazione non riuscita, riprova' : 'Registration failed, please retry';
    if (err.code === 'auth/email-already-in-use') msg = currentLang === 'it' ? 'Questa email è già registrata' : 'This email is already registered';
    else if (err.code === 'auth/weak-password') msg = currentLang === 'it' ? 'Password troppo debole (minimo 6 caratteri)' : 'Password too weak (minimum 6 characters)';
    if (regErr) { regErr.style.display = ''; regErr.textContent = msg; } else toast(msg, 'error');
    if (submitBtn) submitBtn.disabled = false;
    if (waitNotice) waitNotice.style.display = 'none';
    return;
  }
  // La scelta è già stata validata sopra: qui è certamente 'yes' o 'no', mai
  // vuota. Registriamo comunque data e origine anche per il "no" — è un rifiuto
  // esplicito e consapevole, e va conservato come tale (non resta undefined,
  // quindi a costui il prompt una-tantum non verrà mai riproposto).
  const nlConsent = (nlChoice === 'yes');
  // Lingua da salvare sull'utente (serve per scrivergli nella SUA lingua, es. il
  // piè di pagina della newsletter). Va calcolata QUI, non presa da currentLang:
  // qualche riga più sotto la Nazionalità, se scelta, sovrascrive la lingua della
  // form (v5.599). Salvare currentLang prima di quell'override memorizzerebbe una
  // lingua che fra un istante non sarà più quella dell'utente.
  const finalLang = natCode ? (natCode === 'it' ? 'it' : 'en') : currentLang;
  const newUser = { id: Date.now().toString(), authUid, username: u, email: e, isAdmin: false, joined: new Date().toISOString(), lastLogin: new Date().toISOString(), nationalityCode: natCode, nationalityName: natName, ageConfirmed16: true, ageConfirmedAt: new Date().toISOString(), lang: finalLang, newsletterConsent: nlConsent, newsletterConsentDate: new Date().toISOString(), newsletterConsentSource: 'registration' };
  const saved = await fsSave('users', newUser);
  _cache.users = _cache.users || [];
  _cache.users.push(saved);
  currentUser = saved;
  LOCAL.set('currentUser', saved);
  if (submitBtn) submitBtn.disabled = false;
  if (waitNotice) waitNotice.style.display = 'none';
  closeModal('auth-modal');
  updateNavUser();
  sendWelcomeEmail(saved);
  const welcomeEl2 = document.getElementById('hero-welcome-msg');
  if (welcomeEl2) {
    welcomeEl2.style.display = '';
    welcomeEl2.textContent = (currentLang === 'it' ? 'Benvenuto nella famiglia Sgorbions, ' : 'Welcome to the Sgorbions family, ') + u + '! 🎉';
    setTimeout(() => { welcomeEl2.style.display = 'none'; }, 4000);
  }
  // Lingua: la Nazionalità, se scelta, vince sulla lingua della form — quella
  // può essere il frutto di un rilevamento automatico (navigator.language),
  // cioè di un'azione non voluta; la nazionalità è invece un gesto deliberato.
  // Ma se la Nazionalità NON è stata scelta non c'è nessun gesto deliberato da
  // far vincere: si tiene la lingua in uso. Prima invece il campo vuoto veniva
  // trattato come "non italiano" e forzava l'inglese — era questo il baco.
  if (finalLang !== currentLang) {
    setLang(finalLang);
    applyI18n();
  }
  logEvent('new_user', 'Nuovo utente registrato: ' + bold(u), { authUid: authUid || null });
}

