// Calcola e mostra i conteggi automatici (var. ufficiali/non ufficiali/Change)
// contando le figurine della serie con i relativi flag a true.
function updateSeriesVariationCounts(seriesId) {
  const figs = seriesId ? getData('figurines', []).filter(f => f.seriesId === seriesId) : [];
  // Ogni conteggio dichiara la SEZIONE in cui il suo tipo vive. Prima nessuno lo
  // faceva: si contava su tutta la serie, mescolando Figurine, Retro, Album e
  // Altri oggetti. Funzionava per caso — ogni contrassegno vive di fatto nella
  // sua sezione — ma bastava che una figurina finisse marcata isChange per errore
  // e sarebbe stata conteggiata li' dentro senza che nessuno se ne accorgesse.
  // Le CHANGE sono varianti del RETRO, non del fronte: nascono con
  // section:'retros' e il selettore Change esiste solo nella sezione Retro.
  // E' l'equivoco in cui e' caduto Franco, leggendo "146 Change" in una serie che
  // di Change (fra le figurine) non ne ha nessuna. Aveva ragione a fidarsi
  // dell'etichetta: era l'etichetta a tacere.
  // "N. di Figurine" era l'UNICO dei quattro contatori scritto a mano dall'admin, e
  // per questo l'unico che poteva mentire: bastava importare figurine e scordarsi
  // di aggiornarlo. Ora e' calcolato come gli altri tre — e con la STESSA
  // definizione del filtro "Solo figurine set base" e del badge 📦 della pagina
  // serie: nessun contrassegno fra Variazione, Variazione non ufficiale e Change.
  // Tre punti, una sola definizione: non possono piu' divergere.
  const nBase  = figs.filter(f => f.section === 'figurines' && !f.isVariation && !f.isUnofficialVariation && !f.isChange).length;
  const nVar   = figs.filter(f => f.section === 'figurines' && f.isVariation).length;
  const nUnoff = figs.filter(f => f.section === 'figurines' && f.isUnofficialVariation).length;
  const nChg   = figs.filter(f => f.section === 'figurines' && f.isChange).length;
  const elBase = document.getElementById('series-count-input');
  const elVar = document.getElementById('series-count-variations-input');
  const elUnoff = document.getElementById('series-count-unofficial-variations-input');
  const elChg = document.getElementById('series-count-change-input');
  if (elBase) elBase.value = nBase;
  if (elVar) elVar.value = nVar;
  if (elUnoff) elUnoff.value = nUnoff;
  if (elChg) elChg.value = nChg;
}

function toggleSeriesCountGroups() {
  const hasVar = document.getElementById('series-has-variations-input')?.checked;
  const hasUnoff = document.getElementById('series-has-unofficial-variations-input')?.checked;
  const hasChg = document.getElementById('series-has-change-input')?.checked;
  const gVar = document.getElementById('series-count-variations-group');
  const gUnoff = document.getElementById('series-count-unofficial-variations-group');
  const gChg = document.getElementById('series-count-change-group');
  if (gVar) gVar.style.display = hasVar ? '' : 'none';
  if (gUnoff) gUnoff.style.display = hasUnoff ? '' : 'none';
  if (gChg) gChg.style.display = hasChg ? '' : 'none';
}

// Mostra, per la serie attualmente aperta, quanti oggetti di ciascuna
// tipologia (Figurine/Retro/Album/Altri oggetti) sono marcati "Ebay"
function openSeriesEbayModal() {
  const series = getData('series', []).find(s => s.id === currentSeriesId);
  if (!series) return;
  document.getElementById('series-ebay-modal-name').textContent = series.name;
  const figs = getData('figurines', []).filter(f => f.seriesId === currentSeriesId);
  const sectionLabels = { figurines: currentLang === 'it' ? 'Figurine' : 'Stickers', retros: 'Retro', albums: currentLang === 'it' ? 'Album' : 'Albums', extras: currentLang === 'it' ? 'Altri oggetti' : 'Other items', bustine: currentLang === 'it' ? 'Bustine' : 'Packs' };
  const sectionOrder = ['figurines', 'retros', 'albums', 'extras', 'bustine'];
  const counters = document.getElementById('series-ebay-counters');
  counters.innerHTML = sectionOrder.map(sec => {
    const total = figs.filter(f => (f.section || 'figurines') === sec).length;
    const forSaleCount = figs.filter(f => (f.section || 'figurines') === sec && f.forSale).length;
    return `<div class="detail-row"><span class="detail-label">${sectionLabels[sec]}</span><span class="detail-value">${forSaleCount} ${currentLang === 'it' ? 'su' : 'of'} ${total}</span></div>`;
  }).join('');

  // Tabella con tutti gli oggetti marcati Ebay — le colonne cresceranno
  // via via che aggiungiamo i campi che servono per l'export
  const forSaleItems = figs.filter(f => f.forSale)
    .sort((a,b) => sectionOrder.indexOf(a.section||'figurines') - sectionOrder.indexOf(b.section||'figurines') || (a.number||0) - (b.number||0));
  const tableEl = document.getElementById('series-ebay-table');
  if (!forSaleItems.length) {
    tableEl.innerHTML = `<p style="color:var(--muted);font-style:italic;font-size:0.88rem;">${currentLang === 'it' ? 'Nessun oggetto marcato Ebay in questa serie.' : 'No items marked Ebay in this series.'}</p>`;
  } else {
    const rows = forSaleItems.map(f => `<tr>
      <td style="padding:0.4rem 0.6rem;font-size:0.85rem;color:var(--muted);white-space:nowrap;">${sectionLabels[f.section || 'figurines']}</td>
      <td style="padding:0.4rem 0.6rem;font-size:0.85rem;white-space:nowrap;">${f.number || '—'}</td>
      <td style="padding:0.4rem 0.6rem;font-size:0.85rem;">${f.name || ''}</td>
      <td style="padding:0.4rem 0.6rem;font-size:0.85rem;white-space:nowrap;">€${(f.price||0).toFixed(2)}</td>
      <td style="padding:0.4rem 0.6rem;font-size:0.85rem;text-align:center;white-space:nowrap;">${f.quantity||1}</td>
      <td style="padding:0.4rem 0.6rem;font-size:0.85rem;white-space:nowrap;">${f.condition === 'used' ? (currentLang === 'it' ? 'Usato' : 'Used') : (currentLang === 'it' ? 'Nuovo' : 'New')}</td>
    </tr>`).join('');
    tableEl.innerHTML = `<table class="data-table" style="border-spacing:0;width:100%;"><thead><tr>
      <th style="padding:0.4rem 0.6rem;text-align:left;">${currentLang === 'it' ? 'Tipo' : 'Type'}</th>
      <th style="padding:0.4rem 0.6rem;text-align:left;">N.</th>
      <th style="padding:0.4rem 0.6rem;text-align:left;">${currentLang === 'it' ? 'Nome' : 'Name'}</th>
      <th style="padding:0.4rem 0.6rem;text-align:left;">${currentLang === 'it' ? 'Prezzo' : 'Price'}</th>
      <th style="padding:0.4rem 0.6rem;text-align:left;">${currentLang === 'it' ? 'Q.tà' : 'Qty'}</th>
      <th style="padding:0.4rem 0.6rem;text-align:left;">${currentLang === 'it' ? 'Condizione' : 'Condition'}</th>
      </tr></thead><tbody>${rows}</tbody></table>`;
  }

  document.getElementById('series-ebay-modal').classList.remove('hidden');
}

function openAddSeriesModal(seriesId) {
  if (!currentUser?.isAdmin) { toast((currentLang === 'it' ? 'Solo per admin' : 'Admin only'), 'error'); return; }
  document.getElementById('edit-series-id').value = seriesId || '';
  document.getElementById('series-modal-title').textContent = seriesId ? t('modal.series.edit') : t('modal.series.title');
  document.getElementById('series-img-preview').style.display = 'none';
  editingSeriesImg = null;
  if (seriesId) {
    const s = getData('series', []).find(x => x.id === seriesId);
    if (s) {
      document.getElementById('series-name-input').value = s.name;
      document.getElementById('series-year-input').value = s.year;
      // (series-count-input NON si riempie piu' da s.count: e' calcolato piu' sotto
      //  da updateSeriesVariationCounts. Scrivere qui il valore vecchio significava
      //  mostrarlo per un istante prima di sovrascriverlo — e tenere in vita un campo
      //  che l'admin credeva ancora di controllare.)
      document.getElementById('series-first-number-input').value = s.firstNumber || '';
      document.getElementById('series-last-number-input').value = s.lastNumber || '';
      document.getElementById('series-album-count-input').value = s.albumCount || '';
      const huvi = document.getElementById('series-has-unofficial-variations-input'); if (huvi) huvi.checked = s.hasUnofficialVariations || false;
      const hci = document.getElementById('series-has-change-input'); if (hci) hci.checked = s.hasChange || false;
      const nni = document.getElementById('series-no-numbers-input'); if (nni) nni.checked = s.noNumbers || false;
      document.getElementById('series-desc-input').value = s.descIt || s.desc || '';
      const descEnInput = document.getElementById('series-desc-en-input');
      if (descEnInput) descEnInput.value = s.desc || '';
      const rctInput = document.getElementById('series-retro-change-types-input');
      if (rctInput) rctInput.value = (s.retroChangeTypes || []).join('\n');

      if (s.img) { const pr = document.getElementById('series-img-preview'); pr.src = s.img; pr.style.display = 'block'; editingSeriesImg = s.img; }
    }
  } else {
    ['series-name-input','series-year-input','series-count-input','series-first-number-input','series-last-number-input','series-album-count-input','series-desc-input','series-desc-en-input'].forEach(id => document.getElementById(id).value = '');
    const huvi = document.getElementById('series-has-unofficial-variations-input'); if (huvi) huvi.checked = false;
    const hci = document.getElementById('series-has-change-input'); if (hci) hci.checked = false;
    const nni = document.getElementById('series-no-numbers-input'); if (nni) nni.checked = false;
    const rctInput = document.getElementById('series-retro-change-types-input');
    if (rctInput) rctInput.value = '';
  }
  updateSeriesVariationCounts(seriesId || null);
  toggleSeriesCountGroups();
  // Flag visibili solo per admin (ora dentro label in griglia 2 colonne)
  const hasSizesGroup = document.getElementById('series-has-sizes-input')?.closest('.form-group');
  if (hasSizesGroup) hasSizesGroup.style.display = currentUser?.isAdmin ? '' : 'none';
  const hasSubseriesGroup = document.getElementById('series-has-subseries-group');
  if (hasSubseriesGroup) hasSubseriesGroup.style.display = currentUser?.isAdmin ? '' : 'none';
  const hasVariationsGroup = document.getElementById('series-has-variations-input')?.closest('.form-group');
  if (hasVariationsGroup) hasVariationsGroup.style.display = currentUser?.isAdmin ? '' : 'none';
  document.getElementById('add-series-modal').classList.remove('hidden');
}
function handleSeriesImg(e) {
  const file = e.target.files[0]; if (!file) return;
  editingSeriesImgFile = file;
  const reader = new FileReader();
  reader.onload = ev => {
    const pr = document.getElementById('series-img-preview');
    pr.src = ev.target.result; pr.style.display = 'block';
  };
  reader.readAsDataURL(file);
}
let editingSeriesImgFile = null;
async function saveSeries() {
  const name = document.getElementById('series-name-input').value.trim();
  const year = document.getElementById('series-year-input').value;
  const hasSizes = document.getElementById('series-has-sizes-input').checked;
  const hasSubseries = document.getElementById('series-has-subseries-input').checked;
  const hasVariations = document.getElementById('series-has-variations-input')?.checked || false;
  const hasUnofficialVariations = document.getElementById('series-has-unofficial-variations-input')?.checked || false;
  const hasChange = document.getElementById('series-has-change-input')?.checked || false;
  const noNumbers = document.getElementById('series-no-numbers-input')?.checked || false;
  const countVariations = parseInt(document.getElementById('series-count-variations-input').value) || null;
  const countUnofficialVariations = parseInt(document.getElementById('series-count-unofficial-variations-input').value) || null;
  const countChange = parseInt(document.getElementById('series-count-change-input').value) || null;
  const count = document.getElementById('series-count-input').value;
  const firstNumber = parseInt(document.getElementById('series-first-number-input').value) || null;
  const lastNumber = parseInt(document.getElementById('series-last-number-input').value) || null;
  const albumCount = parseInt(document.getElementById('series-album-count-input').value) || null;
  const descIt = document.getElementById('series-desc-input').value.trim();
  const desc = document.getElementById('series-desc-en-input').value.trim();
  let retroChangeTypes = (document.getElementById('series-retro-change-types-input')?.value || '')
    .split('\n').map(v => v.trim()).filter(Boolean);
  // "Errore di stampa" NON puo' piu' stare qui (v5.713): dalla v5.711 e' un TIPO a se'
  // (isPrintError), non un sottotipo di Change. Se restasse fra i "Tipi di change", lo
  // stesso concetto sarebbe rappresentabile in DUE modi — ed e' esattamente la doppia
  // verita' che la v5.711 aveva chiuso. Lo tolgo, e LO DICO: toglierlo in silenzio
  // farebbe pensare a Franco di averlo scritto male.
  if (retroChangeTypes.some(t => /^error[ei]\s+di\s+stampa$/i.test(t))) {
    retroChangeTypes = retroChangeTypes.filter(t => !/^error[ei]\s+di\s+stampa$/i.test(t));
    toast(currentLang === 'it'
      ? '"Errore di stampa" non \u00e8 pi\u00f9 un tipo di change: ora \u00e8 un tipo di oggetto a s\u00e9. L\u2019ho tolto dalla lista.'
      : '"Print error" is no longer a change type: it is now an object type of its own. Removed from the list.',
      'info');
  }
  if (!name || !year) { toast((currentLang === 'it' ? 'Nome e anno sono obbligatori' : 'Name and year are required'), 'error'); return; }
  const fb = document.getElementById('series-save-feedback');
  const btn = document.querySelector('#add-series-modal .btn-primary');
  if (fb) { fb.style.display = ''; fb.textContent = (currentLang === 'it' ? '⏳ Salvataggio in corso...' : '⏳ Saving...'); }
  if (btn) btn.disabled = true;
  let imgUrl = editingSeriesImg || null;
  if (editingSeriesImgFile) {
    try { imgUrl = await uploadToCloudinary(editingSeriesImgFile); }
    catch(e) { toast((currentLang === 'it' ? 'Errore nel caricamento immagine' : 'Image upload error'), 'error'); return; }
  }
  let series = getData('series', []);
  const editId = document.getElementById('edit-series-id').value;
  try {
    if (editId) {
      const idx = series.findIndex(x => x.id === editId);
      if (idx >= 0) {
        series[idx] = { ...series[idx], name, year: +year, count: +count, firstNumber: firstNumber || series[idx].firstNumber || null, lastNumber: lastNumber || series[idx].lastNumber || null, albumCount: albumCount ?? series[idx].albumCount ?? null, desc, descIt, img: imgUrl || series[idx].img, hasSizes, hasSubseries, hasVariations, hasUnofficialVariations, hasChange, noNumbers, countVariations: countVariations ?? series[idx].countVariations ?? null, countUnofficialVariations: countUnofficialVariations ?? series[idx].countUnofficialVariations ?? null, countChange: countChange ?? series[idx].countChange ?? null, retroChangeTypes };
        await fsSave('series', series[idx]);
        _cache.series = series;
      }
    } else {
      const newS = { name, year: +year, count: +count||0, firstNumber: firstNumber || null, lastNumber: lastNumber || null, albumCount: albumCount ?? null, desc, descIt, img: imgUrl, hasSizes, hasSubseries, hasVariations, hasUnofficialVariations, hasChange, noNumbers, countVariations: countVariations ?? null, countUnofficialVariations: countUnofficialVariations ?? null, countChange: countChange ?? null, retroChangeTypes, created: new Date().toISOString() };
      const saved = await fsSave('series', newS);
      _cache.series.push(saved);
    }
  } catch(e) {
    console.error('saveSeries', e);
    if (fb) { fb.style.display = 'none'; fb.textContent = ''; }
    if (btn) btn.disabled = false;
    toast((currentLang === 'it' ? '❌ Salvataggio fallito, riprova (controlla la connessione)' : '❌ Save failed, please retry (check your connection)'), 'error');
    return;
  }
  editingSeriesImgFile = null;
  if (fb) { fb.textContent = (currentLang === 'it' ? '✅ Serie salvata!' : '✅ Series saved!'); }
  if (btn) btn.disabled = false;
  setTimeout(() => {
    closeModal('add-series-modal');
    if (fb) { fb.style.display = 'none'; fb.textContent = ''; }
  }, 1000);
  renderCatalog(); renderHomeSeries(); renderHomeStats(); renderAdminSeries();
}
async function deleteSeries(id) {
  if (!confirm('Delete this series and all its figurines?')) return;
  try {
    // Cancellare il documento della serie cancella già tutte le sue
    // figurine, che ora vivono incorporate al suo interno (non serve più
    // un ciclo di cancellazione separato, anzi sarebbe controproducente:
    // ricreerebbe il documento appena cancellato)
    await fsDelete('series', id);
  } catch(e) {
    console.error('deleteSeries', e);
    toast((currentLang === 'it' ? '❌ Eliminazione fallita, riprova' : '❌ Delete failed, please retry'), 'error');
    return;
  }
  _cache.series = _cache.series.filter(x => x.id !== id);
  _cache.figurines = _cache.figurines.filter(x => x.seriesId !== id);
  renderCatalog(); renderHomeSeries(); renderHomeStats(); renderAdminSeries();
  toast((currentLang === 'it' ? 'Serie eliminata' : 'Series deleted'), 'success');
}

// Pulsante "X" per svuotare un campo di ricerca in un click, invece di
// doverlo selezionare e cancellare a mano
// Mostra quanti oggetti risultano dai filtri/ricerca attivi, sia in vista
// a griglia sia in Vista tabellare — prima non veniva mostrato da nessuna
// parte, né con né senza filtri applicati
// Riceve ora l'ELENCO degli oggetti filtrati, non piu' soltanto quanti sono:
// serve per contare quanti di essi siano gia' nella lista dell'utente.
//
// E' il SECONDO dei due contatori che Franco ha distinto, ed e' bene tenerli
// separati in testa:
//   · quello nella riga della serie  → cosa ho RISPETTO ALLA SERIE. Non si muove
//     mai: e' un traguardo, e un traguardo che balla non misura niente.
//   · questo                          → cosa ho RISPETTO A CIO' CHE STO GUARDANDO.
//     Cambia a ogni filtro, ed e' giusto cosi'.
// Questo secondo numero ha un valore che va oltre l'informazione: e' l'ANTEPRIMA
// ESATTA dei due pulsanti. Dalla v5.670 "Aggiungi/Rimuovi tutti gli oggetti
// visualizzati" agisce su questo identico insieme. Leggere "96 trovati · 3 nella
// tua lista" significa sapere in anticipo che "Aggiungi" ne aggiungera' 93 e
// "Rimuovi" ne togliera' 3. Il pulsante smette di essere un salto nel buio.
//
// NON si festeggia qui con il 🎉 delle categorie: "le hai tutte" riferito a un
// insieme che l'utente si e' appena ritagliato con un filtro sarebbe un traguardo
// finto — e un complimento facile svaluta quello vero.
function updateItemsCountDisplay(items) {
  const el = document.getElementById('items-count-display');
  if (!el) return;
  const elenco = Array.isArray(items) ? items : [];
  const count = elenco.length;
  const it = currentLang === 'it';

  // v5.795 — numeri dei risultati più grandi ed evidenziati, etichette invariate.
  // v5.797 — Franco: colorare SOLO il numero (non l'intera frase). Il numero degli
  //          oggetti nella "tua lista" usa il BLU dei toggle aggiungi/rimuovi lista
  //          (var(--action)), non l'accent.
  const numBase = 'font-size:1.5rem;font-weight:700;';
  const num = v => `<span style="${numBase}color:var(--accent);">${v}</span>`;
  const numBlue = v => `<span style="${numBase}color:var(--action);">${v}</span>`;
  const cfmt = count.toLocaleString(it ? 'it-IT' : 'en-US');
  // v5.850 — su telefono le due frasi vanno tenute su UNA riga: alla larghezza di un telefono
  // "N oggetti trovati" + "N fanno parte della tua lista" non ci stanno a un corpo leggibile.
  // Non si rimpicciolisce oltre: si accorcia il testo, che e' la cosa giusta da comprimere.
  const _mobileCount = _isMobileViewport();
  const trovati = _mobileCount
    ? (it ? `${num(cfmt)} trovati` : `${num(cfmt)} found`)
    : (count === 1
        ? (it ? `${num('1')} oggetto trovato` : `${num('1')} item found`)
        : (it ? `${num(cfmt)} oggetti trovati` : `${num(cfmt)} items found`));

  let html = `<span>${trovati}</span>`;

  if (currentUser && count) {
    const ownedIds = getOwned();
    const n = elenco.filter(f => ownedIds.includes(f.id)).length;
    const nfmt = n.toLocaleString(it ? 'it-IT' : 'en-US');
    // Singolare e plurale: "1 FA parte", non "1 fanno parte". Idem in inglese
    // ("is part" / "are part"). E' il dettaglio che, sbagliato, fa sembrare
    // scritto male tutto il resto — anche quando il resto e' giusto.
    const frase = _mobileCount
      ? (it ? 'in lista' : 'in list')
      : (it
          ? (n === 1 ? 'fa parte della tua lista' : 'fanno parte della tua lista')
          : (n === 1 ? 'is part of your list' : 'are part of your list'));
    // Solo il numero è colorato (blu lista); l'etichetta resta nel colore testo.
    html += `<span>${numBlue(nfmt)} ${frase}</span>`;
  }

  el.innerHTML = `<div style="display:flex;flex-direction:column;gap:1px;">${html}</div>`;
}

function clearSearchField(inputId, renderFn) {
  const input = document.getElementById(inputId);
  if (!input) return;
  input.value = '';
  toggleSearchClearBtn(inputId);
  if (renderFn) renderFn();
  input.focus();
}

function toggleSearchClearBtn(inputId) {
  const input = document.getElementById(inputId);
  const btn = document.getElementById(inputId + '-clear');
  if (!input || !btn) return;
  btn.style.display = input.value ? '' : 'none';
}

function renderCatalog() {
  const q = (document.getElementById('series-search')?.value || '').trim();
  if (q) { renderCatalogSearch(q); return; }
  // Nessuna query: ripristina vista normale
  const resultsEl = document.getElementById('catalog-search-results');
  const grid = document.getElementById('catalog-grid');
  if (resultsEl) resultsEl.style.display = 'none';
  if (grid) grid.style.display = '';
  let series = getData('series', []);
  series = series.sort((a,b) => (a.order ?? 9999) - (b.order ?? 9999));
  if (!series.length) {
    grid.innerHTML = `<div class="empty-state"><div class="empty-icon">🎴</div><p class="empty-title">${t('catalog.empty')}</p></div>`;
    return;
  }
  grid.innerHTML = series.map(s => seriesCardHTML(s)).join('');
}

function renderCatalogSearch(q) {
  q = (q || document.getElementById('series-search')?.value || '').trim().toLowerCase();
  const resultsEl = document.getElementById('catalog-search-results');
  const grid = document.getElementById('catalog-grid');
  if (!q) { renderCatalog(); return; }
  if (resultsEl) resultsEl.style.display = '';
  if (grid) grid.style.display = 'none';

  const allSeries = getData('series', []).sort((a,b) => (a.order??9999)-(b.order??9999));
  const allFigs = getData('figurines', []);

  // Cerca in serie (nome, descrizione) e in figurine (nome, numero, sottoserie, descrizione)
  const results = [];
  allSeries.forEach(s => {
    const desc = (currentLang === 'it' ? (s.descIt || s.desc) : (s.desc || s.descIt)) || '';
    const seriesMatch = s.name.toLowerCase().includes(q) || desc.toLowerCase().includes(q);
    const matchingFigs = allFigs.filter(f => f.seriesId === s.id && (
      (f.name||'').toLowerCase().includes(q) ||
      String(f.number||'').includes(q) ||
      (f.subseries||'').toLowerCase().includes(q) ||
      (f.desc||'').toLowerCase().includes(q)
    ));
    if (seriesMatch || matchingFigs.length) {
      results.push({ series: s, seriesMatch, figs: matchingFigs });
    }
  });

  if (!results.length) {
    resultsEl.innerHTML = `<div class="empty-state"><div class="empty-icon">🔍</div><p class="empty-title">${currentLang === 'it' ? 'Nessun risultato per "' + q + '"' : 'No results for "' + q + '"'}</p></div>`;
    return;
  }

  const totalFigs = results.reduce((n, r) => n + r.figs.length, 0);
  const totalSeries = results.filter(r => r.seriesMatch).length;
  const summary = currentLang === 'it'
    ? `<p style="color:var(--muted);font-size:0.88rem;margin-bottom:1rem;">${results.length} serie trovate · ${totalFigs} oggetti trovati</p>`
    : `<p style="color:var(--muted);font-size:0.88rem;margin-bottom:1rem;">${results.length} series found · ${totalFigs} items found</p>`;

  resultsEl.innerHTML = summary + results.map(r => {
    const s = r.series;
    const desc = (currentLang === 'it' ? (s.descIt || s.desc) : (s.desc || s.descIt)) || '';
    // Nome serie sempre in cima, cliccabile per aprire la serie
    // Prima riga: nome serie a sx + conteggio oggetti a dx
    const seriesHeader = `<div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:0.4rem;">
        <div onclick="openSeriesDetail('${s.id}')" style="cursor:pointer;display:flex;align-items:center;gap:0.5rem;flex:1;min-width:0;">
          ${s.img ? `<img src="${cloudinaryUrl(s.img,'w_40,h_40,c_fit,q_auto,f_auto')}" style="width:28px;height:28px;object-fit:contain;border-radius:4px;background:var(--card2);flex-shrink:0;">` : '<span style="font-size:1rem;flex-shrink:0;">🎴</span>'}
          <span style="font-family:var(--font-display);font-size:0.95rem;font-weight:600;color:var(--accent);white-space:nowrap;overflow:hidden;text-overflow:ellipsis;">${s.name}</span>
          ${r.seriesMatch ? `<span style="font-size:0.65rem;color:var(--muted);border:1px solid var(--border);border-radius:6px;padding:1px 5px;flex-shrink:0;">${currentLang==='it'?'serie':'series'}</span>` : ''}
        </div>
        ${r.figs.length ? `<span style="font-size:0.7rem;color:var(--muted);white-space:nowrap;margin-left:0.5rem;flex-shrink:0;">${r.figs.length} ${currentLang==='it'?'trovati':'found'}</span>` : ''}
      </div>`;
    const sectionLabels = { figurines: currentLang === 'it' ? 'Figurine' : 'Stickers', retros: 'Retro', albums: currentLang === 'it' ? 'Album' : 'Albums', extras: currentLang === 'it' ? 'Altri oggetti' : 'Other items', bustine: currentLang === 'it' ? 'Bustine' : 'Packs' };
    const sectionOrder = ['figurines', 'retros', 'albums', 'extras', 'bustine'];
    const figsHTML = r.figs.length
      ? sectionOrder.map(sec => {
          let inSection = r.figs.filter(f => (f.section || 'figurines') === sec);
          if (sec === 'figurines') {
            const allFigs = getData('figurines', []);
            const priority = f => f.isVariation ? 1 : f.isUnofficialVariation ? 2 : f.isChange ? 3 : 0;
            const groupNumber = f => {
              if (f.baseFigurineId) {
                const base = allFigs.find(x => x.id === f.baseFigurineId);
                if (base) return base.number ?? base.name;
              }
              return f.number ?? f.name;
            };
            inSection = [...inSection].sort((a, b) => {
              const g = String(groupNumber(a)).localeCompare(String(groupNumber(b)), undefined, { numeric: true });
              if (g !== 0) return g;
              return priority(a) - priority(b);
            });
          }
          if (!inSection.length) return '';
          return `<div style="margin-bottom:0.4rem;">
            <div style="font-size:0.9rem;color:#ff9d3d;font-weight:600;margin-bottom:0.25rem;">${sectionLabels[sec]}:</div>
            <div style="display:flex;flex-wrap:wrap;gap:0.3rem;">
              ${inSection.map(f => {
                const isVarOrChange = sec === 'figurines' && (f.isVariation || f.isUnofficialVariation || f.isChange);
                const baseFig = (isVarOrChange && f.baseFigurineId) ? getData('figurines', []).find(x => x.id === f.baseFigurineId) : null;
                const retroFig = (isVarOrChange && f.retroId) ? getData('figurines', []).find(x => x.id === f.retroId) : null;
                const varLabel = f.isVariation ? (currentLang === 'it' ? 'Variazione ufficiale' : 'Official variation')
                  : f.isUnofficialVariation ? (currentLang === 'it' ? 'Variazione non ufficiale' : 'Unofficial variation')
                  : f.isChange ? (currentLang === 'it' ? 'Change' : 'Change') : '';
                const smallImg = (url, title) => url ? `<img src="${cloudinaryUrl(url,'w_32,h_32,c_fit,q_auto,f_auto')}" title="${title}" style="width:22px;height:22px;object-fit:contain;border-radius:4px;background:var(--card);border:1px solid var(--border);">` : '';
                return `<span onclick="openFigFromSearch('${f.id}','${s.id}','${f.section||'figurines'}')" style="cursor:pointer;background:var(--card2);border:1px solid var(--border);color:var(--text);font-size:0.75rem;padding:2px 6px 2px 3px;border-radius:8px;display:inline-flex;align-items:center;gap:4px;">
                ${(() => { const front = isVarOrChange ? (f.img || (baseFig && baseFig.img) || null) : f.img; return front ? `<img src="${cloudinaryUrl(front,'w_32,h_32,c_fit,q_auto,f_auto')}" style="width:22px;height:22px;object-fit:contain;border-radius:4px;background:var(--card);">` : ''; })()}
                ${retroFig ? smallImg(retroFig.img, currentLang === 'it' ? 'Retro associato' : 'Associated retro') : ''}
                <span>${f.number ? '<span style="color:var(--muted);font-size:0.68rem;">#'+f.number+'</span> ' : ''}${f.name}${(sec === 'retros' && f.changeType) ? ' <span style="font-size:0.68rem;"><span style="color:#ffd84d;">Change:</span> <span style="color:var(--muted);">'+f.changeType+'</span></span>' : ''}${isVarOrChange ? ' <span style="font-size:0.68rem;"><span style="color:#ffd84d;">' + varLabel + '</span>' + (retroFig ? ' - <span style="color:var(--info);">' + retroFig.name + '</span>' : '') + '</span>' : ''}</span>
              </span>`;
              }).join('')}
            </div>
          </div>`;
        }).join('') : '';
    return `<div style="background:var(--card);border:1px solid var(--border);border-radius:var(--radius-lg);padding:0.6rem 0.75rem;margin-bottom:0.6rem;">
      ${seriesHeader}
      ${figsHTML}
    </div>`;
  }).join('');
}

function openFigFromSearch(figId, seriesId, section) {
  // Imposta il contesto senza navigare via dai risultati di ricerca
  currentSeriesId = seriesId;
  currentSection = section || 'figurines';
  // Apre direttamente la modal di dettaglio, i risultati rimangono visibili
  openFigDetail(figId);
}

function seriesCardHTML(s) {
  const allItems = getData('figurines', []).filter(f => f.seriesId === s.id);
  const retros = allItems.filter(f => f.section === 'retros');
  const albums = allItems.filter(f => f.section === 'albums');
  const extras = allItems.filter(f => f.section === 'extras');
  const bustine = allItems.filter(f => f.section === 'bustine');
  const figs = allItems.filter(f => f.section !== 'retros' && f.section !== 'albums' && f.section !== 'extras' && f.section !== 'bustine');
  const desc = currentLang === 'it' ? (s.descIt || s.desc) : (s.desc || s.descIt);
  // Calculate mode score (most common score > 0)
  let modeScoreHTML = '';
  const scoredFigs = figs.filter(f => f.score && f.score > 0);
  if (scoredFigs.length) {
    const freq = {};
    scoredFigs.forEach(f => { freq[f.score] = (freq[f.score] || 0) + 1; });
    const modeScore = Object.entries(freq).sort((a,b) => b[1]-a[1])[0][0];
    modeScoreHTML = `<span style="font-size:0.78rem;color:var(--accent);font-family:var(--font-ui);">⭐ ${modeScore} pt</span>`;
  }
  return `<div class="card" onclick="openSeriesDetail('${s.id}')">
    <div class="card-img-placeholder">
      ${s.img ? `<img src="${cloudinaryUrl(s.img, 'w_400,h_400,c_fit,q_auto,f_auto')}" style="width:100%;height:100%;object-fit:contain;position:absolute;top:0;left:0;padding:8px;">` : '🎴'}
    </div>
    <div class="card-body">
      <div style="display:flex;align-items:center;justify-content:space-between;gap:0.5rem;flex-wrap:wrap;margin-bottom:0.5rem;">
        <div class="card-title" style="display:flex;align-items:baseline;gap:0.5rem;flex-wrap:wrap;margin-bottom:0;"><span>${s.name}</span>${s.year ? `<span class="card-tag" style="display:inline;margin-bottom:0;">${s.year}</span>` : ''}</div>
        ${modeScoreHTML || ''}
      </div>
      <div class="card-desc">${(desc||'').substring(0,90)}${(desc||'').length>90?'…':''}</div>
      <div class="card-meta">
        <span class="card-badge">${figs.length} ${currentLang === 'it' ? 'figurine' : 'stickers'}</span>
        ${retros.length ? `<span class="card-badge">${retros.length} ${currentLang === 'it' ? 'retro' : 'retros'}</span>` : ''}
        ${bustine.length ? `<span class="card-badge">${bustine.length} ${currentLang === 'it' ? (bustine.length === 1 ? 'bustina' : 'bustine') : 'packs'}</span>` : ''}
        ${albums.length ? `<span class="card-badge">${albums.length} ${currentLang === 'it' ? 'album' : 'albums'}</span>` : ''}
        ${extras.length ? `<span class="card-badge">${extras.length} ${currentLang === 'it' ? 'Altro' : 'Other'}</span>` : ''}
      </div>
    </div>
  </div>`;
}

function renderHomeSeries() {
  const grid = document.getElementById('home-series-grid');
  if (!grid) return;
  const series = getData('series', []).slice(0, 3);
  if (!series.length) {
    grid.innerHTML = `<div class="empty-state"><div class="empty-icon">🎴</div><p class="empty-title">${t('catalog.empty')}</p></div>`;
    return;
  }
  grid.innerHTML = series.map(s => seriesCardHTML(s)).join('');
}

// ============================================================
//  SERIES DETAIL
// ============================================================
let currentSection = null; // 'figurines' | 'albums' | 'extras'
let currentItemPage = 1;
let _gridOrderedIds = []; // elenco ordinato completo (tutte le pagine) per navigazione avanti/indietro nel dettaglio
let _currentDetailFigId = null;

function navigateFigDetail(direction) {
  if (!_currentDetailFigId) return;
  const idx = _gridOrderedIds.indexOf(_currentDetailFigId);
  if (idx === -1) return;
  const newIdx = idx + direction;
  if (newIdx < 0 || newIdx >= _gridOrderedIds.length) return;
  openFigDetail(_gridOrderedIds[newIdx]);
}
const ROWS_PER_PAGE = 6;
// Determina se una figurina, nella griglia, mostrerà la coppia fronte+retro (card larga,
// 350px) invece della singola foto (card normale, 247px) — stessa logica usata in
// renderItems() per costruire le card, estratta qui per essere riusata anche nel calcolo
// della paginazione (getItemsPerPage) in modalità "Fronte e retro sempre grandi"
function _itemHasWidePair(f, allFigs) {
  if (f.section !== 'figurines') return false;
  const isBaseFig = !f.isVariation && !f.isUnofficialVariation && !f.isChange;
  if (!(((f.isVariation || f.isUnofficialVariation) && f.baseFigurineId && f.retroId) || (isBaseFig && f.retroId))) return false;
  const baseFigDual = isBaseFig ? f : allFigs.find(x => x.id === f.baseFigurineId);
  const retroFigDual = allFigs.find(x => x.id === f.retroId);
  return !!(baseFigDual?.img && retroFigDual?.img);
}

// Stima quante card entrano per riga in modalità "Fronte e retro sempre grandi", dato il
// mix di card larghe (350px, quelle con coppia fronte+retro) e normali (247px) presenti
// nell'insieme filtrato corrente — non è precisa al 100% (il mix esatto per riga dipende
// dall'ordine specifico degli oggetti), ma è una buona approssimazione, molto meglio del
// presupposto fisso di 7 colonne uguali usato dalle altre modalità
function _estimateWideModeCols(items) {
  if (!items.length) return 5;
  const allFigs = getData('figurines', []);
  const wideCount = items.filter(f => _itemHasWidePair(f, allFigs)).length;
  const wideRatio = wideCount / items.length;
  const avgWidth = wideRatio * 350 + (1 - wideRatio) * 247;
  const gap = 12; // 0.75rem
  const containerW = 1800;
  return Math.max(1, Math.floor((containerW + gap) / (avgWidth + gap)));
}

function getItemsPerPage() {
  // In modalità "Fronte e retro sempre grandi", le colonne non sono un numero fisso (le
  // card hanno larghezze diverse) — le stimiamo dal mix reale di card larghe/normali
  // dell'insieme filtrato corrente, così la paginazione riempie comunque righe complete
  // (un multiplo del numero di colonne stimato), come nelle altre 4 modalità
  if (currentSection === 'figurines' && _retroViewMode === 'destra-piena') {
    const cols = _estimateWideModeCols(getCurrentlyFilteredItems());
    return ROWS_PER_PAGE * cols;
  }
  // Colonne reali della griglia per la sezione corrente (vedi renderItems):
  // 5 per i Retro, 7 per tutte le altre sezioni (classe CSS .grid-6)
  const cols = currentSection === 'retros' ? 5 : 7;
  return ROWS_PER_PAGE * cols;
}

function getSectionLabel(section) {
  const it = { figurines: 'Figurine', retros: 'Retro', albums: 'Album', extras: 'Altri oggetti', bustine: 'Bustine' };
  const en = { figurines: 'Stickers', retros: 'Retros', albums: 'Albums', extras: 'Other Items', bustine: 'Packs' };
  return (currentLang === 'it' ? it : en)[section] || section;
}
function getSectionLabelSingular(section) {
  const it = { figurines: 'figurina', retros: 'retro', albums: 'album', extras: 'oggetto', bustine: 'bustina' };
  const en = { figurines: 'sticker', retros: 'retro', albums: 'album', extras: 'item', bustine: 'pack' };
  return (currentLang === 'it' ? it : en)[section] || section;
}
const SECTION_ICONS = { figurines: '&#129535;', retros: '&#128257;', albums: '&#128210;', extras: '&#127873;', bustine: '&#128230;' };
const SECTION_IMAGES = {
  figurines: 'data:image/avif;base64,',
  albums: 'data:image/avif;base64,',
  extras: 'data:image/webp;base64,'
};

// Disegna la riga dei contatori nell'intestazione della serie.
// PRIMA (v5.673-689) stava dentro openSeriesDetail ed era inchiodata a
// section === 'figurines': cambiando scheda (Retro, Album, Altri oggetti) la riga
// non veniva nemmeno RIDISEGNATA — openSeriesSection non la tocca. Restavano quindi
// a schermo i numeri delle FIGURINE, congelati all'apertura, mentre l'utente
// guardava tutt'altro. Franco: "ogni sezione e' a se stante; se sto vedendo le
// figurine non voglio informazioni sul resto" — e vale anche al contrario.
// Ora segue currentSection, e va richiamata a ogni cambio di scheda.
// QUALI TIPI ESISTONO, in questa serie e in questa sezione? (v5.711)
// Una domanda sola, una risposta sola — usata SIA dai contatori SIA dai filtri.
// I contatori gia' si comportavano cosi' (una categoria vuota non compare); ora anche
// i filtri: se in questa sezione non c'e' nessun Change, il filtro "Solo Change" non
// si mostra. Franco: "alla peggio non avremo dati" — e cosi' quel "alla peggio" costa
// zero: la pagina non offre mai un interruttore che non fa niente.
// E' anche il motivo per cui Album e Altri oggetti possono avere TUTTI i tipi senza
// che questo si veda finche' non ci metti dentro qualcosa.
// I "Tipi di change" di una serie, SENZA "errore di stampa" (v5.713).
// Dalla v5.711 l'errore di stampa e' un TIPO a se' (isPrintError), non un sottotipo di
// Change. Continuare a offrirlo nel menu "Tipo di change" ricreerebbe la doppia verita'
// che quella versione aveva appena chiuso: lo stesso concetto rappresentabile in due
// modi, e nessuno dei due autorevole.
// UNA FUNZIONE SOLA, perche' la lista viene letta da TRE punti (il menu della form, la
// riga di dettaglio, l'importazione). Filtrarla in uno solo avrebbe lasciato gli altri
// due a offrirla ancora.
// Il confronto e' tollerante (minuscole, spazi) come lo era il vecchio filtro: se in
// una serie e' scritto "Errori di stampa" o " ERRORE DI STAMPA ", sparisce lo stesso.
// IL TIPO DI UN OGGETTO, in una parola (v5.717).
// Serve alla regola di unicita' dei Retro, che prima usava il CHANGETYPE come
// discriminante. Funzionava finche' i tipi di retro erano due (base e Change), perche'
// solo i Change avevano un changeType. COL QUINTO TIPO NON REGGE PIU': un retro BASE e
// un ERRORE DI STAMPA hanno ENTRAMBI changeType vuoto, e il controllo li scambiava per
// lo stesso oggetto — impedendo a Franco di convertire un Change in errore di stampa,
// perche' trovava il retro base omonimo e bloccava.
// La chiave di unicita' deve contenere IL TIPO, non solo il changeType.
// Stesso ordine di precedenza usato in tutto il sito.
function tipoDiOggetto(f) {
  if (f.isPrintError)          return 'printError';
  if (f.isVariation)           return 'variation';
  if (f.isUnofficialVariation) return 'unofficialVariation';
  if (f.isChange)              return 'change';
  return 'base';
}

function changeTypesDiSerie(seriesId) {
  const s = getData('series', []).find(x => x.id === seriesId);
  // Ordine ALFABETICO (v5.773): i tipi vengono mostrati ordinati nei dropdown "Tipo di change"
  // (entrambe le form). La validazione dell'import usa .find(), indipendente dall'ordine.
  return (s?.retroChangeTypes || [])
    .filter(t => !/^error[ei]\s+di\s+stampa$/i.test((t || '').trim()))
    .slice()
    .sort((a, b) => (a || '').localeCompare((b || ''), 'it', { sensitivity: 'base' }));
}

function tipiPresenti(seriesId, section) {
  const items = getData('figurines', []).filter(f => f.seriesId === seriesId && f.section === section);
  return {
    items,
    base:       items.filter(f => !f.isVariation && !f.isUnofficialVariation && !f.isChange && !f.isPrintError),
    variation:  items.filter(f => f.isVariation),
    unofficial: items.filter(f => f.isUnofficialVariation),
    change:     items.filter(f => f.isChange),
    printError: items.filter(f => f.isPrintError)
  };
}

function renderSeriesMeta(s) {
  const metaEl = document.getElementById('detail-meta');
  if (!metaEl || !s) return;

  // Bullet UNICO, uguale per tutte le categorie. Le icone di prima pretendevano di
  // distinguerle, e due su cinque erano identiche (\u{1F3A8} sia per le variazioni
  // ufficiali sia per le non ufficiali): un simbolo che non distingue e'
  // decorazione, non informazione. Questo non promette nulla — segna l'inizio di una
  // voce, e basta.
  // NON e' un carattere (\u25AA), perche' la dimensione di un carattere la decide il
  // FONT, non noi: risultava minuscolo, e un "quadrato medio" affidabile su tutti i
  // dispositivi non esiste. E' un quadrato disegnato in CSS — misura e forma sono
  // nostre, e uguali ovunque.
  //   forma: border-radius 2px = quadrato smussato · 50% = cerchio · 0 = spigolo vivo
  //   currentColor: prende il colore della riga, quindi resta coerente da solo
  const BULLET = '<span style="display:inline-block;width:9px;height:9px;border-radius:2px;background:currentColor;margin-right:7px;vertical-align:0.05em;"></span>';
  const it = currentLang === 'it';
  const sez = currentSection || 'figurines';
  const items = getData('figurines', []).filter(f => f.seriesId === s.id && f.section === sez);

  const ownedIds = currentUser ? getOwned() : [];
  const miei = elenco => elenco.filter(f => ownedIds.includes(f.id)).length;
  const nfmt = n => n.toLocaleString(it ? 'it-IT' : 'en-US');
  const inLista = it ? 'nella tua lista' : 'in your list';

  // CODICE COLORE (v5.703): ogni contatore prende il colore del suo tipo, letto dalle
  // variabili CSS. Il bullet e' un quadrato con background:currentColor, quindi si
  // tinge DA SOLO insieme al testo — non c'e' modo che i due si sfasino.
  // Il colore va sulla riga dell'INVENTARIO, non su quella della lista: il numero
  // della lista resta in var(--accent) perche' dice un'altra cosa ("questo e' tuo"),
  // e deve restare riconoscibile a colpo d'occhio in ogni riga.
  const colonna = (icona, elenco, etichetta, forte, femminile = true, colore = null) => {
    const quanti = elenco.length;
    const n = miei(elenco);
    const complete = currentUser && quanti > 0 && n === quanti;
    const stile = (forte ? 'font-weight:600;' : '') + (colore ? `color:${colore};` : '');
    const riga1 = `<span${stile ? ` style="${stile}"` : ''}>${icona}${nfmt(quanti)} ${etichetta}</span>`;
    let riga2 = '';
    if (currentUser && (complete || n > 0)) {  // v5.885: se ne possiedi 0, niente riga ("0 nella tua lista" era brutto)
      const testo = complete
        ? (it
            ? (quanti === 1 ? "Ce l'hai!" : (femminile ? 'Le hai tutte!' : 'Li hai tutti!'))
            : (quanti === 1 ? 'You have it!' : 'You have them all!')) + '\u{1F389}'
        : nfmt(n) + ' ' + inLista;
      riga2 = `<span class="col-own" style="color:var(--accent);font-weight:600;">${testo}</span>`;
    }
    return `<div style="display:flex;flex-direction:column;gap:1px;">${riga1}${riga2}</div>`;
  };

  // v5.882 — nomi delle categorie (plurale/singolare/genere), usati sia nell'hub sia in sezione.
  const nomi = {
    figurines: { p: it ? 'figurine' : 'stickers', s: it ? 'figurina' : 'sticker', f: true  },
    retros:    { p: it ? 'retro'    : 'retros',   s: it ? 'retro'    : 'retro',   f: false },
    albums:    { p: it ? 'album'    : 'albums',   s: it ? 'album'    : 'album',   f: false },
    extras:    { p: it ? 'oggetti'  : 'items',    s: it ? 'oggetto'  : 'item',    f: false },
    bustine:   { p: it ? 'bustine'  : 'packs',    s: it ? 'bustina'  : 'pack',    f: true  }
  };

  // Costruisce le colonne (set base, variazioni ufficiali/non ufficiali, change, errori di stampa,
  // in totale) di UNA categoria — la riga di dettaglio. alwaysTotal: mostra "in totale" anche a 0
  // (usato nell'hub, cosi' ogni categoria compare comunque).
  function sezRows(sez2, alwaysTotal) {
    const g = tipiPresenti(s.id, sez2);
    const nm = nomi[sez2] || nomi.figurines;
    const m = [];
    if (g.base.length) m.push(colonna(BULLET, g.base,
      (['bustine','albums','extras'].includes(sez2)
        ? (it ? (g.base.length === 1 ? 'versione standard' : 'versioni standard') : (g.base.length === 1 ? 'standard version' : 'standard versions'))
        : (it ? nm.p + ' set base' : nm.p + ' base set')),
      false, nm.f, 'var(--type-base)'));
    if (g.variation.length) m.push(colonna(BULLET, g.variation,
      it ? (g.variation.length === 1 ? 'variazione ufficiale' : 'variazioni ufficiali')
         : (g.variation.length === 1 ? 'official variation' : 'official variations'),
      false, true, 'var(--type-official)'));
    if (g.unofficial.length) m.push(colonna(BULLET, g.unofficial,
      it ? (g.unofficial.length === 1 ? 'variazione non ufficiale' : 'variazioni non ufficiali')
         : (g.unofficial.length === 1 ? 'unofficial variation' : 'unofficial variations'),
      false, true, 'var(--type-unofficial)'));
    if (g.change.length) m.push(colonna(BULLET, g.change,
      'Change', false, false, 'var(--type-change)'));
    if (g.printError.length) m.push(colonna(BULLET, g.printError,
      it ? (g.printError.length === 1 ? 'errore di stampa' : 'errori di stampa')
         : (g.printError.length === 1 ? 'print error' : 'print errors'),
      false, false, 'var(--type-printerror)'));
    if (g.items.length || alwaysTotal) m.push(colonna(BULLET, g.items,
      it ? (g.items.length === 1 ? nm.s + ' in totale' : nm.p + ' in totale')
         : (g.items.length === 1 ? nm.s + ' in total' : nm.p + ' in total'),
      true, nm.f));
    return m;
  }

  // HUB (pagina dei 5 blocchi, currentSection === null): per OGNI categoria la sua riga di dettaglio
  // completa, una riga per categoria. Dentro una sezione: solo il dettaglio di quella sezione.
  if (!currentSection) {
    metaEl.classList.add('meta-hub');  // v5.886: su mobile le numeriche dell'hub vanno sotto la foto
    const cats = ['figurines', 'retros', 'bustine', 'albums', 'extras'];
    const _pfx = c => '<div class="hub-cat-name" style="font-weight:700;color:var(--text);min-width:96px;flex-shrink:0;">' + getSectionLabel(c) + '</div>';
    metaEl.innerHTML = '<div class="hub-wrap" style="display:flex;flex-direction:column;gap:0.7rem;width:100%;">' +
      cats.map(c => '<div class="hub-cat-row" style="display:flex;flex-wrap:wrap;align-items:flex-start;gap:0.7rem 1.4rem;">' + _pfx(c) + sezRows(c, true).join('') + '</div>').join('') +
      '</div>';
    return;
  }

  metaEl.classList.remove('meta-hub');
  metaEl.innerHTML = sezRows(sez, false).join('');
}

// I contatori in alto alla pagina della serie mostrano anche "N nella tua lista".
// Quel numero cambia ogni volta che l'utente tocca la lista — ma renderSeriesMeta
// veniva chiamata SOLO all'apertura della serie e al cambio di sezione. Risultato
// (segnalato da Franco): metti una figurina in lista, i contatori NON si muovono, e
// per vederli giusti devi uscire dalla pagina e rientrare.
// E' lo stesso difetto della v5.690 — numeri CONGELATI, non sbagliati — in un altro
// punto: la stessa funzione, di nuovo non richiamata quando il dato cambia.
// Un punto solo, chiamato da chiunque tocchi la lista: cosi' la prossima funzione che
// modifichera' la lista non dovra' ricordarsi di ripetere la ricerca della serie.
function refreshSeriesMeta() {
  if (!currentSeriesId) return;
  const s = getData('series', []).find(x => x.id === currentSeriesId);
  if (!s) return;
  try { renderSeriesMeta(s); } catch(e) { console.error('renderSeriesMeta (refresh)', e); }
}

function openSeriesDetail(seriesId) {
  currentSeriesId = seriesId;
  currentSection = null;
  const s = getData('series', []).find(x => x.id === seriesId);
  if (!s) return;
  document.querySelectorAll('.page').forEach(p => p.classList.remove('active'));
  const det = document.getElementById('series-detail');
  det.style.display = 'block';
  const desc = currentLang === 'it' ? (s.descIt || s.desc) : (s.desc || s.descIt);
  document.getElementById('detail-name').textContent = s.name;
  document.getElementById('detail-year').textContent = s.year;
  document.getElementById('detail-desc').textContent = desc || '';
  // v5.856 — su telefono la descrizione della serie si chiude a tendina: parte accorciata a tre
  // righe, con un comando "Mostra tutto / Mostra meno" sotto. Il comando compare solo se il testo
  // e' davvero lungo (oltre ~140 caratteri): sotto quella soglia le tre righe bastano e un
  // comando che non fa niente e' peggio che non averlo. Sul desktop nulla cambia.
  _setupSeriesDescToggle(desc || '');
  const editSeriesBtn = document.getElementById('detail-edit-series-btn');
  if (editSeriesBtn) editSeriesBtn.style.display = currentUser?.isAdmin ? '' : 'none';
  const ebaySeriesBtn = document.getElementById('detail-ebay-series-btn');
  if (ebaySeriesBtn) ebaySeriesBtn.style.display = currentUser?.isAdmin ? '' : 'none';

  // Campi meta nella hero
  renderSeriesMeta(s);
  const cover = document.getElementById('detail-cover');
  cover.innerHTML = s.img ? '<img src="' + cloudinaryUrl(s.img, 'w_200,h_200,c_fit,q_auto,f_auto') + '">' : '<span>&#127924;</span>';
  // show selector, hide items section
  document.getElementById('section-selector').style.display = '';
  document.getElementById('items-section').style.display = 'none';
  // set section images
  ['figurines','retros','albums','extras','bustine'].forEach(sec => {
    const img = document.getElementById('sec-img-' + sec);
    if (img && SECTION_IMAGES[sec]) img.src = SECTION_IMAGES[sec];
  });
  // update counts
  updateSectionCounts();
  window.scrollTo({ top: 0, behavior: 'smooth' });
}

function updateSectionCounts() {
  const owned = getOwned();
  ['figurines','retros','albums','extras','bustine'].forEach(sec => {
    const items = getData('figurines', []).filter(f => f.seriesId === currentSeriesId && f.section === sec);
    const el = document.getElementById('count-' + sec);
    if (!el) return;
    const total = items.length;
    const unit = currentLang === 'it' ? ' oggetti' : ' items';
    if (currentUser && total > 0) {
      const ownedCount = items.filter(f => owned.includes(f.id)).length;
      const ownedLabel = currentLang === 'it' ? ownedCount + ' nella tua lista' : ownedCount + ' in my list';
      el.innerHTML = total + unit + '<br>' + ownedLabel;
    } else {
      el.textContent = total + unit;
    }
  });
}

function openSeriesSection(section) {
  _noPhotoFilter = false;
  _itemTypeFilter = 'base';
  _retroCategoryFilter = null; // il filtro per categoria dei Retro non sopravvive al cambio sezione/serie
  _changeTypeFilter = null; // idem per il filtro Tipo di change (sezione Figurine)
  _ownedFilter = 'all'; // si riparte sempre da "tutti": un filtro dimenticato acceso
                        // fra una sezione e l'altra fa sembrare vuota una sezione piena
  currentSection = section;
  // La riga dei contatori DEVE seguire la scheda. Senza questa chiamata resterebbe
  // quella disegnata all'apertura della serie — cioe' le Figurine — e continuerebbe
  // a mostrarle anche stando nei Retro. Era esattamente il difetto segnalato da
  // Franco: non numeri sbagliati, numeri CONGELATI.
  const _s = getData('series', []).find(x => x.id === currentSeriesId);
  if (_s) renderSeriesMeta(_s);
  const si = document.getElementById('items-search'); if (si) { si.value = ''; si.placeholder = (currentLang === 'it' ? 'Cerca ' : 'Search ') + (getSectionLabel(section) || (currentLang === 'it' ? 'oggetti' : 'items')).toLowerCase() + '...'; }
  currentItemPage = 1;
  bulkEditActive = false;
  const bulkView = document.getElementById('bulk-edit-view');
  if (bulkView) bulkView.innerHTML = '';
  const btn = document.getElementById('bulk-edit-toggle-btn');
  if (btn) btn.textContent = currentLang === 'it' ? '📋 Vista tabellare' : '📋 Table view';
  document.getElementById('section-selector').style.display = 'none';
  document.getElementById('items-section').style.display = '';
  document.getElementById('items-section-title').textContent = getSectionLabel(section);
  document.getElementById('admin-add-item-btn').style.display = currentUser?.isAdmin ? '' : 'none';
  const ebayBtnWrap = document.getElementById('admin-ebay-btn-wrap');
  if (ebayBtnWrap) ebayBtnWrap.style.display = currentUser?.isAdmin ? 'flex' : 'none';
  const ebayTitle = document.getElementById('admin-ebay-title');
  if (ebayTitle) ebayTitle.style.display = currentUser?.isAdmin ? '' : 'none';
  const tableViewBtn = document.getElementById('user-table-view-btn');
  if (tableViewBtn) tableViewBtn.style.display = currentUser ? 'flex' : 'none';
  // Show bulk score box only for admin, figurines and retros sections
  const bulkScoreWrap = document.getElementById('admin-classifica-btn-wrap');
  const bulkScoreTitle = document.getElementById('admin-classifica-title');
  const showBulkScore = currentUser?.isAdmin && (section === 'figurines' || section === 'retros');
  if (bulkScoreWrap) bulkScoreWrap.style.display = showBulkScore ? 'flex' : 'none';
  if (bulkScoreTitle) bulkScoreTitle.style.display = showBulkScore ? '' : 'none';
  // Rename add button based on section
  const addBtn = document.querySelector('#admin-add-item-btn .btn-primary');
  const addLabels = { figurines: currentLang === 'it' ? '+ Aggiungi figurina' : '+ Add sticker', retros: currentLang === 'it' ? '+ Aggiungi retro' : '+ Add retro', albums: currentLang === 'it' ? '+ Aggiungi album' : '+ Add album', extras: currentLang === 'it' ? '+ Aggiungi' : '+ Add' };
  if (addBtn) addBtn.textContent = addLabels[section] || (currentLang === 'it' ? '+ Aggiungi' : '+ Add');
  renderItems();
  // Show WIP banner if less than 50% of stickers have photos
  window.scrollTo({ top: 0, behavior: 'smooth' });
}

function closeItemsSection() {
  document.getElementById('items-section').style.display = 'none';
  document.getElementById('section-selector').style.display = '';
  currentSection = null;
  updateSectionCounts();
  try { renderSeriesMeta(getData('series', []).find(x => x.id === currentSeriesId)); } catch(e) {} // v5.881: hub -> una riga per categoria (non i numeri della sezione appena lasciata)
}

function closeSeriesDetail() {
  // Reset bulk edit state
  bulkEditActive = false;
  const bulkView = document.getElementById('bulk-edit-view');
  if (bulkView) { bulkView.style.display = 'none'; bulkView.innerHTML = ''; }
  const bulkBtn = document.getElementById('bulk-edit-toggle-btn');
  if (bulkBtn) bulkBtn.textContent = (currentLang === 'it' ? '📋 Vista tabellare' : '📋 Table view');
  const grid = document.getElementById('items-grid');
  if (grid) grid.style.display = 'grid';

  document.getElementById('series-detail').style.display = 'none';
  document.getElementById('page-catalog').classList.add('active');
  currentSeriesId = null;
  currentSection = null;
}

// ============================================================
//  ITEMS (figurines/albums/extras unified)
// ============================================================
let _baseFigurineLinkOptions = [];
function _baseFigurineLinkLabel(f) {
  // v5.785 — usa f.section (più robusto di currentSection, valido anche nella form inline del dettaglio).
  // Per i RETRO l'etichetta è il NOME COMPLETO (richiesta di Franco: elenco base ordinato/mostrato per
  // Nome completo), con fallback alla vecchia forma "Categoria · Sottocategoria — Nome" se il fullName
  // non è ancora stato calcolato. Per le Figurine: "#numero Nome".
  if (f.section === 'retros') {
    if (f.fullName && f.fullName.trim()) return f.fullName;
    const parts = [f.category, f.subcategory].map(v => (v||'').trim()).filter(Boolean);
    return (parts.length ? parts.join(' · ') + ' — ' : '') + (f.name || '');
  }
  return (f.number ? '#' + f.number + ' ' : '') + (f.name || '');
}

// v5.785 — ordinamento condiviso delle opzioni "base": Retro per NOME COMPLETO, Figurine per Numero.
function _baseFigurineLinkSort(a, b) {
  if ((a.section || '') === 'retros' || (b.section || '') === 'retros') {
    return (_baseFigurineLinkLabel(a)).localeCompare(_baseFigurineLinkLabel(b), 'it', { sensitivity: 'base' });
  }
  return (a.number || 0) - (b.number || 0);
}

function populateBaseFigurineSelect(excludeId, selectedId) {
  const hidden = document.getElementById('fig-base-figurine-input');
  const search = document.getElementById('fig-base-figurine-search');
  if (!hidden || !search) return;
  _baseFigurineLinkOptions = getData('figurines', [])
    .filter(f => f.seriesId === currentSeriesId && f.section === currentSection && f.id !== excludeId && !f.isVariation && !f.isUnofficialVariation && !f.isChange)
    .sort(_baseFigurineLinkSort); // v5.785 — Retro per Nome completo, Figurine per Numero
  hidden.value = selectedId || '';
  const dd = document.getElementById('fig-base-figurine-dropdown');
  if (dd) dd.style.display = 'none';
  if (selectedId) {
    const b = _baseFigurineLinkOptions.find(x => x.id === selectedId);
    search.value = b ? _baseFigurineLinkLabel(b) : '';
  } else {
    search.value = '';
  }
}

function filterBaseFigurineLink() {
  const q = document.getElementById('fig-base-figurine-search').value.toLowerCase().trim();
  const dd = document.getElementById('fig-base-figurine-dropdown');
  if (!dd) return;
  // v5.785 — la ricerca combacia con ciò che è mostrato (l'etichetta: Nome completo per i Retro,
  // "#numero Nome" per le Figurine) + il numero. Prima cercava su name/category/subcategory, che per i
  // Retro non coincideva col Nome completo mostrato: da qui il "a volte funziona, a volte no".
  const filtered = q
    ? _baseFigurineLinkOptions.filter(f => _baseFigurineLinkLabel(f).toLowerCase().includes(q) || String(f.number||'').includes(q))
    : _baseFigurineLinkOptions;
  if (!filtered.length) { dd.innerHTML = '<div style="padding:10px 12px;color:var(--muted);font-size:0.85rem;">' + (currentLang==='it'?'Nessun risultato':'No results') + '</div>'; dd.style.display = ''; return; }
  dd.style.display = '';
  // v5.785 — niente più limite di 50 (la barra "si esauriva subito" con ~256 basi): mostra tutte le
  // opzioni filtrate; il dropdown resta scrollabile.
  dd.innerHTML = filtered.map(f => {
    return `<div onclick="selectBaseFigurineLink('${f.id}')" style="padding:8px 12px;cursor:pointer;border-bottom:1px solid var(--border);" onmouseover="this.style.background='var(--bg3)'" onmouseout="this.style.background=''">
      <div style="font-size:0.9rem;">${_baseFigurineLinkLabel(f)}</div>
    </div>`;
  }).join('');
}

function selectBaseFigurineLink(id) {
  const f = _baseFigurineLinkOptions.find(x => x.id === id);
  if (!f) return;
  document.getElementById('fig-base-figurine-input').value = id;
  document.getElementById('fig-base-figurine-search').value = _baseFigurineLinkLabel(f);
  document.getElementById('fig-base-figurine-dropdown').style.display = 'none';
}

function clearBaseFigurineLinkIfEmpty() {
  setTimeout(() => {
    const dd = document.getElementById('fig-base-figurine-dropdown');
    if (dd) dd.style.display = 'none';
    const search = document.getElementById('fig-base-figurine-search');
    const hidden = document.getElementById('fig-base-figurine-input');
    if (search && hidden && !search.value.trim()) hidden.value = '';
  }, 200);
}

let _retroLinkOptions = [];
// v5.786 — allSeries=true: pesca i Retro da QUALSIASI serie (per i Change di figurina, caso raro in cui
// il Retro che "fa" il change non appartiene alla serie). Default false: solo la serie corrente (Variazioni).
let _retroLinkAllSeries = false;
function _retroLinkLabel(r) {
  // Nome completo del retro se disponibile, altrimenti Nome (+ changeType). In modalità tutte-le-serie
  // anteponiamo la serie per distinguere retro omonimi di serie diverse.
  const base = (r.fullName && r.fullName.trim()) ? r.fullName : (r.name || '') + (r.changeType ? ' — ' + r.changeType : '');
  if (_retroLinkAllSeries) {
    const s = getData('series', []).find(x => x.id === r.seriesId);
    return (s ? '[' + s.name + '] ' : '') + base;
  }
  return base;
}
function populateRetroSelect(selectedId, allSeries) {
  _retroLinkAllSeries = !!allSeries;
  // v5.791 — (revert v5.787) in modalità Change (allSeries) mostriamo TUTTI i retro, non solo i base.
  _retroLinkOptions = getData('figurines', [])
    .filter(f => f.section === 'retros' && (allSeries || f.seriesId === currentSeriesId))
    .sort((a,b) => (allSeries ? _retroLinkLabel(a).localeCompare(_retroLinkLabel(b), 'it', {sensitivity:'base'}) : ((a.category||'').localeCompare(b.category||'', 'it') || (a.subcategory||'').localeCompare(b.subcategory||'', 'it') || (a.name||'').localeCompare(b.name||'', 'it'))));
  const hidden = document.getElementById('fig-retro-input');
  const search = document.getElementById('fig-retro-search');
  const preview = document.getElementById('fig-retro-selected-preview');
  if (!hidden || !search) return;
  hidden.value = selectedId || '';
  const dd = document.getElementById('fig-retro-dropdown');
  if (dd) dd.style.display = 'none';
  if (selectedId) {
    const r = _retroLinkOptions.find(x => x.id === selectedId);
    if (r) {
      search.value = r.name + (r.changeType ? ' — ' + r.changeType : '');
      if (preview) { const parts = [r.category, r.subcategory].map(v => (v||'').trim()).filter(Boolean); preview.style.display = ''; preview.textContent = '✓ ' + (parts.length ? parts.join(' · ') + ' — ' : '') + r.name + (r.changeType ? ' — ' + r.changeType : ''); }
    }
  } else {
    search.value = '';
    if (preview) preview.style.display = 'none';
  }
}

function filterRetroLink() {
  const q = document.getElementById('fig-retro-search').value.toLowerCase().trim();
  const dd = document.getElementById('fig-retro-dropdown');
  if (!dd) return;
  // v5.786 — ricerca sull'etichetta mostrata (che in modalità tutte-le-serie include la serie) +
  // categoria/sottocategoria; nessun limite di 50.
  const filtered = q
    ? _retroLinkOptions.filter(r => _retroLinkLabel(r).toLowerCase().includes(q) || (r.category||'').toLowerCase().includes(q) || (r.subcategory||'').toLowerCase().includes(q))
    : _retroLinkOptions;
  if (!filtered.length) { dd.innerHTML = '<div style="padding:10px 12px;color:var(--muted);font-size:0.85rem;">' + (currentLang==='it'?'Nessun risultato':'No results') + '</div>'; dd.style.display = ''; return; }
  dd.style.display = '';
  dd.innerHTML = filtered.map(r => {
    const sub = [r.category, r.subcategory].map(v => (v||'').trim()).filter(Boolean).join(' · ');
    return `<div onclick="selectRetroLink('${r.id}')" style="padding:8px 12px;cursor:pointer;border-bottom:1px solid var(--border);" onmouseover="this.style.background='var(--bg3)'" onmouseout="this.style.background=''">
      <div style="font-size:0.9rem;">${esc(_retroLinkLabel(r))}</div>
      ${sub ? `<div style="font-size:0.75rem;color:var(--muted);">${sub}</div>` : ''}
    </div>`;
  }).join('');
}

function selectRetroLink(id) {
  const r = _retroLinkOptions.find(x => x.id === id);
  if (!r) return;
  document.getElementById('fig-retro-input').value = id;
  document.getElementById('fig-retro-search').value = _retroLinkLabel(r);
  document.getElementById('fig-retro-dropdown').style.display = 'none';
  const preview = document.getElementById('fig-retro-selected-preview');
  if (preview) { preview.style.display = ''; preview.textContent = '✓ ' + _retroLinkLabel(r); }
}

function clearRetroLinkIfEmpty() {
  setTimeout(() => {
    const dd = document.getElementById('fig-retro-dropdown');
    if (dd) dd.style.display = 'none';
    const search = document.getElementById('fig-retro-search');
    const hidden = document.getElementById('fig-retro-input');
    if (search && hidden && !search.value.trim()) hidden.value = '';
  }, 200);
}

// I QUATTRO TIPI SI ESCLUDONO A VICENDA (v5.711). Prima le tre caselle erano
// INDIPENDENTI, e il sito risolveva i conflitti PER PRECEDENZA (isVariation vinceva su
// isChange): un oggetto poteva essere marcato come due cose insieme, e nessuno lo
// diceva mai. Col quinto tipo questo non regge piu' — un oggetto E' UNA COSA SOLA.
// L'esclusivita' scatta al CLIC, non al caricamento: un record gia' esistente con due
// flag si apre com'e', ma appena tocchi una casella si sistema. Cosi' non riscriviamo
// dati vecchi di nascosto.
function _esclusivitaTipi(appenaSpuntata) {
  const caselle = ['fig-is-variation-input', 'fig-is-unofficial-variation-input',
                   'fig-is-change-input', 'fig-is-printerror-input'];
  const el = document.getElementById(appenaSpuntata);
  if (!el || !el.checked) return;   // sto SPEGNENDO una casella: non tocco le altre
  caselle.filter(c => c !== appenaSpuntata).forEach(c => {
    const x = document.getElementById(c);
    if (x) x.checked = false;
  });
}

// v5.748 — L'etichetta del selettore base cambia col tipo: "variante" solo per le
// variazioni; per Change/Errore di stampa la parola giusta ("un Change" / "un errore di
// stampa"), perche' quelli NON sono varianti. Vale sia per figurine sia per retro (dove
// le variazioni non esistono proprio).
function _baseFigurineLabelText() {
  const isRetros = currentSection === 'retros';
  const isChg = document.getElementById('fig-is-change-input')?.checked;
  const isPE = document.getElementById('fig-is-printerror-input')?.checked;
  if (currentLang === 'it') {
    const noun = isRetros ? 'Retro base' : 'Figurina base';
    const pron = isRetros ? 'questo' : 'questa';
    const rel = isChg ? 'un Change' : (isPE ? 'un errore di stampa' : 'una variante');
    return noun + ' (di cui ' + pron + ' è ' + rel + ')';
  }
  const noun = isRetros ? 'Base Retro' : 'Base sticker';
  const rel = isChg ? 'a Change' : (isPE ? 'a print error' : 'a variation');
  return noun + ' (the one this is ' + rel + ' of)';
}

function toggleBaseFigurineGroup(appenaSpuntata) {
  if (appenaSpuntata) _esclusivitaTipi(appenaSpuntata);
  const group = document.getElementById('fig-base-figurine-group');
  const retroGroup = document.getElementById('fig-retro-group');
  const numberGroup = document.getElementById('fig-number-group');
  const changeTypeGroup = document.getElementById('fig-retro-change-type-group');
  if (!group) return;
  const isVar = document.getElementById('fig-is-variation-input')?.checked;
  const isUnoff = document.getElementById('fig-is-unofficial-variation-input')?.checked;
  const isChg = document.getElementById('fig-is-change-input')?.checked;
  const isPE = document.getElementById('fig-is-printerror-input')?.checked;
  // un errore di stampa, come le variazioni e i Change, e' collegato a un oggetto base
  const showBase = isVar || isUnoff || isChg || isPE;
  group.style.display = showBase ? '' : 'none';
  const _blt = document.getElementById('fig-base-figurine-label-text');
  if (_blt) _blt.textContent = _baseFigurineLabelText();
  // Il campo Retro associato non si applica mai ai Retro stessi (un retro non ha un retro)
  // v5.786 — il campo Retro ora si mostra ANCHE per i Change (facoltativo): un Change può avere un
  // proprio Retro (il retro che "fa" il change). Per i Change il selettore pesca da TUTTE le serie;
  // per le Variazioni resta la serie corrente. Ripopolo al toggle preservando la selezione corrente.
  if (retroGroup) {
    const showRetro = currentSection !== 'retros';
    retroGroup.style.display = showRetro ? '' : 'none';
    if (showRetro) populateRetroSelect(document.getElementById('fig-retro-input')?.value || null, isChg);
  }
  // ...E PER LO STESSO IDENTICO MOTIVO, nemmeno le VARIAZIONI (v5.707). Una variazione
  // E' il cambio del DIETRO: un retro, che un dietro non ce l'ha, per definizione non
  // puo' variare. Il codice lo sapeva gia' ("un retro non ha un retro", riga sopra) ma
  // non ne aveva tratto questa conseguenza: le due caselle restavano cliccabili nei
  // Retro, e saveItem le leggeva. Bastava una spunta distratta per creare un dato che
  // il dominio non ammette.
  const varOff = document.getElementById('fig-var-official-label');
  const varUnoff = document.getElementById('fig-var-unofficial-label');
  const nascondiVar = (currentSection === 'retros') ? 'none' : '';
  if (varOff) varOff.style.display = nascondiVar;
  if (varUnoff) varUnoff.style.display = nascondiVar;
  // Il Numero si nasconde per Variazioni/Change: eredita quello della figurina base collegata
  if (numberGroup) numberGroup.style.display = (showBase || currentSection === 'retros') ? 'none' : '';
  // Tipo di change: per i Change di Retro E per i Change di FIGURINA (v5.779), con le opzioni
  // configurate sulla serie (stessa lista, campo retroChangeTypes).
  const isTypedChange = isChg && (currentSection === 'retros' || currentSection === 'figurines');
  if (changeTypeGroup) {
    changeTypeGroup.style.display = isTypedChange ? '' : 'none';
    if (isTypedChange) {
      const types = changeTypesDiSerie(currentSeriesId);
      const sel = document.getElementById('fig-retro-change-type-input');
      if (sel) {
        const current = sel.value;
        sel.innerHTML = '<option value="">' + (currentLang === 'it' ? '— scegli —' : '— choose —') + '</option>' +
          types.map(t => `<option value="${t}">${t}</option>`).join('');
        if (types.includes(current)) sel.value = current;
      }
    }
  }
  // Tipo di errore di stampa (testo libero): in TUTTE le sezioni, quando e' un Errore di stampa
  // (isPE). Occupa la stessa posizione del "Tipo di change", con cui e' mutuamente esclusivo.
  const printErrorTypeGroup = document.getElementById('fig-print-error-type-group');
  if (printErrorTypeGroup) printErrorTypeGroup.style.display = isPE ? '' : 'none';
  // v5.774 — per un Change o Errore di stampa di RETRO il Nome non ha valore proprio (eredita
  // quello del retro base): nascondiamo il campo. Al salvataggio il Nome viene comunque derivato.
  // v5.779 — idem per un Change di FIGURINA: eredita il Nome dalla figurina base, campo nascosto.
  const nameGroup = document.getElementById('fig-name-group');
  // v5.790 — Nome nascosto per Change ED Errori di stampa, sia Retro sia figurine (in tutti eredita
  // dalla base). Prima le figurine Errore di stampa mostravano ancora il Nome proprio.
  const _nomeNascosto = (isChg || isPE) && (currentSection === 'retros' || currentSection === 'figurines');
  if (nameGroup) nameGroup.style.display = _nomeNascosto ? 'none' : '';
}

function toggleForSaleFields() {
  const checked = document.getElementById('fig-for-sale-input').checked;
  document.getElementById('fig-for-sale-fields').style.display = checked ? 'grid' : 'none';
}

function openAddItemModal(itemId) {
  if (!currentUser?.isAdmin) { toast((currentLang === 'it' ? 'Solo per admin' : 'Admin only'), 'error'); return; }
  _returnToErroriAfterSave = false;
  document.getElementById('edit-fig-id').value = itemId || '';
  let existingItem = null;
  if (itemId) {
    existingItem = getData('figurines', []).find(x => x.id === itemId);
    if (existingItem) { currentSeriesId = existingItem.seriesId; currentSection = existingItem.section || currentSection; }
  }
  const label = getSectionLabel(currentSection) || (currentLang === 'it' ? 'Oggetto' : 'Item');
  const labelSingular = getSectionLabelSingular(currentSection);
  document.getElementById('fig-modal-title').textContent = (itemId && existingItem)
    ? (existingItem.number ? '# ' + existingItem.number + ' - ' + existingItem.name : existingItem.name)
    : (currentLang === 'it' ? 'Aggiungi ' : 'Add ') + labelSingular;
  const saveBtn = document.querySelector('#add-fig-modal button[onclick="saveFigurine()"]');
  if (saveBtn) { saveBtn.removeAttribute('data-i18n'); saveBtn.textContent = (currentLang === 'it' ? 'Salva ' : 'Save ') + labelSingular; }
  const seriesNameEl = document.getElementById('fig-modal-series-name');
  if (seriesNameEl) { const s = getData('series', []).find(x => x.id === currentSeriesId); seriesNameEl.textContent = s ? s.name : ''; }
  document.getElementById('fig-img-preview').style.display = 'none';
  editingFigImg = null;
  editingFigImgFileSave = null;
  document.getElementById('fig-ebay-img-preview').style.display = 'none';
  editingFigEbayImg = null;
  editingFigEbayImgFileSave = null;
  const ebayImgGroup = document.getElementById('fig-ebay-img-group');
  if (ebayImgGroup) ebayImgGroup.style.display = (currentSection === 'figurines' || currentSection === 'retros') ? '' : 'none';
  switchFigModalTab('generale');
  if (itemId) {
    const f = getData('figurines', []).find(x => x.id === itemId);
    if (f) {
      document.getElementById('fig-number-input').value = f.number || '';
      document.getElementById('fig-no-number-input').checked = f.noNumber || false;
      document.getElementById('fig-category-input').value = f.category || '';
      document.getElementById('fig-subcategory-input').value = f.subcategory || '';
      document.getElementById('fig-name-input').value = f.name;
      document.getElementById('fig-desc-input').value = f.desc || '';
      document.getElementById('fig-score-input').value = f.score || 0;
      document.getElementById('fig-subseries-input').value = f.subseries || '';
      document.getElementById('fig-size-input').value = f.size || '';
      document.getElementById('fig-is-variation-input').checked = f.isVariation || false;
      document.getElementById('fig-is-unofficial-variation-input').checked = f.isUnofficialVariation || false;
      document.getElementById('fig-is-change-input').checked = f.isChange || false;
      // in modifica la checkbox "Errore di stampa" NON veniva ricaricata (v5.767): senza di lei il
      // gruppo "Tipo di errore di stampa" (e il selettore base) non comparivano aprendo un errore.
      document.getElementById('fig-is-printerror-input').checked = f.isPrintError || false;
      document.getElementById('fig-print-error-type-input').value = f.printErrorType || '';
      populateBaseFigurineSelect(itemId, f.baseFigurineId);
      populateRetroSelect(f.retroId || null, !!f.isChange); // v5.786 — Change: retro da tutte le serie
      document.getElementById('fig-for-sale-input').checked = f.forSale || false;
      document.getElementById('fig-price-input').value = f.price || '';
      document.getElementById('fig-quantity-input').value = f.quantity || 1;
      document.getElementById('fig-condition-input').value = f.condition || 'new';
      if (f.img) { const pr = document.getElementById('fig-img-preview'); pr.src = f.img; pr.style.display = 'block'; editingFigImg = f.img; }
      if (f.ebayImg) { const pr2 = document.getElementById('fig-ebay-img-preview'); pr2.src = f.ebayImg; pr2.style.display = 'block'; editingFigEbayImg = f.ebayImg; }
    }
  } else {
    ['fig-number-input','fig-name-input','fig-desc-input','fig-subseries-input','fig-size-input','fig-category-input','fig-subcategory-input'].forEach(id => document.getElementById(id).value = '');
    document.getElementById('fig-no-number-input').checked = false;
    document.getElementById('fig-score-input').value = 0;
    document.getElementById('fig-is-variation-input').checked = false;
    document.getElementById('fig-is-unofficial-variation-input').checked = false;
    document.getElementById('fig-is-change-input').checked = false;
    document.getElementById('fig-is-printerror-input').checked = false;
    populateBaseFigurineSelect(null, null);
    populateRetroSelect(null);
    document.getElementById('fig-for-sale-input').checked = false;
    document.getElementById('fig-price-input').value = '';
    document.getElementById('fig-quantity-input').value = 1;
    document.getElementById('fig-condition-input').value = 'new';
    const rctSel = document.getElementById('fig-retro-change-type-input');
    if (rctSel) rctSel.value = '';
    const petInput = document.getElementById('fig-print-error-type-input');
    if (petInput) petInput.value = '';
  }
  toggleForSaleFields();
  toggleBaseFigurineGroup();
  // v5.788 — reset ESPLICITO del "Tipo di change". La modale riusa lo stesso DOM tra un'apertura e
  // l'altra, quindi il select conservava il valore precedente: clonando una figurina base (changeType
  // vuoto) restava il valore di una modifica precedente, che toggleBaseFigurineGroup poi "ripristinava"
  // spuntando Change. Ora lo si imposta SEMPRE: al valore della sorgente se c'è, altrimenti vuoto.
  {
    const sel = document.getElementById('fig-retro-change-type-input');
    if (sel) sel.value = (itemId && existingItem?.changeType) ? existingItem.changeType : '';
  }
  // Show/hide conditional fields based on series flags
  const _ser = getData('series', []).find(s => s.id === currentSeriesId);
  const hasSizes = _ser?.hasSizes || false;
  const hasSubseries = _ser?.hasSubseries || false;
  // Aggiorna le colonne della griglia in base alla visibilità della Sottoserie
  const figGrid = document.getElementById('fig-modal-grid');
  if (figGrid) {
    figGrid.style.gridTemplateColumns = hasSubseries
      ? '80px minmax(0,70px) 1fr'
      : '80px 1fr';
  }
  const delBtn = document.getElementById('fig-modal-delete-btn');
  if (delBtn) delBtn.style.display = itemId ? '' : 'none';

  // Per la sezione Retro, nasconde i campi non rilevanti (numero, flag variazione)
  // Il Punteggio resta visibile anche per i Retro; la Categoria è esclusiva dei Retro
  const isRetros = currentSection === 'retros';
  // v5.749 — La visibilità di "Figurina/Retro base" è governata SOLO da toggleBaseFigurineGroup()
  // (chiamato sopra): si mostra solo con un tipo spuntato. La vecchia forEach qui la
  // riforzava sempre visibile per le figurine, anche senza alcuna variazione spuntata.
  // Il Numero si nasconde per i Retro, e anche per Variazioni/Change (eredita quello della figurina base)
  const isVarOrChg = document.getElementById('fig-is-variation-input')?.checked ||
                      document.getElementById('fig-is-unofficial-variation-input')?.checked ||
                      document.getElementById('fig-is-change-input')?.checked ||
                      document.getElementById('fig-is-printerror-input')?.checked;
  const numberGroup = document.getElementById('fig-number-group');
  if (numberGroup) numberGroup.style.display = (currentSection === 'figurines' && !isVarOrChg) ? '' : 'none';
  // Sottoserie e Taglia dipendono sia dai flag della serie sia dalla sezione (mai per i Retro)
  const sizeGroup = document.getElementById('fig-size-group');
  if (sizeGroup) sizeGroup.style.display = (hasSizes && !isRetros) ? '' : 'none';
  const subseriesGroup = document.getElementById('fig-subseries-group');
  if (subseriesGroup) subseriesGroup.style.display = (hasSubseries && !isRetros) ? '' : 'none';
  const categoryGroup = document.getElementById('fig-category-group');
  if (categoryGroup) categoryGroup.style.display = isRetros ? '' : 'none';
  const subcategoryGroup = document.getElementById('fig-subcategory-group');
  if (subcategoryGroup) subcategoryGroup.style.display = isRetros ? '' : 'none';
  // Per i Retro, in griglia restano Categoria, Sottocategoria e Nome
  if (figGrid && isRetros) {
    figGrid.style.gridTemplateColumns = 'minmax(0,140px) minmax(0,140px) 1fr';
  }
  // Per i Retro, il blocco flag resta visibile ma solo con la checkbox Change
  // (Variazione ufficiale/non ufficiale non si applicano ai Retro)
  const flagsBlock = document.querySelector('#add-fig-modal [data-flags-block]');
  if (flagsBlock) flagsBlock.style.display = 'grid';
  const varOfficialLabel = document.getElementById('fig-var-official-label');
  const varUnofficialLabel = document.getElementById('fig-var-unofficial-label');
  if (varOfficialLabel) varOfficialLabel.style.display = isRetros ? 'none' : '';
  if (varUnofficialLabel) varUnofficialLabel.style.display = isRetros ? 'none' : '';
  const baseLabelText = document.getElementById('fig-base-figurine-label-text');
  if (baseLabelText) baseLabelText.textContent = _baseFigurineLabelText();

  document.getElementById('add-fig-modal').classList.remove('hidden');
}

async function deleteFigurineFromModal() {
  const itemId = document.getElementById('edit-fig-id').value;
  if (!itemId) return;
  if (!confirm(currentLang === 'it' ? 'Eliminare questo oggetto?' : 'Delete this item?')) return;
  await fsDelete('figurines', itemId);
  _cache.figurines = _cache.figurines.filter(x => x.id !== itemId);
  closeModal('add-fig-modal');
  if (_returnToErroriAfterSave) {
    _returnToErroriAfterSave = false;
    showPage('profile');
    adminTab('errori');
  } else {
    renderItems(); renderHomeStats(); updateSectionCounts();
  }
  toast(currentLang === 'it' ? 'Eliminato' : 'Deleted', 'success');
}

// keep openAddFigModal as alias for admin panel
function openAddFigModal(figId) { openAddItemModal(figId); }

// v5.781 — CLONA un oggetto: apre la modale "Aggiungi" precompilata con TUTTI i campi dell'oggetto
// di partenza, ma come record NUOVO. Riusa openAddItemModal(itemId) (che popola ogni campo, immagine
// compresa) e poi SVUOTA edit-fig-id: così saveFigurine CREA invece di aggiornare — nessun record
// pre-salvato, e si evita di scrivere subito una chiave duplicata. L'admin ritocca ciò che serve
// (di norma Numero/Nome) e salva. Disponibile su qualsiasi oggetto (Figurine/Retro/Album/Altro).
function cloneFigurine(itemId) {
  if (!currentUser?.isAdmin) { toast((currentLang === 'it' ? 'Solo per admin' : 'Admin only'), 'error'); return; }
  const src = getData('figurines', []).find(x => x.id === itemId);
  if (!src) { toast((currentLang === 'it' ? 'Oggetto non trovato' : 'Item not found'), 'error'); return; }
  closeModal('fig-detail-modal');            // se il clone parte dalla scheda di dettaglio, la chiude
  openAddItemModal(itemId);                  // popola tutti i campi (e l'immagine) dalla sorgente
  document.getElementById('edit-fig-id').value = '';  // NUOVO record: al salvataggio crea, non aggiorna
  // v5.789 — openAddItemModal(itemId) aveva escluso la sorgente dal selettore "Figurina base" (una
  // figurina non è base di sé stessa in MODIFICA). Ma nel Clona il record è una COPIA: la figurina di
  // partenza dev'essere selezionabile come base (tipico: clono una base per farne un suo Change).
  // Ripopolo il selettore base SENZA escludere nulla, preservando l'eventuale base già copiata.
  populateBaseFigurineSelect(null, document.getElementById('fig-base-figurine-input')?.value || null);
  // v5.792 — il Clona NON copia i campi del singolo PEZZO FISICO: Foto, Foto Ebay e Retro. Il nuovo
  // oggetto avrà la sua foto e il suo retro. (Franco: "possibile che cloni anche il retro?" + la foto
  // veniva duplicata nell'anteprima di ricerca perché il change aveva una foto propria = quella base.)
  editingFigImg = null; editingFigImgFileSave = null;
  editingFigEbayImg = null; editingFigEbayImgFileSave = null;
  const _clImgPrev = document.getElementById('fig-img-preview'); if (_clImgPrev) _clImgPrev.style.display = 'none';
  const _clEbayPrev = document.getElementById('fig-ebay-img-preview'); if (_clEbayPrev) _clEbayPrev.style.display = 'none';
  populateRetroSelect(null, document.getElementById('fig-is-change-input')?.checked || false);
  const labelSingular = getSectionLabelSingular(src.section || currentSection);
  const t = document.getElementById('fig-modal-title');
  if (t) t.textContent = (currentLang === 'it' ? 'Clona ' : 'Clone ') + labelSingular;
  toast((currentLang === 'it' ? '📋 Copia pronta: cambia Numero/Nome e salva' : '📋 Copy ready: change Number/Name and save'), 'success');
}

function getOwned() {
  const uid = currentUser?.id || 'guest';
  // Use cached Firebase data if available, fallback to localStorage
  if (_cache.ownedMap && _cache.ownedMap[uid]) return _cache.ownedMap[uid];
  return LOCAL.get('owned_' + uid) || [];
}
async function toggleOwned(figId) {
  if (!currentUser) { openAuth('register'); return; }
  let owned = getOwned();
  if (owned.includes(figId)) owned = owned.filter(x => x !== figId);
  else owned.push(figId);
  // Save to cache, localStorage, and Firebase
  if (!_cache.ownedMap) _cache.ownedMap = {};
  _cache.ownedMap[currentUser.id] = owned;
  LOCAL.set('owned_' + currentUser.id, owned);
  await saveOwnedToFirebase(currentUser.id, owned);
  renderItems(); renderProfile();
  refreshSeriesMeta();   // i contatori in alto seguono la lista (v5.709)
  if (bulkEditActive) renderBulkEditView();
}

async function saveOwnedToFirebase(userId, owned) {
  // Restituisce true/false: chi chiama DEVE sapere se il salvataggio e' riuscito.
  // Fino alla v5.681 questa funzione inghiottiva l'errore in un console.error —
  // cioe' lo scriveva in un posto che nessun utente guarda mai — e le due chiamate
  // interattive (spunta di una figurina, e i due pulsanti aggiungi/rimuovi tutto)
  // non l'aspettavano nemmeno.
  // Conseguenza: se la scrittura falliva (quota Firestore esaurita, rete assente,
  // regole), la schermata mostrava comunque la lista nuova — la legge da cache e
  // localStorage — mentre Firestore conservava quella VECCHIA. L'utente credeva di
  // aver salvato. E il ricalcolo del punteggio, che legge Firestore, ricalcolava
  // sul dato vecchio: era il sintomo con cui il baco e' venuto a galla, ma il
  // sintomo era il meno grave. Il grave e' la perdita silenziosa del lavoro.
  try {
    await fsSave('owned', { id: userId, userId, authUid: currentUser?.authUid || null, owned });
    await _updatePublicScore(userId, owned);
    return true;
  } catch(e) {
    console.error('saveOwned error', e);
    toast(currentLang === 'it'
      ? '⚠️ Modifica NON salvata: il server non ha risposto. Ricarica la pagina e controlla la tua lista.'
      : '⚠️ Change NOT saved: the server did not respond. Reload the page and check your list.', 'error');
    return false;
  }
}

async function _updatePublicScore(userId, owned) {
  // Pubblica SOLO il punteggio aggregato e i conteggi per la Classifica,
  // mai la lista dettagliata di quali figurine specifiche si possiedono
  // (quella resta privata nella collezione 'owned').
  try {
    const allFigs = getData('figurines', []);
    const ownedFigs = allFigs.filter(f => owned.includes(f.id));
    const score = ownedFigs.reduce((sum, f) => sum + (f.score || 0), 0);
    const countFigurines = ownedFigs.filter(f => f.section === 'figurines' || !f.section).length;
    const countAlbums = ownedFigs.filter(f => f.section === 'albums').length;
    const countExtras = ownedFigs.filter(f => f.section === 'extras').length;
    const { doc, setDoc } = window._fb;
    await setDoc(doc(db, 'public_profiles', userId), { score, countFigurines, countAlbums, countExtras }, { merge: true });

    // Aggiorna anche la copia in memoria: senza questo, la Classifica
    // mostrerebbe il vecchio punteggio finché non si ricarica la pagina,
    // anche se su Firestore il dato è già corretto
    if (Array.isArray(_cache.public_profiles)) {
      const idx = _cache.public_profiles.findIndex(p => p.id === userId);
      if (idx >= 0) {
        _cache.public_profiles[idx] = { ..._cache.public_profiles[idx], score, countFigurines, countAlbums, countExtras };
      }
    }
  } catch(e) { console.warn('_updatePublicScore failed', e.message); }
}

// ============================================================
//  RICALCOLO UNA TANTUM DEI PUNTEGGI PUBBLICI (public_profiles)
//  Serve per gli utenti registrati prima dell'introduzione di
//  _updatePublicScore(): il loro public_profiles non ha ancora i campi
//  score/countFigurine/countAlbums/countExtras (mostrano 0 in Classifica
//  finché non lo eseguono). Da questo punto in poi ogni "Ce l'ho" li
//  aggiorna già in automatico, quindi va usato solo occasionalmente.
// ============================================================
async function backfillPublicScores() {
  const btn = document.getElementById('backfill-score-btn');
  const progressEl = document.getElementById('backfill-score-progress');
  if (btn) btn.disabled = true;
  if (progressEl) { progressEl.style.display = ''; progressEl.textContent = 'Lettura dati in corso...'; }

  try {
    const allUsers = await fsGetAll('users');
    const allOwned = await fsGetAll('owned');
    const ownedByUserId = {};
    for (const o of allOwned) ownedByUserId[o.userId] = o.owned || [];

    // Scorre SEMPRE tutti gli utenti, uno per uno — chi non ha mai usato
    // "Mia lista" riceve comunque un punteggio 0 scritto esplicitamente,
    // invece di essere semplicemente saltato
    let done = 0;
    for (const user of allUsers) {
      await _updatePublicScore(user.id, ownedByUserId[user.id] || []);
      done++;
      if (progressEl) progressEl.textContent = 'Ricalcolati ' + done + ' / ' + allUsers.length + '...';
    }

    // Dati "Mia lista" orfani (nessun utente corrispondente): solo un avviso,
    // non influenzano il conteggio principale
    const realUserIds = new Set(allUsers.map(u => u.id));
    const orphanOwned = allOwned.filter(o => !realUserIds.has(o.userId)).length;

    if (progressEl) progressEl.textContent = 'Completato: punteggio aggiornato per tutti i ' + done + ' utenti.' + (orphanOwned ? ' (' + orphanOwned + ' dati "Mia lista" orfani ignorati, utenti non più esistenti)' : '');
    toast('Punteggio ricalcolato per tutti i ' + done + ' utenti', 'success');
    _cache.public_profiles = await fsGetAll('public_profiles');
    renderClassifica();
  } catch(e) {
    console.error('backfillPublicScores', e);
    toast('Errore durante il ricalcolo: ' + e.message, 'error');
  } finally {
    if (btn) btn.disabled = false;
  }
}

async function loadAllOwnedFromFirebase() {
  try {
    if (!_cache.ownedMap) _cache.ownedMap = {};
    if (currentUser?.isAdmin) {
      // L'admin legge l'intera collezione (serve al pannello di gestione utenti)
      const allOwned = await fsGetAll('owned');
      for (const doc of allOwned) {
        _cache.ownedMap[doc.userId] = doc.owned || [];
      }
    } else if (currentUser) {
      // Un utente normale legge solo il proprio documento: 'owned' è privata,
      // la Classifica ora usa il punteggio già aggregato in public_profiles
      const own = await fsGet('owned', currentUser.id);
      if (own) _cache.ownedMap[currentUser.id] = own.owned || [];
    }
    // Migrate current user's localStorage data to Firebase if not yet saved
    if (currentUser && (!_cache.ownedMap[currentUser.id] || !_cache.ownedMap[currentUser.id].length)) {
      const localOwned = LOCAL.get('owned_' + currentUser.id);
      if (localOwned && localOwned.length > 0) {
        _cache.ownedMap[currentUser.id] = localOwned;
        await saveOwnedToFirebase(currentUser.id, localOwned);
      }
    }
  } catch(e) { console.error('loadAllOwned error', e); }
}

function setNoPhotoFilter(val) {
  _noPhotoFilter = val;
  currentItemPage = 1;
  try { renderItems(); } catch(e) { console.error('renderItems (setNoPhotoFilter)', e); }
  try { if (bulkEditActive) renderBulkEditView(); } catch(e) { console.error('renderBulkEditView (setNoPhotoFilter)', e); }
}

function renderItemTypeFilters() {
  const el = document.getElementById('items-filter-toggles');
  if (!el) return;

  const it = (currentLang === 'it');
  const sez = currentSection || 'figurines';

  // FILTRI DINAMICI (v5.711). Un filtro compare SOLO SE quel tipo esiste davvero in
  // questa serie e in questa sezione. Stessa regola dei contatori, e la stessa
  // funzione: tipiPresenti().
  // Perche': Franco ha deciso che tutti e cinque i tipi sono AMMESSI ovunque ("alla
  // peggio non avremo dati"). Ma un filtro sempre visibile su una sezione vuota
  // sarebbe un interruttore che, cliccato, mostra una pagina vuota — l'"interruttore
  // che non fa niente" che avevamo evitato nei Retro. Cosi' invece il "alla peggio"
  // costa davvero zero: la pagina non offre mai un comando inutile, e il giorno che
  // inserisci il primo Change in un Album, il filtro appare DA SOLO.
  const g = tipiPresenti(currentSeriesId, sez);

  // se il filtro acceso punta a un tipo che qui non esiste (es. cambiando serie),
  // torna su "base": un filtro fantasma mostrerebbe una pagina vuota senza spiegazione
  const presente = {
    all: true,
    base: g.base.length > 0,
    variation: g.variation.length > 0,
    unofficialVariation: g.unofficial.length > 0,
    anyVariation: g.variation.length > 0 && g.unofficial.length > 0,
    change: g.change.length > 0,
    printError: g.printError.length > 0
  };
  if (!presente[_itemTypeFilter]) _itemTypeFilter = presente.base ? 'base' : 'all';

  const coloreTipo = {
    base: 'var(--type-base)',
    variation: 'var(--type-official)',
    unofficialVariation: 'var(--type-unofficial)',
    change: 'var(--type-change)',
    printError: 'var(--type-printerror)'
  };
  const item = (key, label, icon, bold, labelHTML) => {
    const col = coloreTipo[key] || 'var(--text)';
    return `
    <div style="display:flex;align-items:center;gap:0.4rem;">
      <button class="toggle-btn-blue ${_itemTypeFilter === key ? 'on' : ''}" onclick="toggleItemTypeFilter('${key}')" title="${label}"></button>
      <span style="font-size:0.82rem;color:${col};${bold ? 'font-weight:600;' : ''}">${icon ? icon + ' ' : ''}${labelHTML || label}</span>
    </div>`;
  };

  // il nome dell'oggetto cambia con la sezione: "figurine set base", "retro set base",
  // "album set base", "oggetti set base"
  const nomeP = { figurines: it ? 'figurine' : 'stickers', retros: it ? 'retro' : 'retros',
                  albums: it ? 'album' : 'albums', extras: it ? 'oggetti' : 'items' }[sez]
              || (it ? 'figurine' : 'stickers');

  // IN FILA, non in colonna (v5.712). Erano impilati da sempre — non l'ha rotto la
  // v5.711 — ma nella stessa pagina i filtri del POSSESSO sono in riga (v5.697): una
  // fila e una colonna a due centimetri di distanza, senza che nulla lo giustifichi.
  // flex-wrap: con sette filtri (Figurine) va a capo da solo; con tre (Retro) sta su
  // una riga sola. Il gap verticale serve proprio per quando va a capo.
  let html = '<div style="display:flex;flex-wrap:wrap;gap:0.5rem 1.5rem;align-items:center;">';

  html += item('all', it ? 'Tutte' : 'All', '', false);   // v5.852 — era 'Tutti': il filtro parla di figurine, femminile

  if (presente.base) html += item('base',
    (['bustine','albums','extras'].includes(currentSection)
      ? (it ? 'Versione standard' : 'Standard version')
      : (it ? (nomeP.charAt(0).toUpperCase() + nomeP.slice(1)) + ' set base' : 'Base set ' + nomeP)), '', true);

  if (presente.variation) html += item('variation',
    it ? 'Variazioni ufficiali' : 'Official variations', '');

  if (presente.unofficialVariation) html += item('unofficialVariation',
    it ? 'Variazioni non ufficiali' : 'Unofficial variations', '');

  // l'unione ha senso SOLO se esistono entrambe: con una sola, direbbe la stessa cosa
  // del filtro qui sopra, e sarebbe un doppione
  if (presente.anyVariation) {
    // v5.870 — etichetta UGUALE su mobile e desktop: "Variazioni (ufficiali e non ufficiali)"
    // con le parentesi e la "e" (prima su telefono si toglievano le parentesi). I due tipi
    // restano colorati.
    const etIt = 'Variazioni (<span style="color:var(--type-official);">ufficiali</span> e <span style="color:var(--type-unofficial);">non ufficiali</span>)';
    const etEn = 'Variations (<span style="color:var(--type-official);">official</span> and <span style="color:var(--type-unofficial);">unofficial</span>)';
    html += item('anyVariation',
      it ? 'Variazioni (ufficiali e non ufficiali)' : 'Variations (official and unofficial)',
      '', false, it ? etIt : etEn);
  }

  if (presente.change) html += item('change', it ? 'Change' : 'Change', '');

  if (presente.printError) html += item('printError',
    it ? 'Errori di stampa' : 'Print errors', '');

  html += '</div>';

  el.innerHTML = html;

  // SECONDA RIGA: il filtro sul POSSESSO. Contenitore separato, con una linea
  // sopra, perche' e' un'altra domanda: il tipo chiede "che cosa e' questo?", il
  // possesso chiede "ce l'ho?". Si combinano — "le variazioni ufficiali che mi
  // mancano" — quindi non possono stare nello stesso gruppo radio.
  // Solo per chi ha fatto l'accesso: senza lista, "cosa mi manca" non vuol dire nulla.
  // I DUE FILTRI ADMIN escono da qui: vanno nel loro riquadro, in ultima posizione
  // (v5.699). Prima erano appesi in coda ai filtri di tipo, dentro lo stesso
  // contenitore — quindi un admin vedeva quattro gruppi di interruttori senza che
  // nulla dicesse quali fossero suoi soltanto.
  const elAdm = document.getElementById('items-admin-filters');
  const elAdmT = document.getElementById('items-admin-filter-toggles');
  if (elAdm && elAdmT) {
    if (!currentUser?.isAdmin) {
      elAdm.style.display = 'none';
      elAdmT.innerHTML = '';
    } else {
      const itl = (currentLang === 'it');
      // niente emoji, per la regola posta da Franco: le icone ci sono sempre o mai.
      // (v5.692 le tolse dai filtri di tipo; queste due erano rimaste indietro.)
      // v5.796 — "Senza foto" NON è più qui: spostato tra i filtri per tutti gli utenti (vedi sotto).
      let ha = '';

      // Solo nelle FIGURINE: il setaccio applica questo filtro unicamente li'
      // (currentSection === 'figurines'). Mostrarlo nei Retro sarebbe un interruttore
      // che non fa niente — il peggior tipo di comando.
      if (currentSection === 'figurines') {
        const senzaUff = itl
          ? 'Figurine set base prive di variazioni ufficiali'
          : 'Base set stickers without official variations';
        ha += `
          <div style="display:flex;align-items:center;gap:0.4rem;">
            <button class="toggle-btn-blue ${_noOfficialVariationFilter ? 'on' : ''}" onclick="toggleNoOfficialVariationFilter()" title="${senzaUff}"></button>
            <span style="font-size:0.82rem;color:var(--muted);">${senzaUff}</span>
          </div>`;
      }

      ha += `
        <div style="display:flex;align-items:center;gap:0.4rem;">
          <button class="toggle-btn-blue ${_ebayFilter ? 'on' : ''}" onclick="toggleEbayFilter()" title="Ebay"></button>
          <span style="font-size:0.82rem;color:var(--muted);">Ebay</span>
        </div>`;
      elAdmT.innerHTML = ha;
      elAdm.style.display = '';
    }
  }

  // SECONDA RIGA di selettori (contenitore items-owned-toggles, separato da un bordo):
  //  - i filtri di POSSESSO ("Solo presenti/mancanti dalla tua lista") solo per chi ha
  //    fatto l'accesso (senza lista non vogliono dire nulla);
  //  - "Senza foto" per TUTTI gli utenti, in CODA a questa stessa riga (v5.798 — Franco:
  //    va al fondo della seconda riga di selettori, non su una riga separata sotto).
  // La riga è quindi sempre visibile: da anonimo contiene il solo "Senza foto".
  const elOwned = document.getElementById('items-owned-toggles');
  if (elOwned) {
    const itl = (currentLang === 'it');
    // stessa identica forma dei filtri di tipo: bottone toggle-btn-blue + etichetta
    const itemToggle = (isOn, onclickAttr, label) => `
        <div style="display:flex;align-items:center;gap:0.4rem;">
          <button class="toggle-btn-blue ${isOn ? 'on' : ''}" onclick="${onclickAttr}" title="${label}"></button>
          <span style="font-size:0.82rem;color:var(--text);">${label}</span>
        </div>`;
    // in FILA, non in colonna: stanno comodamente su una riga sola (wrap se serve).
    let h2 = '<div style="display:flex;flex-wrap:wrap;gap:0.5rem 1.5rem;">';
    if (currentUser) {
      // v5.853 — le etichette tornano per esteso anche su telefono (la v5.852 le aveva
      // accorciate in "Presenti"/"Mancanti"): a fare spazio ci pensa il filtro "Senza foto",
      // che su telefono non compare piu' (vedi sotto). Meglio togliere un filtro intero che
      // amputare il nome di due.
      h2 += itemToggle(_ownedFilter === 'owned', "toggleOwnedFilter('owned')", itl ? 'Presenti nella tua lista' : 'In my list');
      h2 += itemToggle(_ownedFilter === 'missing', "toggleOwnedFilter('missing')", itl ? 'Mancanti dalla tua lista' : 'Missing from my list');
    }
    // v5.853 — il filtro "Senza foto" su telefono non compare: e' un filtro di servizio, e la
    // riga serve tutta ai due filtri di possesso, che tornano cosi' col nome per esteso.
    if (!_isMobileViewport()) {
      const senzaFoto = _noPhotoFilter ? (itl ? 'Con foto' : 'With photo') : (itl ? 'Senza foto' : 'Without photo');
      h2 += itemToggle(_noPhotoFilter, `setNoPhotoFilter(${!_noPhotoFilter})`, senzaFoto);
    }
    h2 += '</div>';
    elOwned.innerHTML = h2;
    elOwned.style.display = 'flex';
  }
  const introEl = document.getElementById('items-filter-intro');
  if (introEl) {
    introEl.style.display = 'flex';
    const introTextEl = document.getElementById('items-filter-intro-text');
    if (introTextEl) introTextEl.textContent = t('items.filterIntro');
  }
}

// Usata dalla modalità "Fronte e retro sempre grandi": aspetta di conoscere
// l'orientamento di ENTRAMBE le foto (fronte e retro) prima di decidere il layout finale.
// Si parte assumendo l'ipotesi "affiancate" (card doppia in larghezza, altezza normale) —
// se risultano invece entrambe orizzontali, si passa a "impilate" (card normale in
// larghezza, doppia in altezza): la forma della card cambia dinamicamente, dato che
// l'orientamento si scopre solo al caricamento delle foto
const _dualOrientationState = {};
// Legge a runtime (dal DOM già costruito) la larghezza reale che una card affiancata
// confermata sta usando per ciascuna foto — mai un numero scritto a mano, così si adatta
// da solo a schermo/risoluzione. Se sulla pagina non c'è ancora nessuna card affiancata
// confermata (raro: succederebbe solo se la primissima card processata è già un caso
// impilate), usa come ripiego metà della larghezza della card corrente
function _getConfirmedRowSlotWidth(currentContainerId) {
  const ref = document.querySelector('[data-confirmed-row="true"]');
  if (ref && ref.id !== currentContainerId && ref.children[0]) {
    const w = ref.children[0].offsetWidth;
    if (w > 0) return w;
  }
  const currentCard = document.getElementById(currentContainerId)?.closest('.fig-card');
  return currentCard ? currentCard.offsetWidth / 2 : 175;
}

function _checkBothOrientationForStack(containerId, which, isVertical, natW, natH) {
  if (!_dualOrientationState[containerId]) _dualOrientationState[containerId] = {};
  _dualOrientationState[containerId][which] = { isVertical, natW, natH };
  const state = _dualOrientationState[containerId];
  if (state.front !== undefined && state.retro !== undefined) {
    const bothHorizontal = !state.front.isVertical && !state.retro.isVertical;
    const c = document.getElementById(containerId);
    if (!c) return;
    if (bothHorizontal) {
      c.style.flexDirection = 'column';
      const retroDiv = c.children[1];
      if (retroDiv) { retroDiv.style.borderLeft = 'none'; retroDiv.style.borderTop = '1px solid var(--border)'; }
      // Invece di far riempire tutta la larghezza della card (350px) alle foto impilate, le
      // vincoliamo alla stessa larghezza che la pagina sta GIÀ usando in quel momento per un
      // caso affiancato confermato (letta a runtime dal DOM, non un numero fisso — cambia da
      // sola con schermo/risoluzione) — l'altezza si riduce di conseguenza, proporzionalmente
      // alla forma reale di ciascuna foto (dimensioni vere, non stimate)
      const refW = _getConfirmedRowSlotWidth(containerId);
      const frontH = refW * (state.front.natH / state.front.natW);
      const retroH = refW * (state.retro.natH / state.retro.natW);
      const frontImg = c.children[0].querySelector('img');
      const retroImg = c.children[1].querySelector('img');
      [frontImg, retroImg].forEach(img => {
        if (img) { img.style.width = refW + 'px'; img.style.height = 'auto'; img.style.margin = '0 auto'; img.style.display = 'block'; img.style.objectFit = ''; }
      });
      const totalH = frontH + retroH + 4; // +4px per il padding verticale (2px sopra e sotto)
      const placeholder = c.closest('.fig-img-placeholder');
      const cardW = c.closest('.fig-card')?.offsetWidth || 350;
      if (placeholder) placeholder.style.aspectRatio = (cardW / totalH).toFixed(3);
    } else {
      // Confermata affiancata (non entrambe orizzontali) — la marchiamo come riferimento
      // valido, così eventuali card impilate sulla stessa pagina possono leggerne la
      // larghezza reale invece di usare un numero scritto a mano
      c.dataset.confirmedRow = 'true';
    }
    delete _dualOrientationState[containerId];
  }
}

function openFilterLegendModal() {
  document.getElementById('filter-legend-modal').classList.remove('hidden');
}

function setRetroViewMode(mode) {
  _retroViewMode = mode;
  try { renderItems(); } catch(e) { console.error('renderItems (setRetroViewMode)', e); }
}

function toggleNoOfficialVariationFilter() {
  _noOfficialVariationFilter = !_noOfficialVariationFilter;
  currentItemPage = 1;
  try { renderItems(); } catch(e) { console.error('renderItems (toggleNoOfficialVariationFilter)', e); }
  try { if (bulkEditActive) renderBulkEditView(); } catch(e) { console.error('renderBulkEditView (toggleNoOfficialVariationFilter)', e); }
}

function toggleEbayFilter() {
  _ebayFilter = !_ebayFilter;
  currentItemPage = 1;
  try { renderItems(); } catch(e) { console.error('renderItems (toggleEbayFilter)', e); }
  try { if (bulkEditActive) renderBulkEditView(); } catch(e) { console.error('renderBulkEditView (toggleEbayFilter)', e); }
}

function toggleOwnedFilter(key) {
  // NON e' un radio puro come il filtro sul tipo, ed e' voluto.
  // Il tipo ha bisogno di un "Tutte", perche' non esiste uno stato neutro: un tipo
  // lo devi pur mostrare. Il possesso invece HA uno stato neutro naturale — nessun
  // filtro — e questi sono INTERRUTTORI: uno che hai acceso lo puoi spegnere.
  // Quindi niente terzo pulsante "Tutti": due "Tutti" nella stessa pagina, con
  // significati diversi, erano una domanda a cui l'utente non doveva rispondere.
  // Riclicchi quello acceso → torna 'all'. Ne accendi l'altro → il primo si spegne.
  _ownedFilter = (_ownedFilter === key) ? 'all' : key;
  currentItemPage = 1;
  try { renderItems(); } catch(e) { console.error('renderItems (toggleOwnedFilter)', e); }
  try { if (bulkEditActive) renderBulkEditView(); } catch(e) { console.error('renderBulkEditView (toggleOwnedFilter)', e); }
}

function toggleItemTypeFilter(type) {
  _itemTypeFilter = type; // comportamento radio puro: sempre uno solo attivo
  currentItemPage = 1;
  try { renderItems(); } catch(e) { console.error('renderItems (toggleItemTypeFilter)', e); }
  try { if (bulkEditActive) renderBulkEditView(); } catch(e) { console.error('renderBulkEditView (toggleItemTypeFilter)', e); }
}

// Calcola gli oggetti attualmente visibili per la serie/sezione corrente,
// applicando gli stessi filtri usati da griglia e vista tabellare (ricerca
// testuale, filtro "solo senza foto", filtro tipo). Funzione condivisa per
// evitare che i tre punti (griglia, tabella, Punteggio selezionati)
// finiscano per applicare criteri leggermente diversi tra loro.
// Applica una modifica a tutte le figurine attualmente filtrate con UNA
// SOLA scrittura del documento serie (invece di una scrittura separata per
// ogni figurina) — dato che il documento serie viene comunque riscritto
// per intero ad ogni modifica (Firestore non permette di sostituire un
// singolo elemento di un array per contenuto), fare 160 scritture in
// sequenza è sia lento sia a rischio: se anche una sola fallisce a metà
// (rete, dimensione del documento), il ciclo si ferma lì senza errore
// visibile, lasciando le figurine successive non modificate — esattamente
// il bug segnalato da Franco
async function _applyBulkFigurineUpdate(updateFn, confirmMsg, successMsg, skipConfirm) {
  const items = getCurrentlyFilteredItems();
  if (!items.length) { toast(currentLang === 'it' ? 'Nessun oggetto trovato con i filtri attuali' : 'No items found with the current filters', 'error'); return false; }
  if (!skipConfirm && !confirm(confirmMsg(items.length))) return false;
  const seriesList = getData('series', []);
  const sIdx = seriesList.findIndex(s => s.id === currentSeriesId);
  if (sIdx < 0) { toast(currentLang === 'it' ? 'Serie non trovata' : 'Series not found', 'error'); return false; }
  const series = seriesList[sIdx];
  series.items = series.items || [];
  const targetIds = new Set(items.map(i => i.id));
  series.items.forEach((it, idx) => {
    if (targetIds.has(it.id)) series.items[idx] = updateFn(it);
  });
  _recomputeSeriesCounts(series);
  try {
    await fsSave('series', series);
  } catch(e) {
    toast((currentLang === 'it' ? '❌ Salvataggio fallito, riprova: ' : '❌ Save failed, please retry: ') + e.message, 'error');
    return false;
  }
  let figs = getData('figurines', []);
  targetIds.forEach(id => {
    const flatIdx = figs.findIndex(x => x.id === id);
    const updated = series.items.find(x => x.id === id);
    if (flatIdx >= 0 && updated) figs[flatIdx] = updated;
  });
  _cache.figurines = figs;
  renderItems();
  if (bulkEditActive) renderBulkEditView();
  toast(successMsg(items.length), 'success');
  return true;
}

function openEbayBulkModal() {
  const items = getCurrentlyFilteredItems();
  if (!items.length) { toast(currentLang === 'it' ? 'Nessun oggetto trovato con i filtri attuali' : 'No items found with the current filters', 'error'); return; }
  document.getElementById('ebay-bulk-modal-desc').textContent = currentLang === 'it'
    ? `I valori inseriti verranno applicati a tutti i ${items.length} oggetti attualmente visualizzati.`
    : `These values will be applied to all ${items.length} currently displayed items.`;
  document.getElementById('ebay-bulk-price').value = '';
  document.getElementById('ebay-bulk-quantity').value = 1;
  document.getElementById('ebay-bulk-condition').value = 'new';
  document.getElementById('ebay-bulk-modal').classList.remove('hidden');
}

async function confirmEbayBulkApply() {
  const price = parseFloat(document.getElementById('ebay-bulk-price').value) || 0;
  const quantity = parseInt(document.getElementById('ebay-bulk-quantity').value) || 1;
  const condition = document.getElementById('ebay-bulk-condition').value;
  const ok = await _applyBulkFigurineUpdate(
    it => ({ ...it, forSale: true, price, quantity, condition }),
    null,
    n => currentLang === 'it' ? `✅ ${n} oggetti aggiornati per Ebay` : `✅ ${n} items updated for Ebay`,
    true
  );
  if (ok) closeModal('ebay-bulk-modal');
}

async function unmarkFilteredForSale() {
  await _applyBulkFigurineUpdate(
    it => ({ ...it, forSale: false, price: null, quantity: null, condition: null }),
    n => currentLang === 'it' ? `Togliere "Ebay" a tutti i ${n} oggetti attualmente visualizzati?` : `Remove "Ebay" from all ${n} currently displayed items?`,
    n => currentLang === 'it' ? `✅ "Ebay" tolto da ${n} oggetti` : `✅ "Ebay" removed from ${n} items`
  );
}

function getCurrentlyFilteredItems(opts) {
  const searchQ = (document.getElementById('items-search')?.value || '').toLowerCase().trim();
  const allFigs = getData('figurines', []);
  // getOwned() una volta sola, FUORI dal ciclo: dentro verrebbe richiamata per ogni
  // singolo oggetto della serie (368 volte, e per ogni ridisegno).
  const _own = (currentUser && _ownedFilter !== 'all') ? getOwned() : null;
  const _skipCat = !!(opts && opts.skipCategory); // gli specchietti chiedono i conteggi ignorando il filtro-categoria
  const _skipChangeType = !!(opts && opts.skipChangeType); // idem per lo specchietto Tipo di change
  return allFigs.filter(f => {
    if (f.seriesId !== currentSeriesId || f.section !== currentSection) return false;
    // Filtro per categoria (solo Retro), attivato cliccando un box nello specchietto risultati (v5.762)
    if (!_skipCat && _retroCategoryFilter !== null && currentSection === 'retros'
        && ((f.category || '').trim()) !== _retroCategoryFilter) return false;
    // Filtro per Tipo di change (solo Figurine): mostra SOLO i Change di quel tipo (v5.809)
    if (!_skipChangeType && _changeTypeFilter !== null && currentSection === 'figurines'
        && !(f.isChange && ((f.changeType || '').trim()) === _changeTypeFilter)) return false;
    if (_noPhotoFilter && f.img) return false;
    if (_own) {
      const ceLho = _own.includes(f.id);
      if (_ownedFilter === 'owned' && !ceLho) return false;
      if (_ownedFilter === 'missing' && ceLho) return false;
    }
    // UN SOLO BLOCCO PER TUTTE E QUATTRO LE SEZIONI (v5.711). Prima ce n'erano DUE —
    // uno per le Figurine e uno per i Retro — che definivano "base" in modo DIVERSO.
    // E' cosi' che nascono le doppie verita'. I tipi ora sono cinque e valgono
    // ovunque: QUALI di essi esistano in una sezione lo dicono i DATI, non un ramo del
    // codice. L'unica impossibilita' strutturale resta quella dei Retro (una variazione
    // e' il cambio del dietro, e un retro un dietro non ce l'ha) — ma non serve
    // scriverla qui: la form gia' impedisce di crearne (v5.707), quindi il filtro non
    // trovera' nulla da solo.
    if (_itemTypeFilter !== 'all') {
      const matchesType =
        (_itemTypeFilter === 'base' && !f.isVariation && !f.isUnofficialVariation && !f.isChange && !f.isPrintError) ||
        (_itemTypeFilter === 'variation' && f.isVariation) ||
        (_itemTypeFilter === 'unofficialVariation' && f.isUnofficialVariation) ||
        (_itemTypeFilter === 'anyVariation' && (f.isVariation || f.isUnofficialVariation)) ||
        (_itemTypeFilter === 'change' && f.isChange) ||
        // ERA UNA STRINGA, ORA E' UN FLAG. Il vecchio codice faceva:
        //     f.isChange && (f.changeType||'').toLowerCase().trim() === 'errore di stampa'
        // Bastava scrivere "Errori di stampa" al plurale in una serie perche' il filtro
        // smettesse di trovarli — in silenzio, senza modo di accorgersene.
        (_itemTypeFilter === 'printError' && f.isPrintError);
      if (!matchesType) return false;
    }
    if (currentSection === 'figurines' && _noOfficialVariationFilter) {
      if (f.isVariation || f.isUnofficialVariation || f.isChange) return false; // impone sempre "solo base", a prescindere dal filtro tipo
      const hasOfficialVariation = allFigs.some(x => x.baseFigurineId === f.id && x.isVariation);
      if (hasOfficialVariation) return false;
    }
    if (_ebayFilter && !f.forSale) return false;
    if (!searchQ) return true;
    return (f.name||'').toLowerCase().includes(searchQ) || String(f.number||'').includes(searchQ) || (f.subseries||'').toLowerCase().includes(searchQ) || (f.category||'').toLowerCase().includes(searchQ) || (f.subcategory||'').toLowerCase().includes(searchQ) || (f.fullName||'').toLowerCase().includes(searchQ);
  });
}

// v5.760/762 — Specchietti "Retro per categoria" nella pagina Retro. Due riquadri, entrambi
// visibili a TUTTI e solo nella sezione Retro, entrambi A SCOMPARSA (triangolo, chiusi al
// caricamento) e con lo STESSO titolo "Clicca qui per vedere...". Il totale si vede solo da aperto.
//   1) in alto (prima della ricerca): SOLO i Retro base (esclusi Change ed Errori di stampa),
//      foto d'insieme della serie, NON cambia con la ricerca. Box statici (non cliccabili).
//   2) nei risultati (sopra griglia/tabella): conteggi COERENTI con la ricerca/filtri in corso,
//      MA ignorando il filtro-categoria stesso (cosi' tutte le categorie restano visibili e si
//      passa dall'una all'altra). I box sono CLICCABILI: cliccando si applica quella categoria
//      come filtro (evidenziata); riclick sulla stessa, o il badge "✕", azzerano il filtro.
// Categorie in ordine alfabetico (localeCompare 'it'); categoria vuota = "(Senza categoria)".
function _retroCatCounts(items) {
  const map = new Map();
  for (const f of items) {
    const cat = (f.category || '').trim(); // valore REALE ('' = senza categoria)
    map.set(cat, (map.get(cat) || 0) + 1);
  }
  return [...map.entries()].sort((a, b) => a[0].localeCompare(b[0], 'it', { sensitivity: 'base' }));
}
function _retroCatLabel(cat) {
  return cat || (currentLang === 'it' ? '(Senza categoria)' : '(No category)');
}
// Riquadro a scomparsa. `clickable`: box cliccabili come filtro (riquadro risultati) o statici
// (riquadro in alto). `open`: stato aperto/chiuso. `toggleFn`: nome funzione toggle da chiamare.
function _retroCatPanelHTML(pairs, open, clickable, toggleFn) {
  const it = (currentLang === 'it');
  const total = pairs.reduce((s, p) => s + p[1], 0);
  // Titolo diverso per i due riquadri: quello dei risultati (cliccabile) FILTRA, quello in alto
  // (statico, solo Retro base) è un semplice conteggio.
  const title = clickable
    ? (it ? 'Clicca qui per filtrare i risultati della ricerca per categoria'
          : 'Click here to filter the search results by category')
    : (it ? 'Clicca qui per vedere i retro conteggiati per categoria'
          : 'Click here to see the retros counted by category');
  let header = `<div onclick="${toggleFn}()" style="cursor:pointer;display:flex;align-items:center;gap:0.5rem;flex-wrap:wrap;user-select:none;">`
    + `<span style="color:var(--accent);font-size:0.8rem;">${open ? '▼' : '▶'}</span>`
    + `<span style="font-size:0.85rem;font-weight:600;color:var(--text);">${title}</span>`
    + (open ? `<span style="color:var(--muted);font-size:0.82rem;font-weight:400;">· ${it ? 'totale' : 'total'} ${total}</span>` : '');
  // Badge del filtro attivo + reset — nel riquadro risultati, visibile SEMPRE (anche da chiuso)
  if (clickable && _retroCategoryFilter !== null) {
    header += `<span onclick="event.stopPropagation();clearRetroCategoryFilter()" title="${it ? 'Azzera il filtro per categoria' : 'Clear category filter'}" style="cursor:pointer;display:inline-flex;align-items:center;gap:0.3rem;background:var(--accent);color:var(--bg);border-radius:999px;padding:0.1rem 0.55rem;font-size:0.78rem;font-weight:600;">`
      + `${it ? 'filtro' : 'filter'}: ${esc(_retroCatLabel(_retroCategoryFilter))} ✕</span>`;
  }
  header += `</div>`;

  let body = '';
  if (open) {
    let chips;
    if (clickable) {
      _retroResultCatVals = pairs.map(p => p[0]); // valori reali, per l'onclick via indice
      chips = pairs.map(([cat, n], i) => {
        const active = _retroCategoryFilter !== null && _retroCategoryFilter === cat;
        const bg = active ? 'var(--accent)' : 'var(--card2)';
        const fg = active ? 'var(--bg)' : 'var(--text)';
        const nf = active ? 'var(--bg)' : 'var(--accent)';
        return `<span onclick="setRetroCategoryFilterByIndex(${i})" title="${it ? 'Filtra per questa categoria' : 'Filter by this category'}" style="cursor:pointer;display:inline-flex;align-items:center;gap:0.35rem;background:${bg};border:1px solid var(--border);border-radius:999px;padding:0.15rem 0.6rem;font-size:0.82rem;line-height:1.4;">`
          + `<span style="color:${fg};">${esc(_retroCatLabel(cat))}</span>`
          + `<span style="color:${nf};font-weight:700;">${n}</span></span>`;
      }).join('');
    } else {
      chips = pairs.map(([cat, n]) =>
        `<span style="display:inline-flex;align-items:center;gap:0.35rem;background:var(--card2);border:1px solid var(--border);border-radius:999px;padding:0.15rem 0.6rem;font-size:0.82rem;line-height:1.4;">`
        + `<span style="color:var(--text);">${esc(_retroCatLabel(cat))}</span>`
        + `<span style="color:var(--accent);font-weight:700;">${n}</span></span>`).join('');
    }
    body = `<div style="display:flex;flex-wrap:wrap;gap:0.4rem;margin-top:0.6rem;">${chips}</div>`;
  }
  return `<div style="background:var(--card);border:1px solid var(--border2);border-radius:var(--radius-lg);padding:0.8rem 0.9rem;">${header}${body}</div>`;
}
function renderRetroCategorySummaries() {
  const topEl = document.getElementById('retro-cat-summary-top');
  const resEl = document.getElementById('retro-cat-summary-results');
  const isRetro = currentSection === 'retros' && !!currentSeriesId;

  if (topEl) {
    if (!isRetro) { topEl.style.display = 'none'; topEl.innerHTML = ''; }
    else {
      // Solo Retro base della serie: la categoria conta una volta per Retro base, non per Change
      const baseRetros = getData('figurines', []).filter(f =>
        f.seriesId === currentSeriesId && f.section === 'retros' && !f.isChange && !f.isPrintError);
      const pairs = _retroCatCounts(baseRetros);
      topEl.innerHTML = pairs.length ? _retroCatPanelHTML(pairs, _retroCatTopOpen, false, 'toggleRetroCatTop') : '';
      topEl.style.display = pairs.length ? '' : 'none';
    }
  }

  if (resEl) {
    if (!isRetro) { resEl.style.display = 'none'; resEl.innerHTML = ''; }
    else {
      // skipCategory: i conteggi ignorano il filtro-categoria attivo, cosi' tutte le categorie
      // restano visibili e cliccabili; la griglia invece lo applica (vedi getCurrentlyFilteredItems)
      const pairs = _retroCatCounts(getCurrentlyFilteredItems({ skipCategory: true }));
      resEl.innerHTML = pairs.length ? _retroCatPanelHTML(pairs, _retroCatResultsOpen, true, 'toggleRetroCatResults') : '';
      resEl.style.display = pairs.length ? '' : 'none';
    }
  }
}
function toggleRetroCatTop() {
  _retroCatTopOpen = !_retroCatTopOpen;
  try { renderRetroCategorySummaries(); } catch(e) { console.error('toggleRetroCatTop', e); }
}
function toggleRetroCatResults() {
  _retroCatResultsOpen = !_retroCatResultsOpen;
  try { renderRetroCategorySummaries(); } catch(e) { console.error('toggleRetroCatResults', e); }
}
function setRetroCategoryFilterByIndex(i) {
  const cat = _retroResultCatVals[i];
  if (cat === undefined) return;
  _retroCategoryFilter = (_retroCategoryFilter === cat) ? null : cat; // riclick sulla stessa = azzera
  currentItemPage = 1;
  try { renderItems(); } catch(e) { console.error('renderItems (setRetroCategoryFilter)', e); }
  try { if (bulkEditActive) renderBulkEditView(); } catch(e) { console.error('renderBulkEditView (setRetroCategoryFilter)', e); }
}
function clearRetroCategoryFilter() {
  _retroCategoryFilter = null;
  currentItemPage = 1;
  try { renderItems(); } catch(e) { console.error('renderItems (clearRetroCategoryFilter)', e); }
  try { if (bulkEditActive) renderBulkEditView(); } catch(e) { console.error('renderBulkEditView (clearRetroCategoryFilter)', e); }
}

// v5.809 — Specchietti "Change per Tipo di change" nella sezione Figurine. Stesso schema dei "Retro
// per categoria": due riquadri a scomparsa (chiusi di default), visibili a TUTTI e solo nella sezione
// Figurine, solo se esistono Change.
//   1) in alto (prima della ricerca): TUTTI i Change della serie, panoramica non filtrata (box statici);
//   2) nei risultati (dopo i filtri, sopra la griglia): conteggi coerenti con ricerca/filtri in corso
//      (ma ignorando il filtro-tipo-change stesso). Box CLICCABILI: cliccando si mostrano solo i Change
//      di quel tipo; riclick sulla stessa, o il badge "✕", azzerano il filtro.
function _changeTypeCounts(items) {
  const map = new Map();
  for (const f of items) {
    if (!f.isChange) continue;
    const ct = (f.changeType || '').trim();
    map.set(ct, (map.get(ct) || 0) + 1);
  }
  return [...map.entries()].sort((a, b) => a[0].localeCompare(b[0], 'it', { sensitivity: 'base' }));
}
function _changeTypeLabel(ct) {
  return ct || (currentLang === 'it' ? '(Senza tipo)' : '(No type)');
}
function _changeTypePanelHTML(pairs, open, clickable, toggleFn) {
  const it = (currentLang === 'it');
  const total = pairs.reduce((s, p) => s + p[1], 0);
  const title = clickable
    ? (it ? 'Clicca qui per filtrare i risultati della ricerca per tipo di change'
          : 'Click here to filter the search results by change type')
    : (it ? 'Clicca qui per vedere i Change conteggiati per tipo'
          : 'Click here to see the Changes counted by type');
  let header = `<div onclick="${toggleFn}()" style="cursor:pointer;display:flex;align-items:center;gap:0.5rem;flex-wrap:wrap;user-select:none;">`
    + `<span style="color:var(--accent);font-size:0.8rem;">${open ? '▼' : '▶'}</span>`
    + `<span style="font-size:0.85rem;font-weight:600;color:var(--text);">${title}</span>`
    + (open ? `<span style="color:var(--muted);font-size:0.82rem;font-weight:400;">· ${it ? 'totale' : 'total'} ${total}</span>` : '');
  if (clickable && _changeTypeFilter !== null) {
    header += `<span onclick="event.stopPropagation();clearChangeTypeFilter()" title="${it ? 'Azzera il filtro per tipo di change' : 'Clear change type filter'}" style="cursor:pointer;display:inline-flex;align-items:center;gap:0.3rem;background:var(--accent);color:var(--bg);border-radius:999px;padding:0.1rem 0.55rem;font-size:0.78rem;font-weight:600;">`
      + `${it ? 'filtro' : 'filter'}: ${esc(_changeTypeLabel(_changeTypeFilter))} ✕</span>`;
  }
  header += `</div>`;

  let body = '';
  if (open) {
    let chips;
    if (clickable) {
      _changeTypeResultVals = pairs.map(p => p[0]);
      chips = pairs.map(([ct, n], i) => {
        const active = _changeTypeFilter !== null && _changeTypeFilter === ct;
        const bg = active ? 'var(--accent)' : 'var(--card2)';
        const fg = active ? 'var(--bg)' : 'var(--text)';
        const nf = active ? 'var(--bg)' : 'var(--accent)';
        return `<span onclick="setChangeTypeFilterByIndex(${i})" title="${it ? 'Filtra per questo tipo di change' : 'Filter by this change type'}" style="cursor:pointer;display:inline-flex;align-items:center;gap:0.35rem;background:${bg};border:1px solid var(--border);border-radius:999px;padding:0.15rem 0.6rem;font-size:0.82rem;line-height:1.4;">`
          + `<span style="color:${fg};">${esc(_changeTypeLabel(ct))}</span>`
          + `<span style="color:${nf};font-weight:700;">${n}</span></span>`;
      }).join('');
    } else {
      chips = pairs.map(([ct, n]) =>
        `<span style="display:inline-flex;align-items:center;gap:0.35rem;background:var(--card2);border:1px solid var(--border);border-radius:999px;padding:0.15rem 0.6rem;font-size:0.82rem;line-height:1.4;">`
        + `<span style="color:var(--text);">${esc(_changeTypeLabel(ct))}</span>`
        + `<span style="color:var(--accent);font-weight:700;">${n}</span></span>`).join('');
    }
    body = `<div style="display:flex;flex-wrap:wrap;gap:0.4rem;margin-top:0.6rem;">${chips}</div>`;
  }
  return `<div style="background:var(--card);border:1px solid var(--border2);border-radius:var(--radius-lg);padding:0.8rem 0.9rem;">${header}${body}</div>`;
}
function renderChangeTypeSummaries() {
  const topEl = document.getElementById('change-type-summary-top');
  const resEl = document.getElementById('change-type-summary-results');
  const isFig = currentSection === 'figurines' && !!currentSeriesId;
  if (topEl) {
    if (!isFig) { topEl.style.display = 'none'; topEl.innerHTML = ''; }
    else {
      const changes = getData('figurines', []).filter(f =>
        f.seriesId === currentSeriesId && f.section === 'figurines' && f.isChange);
      const pairs = _changeTypeCounts(changes);
      topEl.innerHTML = pairs.length ? _changeTypePanelHTML(pairs, _changeTypeTopOpen, false, 'toggleChangeTypeTop') : '';
      topEl.style.display = pairs.length ? '' : 'none';
    }
  }
  if (resEl) {
    if (!isFig) { resEl.style.display = 'none'; resEl.innerHTML = ''; }
    else {
      const pairs = _changeTypeCounts(getCurrentlyFilteredItems({ skipChangeType: true }));
      resEl.innerHTML = pairs.length ? _changeTypePanelHTML(pairs, _changeTypeResultsOpen, true, 'toggleChangeTypeResults') : '';
      resEl.style.display = pairs.length ? '' : 'none';
    }
  }
}
function toggleChangeTypeTop() {
  _changeTypeTopOpen = !_changeTypeTopOpen;
  try { renderChangeTypeSummaries(); } catch(e) { console.error('toggleChangeTypeTop', e); }
}
function toggleChangeTypeResults() {
  _changeTypeResultsOpen = !_changeTypeResultsOpen;
  try { renderChangeTypeSummaries(); } catch(e) { console.error('toggleChangeTypeResults', e); }
}
function setChangeTypeFilterByIndex(i) {
  const ct = _changeTypeResultVals[i];
  if (ct === undefined) return;
  _changeTypeFilter = (_changeTypeFilter === ct) ? null : ct; // riclick sulla stessa = azzera
  currentItemPage = 1;
  try { renderItems(); } catch(e) { console.error('renderItems (setChangeTypeFilter)', e); }
  try { if (bulkEditActive) renderBulkEditView(); } catch(e) { console.error('renderBulkEditView (setChangeTypeFilter)', e); }
}
function clearChangeTypeFilter() {
  _changeTypeFilter = null;
  currentItemPage = 1;
  try { renderItems(); } catch(e) { console.error('renderItems (clearChangeTypeFilter)', e); }
  try { if (bulkEditActive) renderBulkEditView(); } catch(e) { console.error('renderBulkEditView (clearChangeTypeFilter)', e); }
}

function renderItems() {
  const grid = document.getElementById('items-grid');
  if (!currentSeriesId || !grid || !currentSection) return;
  const searchQ = (document.getElementById('items-search')?.value || '').toLowerCase().trim();
  if (searchQ) currentItemPage = 1;

  // Render filtri tipo (sezione Figurine o Retro)
  renderItemTypeFilters();

  // Specchietto "Retro per categoria" (solo sezione Retro) — v5.760
  try { renderRetroCategorySummaries(); } catch(e) { console.error('renderRetroCategorySummaries', e); }

  // Specchietto "Change per Tipo di change" (solo sezione Figurine) — v5.809
  try { renderChangeTypeSummaries(); } catch(e) { console.error('renderChangeTypeSummaries', e); }

  // Selettore "Vista retro" — visibile solo nella sezione Figurine, per tutti
  const retroViewSelector = document.getElementById('retro-view-selector');
  if (retroViewSelector) {
    retroViewSelector.style.display = currentSection === 'figurines' ? 'flex' : 'none';
    const sel = document.getElementById('retro-view-mode-select');
    if (sel && sel.value !== _retroViewMode) sel.value = _retroViewMode;
  }

  // v5.828 — Toggle "Mostra nomi" / "Nascondi nomi", nello stile dei filtri (.toggle-btn-blue).
  // Compare SOLO sotto la soglia mobile, SOLO nella sezione Figurine e SOLO se la serie ha i
  // numeri: in una serie marcata "Non ha numeri" nascondere il nome lascerebbe la card muta.
  // Sul desktop resta display:none, quindi la barra dei controlli e' identica a prima.
  const figLabelSelector = document.getElementById('fig-label-selector');
  if (figLabelSelector) {
    const showIt = (currentSection === 'figurines') && _isMobileViewport() && _serieHaNumeri();
    figLabelSelector.style.display = showIt ? 'flex' : 'none';
    if (showIt) {
      const on = (_figLabelMode === 'full');
      const lab = on
        ? (currentLang === 'it' ? 'Nascondi nomi' : 'Hide names')
        : (currentLang === 'it' ? 'Mostra nomi' : 'Show names');
      figLabelSelector.innerHTML =
        `<button class="toggle-btn-blue ${on ? 'on' : ''}" onclick="toggleFigLabelMode()" title="${lab}"></button>` +
        `<span style="font-size:0.82rem;color:var(--text);">${lab}</span>`;
    } else {
      figLabelSelector.innerHTML = '';
    }
  }

  const allItems = getCurrentlyFilteredItems().sort((a,b) => {
    if (currentSection === 'figurines') {
      const allFigsForSort = getData('figurines', []);
      // Figurina di riferimento: se stessa se è base, altrimenti la figurina base collegata
      const refFig = f => {
        if (!f.isVariation && !f.isUnofficialVariation && !f.isChange) return f;
        return f.baseFigurineId ? allFigsForSort.find(x => x.id === f.baseFigurineId) : null;
      };
      const refA = refFig(a), refB = refFig(b);
      const numA = refA?.number, numB = refB?.number;
      if (numA && numB) {
        if (numA !== numB) return numA - numB;
      } else if (numA && !numB) {
        return -1; // i gruppi con numero vengono prima di quelli senza
      } else if (!numA && numB) {
        return 1;
      } else {
        // Nessuna delle due ha un numero: si raggruppa per Nome della figurina di riferimento
        const nameCmp = (refA?.name||'').localeCompare(refB?.name||'', 'it');
        if (nameCmp !== 0) return nameCmp;
      }

      // Stesso gruppo (stesso numero, o stesso nome se senza numero): figurina base, poi
      // variazioni ufficiali, poi non ufficiali, poi Change
      const typeRank = f => f.isChange ? 3 : f.isUnofficialVariation ? 2 : f.isVariation ? 1 : 0;
      const rankA = typeRank(a), rankB = typeRank(b);
      if (rankA !== rankB) return rankA - rankB;
      if (rankA === 0) {
        // Figurina base: eventuale sotto-ordinamento per sottoserie se il numero manca
        return (a.subseries||'').localeCompare(b.subseries||'');
      }
      if (rankA === 3) {
        // Change: per nome
        return (a.name||'').localeCompare(b.name||'', 'it');
      }
      // Variazioni (ufficiali o non ufficiali): per Retro (Categoria + Nome)
      const retroA = a.retroId ? allFigsForSort.find(x => x.id === a.retroId) : null;
      const retroB = b.retroId ? allFigsForSort.find(x => x.id === b.retroId) : null;
      const catCmp = (retroA?.category||'').localeCompare(retroB?.category||'', 'it');
      if (catCmp !== 0) return catCmp;
      const subcatCmp = (retroA?.subcategory||'').localeCompare(retroB?.subcategory||'', 'it');
      if (subcatCmp !== 0) return subcatCmp;
      return (retroA?.name||'').localeCompare(retroB?.name||'', 'it');
    }
    if (currentSection === 'retros') {
      const catCmp = (a.category||'').localeCompare(b.category||'', 'it');
      if (catCmp !== 0) return catCmp;
      const subcatCmp = (a.subcategory||'').localeCompare(b.subcategory||'', 'it');
      if (subcatCmp !== 0) return subcatCmp;
      return (a.name||'').localeCompare(b.name||'', 'it');
    }
    if (!a.number && !b.number) return (a.subseries||'').localeCompare(b.subseries||'');
    if (!a.number) return 1;
    if (!b.number) return -1;
    return a.number - b.number;
  });
  updateItemsCountDisplay(allItems);
  const owned = getOwned();
  // Barra di avanzamento RIMOSSA (v5.689, richiesta di Franco: "non mi e' mai
  // piaciuta"). Con lei sono spariti il titolo "La mia lista", il contenitore
  // detail-progress-toprow e l'etichetta: la riga di colonne in alto dice la stessa
  // cosa meglio, ripartita per categoria.
  // ATTENZIONE — due delle scritture che stavano qui NON avevano guardia:
  //     pw.style.display = ''
  //     document.getElementById('detail-progress-fill').style.width = ...
  // Tolti gli elementi, avrebbero fatto ESPLODERE l'apertura di OGNI serie. Non e'
  // un dettaglio: e' il motivo per cui questo blocco andava riscritto e non
  // ritagliato via a pezzi.
  const bulkBtns = document.getElementById('bulk-owned-btns');
  if (bulkBtns) bulkBtns.style.display = (currentUser && (currentSection === 'figurines' || currentSection === 'retros') && allItems.length) ? 'flex' : 'none';

  // Il messaggio di completamento resta, e continua a NON seguire i filtri:
  // si e' completi rispetto a tutta la SEZIONE, non a cio' che si e' appena
  // ritagliato con un filtro. Bastava altrimenti filtrare per variazioni,
  // possedere quelle tre, e vedersi annunciare "Hai tutte le figurine!" — un
  // complimento falso, corretto in v5.671.
  const itemsSerie = getData('figurines', []).filter(f => f.seriesId === currentSeriesId && f.section === currentSection);
  const completeMsg = document.getElementById('items-complete-msg');
  if (completeMsg) {
    const ownedCount = itemsSerie.filter(f => owned.includes(f.id)).length;
    const isComplete = currentUser && currentSection === 'figurines' && itemsSerie.length > 0 && ownedCount === itemsSerie.length;
    completeMsg.style.display = isComplete ? '' : 'none';
    if (isComplete) completeMsg.textContent = currentLang === 'it'
      ? '\u{1F389} Hai tutte le figurine in lista, per questa serie!'
      : '\u{1F389} You have all the stickers in your list, for this series!';
  }

  if (!allItems.length) {
    grid.innerHTML = `<div class="empty-state"><p class="empty-title" style="white-space:nowrap;">${currentLang === 'it' ? 'Nessun oggetto ancora!' : 'Nothing here yet!'}</p></div>`;
    document.getElementById('items-pagination').innerHTML = '';
    return;
  }
  // Pagination
  const totalPages = Math.ceil(allItems.length / getItemsPerPage());
  if (currentItemPage > totalPages) currentItemPage = totalPages;
  const start = (currentItemPage - 1) * getItemsPerPage();
  const items = allItems.slice(start, start + getItemsPerPage());
  // Elenco completo ordinato (tutte le pagine), usato per navigare avanti/indietro nel dettaglio
  _gridOrderedIds = allItems.map(f => f.id);
  // Pagination controls (top)
  const paginationTop = document.getElementById('items-pagination-top');
  const totalPagesTop = Math.ceil(allItems.length / getItemsPerPage());
  function paginationHTML(cur, tot, total) {
    if (tot <= 1) return '';
    const _ser = getData('series', []).find(s => s.id === currentSeriesId);
    const firstNum = currentSection === 'retros' ? 1 : _ser?.firstNumber;
    const sectionLabelLower = (getSectionLabel(currentSection) || (currentLang === 'it' ? 'oggetti' : 'items')).toLowerCase();
    let rangeStr = '';
    if (firstNum != null) {
      const from = firstNum + (cur - 1) * getItemsPerPage();
      const to = Math.min(firstNum + cur * getItemsPerPage() - 1, firstNum + total - 1);
      rangeStr = currentLang === 'it'
        ? ` &nbsp;|&nbsp; ${sectionLabelLower} ${from}..${to}`
        : ` &nbsp;|&nbsp; ${sectionLabelLower} ${from}..${to}`;
    }
    const label = currentLang === 'it'
      ? `Pagina ${cur} di ${tot}${rangeStr} &nbsp;|&nbsp; ${total} ${sectionLabelLower}`
      : `Page ${cur} of ${tot}${rangeStr} &nbsp;|&nbsp; ${total} total`;
    return `<div class="pag-row" style="display:flex;align-items:center;justify-content:center;gap:1rem;margin-bottom:1rem;flex-wrap:wrap;">
      ${cur > 1 ? `<button onclick="changeItemPage(1)" class="btn-secondary" style="padding:0.4rem 1rem;">⏮ ${currentLang === 'it' ? 'Prima' : 'First'}</button>` : ''}
      <button onclick="changeItemPage(${cur - 1})" ${cur === 1 ? 'disabled style="opacity:0.3;"' : ''} class="btn-secondary" style="padding:0.4rem 1rem;">◀ ${currentLang === 'it' ? 'Precedente' : 'Previous'}</button>
      <span class="pag-label" style="font-family:var(--font-ui);color:var(--text);font-size:0.9rem;">${label}</span>
      <button onclick="changeItemPage(${cur + 1})" ${cur === tot ? 'disabled style="opacity:0.3;"' : ''} class="btn-secondary" style="padding:0.4rem 1rem;">${currentLang === 'it' ? 'Successiva' : 'Next'} ▶</button>
      ${cur < tot ? `<button onclick="changeItemPage(${tot})" class="btn-secondary" style="padding:0.4rem 1rem;">${currentLang === 'it' ? 'Ultima' : 'Last'} ⏭</button>` : ''}
    </div>`;
  }
  if (paginationTop) paginationTop.innerHTML = paginationHTML(currentItemPage, totalPagesTop, allItems.length);

  if (currentSection === 'retros' || currentSection === 'figurines') {
    const useFlexForWideMode = currentSection === 'figurines' && _retroViewMode === 'destra-piena';
    if (useFlexForWideMode) {
      grid.style.display = 'flex';
      grid.style.flexWrap = 'wrap';
      grid.style.gridTemplateColumns = '';
    } else {
      grid.style.display = '';
      grid.style.flexWrap = '';
      grid.style.gridTemplateColumns = currentSection === 'retros' ? 'repeat(5, 1fr)' : '';
    }
    grid.style.width = 'min(1800px, 96vw)';
    grid.style.maxWidth = '1800px';
    grid.style.marginLeft = '50%';
    grid.style.marginRight = '0';
    grid.style.transform = 'translateX(-50%)';
  } else {
    grid.style.display = '';
    grid.style.flexWrap = '';
    grid.style.gridTemplateColumns = '';
    grid.style.width = '';
    grid.style.maxWidth = '';
    grid.style.marginLeft = '';
    grid.style.marginRight = '';
    grid.style.transform = '';
  }

  // v5.758 — Retro nella card: la prima riga antepone "Categoria - " al nome, TRANNE quando il
  // nome comincia già con la categoria (decisione per singolo retro; ex flag di serie
  // retroNameHasCategory, rimosso). Stessa regola del Nome completo (_retroNameStartsWithCategory).

  grid.innerHTML = items.map(f => {
    const isOwned = owned.includes(f.id);
    const icon = SECTION_ICONS[currentSection];
    // Una Variazione/Change è essenzialmente un collegamento (Figurina base + Retro): se non ha
    // una foto propria, riusiamo quella della figurina base collegata, senza duplicare il dato
    let displayImg = f.img;
    let baseFigForImg = null;
    if (!displayImg && currentSection === 'figurines' && (f.isVariation || f.isUnofficialVariation || f.isChange) && f.baseFigurineId) {
      baseFigForImg = getData('figurines', []).find(x => x.id === f.baseFigurineId);
      if (baseFigForImg?.img) displayImg = baseFigForImg.img;
    }
    // Per le Variazioni (non Change) e per le figurine base, se sono disponibili sia la foto
    // propria (fronte) sia quella del Retro collegato, le mostriamo impilate verticalmente
    // nella stessa altezza totale del box: colpo d'occhio immediato per riconoscerle nella
    // griglia. Esclusi i Change, che di solito differiscono nella parte frontale, non nel retro
    let imgHTML;
    let hasWidePair = false;
    let _cardNoPhoto = false;  // v5.873
    const isBaseFig = currentSection === 'figurines' && !f.isVariation && !f.isUnofficialVariation && !f.isChange;
    // v5.786 — un Change può avere un proprio Retro; se non ce l'ha, usa quello della figurina base
    // (così sulla card mostra comunque il retro della base). retro effettivo = proprio || della base.
    const _baseForChange = (f.isChange && f.baseFigurineId) ? (baseFigForImg || getData('figurines', []).find(x => x.id === f.baseFigurineId)) : null;
    const _effRetroId = f.isChange ? (f.retroId || _baseForChange?.retroId || null) : f.retroId;
    // v5.853 — su telefono, col filtro "Figurine set base" attivo si mostra SOLO IL FRONTE.
    // Sono tutte figurine base, quindi affiancare il retro dimezza il fronte senza aggiungere
    // informazione. Fuori da quel filtro, e sul desktop, la coppia fronte+retro resta.
    // NB: qui NON si puo' usare _mobileFigCard, che e' dichiarato piu' sotto (con const, quindi
    // in temporal dead zone: leggerlo prima non da' undefined, lancia). Era il bug della v5.854:
    // ogni card falliva, la griglia restava col segnaposto "nessun risultato" gia' presente in
    // index.html, mentre il conteggio - calcolato prima - diceva giustamente che i risultati
    // c'erano. Le condizioni si ricalcolano qui dai loro ingredienti.
    const _soloFronte = _isMobileViewport() && currentSection === 'figurines' && _itemTypeFilter === 'base';
    if (!_soloFronte && (((f.isVariation || f.isUnofficialVariation) && f.baseFigurineId && f.retroId) || (f.isChange && f.baseFigurineId && _effRetroId) || (isBaseFig && f.retroId))) {
      const baseFigDual = isBaseFig ? f : (baseFigForImg || getData('figurines', []).find(x => x.id === f.baseFigurineId));
      const retroFigDual = getData('figurines', []).find(x => x.id === _effRetroId);
      if (baseFigDual?.img && retroFigDual?.img) {
        if (_retroViewMode === 'destra-piena') hasWidePair = true;
        if (_retroViewMode === 'destra') {
          imgHTML = `<div style="width:100%;height:100%;position:absolute;top:0;left:0;display:flex;flex-direction:row;">
            <div style="flex:1;min-height:0;overflow:hidden;"><img src="${cloudinaryUrl(baseFigDual.img)}" style="width:100%;height:100%;object-fit:contain;padding:2px;"></div>
            <div style="flex:1;min-height:0;overflow:hidden;border-left:1px solid var(--border);"><img src="${cloudinaryUrl(retroFigDual.img)}" style="width:100%;height:100%;object-fit:contain;padding:2px;"></div>
          </div>`;
        } else if (_retroViewMode === 'dinamico') {
          const dualId = 'dual-' + f.id;
          imgHTML = `<div id="${dualId}" style="width:100%;height:100%;position:absolute;top:0;left:0;display:flex;flex-direction:column;">
            <div style="flex:1;min-height:0;overflow:hidden;"><img src="${cloudinaryUrl(baseFigDual.img)}" style="width:100%;height:100%;object-fit:contain;padding:2px;"></div>
            <div style="flex:1;min-height:0;overflow:hidden;border-top:1px solid var(--border);"><img src="${cloudinaryUrl(retroFigDual.img)}" style="width:100%;height:100%;object-fit:contain;padding:2px;" onload="if(this.naturalHeight>this.naturalWidth){const c=document.getElementById('${dualId}');if(c){c.style.flexDirection='row';const rd=c.children[1];rd.style.borderTop='none';rd.style.borderLeft='1px solid var(--border)';}}"></div>
          </div>`;
        } else if (_retroViewMode === 'fronte-grande') {
          const dualId2 = 'dualf-' + f.id;
          imgHTML = `<div id="${dualId2}" style="width:100%;height:100%;position:absolute;top:0;left:0;display:flex;flex-direction:column;">
            <div style="flex:1;min-height:0;overflow:hidden;"><img src="${cloudinaryUrl(baseFigDual.img)}" style="width:100%;height:100%;object-fit:contain;padding:2px;" onload="if(this.naturalHeight>this.naturalWidth){const c=document.getElementById('${dualId2}');if(c){c.style.flexDirection='row';const rd=c.children[1];rd.style.borderTop='none';rd.style.borderLeft='1px solid var(--border)';}}"></div>
            <div style="flex:1;min-height:0;overflow:hidden;border-top:1px solid var(--border);"><img src="${cloudinaryUrl(retroFigDual.img)}" style="width:100%;height:100%;object-fit:contain;padding:2px;"></div>
          </div>`;
        } else if (_retroViewMode === 'destra-piena') {
          // Fronte+Retro mai rimpiccioliti rispetto alla dimensione "piena" che avrebbero in
          // metà di una card normale (metà larghezza se affiancate, metà altezza se impilate).
          // Si parte affiancate (card doppia in larghezza, altezza normale); se poi risultano
          // ENTRAMBE orizzontali, si passa a impilate (card normale in larghezza, doppia in
          // altezza) — la forma della card cambia dinamicamente, dato che l'orientamento si
          // scopre solo al caricamento delle foto
          const dualId5 = 'dualp-' + f.id;
          imgHTML = `<div id="${dualId5}" style="width:100%;height:100%;position:absolute;top:0;left:0;display:flex;flex-direction:row;">
            <div style="flex:1;min-height:0;overflow:hidden;"><img src="${cloudinaryUrl(baseFigDual.img)}" style="width:100%;height:100%;object-fit:contain;padding:2px;" onload="_checkBothOrientationForStack('${dualId5}','front',this.naturalHeight>this.naturalWidth,this.naturalWidth,this.naturalHeight)"></div>
            <div style="flex:1;min-height:0;overflow:hidden;border-left:1px solid var(--border);"><img src="${cloudinaryUrl(retroFigDual.img)}" style="width:100%;height:100%;object-fit:contain;padding:2px;" onload="_checkBothOrientationForStack('${dualId5}','retro',this.naturalHeight>this.naturalWidth,this.naturalWidth,this.naturalHeight)"></div>
          </div>`;
        } else {
          // 'sotto' (default)
          imgHTML = `<div style="width:100%;height:100%;position:absolute;top:0;left:0;display:flex;flex-direction:column;">
            <div style="flex:1;min-height:0;overflow:hidden;"><img src="${cloudinaryUrl(baseFigDual.img)}" style="width:100%;height:100%;object-fit:contain;padding:2px;"></div>
            <div style="flex:1;min-height:0;overflow:hidden;border-top:1px solid var(--border);"><img src="${cloudinaryUrl(retroFigDual.img)}" style="width:100%;height:100%;object-fit:contain;padding:2px;"></div>
          </div>`;
        }
      }
    }
    if (!imgHTML) {
      // v5.872 — quando manca la foto, un placeholder GRIGIO PIENO "FOTO NON DISPONIBILE" che
      // riempie tutto il riquadro come una foto vera: cosi' il box immagine ha sempre area piena
      // e le card restano uniformi (prima il fallback era un box piccolo centrato che lasciava
      // spazio vuoto attorno).
      _cardNoPhoto = !displayImg;
      imgHTML = displayImg ? `<img src="${cloudinaryUrl(displayImg)}" style="width:100%;height:100%;object-fit:contain;position:absolute;top:0;left:0;border-radius:0;padding:4px;">` : `<div class="fig-noimg">${currentLang === 'it' ? 'FOTO NON DISPONIBILE' : 'PHOTO NOT AVAILABLE'}</div>`;
    }
    // Il badge distingue ora le due variazioni, invece di accorparle in un
    // generico "Variazione" che non diceva quale delle due fosse — proprio la sola
    // informazione che serviva saperne.
    // Su DUE RIGHE, e con l'ordine delle parole giusto per ciascuna lingua:
    //   IT: "Variazione / ufficiale"  (aggettivo dopo)
    //   EN: "Official / variation"    (aggettivo prima)
    // Tradurre riga per riga avrebbe prodotto "Variation / official", che in
    // inglese non si dice.
    let typeBadgeHTML = '';
    // BADGE ANCHE NEI RETRO (v5.706). Franco: "servono anche sui Retro: anche li'
    // abbiamo le stesse tipologie". Vero — e i contatori della serie le contavano
    // gia' (gVar, gUnoff): erano solo i badge a fermarsi alle Figurine.
    // La condizione era `currentSection === 'figurines'`, e nei Retro NON compariva
    // nessun badge: il tipo lo diceva solo la scritta in basso.
    if (true) {   // v5.711: i badge valgono in TUTTE E QUATTRO le sezioni
      const it = currentLang === 'it';
      let r1 = '', r2 = '', cls = '';
      // Nei RETRO esistono solo due tipi: set base e Change. Le variazioni non
      // possono esistere (una variazione e' il cambio del dietro; un retro non ha un
      // dietro). I due rami qui sotto sono percio' inerti nei retro — restano perche'
      // la stessa funzione serve entrambe le sezioni.
      if (currentSection === 'figurines' && f.isVariation) {
        r1 = it ? 'Variazione' : 'Official';
        r2 = it ? 'ufficiale'  : 'variation';
        cls = 'fig-badge-official';
      } else if (currentSection === 'figurines' && f.isUnofficialVariation) {
        r1 = it ? 'Variazione'   : 'Unofficial';
        r2 = it ? 'non ufficiale': 'variation';
        cls = 'fig-badge-unofficial';
      } else if (f.isPrintError) {
        // il quinto tipo (v5.711). Due righe, come le variazioni: "Errore" / "di stampa"
        r1 = it ? 'Errore'    : 'Print';
        r2 = it ? 'di stampa' : 'error';
        cls = 'fig-badge-printerror';
      } else if (f.isChange) {
        r1 = 'Change';
        cls = 'fig-badge-change';
      }
      if (r1) {
        typeBadgeHTML = `<div class="fig-owned-badge ${cls}">${esc(r1)}${r2 ? '<br>' + esc(r2) : ''}</div>`;
      }
    }
    const adminBtns = currentUser?.isAdmin ? `<div style="position:absolute;top:8px;left:8px;display:flex;gap:4px;"><button class="tbl-btn tbl-btn-edit" style="font-size:1.05rem;font-weight:bold;line-height:1;padding:3px 8px;" title="${currentLang === 'it' ? 'Modifica' : 'Edit'}" onclick="event.stopPropagation();openAddItemModal('${f.id}')">&#9998;</button><button class="tbl-btn tbl-btn-edit" style="font-size:1.05rem;font-weight:bold;line-height:1;padding:3px 8px;" title="${currentLang === 'it' ? 'Clona' : 'Clone'}" onclick="event.stopPropagation();cloneFigurine('${f.id}')">&#10697;</button></div>` : '';
    const reportBtn = currentUser && !currentUser.isAdmin ? `<button onclick="event.stopPropagation();openSegnalazioneModal('${f.id}')" title="${currentLang === 'it' ? 'Segnala qualcosa all\'amministratore per questa figurina' : 'Report something to the administrator about this sticker'}" style="font-size:0.65rem;padding:1px 6px;border-radius:6px;border:1px solid rgba(255,255,255,0.15);background:transparent;color:var(--muted);cursor:pointer;">🚩</button>` : '';
    const descHTML = f.desc ? `<div class="fig-desc" style="font-size:0.78rem;color:var(--muted);margin-top:4px;">${f.desc.substring(0,60)}${f.desc.length>60?'...':''}</div>` : '';
    const scoreHTML = (f.score && f.score > 0) ? `<div style="font-size:0.78rem;color:var(--accent);margin-top:4px;">⭐ ${f.score} pt</div>` : '';
    const sizeHTML = f.size ? `<div style="font-size:0.78rem;color:var(--muted);margin-top:2px;">📏 ${f.size}</div>` : '';
    // v5.804 — Franco: la sottoserie NON sostituisce più il numero sulla card. Il numero resta in
    // etichetta (#N) e la sottoserie va su una riga a parte, nello stesso punto/stile in cui i Retro
    // mostrano la loro categoria (vedi subseriesHTML poco sotto).
    const figLabel = f.number ? `#${f.number}` : '';
    const catParts = [f.category, f.subcategory].map(v => (v||'').trim()).filter(Boolean);
    // Prima riga (nome): se la serie NON dichiara che il nome del retro contiene già la
    // categoria, anteponiamo "Categoria - ". Seconda riga: la Categoria (col Sottocategoria
    // se presente) come sempre.
    const catPrefix = (currentSection === 'retros' && !_retroNameStartsWithCategory(f) && (f.category||'').trim()) ? esc(f.category.trim()) + ' - ' : '';
    const categoryHTML = (currentSection === 'retros' && catParts.length) ? `<div style="font-size:0.78rem;color:var(--muted);">${catParts.join(' · ')}</div>` : '';
    // v5.804 — riga Sottoserie per le Figurine, nello stesso punto/stile della categoria dei Retro.
    const subseriesHTML = (currentSection === 'figurines' && f.subseries) ? `<div style="font-size:0.78rem;color:var(--muted);">${esc(f.subseries)}</div>` : '';
    // v5.765 — Card Retro: PRIMA riga = Categoria (con Sottocategoria se presente), SECONDA riga
    // = Nome. Sostituisce il vecchio schema (prima riga "Categoria - Nome", seconda la categoria).
    // Le Figurine restano invariate. Il vecchio prefisso catPrefix qui per i Retro non serve piu'.
    const isRetroCard = currentSection === 'retros';
    // v5.829 — solo telefono, solo card Figurina: PRIMA riga = numero + punteggio (stesso corpo),
    // SECONDA riga = nome (quando i nomi sono mostrati). Il punteggio esce quindi dalla sua riga
    // a se' piu' in basso, che su una card da 85px era una riga sprecata.
    const _mobileFigCard = _isMobileViewport() && !isRetroCard;
    const scoreInlineHTML = (_mobileFigCard && f.score && f.score > 0)
      ? `<span class="fig-score-inline">⭐ ${f.score} pt</span>` : '';
    const figNameInner = isRetroCard
      ? esc(catParts.length ? catParts.join(' · ') : (currentLang === 'it' ? '(senza categoria)' : '(no category)'))
      : (_mobileFigCard
          ? `<span class="fig-number" style="font-size:1.05rem;">${figLabel}</span>${scoreInlineHTML}` +
            (_figLabelOnlyNumber() ? '' : `<div class="fig-name-line">${catPrefix}${f.name}</div>`)
          : `<span class="fig-number" style="font-size:1.05rem;">${figLabel}</span>${figLabel ? ' ' : ''}${catPrefix}${f.name}`);
    // v5.780 — se il Nome del Retro è IDENTICO alla Categoria (caso raro), la riga del Nome è
    // ridondante rispetto alla prima riga (la Categoria): la omettiamo, mostrando solo la Categoria.
    // Confronto esatto (trim, case-insensitive); non usa _retroNameStartsWithCategory (che è "inizia
    // con", troppo largo qui). La Sottocategoria non entra nel confronto: si guarda solo la Categoria.
    const _retroNameEqualsCategory = (f.name || '').trim() !== '' &&
      (f.name || '').trim().toLowerCase() === (f.category || '').trim().toLowerCase();
    const retroNameLineHTML = (isRetroCard && f.name && !_retroNameEqualsCategory)
      ? `<div style="font-size:0.9rem;color:var(--text);margin-top:1px;">${esc(f.name || '')}</div>`
      : '';
    const imgAspectRatio = currentSection === 'retros' ? '1.6' : '1';
    // LA SCRITTA DEL TIPO VIVE SOLO NEI RETRO (v5.705).
      // Nelle FIGURINE era ridondante: il badge in alto a destra dice gia' il tipo, ed
      // e' piu' visibile — Franco lo aveva fatto introdurre proprio per questo. Due
      // volte la stessa informazione sulla stessa card e' una di troppo.
      // NEI RETRO INVECE IL BADGE NON ESISTE (typeBadgeHTML si costruisce solo se
      // currentSection === 'figurines'): li' questa scritta e' l'UNICA cosa che dice
      // il tipo, e per giunta mostra anche il changeType, che il badge non mostra
      // nemmeno nelle Figurine. Toglierla ovunque avrebbe CANCELLATO
      // un'informazione dai Retro, in silenzio.
      // Il set base non ha badge, e non deve averlo: il badge segnala un'ECCEZIONE.
      // La sua assenza dice "questa e' base" — non e' un'omissione, e' un'affermazione.
      // Ne segue, gratis, il comportamento che Franco voleva ottenere con una regola:
      // col filtro "Solo set base" acceso, in pagina non compare nessun badge.
      // Ora che anche i Retro hanno il badge, la scritta NON deve ripetere "Change":
      // lo dice gia' il badge rosa. Resta solo per il DETTAGLIO che il badge non puo'
      // contenere — il changeType ("Errore di stampa", "Fronte"...). Se non c'e'
      // changeType, non c'e' nulla da aggiungere e la scritta sparisce.
      // v5.767/768 — In fondo alla card Retro (alla riga del toggle "Mia lista"), a sinistra: il
      // Tipo di change per i Change, OPPURE il Tipo di errore di stampa per gli Errori di stampa (i
      // due sono mutuamente esclusivi), in MAIUSCOLO. v5.768: ciascuno nel COLORE DEL SUO TIPO, in
      // continuita' col color code — Change = var(--type-change) (rosa), Errore di stampa =
      // var(--type-printerror). Base/senza tipo: separatore vuoto.
      // v5.783 — indicatore di tipo in fondo alla card (riga del toggle "Mia lista"): ora ANCHE per
      // le FIGURINE Change/Errore di stampa, non più solo per i Retro. changeType (colore --type-change)
      // per i Change; printErrorType (colore --type-printerror) per gli Errori di stampa. Per le figurine
      // Change il tipo è stato tolto dal testo principale (era ": TIPO" in v5.779) e portato qui, come i Retro.
      const _cardIsChg = f.isChange && f.changeType;
      const _cardIsPE  = f.isPrintError && f.printErrorType;
      const _cardTypeTxt = _cardIsChg ? f.changeType : (_cardIsPE ? f.printErrorType : '');
      const _cardTypeColor = _cardIsChg ? 'var(--type-change)' : (_cardIsPE ? 'var(--type-printerror)' : 'var(--text)');
      const typeIndicatorHTML = _cardTypeTxt
        ? `<div style="font-size:0.82rem;color:${_cardTypeColor};font-weight:600;">${esc((_cardTypeTxt || '').toUpperCase())}</div>`
        : '<div></div>';
    // v5.828 — col filtro "Solo base" attivo, su telefono NON si mostra il nome del retro
  // associato: sono tutte figurine base, quindi la riga e' ridondante e ruba spazio.
  // Guardia di viewport: sul desktop il nome del retro resta sempre.
  const _hideRetroName = _isMobileViewport() && _itemTypeFilter === 'base';
  const retroNameHTML = (currentSection === 'figurines' && !f.isChange && f.retroId && !_hideRetroName)
      ? (() => { const r = getData('figurines', []).find(x => x.id === f.retroId); return r ? `<div style="font-size:0.78rem;color:var(--muted);">${r.name}</div>` : ''; })()
      : '';
    const isWideFlexMode = currentSection === 'figurines' && _retroViewMode === 'destra-piena';
    const cardSpanStyle = isWideFlexMode
      ? (hasWidePair ? 'cursor:pointer;flex:0 0 350px;' : 'cursor:pointer;flex:0 0 247px;')
      : 'cursor:pointer;';
    const finalAspectRatio = hasWidePair ? '2' : imgAspectRatio;
    return `<div class="fig-card${_cardNoPhoto ? ' fig-card--noimg' : ''}" onclick="if(!event.target.closest('button'))openFigDetail('${f.id}')" style="${cardSpanStyle}">
      ${_mobileFigCard ? `<div class="fig-badge-row">${typeBadgeHTML}</div>` : ''}
      <div class="fig-img-placeholder" style="aspect-ratio:${finalAspectRatio};display:flex;align-items:center;justify-content:center;font-size:3rem;background:linear-gradient(135deg,var(--bg2),var(--card2));position:relative;">
        ${imgHTML}${_mobileFigCard ? '' : typeBadgeHTML}${adminBtns}
      </div>
      <div class="fig-body">
        <div class="fig-name">${figNameInner}</div>
        ${isRetroCard ? retroNameLineHTML : subseriesHTML}
        ${retroNameHTML}
        ${descHTML}
        ${sizeHTML}
        ${_mobileFigCard ? '' : `<div style="display:flex;align-items:center;gap:0.5rem;">${scoreHTML}</div>`}
        <div class="fig-actions">
        ${typeIndicatorHTML}
        <div class="fig-act fig-act-mylist"><span class="fig-act-label">${t('owned.toggle')}</span><button class="owned-btn ${isOwned?'on':''}" title="${isOwned ? (currentLang==='it'?'\u00c8 nella tua lista \u2014 clicca per toglierla':'In your list \u2014 click to remove') : (currentLang==='it'?'Aggiungi alla tua lista':'Add to your list')}" onclick="event.stopPropagation();toggleOwned('${f.id}')">\u2713</button></div>
        ${(currentUser && !currentUser.isAdmin) ? `<div class="fig-act fig-act-wishlist"><span class="fig-act-label">${currentLang==='it'?'Ciò che cerco':'Looking for'}</span><button class="wishlist-heart-btn" data-wishlist-id="${f.id}" title="${currentLang==='it'?(_wishlist.includes(f.id)?'Togli da &quot;Ciò che cerco&quot;':'Aggiungi a &quot;Ciò che cerco&quot;'):(_wishlist.includes(f.id)?'Remove from &quot;What I\'m looking for&quot;':'Add to &quot;What I\'m looking for&quot;')}" style="background:${_wishlist.includes(f.id)?'rgba(var(--danger-rgb),0.15)':'transparent'};border:1px solid ${_wishlist.includes(f.id)?'var(--danger)':'rgba(255,255,255,0.15)'};color:${_wishlist.includes(f.id)?'var(--danger)':'var(--muted)'};border-radius:8px;padding:3px 8px;cursor:pointer;font-size:1rem;line-height:1;position:relative;z-index:2;">${_wishlist.includes(f.id)?'❤️':'♡'}</button></div>` : ''}
        ${reportBtn ? `<div class="fig-act fig-act-report"><span class="fig-act-label">${currentLang==='it'?'Errore?':'Error?'}</span>${reportBtn}</div>` : ''}
        </div>
      </div>
    </div>`;
  }).join('');

  // Event delegation per i pulsanti cuore wishlist: rimossa la vecchia istanza e aggiunta nuova
  if (grid._wishlistHandler) grid.removeEventListener('click', grid._wishlistHandler);
  grid._wishlistHandler = function(e) {
    const btn = e.target.closest('.wishlist-heart-btn');
    if (btn) {
      e.stopPropagation();
      toggleWishlist(btn.dataset.wishlistId);
    }
  };
  grid.addEventListener('click', grid._wishlistHandler);

  // Render pagination controls (bottom)
  const paginationEl = document.getElementById('items-pagination');
  if (paginationEl) {
    paginationEl.innerHTML = paginationHTML(currentItemPage, Math.ceil(allItems.length / getItemsPerPage()), allItems.length);
    paginationEl.style.marginTop = '1.5rem';
  }
}

function changeItemPage(page) {
  const allItems = getData('figurines', []).filter(f => f.seriesId === currentSeriesId && f.section === currentSection);
  const totalPages = Math.ceil(allItems.length / getItemsPerPage());
  if (page < 1 || page > totalPages) return;
  currentItemPage = page;
  renderItems();
  // v5.868 — Franco: dopo il cambio pagina il cursore torna in alto, ma NON in cima assoluta
  // (dove si vedono ricerca e filtri): si ferma sulla riga dei pulsanti di paginazione, così la
  // prima cosa visibile è quella riga e SUBITO SOTTO la prima riga di figurine. Ancoriamo a
  // #items-pagination-top e sottraiamo l'ingombro di navbar + banner (misurati, non a mano, così
  // restano giusti se cambiano). requestAnimationFrame: aspetta che il nuovo layout sia calcolato.
  requestAnimationFrame(() => {
    const anchor = document.getElementById('items-pagination-top') || document.getElementById('items-grid');
    if (!anchor) { window.scrollTo({ top: 0, behavior: 'smooth' }); return; }
    let offset = 8;
    const nav = document.getElementById('navbar');
    if (nav) offset += nav.offsetHeight;
    const banner = document.getElementById('construction-banner');
    if (banner && getComputedStyle(banner).display !== 'none') offset += banner.offsetHeight;
    const y = anchor.getBoundingClientRect().top + window.scrollY - offset;
    window.scrollTo({ top: Math.max(0, y), behavior: 'smooth' });
  });
}

// renderFigurines kept as alias for admin panel compatibility
function renderFigurines() { if (currentSection) renderItems(); }

let editingFigImgFileSave = null;
function handleFigImg(e) {
  const file = e.target.files[0]; if (!file) return;
  editingFigImgFileSave = file;
  const reader = new FileReader();
  reader.onload = ev => {
    const pr = document.getElementById('fig-img-preview');
    pr.src = ev.target.result; pr.style.display = 'block';
  };
  reader.readAsDataURL(file);
}

function handleFigEbayImg(e) {
  const file = e.target.files[0]; if (!file) return;
  editingFigEbayImgFileSave = file;
  const reader = new FileReader();
  reader.onload = ev => {
    const pr = document.getElementById('fig-ebay-img-preview');
    pr.src = ev.target.result; pr.style.display = 'block';
  };
  reader.readAsDataURL(file);
}

let _savingFigurine = false;
async function saveFigurine() {
  if (_savingFigurine) return; // evita duplicati da doppio click o click ripetuto durante il salvataggio
  _savingFigurine = true;
  const btn = document.querySelector('#add-fig-modal button[onclick="saveFigurine()"]');
  if (btn) btn.disabled = true;
  try {
    await _saveFigurineInner();
  } finally {
    _savingFigurine = false;
    if (btn) btn.disabled = false;
  }
}
async function _saveFigurineInner() {
  const number = document.getElementById('fig-number-input').value;
  const noNumber = document.getElementById('fig-no-number-input')?.checked || false;
  let name = document.getElementById('fig-name-input').value.trim();
  const desc = document.getElementById('fig-desc-input').value.trim();
  const score = parseInt(document.getElementById('fig-score-input').value) || 0;
  const subseries = document.getElementById('fig-subseries-input')?.value.trim() || '';
  const size = document.getElementById('fig-size-input')?.value.trim() || '';
  const category = document.getElementById('fig-category-input')?.value.trim() || '';
  const subcategory = document.getElementById('fig-subcategory-input')?.value.trim() || '';
  // NEI RETRO I FLAG DI VARIAZIONE SONO SEMPRE FALSI, comunque sia la casella.
  // Nasconderla non basta: se e' rimasta spuntata da una modifica precedente, il suo
  // valore verrebbe letto lo stesso. Qui la regola diventa un fatto.
  const _retroNoVar = (currentSection === 'retros');
  const isVariation = _retroNoVar ? false : (document.getElementById('fig-is-variation-input')?.checked || false);
  const isUnofficialVariation = _retroNoVar ? false : (document.getElementById('fig-is-unofficial-variation-input')?.checked || false);
  // ERRORE DI STAMPA (v5.711): quinto tipo, valido in TUTTE E QUATTRO le sezioni.
  // Prima non era un tipo, era una STRINGA: il filtro cercava changeType === "errore
  // di stampa". Bastava scriverlo al plurale in una serie perche' smettesse di
  // trovarlo, in silenzio. Ora e' un flag, e non puo' piu' sbagliarsi.
  const isPrintError = document.getElementById('fig-is-printerror-input')?.checked || false;
  const isChange = document.getElementById('fig-is-change-input')?.checked || false;
  const baseFigurineId = document.getElementById('fig-base-figurine-input')?.value || null;
  const retroId = document.getElementById('fig-retro-input')?.value || null;
  const forSale = document.getElementById('fig-for-sale-input')?.checked || false;
  const price = forSale ? (parseFloat(document.getElementById('fig-price-input').value) || 0) : null;
  const quantity = forSale ? (parseInt(document.getElementById('fig-quantity-input').value) || 1) : null;
  const condition = forSale ? document.getElementById('fig-condition-input').value : null;
  const isRetrosSection = currentSection === 'retros';
  // v5.779 — changeType per i Change di Retro E per i Change di figurina (stessa lista di serie)
  const changeType = (isChange && (isRetrosSection || currentSection === 'figurines')) ? (document.getElementById('fig-retro-change-type-input')?.value || null) : null;
  // Tipo di errore di stampa (testo libero, tutte le sezioni): valorizzato solo per gli Errori di
  // stampa. Mutuamente esclusivo col Tipo di change (isPrintError e isChange non coesistono).
  const printErrorType = isPrintError ? (document.getElementById('fig-print-error-type-input')?.value.trim() || null) : null;
  const isVarOrChgSection = isVariation || isUnofficialVariation || isChange;
  // v5.774 — per un Change o Errore di stampa di RETRO il Nome eredita quello del retro base
  // (il campo e' nascosto nella form). Se il base non e' ancora selezionato ci pensa il controllo
  // "Retro base obbligatorio" piu' sotto, quindi qui saltiamo il "Nome obbligatorio".
  // v5.779/790 — il Nome eredita dalla base per Change ED Errori di stampa, sia Retro sia figurine.
  const _nomeEreditato = (isChange || isPrintError) && (isRetrosSection || currentSection === 'figurines');
  if (_nomeEreditato && baseFigurineId) {
    const _bR = getData('figurines', []).find(x => x.id === baseFigurineId);
    if (_bR) name = _bR.name || '';
  }
  const numberRequired = (currentSection === 'figurines') && !isVarOrChgSection && !isPrintError; // v5.880: il numero ha senso solo per le figurine
  if ((!name && !_nomeEreditato) || (numberRequired && !number)) { toast((currentLang === 'it' ? (numberRequired ? 'Numero e nome sono obbligatori' : 'Il nome è obbligatorio') : (numberRequired ? 'Number and name are required' : 'Name is required')), 'error'); return; }
  if (isRetrosSection) {
    const editId = document.getElementById('edit-fig-id').value;
    // LA CHIAVE DI UNICITA' COMPRENDE IL TIPO (v5.717). Prima confrontava solo il
    // changeType — e allora un retro BASE e un ERRORE DI STAMPA, che hanno ENTRAMBI
    // changeType vuoto, sembravano lo stesso oggetto. Convertire un Change in errore di
    // stampa risultava IMPOSSIBILE: il controllo trovava il retro base omonimo e
    // bloccava. Il changeType funzionava da discriminante finche' i tipi di retro erano
    // due; col quinto non regge piu'.
    const tipoNuovo = tipoDiOggetto({ isVariation, isUnofficialVariation, isChange, isPrintError });
    const dup = getData('figurines', []).find(f =>
      f.id !== editId &&
      f.seriesId === currentSeriesId &&
      f.section === 'retros' &&
      (f.name||'').toLowerCase() === name.toLowerCase() &&
      (f.category||'').toLowerCase() === category.toLowerCase() &&
      tipoDiOggetto(f) === tipoNuovo &&
      // il changeType distingue due CHANGE fra loro; per gli altri tipi non esiste
      (tipoNuovo !== 'change' ||
        (f.changeType||'').toLowerCase().trim() === (changeType||'').toLowerCase().trim())
    );
    if (dup) {
      toast((currentLang === 'it' ? 'Esiste già un Retro con la stessa Categoria, lo stesso Nome e lo stesso Tipo di change in questa serie' : 'A Retro with the same Category, Name and Change type already exists in this series'), 'error');
      return;
    }
  }
  if ([isVariation, isUnofficialVariation, isChange].filter(Boolean).length > 1) {
    toast((currentLang === 'it' ? 'Variazione ufficiale, non ufficiale e Change sono mutuamente esclusivi: spunta solo una opzione' : 'Official variation, unofficial variation and Change are mutually exclusive: check only one'), 'error');
    return;
  }
  if ((isVariation || isUnofficialVariation || isChange || isPrintError) && !baseFigurineId) {
    const label = isRetrosSection ? (currentLang === 'it' ? 'Retro base' : 'Base Retro') : (currentLang === 'it' ? 'Figurina base' : 'Base sticker');
    toast((currentLang === 'it' ? `Il campo "${label}" è obbligatorio quando è selezionata una Variazione, un Change o un Errore di stampa` : `The "${label}" field is required when a Variation, Change or Print error is selected`), 'error');
    return;
  }
  if (!isRetrosSection && (isVariation || isUnofficialVariation) && !retroId) {
    toast((currentLang === 'it' ? 'Il campo "Retro associato" è obbligatorio quando è selezionata una Variazione ufficiale o non ufficiale' : 'The "Associated retro" field is required when an official or unofficial Variation is selected'), 'error');
    return;
  }
  if (isChange && (isRetrosSection || currentSection === 'figurines') && !changeType) {
    toast((currentLang === 'it' ? 'Il campo "Tipo di change" è obbligatorio per un Change' : 'The "Change type" field is required for a Change'), 'error');
    return;
  }
  if (isPrintError && !printErrorType) {
    toast((currentLang === 'it' ? 'Il campo "Tipo di errore di stampa" è obbligatorio quando è selezionato "Errore di stampa"' : 'The "Print error type" field is required when "Print error" is selected'), 'error');
    return;
  }
  toast((currentLang === 'it' ? 'Salvataggio...' : 'Saving...'), 'success');
  // Per Variazioni/Change il Numero eredita quello della figurina base collegata
  let finalNumber = number ? +number : null;
  if ((isVarOrChgSection || isPrintError) && baseFigurineId) {
    const baseFigForNum = getData('figurines', []).find(x => x.id === baseFigurineId);
    finalNumber = baseFigForNum ? baseFigForNum.number : null;
  }
  let imgUrl = editingFigImg || null;
  if (editingFigImgFileSave) {
    try { imgUrl = await uploadToCloudinary(editingFigImgFileSave); }
    catch(e) { toast((currentLang === 'it' ? 'Caricamento immagine fallito' : 'Image upload failed'), 'error'); return; }
  }
  let ebayImgUrl = editingFigEbayImg || null;
  if (editingFigEbayImgFileSave) {
    try { ebayImgUrl = await uploadToCloudinary(editingFigEbayImgFileSave); }
    catch(e) { toast((currentLang === 'it' ? 'Caricamento foto Ebay fallito' : 'Ebay photo upload failed'), 'error'); return; }
  }
  let figs = getData('figurines', []);
  const editId = document.getElementById('edit-fig-id').value;
  try {
    if (editId) {
      const idx = figs.findIndex(x => x.id === editId);
      if (idx >= 0) {
        figs[idx] = { ...figs[idx], number: finalNumber, noNumber, name, desc, score, subseries, size, category, subcategory, isVariation, isUnofficialVariation, isChange, isPrintError, baseFigurineId: (isVariation || isUnofficialVariation || isChange || isPrintError) ? (baseFigurineId || null) : null, retroId: (currentSection !== 'retros') ? (retroId || null) : null/* v5.786: retro anche per Change */, changeType, printErrorType, img: imgUrl || figs[idx].img, ebayImg: ebayImgUrl || figs[idx].ebayImg || null, forSale, price, quantity, condition };
        figs[idx].fullName = computeFullName(figs[idx], figs);
        await fsSave('figurines', figs[idx]);
        _cache.figurines = figs;
      }
    } else {
      const newF = { seriesId: currentSeriesId, section: currentSection || 'figurines', number: finalNumber, noNumber, name, desc, score, subseries, size, category, subcategory, isVariation, isUnofficialVariation, isChange, isPrintError, baseFigurineId: (isVariation || isUnofficialVariation || isChange || isPrintError) ? (baseFigurineId || null) : null, retroId: (currentSection !== 'retros') ? (retroId || null) : null/* v5.786: retro anche per Change */, changeType, printErrorType, img: imgUrl || null, ebayImg: ebayImgUrl || null, forSale, price, quantity, condition };
      newF.fullName = computeFullName(newF, figs);
      const saved = await fsSave('figurines', newF);
    }
  } catch(e) {
    console.error('saveFigurine', e);
    toast((currentLang === 'it' ? '❌ Salvataggio fallito, riprova (controlla la connessione)' : '❌ Save failed, please retry (check your connection)'), 'error');
    return;
  }
  editingFigImgFileSave = null;
  editingFigEbayImgFileSave = null;
  closeModal('add-fig-modal');
  if (_returnToErroriAfterSave) {
    _returnToErroriAfterSave = false;
    showPage('profile');
    adminTab('errori');
  } else {
    renderItems(); renderHomeStats(); updateSectionCounts();
  }
  toast((currentLang === 'it' ? 'Salvato! 🧟' : 'Saved! 🧟'), 'success');
}

async function deleteFigurine(id) {
  if (!confirm('Eliminare questo oggetto?')) return;
  await fsDelete('figurines', id);
  _cache.figurines = _cache.figurines.filter(x => x.id !== id);
  renderItems(); renderHomeStats(); updateSectionCounts();
  toast('Eliminato', 'success');
}

// ============================================================
//  BLOG / Q&A
// ============================================================
function openPostModal() {
  if (!currentUser) { openAuth('login'); return; }
  ['post-title-input','post-body-input'].forEach(id => document.getElementById(id).value = '');
  document.getElementById('post-modal').classList.remove('hidden');
}
async function savePost() {
  const type = document.getElementById('post-type').value;
  const title = document.getElementById('post-title-input').value.trim();
  const body = document.getElementById('post-body-input').value.trim();
  if (!title) { toast(currentLang === 'it' ? 'Il titolo è obbligatorio' : 'The title is required', 'error'); return; }
  const newPost = { type, title, body, author: currentUser.username, authorId: currentUser.id, authorAuthUid: currentUser.authUid || null, date: new Date().toISOString(), comments: [] };
  const saved = await fsSave('posts', newPost);
  _cache.posts.unshift(saved);
  closeModal('post-modal');
  renderBlog();
  toast(currentLang === 'it' ? 'Post pubblicato! 💬' : 'Post published! 💬', 'success');
  logEvent('new_post', 'Nuovo post nel blog di ' + bold(currentUser.username) + ': ' + esc(title));
}

async function submitComment(postId) {
  if (!currentUser) { openAuth('login'); return; }
  const textarea = document.getElementById('reply-input-' + postId);
  const text = textarea ? textarea.value.trim() : '';
  if (!text) { toast('Please write something first', 'error'); return; }
  const idx = _cache.posts.findIndex(p => p.id === postId);
  if (idx < 0) return;
  if (!_cache.posts[idx].comments) _cache.posts[idx].comments = [];
  _cache.posts[idx].comments.push({
    id: Date.now().toString(),
    author: currentUser.username,
    authorId: currentUser.id,
    isAdmin: !!currentUser.isAdmin,
    text,
    date: new Date().toISOString()
  });
  await fsSave('posts', _cache.posts[idx]);
  sendReplyNotificationEmail(_cache.posts[idx].authorId, _cache.posts[idx].title, currentUser.username, text);
  renderBlog();
  toast('Risposta inviata! ✅', 'success');
}

async function deleteComment(postId, commentId) {
  if (!currentUser) return;
  const idx = _cache.posts.findIndex(p => p.id === postId);
  if (idx < 0) return;
  const c = _cache.posts[idx].comments.find(c => c.id === commentId);
  if (!c) return;
  if (!currentUser.isAdmin && c.authorId !== currentUser.id) { toast('Non autorizzato', 'error'); return; }
  _cache.posts[idx].comments = _cache.posts[idx].comments.filter(c => c.id !== commentId);
  await fsSave('posts', _cache.posts[idx]);
  renderBlog();
  toast('Commento eliminato', 'success');
}

async function deletePost(id) {
  if (!currentUser?.isAdmin) { toast((currentLang === 'it' ? 'Solo per admin' : 'Admin only'), 'error'); return; }
  if (!confirm('Delete this post?')) return;
  await fsDelete('posts', id);
  _cache.posts = _cache.posts.filter(p => p.id !== id);
  renderBlog();
  toast((currentLang === 'it' ? 'Post eliminato' : 'Post deleted'), 'success');
}

function renderBlog() {
  const list = document.getElementById('blog-list');
  // migrate old posts that used single reply field
  let posts = getData('posts', []);
  let migrated = false;
  posts = posts.map(p => {
    if (!p.comments) {
      p.comments = [];
      if (p.reply && p.reply.text) {
        p.comments.push({ id: 'migrated', author: 'admin', authorId: 'admin', isAdmin: true, text: p.reply.text, date: p.reply.date || p.date });
        delete p.reply;
        migrated = true;
      }
    }
    return p;
  });
  if (migrated) setData('posts', posts);

  if (!posts.length) {
    list.innerHTML = `<div class="empty-state"><div class="empty-icon">💬</div><p class="empty-title">${t('blog.empty')}</p></div>`;
    return;
  }

  list.innerHTML = posts.map(p => {
    const badgeClass = p.type === 'question' ? 'badge-question' : 'badge-news';
    const badgeLabel = p.type === 'question' ? '❓ ' + (currentLang==='it'?'Domanda':'Question') : '📢 ' + (currentLang==='it'?'Notizia':'News');
    const dateStr = new Date(p.date).toLocaleDateString(currentLang === 'it' ? 'it-IT' : 'en-GB', { year:'numeric', month:'short', day:'numeric' });
    const comments = p.comments || [];
    const commentCount = comments.length;

    // render comments
    const commentsHTML = comments.map(c => {
      const cDate = new Date(c.date).toLocaleDateString(currentLang==='it'?'it-IT':'en-GB', { day:'numeric', month:'short', hour:'2-digit', minute:'2-digit' });
      const canDel = currentUser && (currentUser.isAdmin || currentUser.id === c.authorId);
      return `<div class="comment">
        <div class="comment-avatar ${c.isAdmin ? 'is-admin' : ''}">${displayAuthorName(c.author)[0].toUpperCase()}</div>
        <div class="comment-bubble ${c.isAdmin ? 'is-admin' : ''}">
          <div class="comment-header">
            <span class="comment-author">@${displayAuthorName(c.author)}</span>${(()=>{ const u = getData("users",[]).find(x=>x.id===c.authorId); return u?.nationalityCode ? `<img src="${flagUrl(u.nationalityCode)}" title="${u.nationalityName||''}" style="width:18px;height:12px;object-fit:cover;border-radius:2px;vertical-align:middle;">` : ""; })()}
            ${c.isAdmin ? `<span class="comment-admin-badge">👑 ${t('comment.admin')}</span>` : ''}
            <span class="comment-date">${cDate}</span>
            ${canDel ? `<button class="comment-del-btn" onclick="deleteComment('${p.id}','${c.id}')" title="Delete">✕</button>` : ''}
          </div>
          <div class="comment-text">${c.text.replace(/\n/g,'<br>')}</div>
        </div>
      </div>`;
    }).join('');

    // reply box
    const replyBoxHTML = currentUser
      ? `<div class="reply-box">
          <div class="reply-box-avatar ${currentUser.isAdmin?'is-admin':''}">${currentUser.username[0].toUpperCase()}</div>
          <textarea class="reply-textarea" id="reply-input-${p.id}" placeholder="Scrivi una risposta..."
            onkeydown="if(event.key==='Enter'&&(event.ctrlKey||event.metaKey)){submitComment('${p.id}');event.preventDefault();}" rows="1"></textarea>
          <button class="reply-send-btn" type="button" onclick="event.preventDefault();submitComment('${p.id}')" title="Invia">↑</button>
        </div>`
      : `<div style="margin-top:0.75rem;font-size:0.82rem;color:var(--muted);">
          <a style="color:var(--accent3);cursor:pointer;text-decoration:none;" onclick="openAuth('login')">${t('comment.login')}</a>
        </div>`;

    return `<div class="blog-card">
      <div class="blog-meta">
        <span class="blog-author">@${displayAuthorName(p.author)}</span>
        <span class="blog-date">${dateStr}</span>
        <span class="blog-type-badge ${badgeClass}">${badgeLabel}</span>
        ${currentUser?.isAdmin ? `<button class="tbl-btn tbl-btn-del" style="margin-left:auto;" onclick="deletePost('${p.id}')" title="${currentLang === 'it' ? 'Elimina questo post' : 'Delete this post'}">🗑️</button>` : ''}
      </div>
      <div class="blog-title">${p.title}</div>
      ${p.body ? `<div class="blog-excerpt">${p.body}</div>` : ''}
      <div class="comments-section">
        ${commentsHTML}
        ${replyBoxHTML}
        ${commentCount > 0 ? `<div style="font-size:0.75rem;color:var(--muted);margin-top:0.5rem;padding-top:0.5rem;">💬 ${commentCount} ${commentCount===1?(currentLang==='it'?'risposta':'reply'):(currentLang==='it'?'risposte':'replies')}</div>` : ''}
      </div>
    </div>`;
  }).join('');
}

// ============================================================
//  CONTACT
// ============================================================
// ============================================================
//  CONSERVAZIONE DEI MESSAGGI DI CONTATTO (6 mesi per i non registrati)
// ------------------------------------------------------------
//  Il form Contatti e' aperto agli ANONIMI: chi scrive senza avere un account
//  non ha un profilo, non ha un pulsante, e non ha quindi ALCUN modo di rivedere
//  o cancellare cio' che ci ha lasciato. Un tempo di conservazione automatico e'
//  l'unico strumento che protegge anche chi non puo' fare nulla da solo.
//
//  Si CANCELLA il record intero, non si "anonimizza" l'indirizzo. Svuotare la sola
//  e-mail sarebbe stato un mezzo lavoro: nei messaggi di contatto la gente si
//  firma ("sono Mario Rossi di Bergamo..."), quindi il TESTO continuerebbe a
//  identificarla e il record resterebbe un dato personale a tutti gli effetti.
//  Cancellando tutto, non resta niente da identificare.
//
//  QUANDO GIRA: il sito e' statico, non c'e' nessun processo notturno. L'unico
//  momento possibile e' l'apertura del pannello da parte dell'admin
//  (_loadAdminOnlyData). Se l'admin non entrasse per mesi, per mesi non si
//  cancellerebbe nulla: e' un limite dichiarato, non un difetto nascosto.
//
//  NON tocca: i messaggi di chi ha un account (li rivede dal profilo, e spariranno
//  con la cancellazione dell'account) e gli annunci creati dall'admin.
// ============================================================
const CONTACT_RETENTION_MONTHS = 6;
const CONTACT_PURGE_MAX_PER_RUN = 40; // tetto per non consumare la quota Firestore in un colpo

// ============================================================
//  CONSERVAZIONE DEL REGISTRO EVENTI (6 mesi)
// ------------------------------------------------------------
//  Il registro sopravvive alla cancellazione dell'account — scelta di Franco, ed
//  e' difendibile: e' un registro di sicurezza, e sapere CHI se n'e' andato e
//  quando e' proprio il motivo per cui esiste. Ma non sopravvive al TEMPO.
//  Nelle descrizioni ci sono nomi utente e, per le richieste di reset password,
//  indirizzi e-mail digitati sul form di login — che non sono nemmeno detto
//  appartengano a un nostro utente: chiunque puo' scriverci quello che vuole.
//  Per quelli la scadenza e' l'unica pulizia possibile, perche' un evento
//  generato da chi non e' autenticato non ha authUid e non e' riconducibile a
//  nessuno.
//  Come per i messaggi di contatto: gira all'apertura del pannello admin (il
//  sito e' statico, non c'e' nessun processo notturno), a tetto per non
//  consumare la quota.
// ============================================================
const EVENTI_PURGE_MAX_PER_RUN = 40;

async function purgeOldEventi() {
  try {
    const eventi = getData('eventi', []);
    if (!eventi.length) return;

    const limite = new Date();
    limite.setMonth(limite.getMonth() - EVENTI_RETENTION_MONTHS);

    const scaduti = eventi.filter(e => e.date && new Date(e.date) < limite);
    if (!scaduti.length) return;

    const lotto = scaduti.slice(0, EVENTI_PURGE_MAX_PER_RUN);
    let fatti = 0;
    for (const e of lotto) {
      try { await fsDelete('eventi', e.id); fatti++; }
      catch(err) { console.warn('[retention] evento non cancellato', e.id, err.message); }
    }
    if (fatti) {
      _cache.eventi = getData('eventi', []).filter(e => !lotto.some(x => x.id === e.id));
      updateBellBadge();
      console.log(`[retention] cancellati ${fatti} eventi piu' vecchi di ${EVENTI_RETENTION_MONTHS} mesi`);
      if (scaduti.length > lotto.length) {
        console.log(`[retention] ne restano ${scaduti.length - lotto.length}: al prossimo accesso`);
      }
    }
  } catch(e) { console.warn('[retention] purgeOldEventi', e.message); }
}

// ============================================================
//  CONSERVAZIONE DELLE SEGNALAZIONI (6 mesi)
// ------------------------------------------------------------
//  Era l'ultima raccolta senza un termine. Sparivano se l'autore cancellava
//  l'account, o se l'admin le cancellava a mano — ma di un utente che resta
//  iscritto per anni, le segnalazioni restavano li' per sempre, con nome utente e
//  commento.
//
//  ATTENZIONE, e' diversa dalle altre: una segnalazione non e' solo un dato
//  personale, e' un ERRORE DELL'INVENTARIO che qualcuno ci ha indicato. Se dopo
//  sei mesi non e' stato corretto, cancellandola si perde l'informazione — e
//  l'errore resta nel catalogo senza che nessuno lo ricordi piu'. La scadenza,
//  qui, e' anche una scadenza sul lavoro dell'admin.
//  Prima di cancellarne una NON LETTA, quindi, lo si dice a voce alta in console:
//  se ne spariscono di non lette, vuol dire che sono passate inosservate per sei
//  mesi, ed e' bene saperlo.
// ============================================================
const SEGN_RETENTION_MONTHS = 6;
const SEGN_PURGE_MAX_PER_RUN = 40;

async function purgeOldSegnalazioni() {
  try {
    const segn = getData('segnalazioni', []);
    if (!segn.length) return;

    const limite = new Date();
    limite.setMonth(limite.getMonth() - SEGN_RETENTION_MONTHS);

    const scadute = segn.filter(x => x.date && new Date(x.date) < limite);
    if (!scadute.length) return;

    const lotto = scadute.slice(0, SEGN_PURGE_MAX_PER_RUN);
    const nonLette = lotto.filter(x => !x.read).length;
    let fatti = 0;
    for (const x of lotto) {
      try { await fsDelete('segnalazioni', x.id); fatti++; }
      catch(e) { console.warn('[retention] segnalazione non cancellata', x.id, e.message); }
    }
    if (fatti) {
      _cache.segnalazioni = getData('segnalazioni', []).filter(x => !lotto.some(y => y.id === x.id));
      updateBellBadge();
      renderAdminSegnalazioni();
      console.log(`[retention] cancellate ${fatti} segnalazioni piu' vecchie di ${SEGN_RETENTION_MONTHS} mesi`);
      if (nonLette) {
        console.warn(`[retention] ATTENZIONE: ${nonLette} di queste NON erano state lette. Erano errori dell'Inventario mai esaminati.`);
      }
      if (scadute.length > lotto.length) {
        console.log(`[retention] ne restano ${scadute.length - lotto.length}: al prossimo accesso`);
      }
    }
  } catch(e) { console.warn('[retention] purgeOldSegnalazioni', e.message); }
}

async function purgeOldContactMessages() {
  try {
    const msgs = getData('contact_messages', []);
    if (!msgs.length) return;

    const limite = new Date();
    limite.setMonth(limite.getMonth() - CONTACT_RETENTION_MONTHS);

    // Gli indirizzi degli utenti registrati, in minuscolo: i loro messaggi restano.
    const registrati = new Set(
      getData('users', []).map(u => (u.email || '').toLowerCase()).filter(Boolean)
    );

    const scaduti = msgs.filter(m =>
      !m.isAnnouncement &&
      m.date && new Date(m.date) < limite &&
      !registrati.has((m.email || '').toLowerCase())
    );
    if (!scaduti.length) return;

    const lotto = scaduti.slice(0, CONTACT_PURGE_MAX_PER_RUN);
    let fatti = 0;
    for (const m of lotto) {
      try { await fsDelete('contact_messages', m.id); fatti++; }
      catch(e) { console.warn('[retention] cancellazione fallita per', m.id, e.message); }
    }
    if (fatti) {
      _cache.contact_messages = getData('contact_messages', []).filter(m => !lotto.some(x => x.id === m.id));
      console.log(`[retention] cancellati ${fatti} messaggi di non registrati piu' vecchi di ${CONTACT_RETENTION_MONTHS} mesi`);
      if (scaduti.length > lotto.length) {
        console.log(`[retention] ne restano ${scaduti.length - lotto.length}: verranno cancellati al prossimo accesso`);
      }
    }
  } catch(e) { console.warn('[retention] purgeOldContactMessages', e.message); }
}

async function sendContact() {
  // Il campo Nome e' stato tolto (v5.634): non serviva a nulla che l'e-mail non
  // facesse gia' meglio, ed era un dato personale in piu' da custodire, dichiarare
  // e cancellare. Il dato che non raccogli e' l'unico che non ti crea problemi.
  const email = document.getElementById('contact-email').value.trim();
  const subject = document.getElementById('contact-subject').value.trim();
  const message = document.getElementById('contact-message').value.trim();
  if (!email || !message) { toast(currentLang === 'it' ? 'Compila e-mail e messaggio' : 'Please fill in e-mail and message', 'error'); return; }
  const msg = { email, subject, message, date: new Date().toISOString(), read: false };
  const saved = await fsSave('contact_messages', msg);
  _cache.contact_messages.unshift(saved);
  // Si svuota anche l'indirizzo, non solo oggetto e testo. Finora restava li':
  // aveva un senso quando si rimaneva sulla pagina (magari volevi scriverne un
  // altro), ma ora che si esce non ne ha piu' — e su un computer condiviso
  // sarebbe l'indirizzo di qualcuno lasciato in un campo di una pagina che nessuno
  // sta piu' guardando.
  ['contact-email','contact-subject','contact-message'].forEach(id => document.getElementById(id).value = '');
  toast(currentLang === 'it' ? 'Messaggio inviato! Ti risponderemo presto 📩' : 'Message sent! We\'ll get back to you soon 📩', 'success');

  // Chi ha appena scritto non ha piu' nulla da fare qui: la pagina Contatti resta
  // aperta su un modulo vuoto, e va abbandonata a mano. Lo si fa da soli.
  // Si torna DA DOVE SI VENIVA (_previousPage, lo stesso meccanismo del pulsante
  // "← Torna a ..."), non genericamente alla Home: se uno stava sfogliando
  // l'Inventario ed e' passato di qui per una domanda, e' li' che vuole tornare.
  // Il ritardo lascia vedere la conferma prima che la pagina cambi.
  setTimeout(() => {
    const dove = (_previousPage && _previousPage !== 'contact') ? _previousPage : 'home';
    showPage(dove);
  }, 1500);
}

// ============================================================
//  PROFILE
// ============================================================
async function saveAnonSetting() {
  if (!currentUser) return;
  const cb = document.getElementById('profile-anon-toggle');
  const enabling = cb?.checked || false;
  const L = currentLang === 'it';
  const msg = enabling
    ? (L ? `Attivando l'anonimato, il tuo nome sarà "Collezionista Anonimo". Gli altri non potranno identificarti, ma vedrai sempre la tua posizione.\n\nConfermi?`
         : `By enabling anonymity, your name becomes "Anonymous Collector". Others won't identify you, but you'll still see your own position.\n\nConfirm?`)
    : (L ? `Disattivando l'anonimato, il tuo nome e avatar torneranno visibili a tutti.\n\nConfermi?`
         : `By disabling anonymity, your name and avatar will be visible to everyone again.\n\nConfirm?`);
  if (!confirm(msg)) {
    cb.checked = !enabling; // revert
    return;
  }
  currentUser.isAnonymous = enabling;
  LOCAL.set('currentUser', currentUser);
  await fsSave('users', currentUser);
  toast(L
    ? (enabling ? '🕵️ Profilo anonimo attivato' : 'Profilo pubblico ripristinato')
    : (enabling ? '🕵️ Anonymous profile enabled' : 'Public profile restored'), 'success');
}

// Carica, con una query mirata (non tutta la collezione), solo i messaggi
// di contatto con la stessa e-mail dell'utente corrente — richiede la
// regola dedicata in firestore.rules, altrimenti Firestore rifiuta la
// query per intero (non singoli documenti)
async function loadMyContactMessages() {
  if (!currentUser?.email) return [];
  try {
    const { collection: col, query: qf, where: wf, getDocs: gd } = window._fb;
    const q = qf(col(db, 'contact_messages'), wf('email', '==', currentUser.email));
    const snap = await gd(q);
    return snap.docs.map(d => ({ ...d.data(), id: d.id }));
  } catch(e) {
    console.error('loadMyContactMessages', e);
    return [];
  }
}

// Mostra all'utente, nel proprio profilo, i messaggi che ha scritto tramite
// Contatti (abbinati per e-mail, non per essere stato loggato al momento
// dell'invio — funziona quindi anche per messaggi scritti in passato da
// anonimo, se l'e-mail coincide con quella dell'account) e l'eventuale
// risposta dell'admin. Serve come rete di sicurezza quando l'e-mail di
// risposta non arriva per problemi di consegna (es. blacklist Aruba/Hotmail)
async function renderMyMessages() {
  const wrap = document.getElementById('profile-my-messages');
  const list = document.getElementById('profile-my-messages-list');
  if (!wrap || !list || !currentUser?.email) return;
  const myMsgs = (await loadMyContactMessages()).sort((a, b) => new Date(b.date) - new Date(a.date));
  if (!myMsgs.length) { wrap.style.display = 'none'; return; }
  wrap.style.display = '';
  markRepliesAsRead(myMsgs); // fire-and-forget, non blocca la visualizzazione
  list.innerHTML = myMsgs.map(m => m.isAnnouncement ? `
    <div style="background:var(--card2);border:1px solid var(--accent);border-radius:10px;padding:0.85rem 1rem;margin-bottom:0.75rem;">
      <div style="font-size:0.78rem;color:var(--accent);margin-bottom:0.3rem;">📢 ${currentLang === 'it' ? 'Comunicazione dello staff' : 'Staff announcement'} — ${new Date(m.date).toLocaleDateString(currentLang === 'it' ? 'it-IT' : 'en-US', {day:'numeric',month:'short',year:'numeric'})}${m.subject ? ' — ' + m.subject : ''}</div>
      <div style="font-size:0.9rem;">${m.message}</div>
    </div>` : `
    <div style="background:var(--card2);border:1px solid var(--border);border-radius:10px;padding:0.85rem 1rem;margin-bottom:0.75rem;">
      <div style="font-size:0.78rem;color:var(--muted);margin-bottom:0.3rem;">${new Date(m.date).toLocaleDateString(currentLang === 'it' ? 'it-IT' : 'en-US', {day:'numeric',month:'short',year:'numeric'})}${m.subject ? ' — ' + m.subject : ''}</div>
      <div style="font-size:0.9rem;margin-bottom:${m.replyText ? '0.6rem' : '0'};">${m.message}</div>
      ${m.replyText ? `<div style="border-left:2px solid var(--accent);padding-left:0.75rem;margin-top:0.5rem;">
        <div style="font-size:0.78rem;color:var(--accent);margin-bottom:0.2rem;">${currentLang === 'it' ? 'Risposta dello staff' : 'Staff reply'}${m.repliedAt ? ' — ' + new Date(m.repliedAt).toLocaleDateString(currentLang === 'it' ? 'it-IT' : 'en-US', {day:'numeric',month:'short',year:'numeric'}) : ''}</div>
        <div style="font-size:0.9rem;">${m.replyText}</div>
      </div>` : `<div style="font-size:0.82rem;color:var(--muted);font-style:italic;">${currentLang === 'it' ? 'In attesa di risposta...' : 'Awaiting reply...'}</div>`}
    </div>`).join('');
}

// Controlla se l'utente ha risposte dello staff non ancora viste, e mostra
// il badge accanto all'icona profilo di conseguenza
async function checkUnreadReplies() {
  const badge = document.getElementById('nav-reply-badge');
  if (!badge || !currentUser || currentUser.isAdmin) return;
  const myMsgs = await loadMyContactMessages();
  const unread = myMsgs.filter(m => m.replied && !m.userReadReply).length;
  if (unread > 0) {
    badge.style.display = '';
    badge.textContent = unread > 9 ? '9+' : unread;
  } else {
    badge.style.display = 'none';
  }
}

// Segna come lette tutte le risposte dell'utente corrente (chiamata
// quando apre la sezione "I miei messaggi con lo staff" nel profilo)
async function markRepliesAsRead(myMsgs) {
  const toMark = myMsgs.filter(m => m.replied && !m.userReadReply);
  if (!toMark.length) return;
  await Promise.all(toMark.map(m => { m.userReadReply = true; return fsSave('contact_messages', m); }));
  const badge = document.getElementById('nav-reply-badge');
  if (badge) badge.style.display = 'none';
}

function renderProfile() {
  if (!currentUser) { showPage('home'); return; }
  const backLabelEl = document.getElementById('profile-back-btn-label');
  if (backLabelEl) {
    const pageLabels = {
      home: currentLang === 'it' ? 'Home' : 'Home',
      catalog: currentLang === 'it' ? 'Inventario' : 'Inventory',
      blog: currentLang === 'it' ? 'Blog / D&R' : 'Blog / Q&A',
      classifica: currentLang === 'it' ? 'Classifica' : 'Leaderboard',
      wantlist: currentLang === 'it' ? 'Liste' : 'Lists',
      wishlist: currentLang === 'it' ? 'Ciò che cerco' : 'What I\'m looking for',
      newsletter: currentLang === 'it' ? 'Comunicazioni' : 'Communications',
      contact: currentLang === 'it' ? 'Contatti' : 'Contact'
    };
    backLabelEl.textContent = (currentLang === 'it' ? 'Torna a ' : 'Back to ') + (pageLabels[_previousPage] || pageLabels.home);
  }
  document.getElementById('profile-username').textContent = currentUser.username + (currentUser.isAdmin ? ' 👑' : '');
  document.getElementById('profile-email').textContent = currentUser.email;
  // Show warning if user must change password
  const mustChangeBanner = document.getElementById('must-change-pwd-banner');
  if (mustChangeBanner) mustChangeBanner.style.display = currentUser.mustChangePassword ? '' : 'none';
  // Chi ha fatto accesso con Google non ha una password da cambiare qui
  const changePwdBtn = document.getElementById('profile-change-pwd-btn');
  if (changePwdBtn) changePwdBtn.style.display = (fbAuth?.currentUser?.providerData?.[0]?.providerId === 'google.com') ? 'none' : '';
  // Show anon toggle (only for non-admin users)
  const anonWrap = document.getElementById('profile-anon-wrap');
  if (anonWrap) anonWrap.style.display = currentUser.isAdmin ? 'none' : '';
  if (currentUser.isAdmin) {
    const myMsgsWrap = document.getElementById('profile-my-messages');
    if (myMsgsWrap) myMsgsWrap.style.display = 'none';
  } else {
    renderMyMessages();
  }
  // L'autocancellazione account non deve mai essere visibile all'admin, né
  // per il proprio account né per nessun utente durante l'impersonificazione
  const dangerZone = document.getElementById('profile-danger-zone');
  if (dangerZone) dangerZone.style.display = (currentUser.isAdmin || isImpersonating()) ? 'none' : '';
  // "Cambia password": non puo' funzionare durante l'impersonificazione. Firebase
  // Auth non sa nulla dell'impersonificazione — e' una finzione che vive solo nel
  // nostro codice — quindi la sessione autenticata resta quella dell'ADMIN, e un
  // cambio password agirebbe sulla password DELL'ADMIN, non su quella dell'utente
  // impersonato. Un pulsante che, se premuto, farebbe la cosa sbagliata
  // sull'account sbagliato.
  // Grigiato e non nascosto: cosi' l'admin vede che la funzione esiste e capisce
  // PERCHE' non e' disponibile, invece di chiedersi dove sia finita.
  // (La sezione "Elimina il mio account" e' gia' nascosta qui sopra, per la
  // stessa ragione di fondo.)
  const pwdBtn = document.getElementById('profile-change-pwd-btn');
  if (pwdBtn) {
    const bloccato = isImpersonating();
    pwdBtn.disabled = bloccato;
    pwdBtn.style.opacity = bloccato ? '0.4' : '';
    pwdBtn.style.cursor = bloccato ? 'not-allowed' : '';
    pwdBtn.title = bloccato
      ? (currentLang === 'it'
          ? "Non disponibile durante l'impersonificazione: la sessione autenticata è quella dell'admin, quindi cambieresti la password dell'admin."
          : "Not available while impersonating: the authenticated session is the admin's, so you would change the admin's password.")
      : '';
  }

  const anonCb = document.getElementById('profile-anon-toggle');
  if (anonCb) anonCb.checked = currentUser.isAnonymous || false;
  // Preferenze e-mail: il box non ha senso per l'admin (è lui che la manda)
  const nlWrap = document.getElementById('profile-email-prefs-wrap');
  if (nlWrap) nlWrap.style.display = currentUser.isAdmin ? 'none' : '';
  const nlCb = document.getElementById('profile-newsletter-toggle');
  if (nlCb) nlCb.checked = hasNewsletterConsent(currentUser); // undefined ("mai chiesto") = spento
  const natDisplay = document.getElementById('profile-nationality-display');
  if (natDisplay) {
    if (currentUser.nationalityCode) {
      natDisplay.innerHTML = `<img src="${flagUrl(currentUser.nationalityCode)}" style="width:20px;height:14px;object-fit:cover;border-radius:2px;vertical-align:middle;"> ${currentUser.nationalityName || ''}`;
    } else {
      natDisplay.textContent = (currentLang === 'it' ? 'Nessuna nazionalità impostata' : 'No nationality set');
    }
  }
  const natBtn = document.getElementById('profile-change-nat-btn');
  if (natBtn) natBtn.textContent = t(currentUser.nationalityCode ? 'profile.changeNat' : 'profile.setNat');
  const avatarText = document.getElementById('profile-avatar-text');
  const profileAvatar = document.getElementById('profile-avatar');
  // Always reset first
  profileAvatar.style.backgroundImage = '';
  profileAvatar.style.backgroundSize = '';
  profileAvatar.style.backgroundPosition = '';
  if (currentUser.avatar) {
    if (avatarText) avatarText.style.display = 'none';
    profileAvatar.style.backgroundImage = 'url(' + currentUser.avatar + ')';
    profileAvatar.style.backgroundSize = 'cover';
    profileAvatar.style.backgroundPosition = 'center';
  } else {
    if (avatarText) { avatarText.style.display = ''; avatarText.textContent = currentUser.username[0].toUpperCase(); }
  }
  const allFigs = getData('figurines', []);
  const owned = getOwned();
  const ownedFigs = allFigs.filter(f => owned.includes(f.id));
  const profileStatsBox = document.getElementById('profile-stats-box');
  if (profileStatsBox) profileStatsBox.style.display = currentUser.isAdmin ? 'none' : '';
  document.getElementById('profile-owned').textContent = ownedFigs.length;
  const seriesIds = [...new Set(ownedFigs.map(f => f.seriesId))];
  document.getElementById('profile-series-count').textContent = seriesIds.length;
  document.getElementById('admin-panel').style.display = currentUser.isAdmin ? '' : 'none';
  if (currentUser.isAdmin) {
    const currentActiveTab = document.querySelector('.admin-tab.active');
    const currentTab = currentActiveTab?.getAttribute('onclick')?.match(/adminTab\('(\w+)'\)/)?.[1];
    adminTab(currentTab || 'users');
  }
  renderMyCollection(ownedFigs);
}

function renderMyCollection(ownedFigs) {
  const el = document.getElementById('my-collection-list');
  if (!el) return; // section removed
  const series = getData('series', []);
  if (!ownedFigs.length) {
    el.innerHTML = `<div class="empty-state"><div class="empty-icon">😢</div><p class="empty-title">${currentLang === 'it' ? "Nessuna figurina ancora!" : "No stickers yet!"}</p><p class="empty-sub">${currentLang === 'it' ? "Sfoglia l'Inventario e aggiungi le figurine alla tua lista." : "Browse the Inventory and add stickers to your list."}</p></div>`;
    return;
  }
  const bySeries = {};
  ownedFigs.forEach(f => {
    if (!bySeries[f.seriesId]) bySeries[f.seriesId] = [];
    bySeries[f.seriesId].push(f);
  });
  el.innerHTML = Object.entries(bySeries).map(([sId, figs]) => {
    const s = series.find(x => x.id === sId);
    const allSeriesFigs = getData('figurines', []).filter(f => f.seriesId === sId);
    return `<div style="background:var(--card);border:1px solid var(--border);border-radius:var(--radius-lg);padding:1.25rem;margin-bottom:1rem;">
      <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:0.75rem;">
        <span style="font-family:var(--font-ui);font-size:1.1rem;">${s ? s.name : 'Unknown Series'}</span>
        <span class="card-badge">${figs.length} / ${allSeriesFigs.length}</span>
      </div>
      <div class="progress-bar"><div class="progress-fill" style="width:${Math.round(figs.length/allSeriesFigs.length*100)}%"></div></div>
      <div style="display:flex;flex-wrap:wrap;gap:0.4rem;margin-top:0.75rem;">
        ${figs.sort((a,b)=>a.number-b.number).map(f=>`<span style="background:rgba(181,255,46,0.08);border:1px solid rgba(181,255,46,0.2);color:var(--accent);font-size:0.78rem;padding:2px 8px;border-radius:12px;">#${String(f.number).padStart(2,'0')} ${f.name}</span>`).join('')}
      </div>
    </div>`;
  }).join('');
}

