function toggleReplyBox(id) {
  const box = document.getElementById('reply-box-' + id);
  if (!box) return;
  const isOpen = box.style.display !== 'none';
  document.querySelectorAll('[id^="reply-box-"]').forEach(b => b.style.display = 'none');
  box.style.display = isOpen ? 'none' : '';
  if (!isOpen) {
    const ta = document.getElementById('reply-text-' + id);
    if (ta) ta.focus();
  }
}

async function sendContactReply(id) {
  const msg = getData('contact_messages', []).find(m => m.id === id);
  if (!msg) return;
  const textarea = document.getElementById('reply-text-' + id);
  const replyText = textarea?.value.trim();
  if (!replyText) { toast(currentLang === 'it' ? 'Scrivi una risposta prima di inviare' : 'Write a reply before sending', 'error'); return; }

  const alsoEmail = document.getElementById('reply-also-email-' + id)?.checked || false;

  if (alsoEmail) {
    const subject = (currentLang === 'it' ? 'Re: ' : 'Re: ') + (msg.subject || (currentLang === 'it' ? 'la tua richiesta' : 'your request'));
    // Nome per il saluto della risposta. Il campo Nome non esiste piu', quindi:
    //   1. se chi ha scritto e' un utente registrato, si usa il suo nome utente;
    //   2. i messaggi VECCHI hanno ancora msg.name: si rispetta;
    //   3. altrimenti la parte dell'e-mail prima della chiocciola.
    // Senza questa catena le risposte partirebbero con un saluto vuoto.
    const destName = (getData('users', []).find(u => u.email === msg.email)?.username)
      || msg.name
      || (msg.email || '').split('@')[0];
    const result = await sendEmail(msg.email, destName, subject, replyText, { source: 'messages' });
    if (!result.ok) {
      toast((currentLang === 'it' ? '❌ Invio e-mail fallito: ' : '❌ E-mail send failed: ') + result.error, 'error');
      return;
    }
  }

  msg.replied = true;
  msg.repliedAt = new Date().toISOString();
  msg.replyText = replyText;
  msg.userReadReply = false; // ogni nuova risposta torna "non letta" per l'utente, anche se il messaggio aveva già avuto una risposta in passato
  msg.read = true; // rispondere implica averlo letto, anche se "Segna letto" non è mai stato premuto esplicitamente
  await fsSave('contact_messages', msg);
  if (_cache.contact_messages) {
    const idx = _cache.contact_messages.findIndex(m => m.id === id);
    if (idx >= 0) _cache.contact_messages[idx] = msg;
  }

  toast(alsoEmail ? (currentLang === 'it' ? '✅ Risposta inviata (anche via e-mail)!' : '✅ Reply sent (also by e-mail)!') : (currentLang === 'it' ? '✅ Risposta salvata nel sito' : '✅ Reply saved on the site'), 'success');
  renderAdminContacts();
}

async function deleteContactMsg(id) {
  if (!confirm(currentLang === 'it' ? 'Eliminare questo messaggio?' : 'Delete this message?')) return;
  await fsDelete('contact_messages', id);
  if (_cache.contact_messages) _cache.contact_messages = _cache.contact_messages.filter(m => m.id !== id);
  renderAdminContacts();
  updateMsgBadge();
}

async function markContactRead(id) {
  const msgs = _cache.contact_messages || [];
  const idx = msgs.findIndex(m => m.id === id);
  if (idx === -1) return;
  msgs[idx].read = true;
  await fsSave('contact_messages', msgs[idx]);
  renderAdminContacts();
  updateMsgBadge();
}
let _usersSort = { col: 'username', dir: 1 };

function sortAdminUsers(col) {
  if (_usersSort.col === col) _usersSort.dir *= -1;
  else { _usersSort.col = col; _usersSort.dir = 1; }
  renderAdminUsers();
}

function renderAdminUsers() {
  const el = document.getElementById('admin-users-table');
  let users = [...getData('users', [])];

  // Conteggio accanto al titolo. Il numero sta in un <span> SUO, fratello di
  // quello con data-i18n: applyI18n() riscrive il textContent dell'elemento
  // tradotto, quindi un conteggio infilato lì dentro verrebbe cancellato al
  // primo cambio di lingua.
  const cntEl = document.getElementById('admin-users-count');
  if (cntEl) {
    const L = currentLang === 'it';
    const admins = users.filter(u => u.isAdmin).length;
    const normali = users.length - admins;
    cntEl.textContent = L
      ? `${users.length} (${normali} utenti + ${admins} admin)`
      : `${users.length} (${normali} users + ${admins} admin)`;
  }
  const { col, dir } = _usersSort;
  users.sort((a, b) => {
    let va, vb;
    if (col === 'username') { va = (a.username || '').toLowerCase(); vb = (b.username || '').toLowerCase(); }
    else if (col === 'email') { va = (a.email || '').toLowerCase(); vb = (b.email || '').toLowerCase(); }
    else if (col === 'lastLogin') { va = a.lastLogin || ''; vb = b.lastLogin || ''; }
    else if (col === 'joined') { va = a.joined || ''; vb = b.joined || ''; }
    else { va = ''; vb = ''; }
    return va < vb ? -dir : va > vb ? dir : 0;
  });
  const arrow = (c) => _usersSort.col === c ? (_usersSort.dir === 1 ? ' ↑' : ' ↓') : '';
  el.innerHTML = `<table class="data-table compact"><thead><tr>
    <th>${(currentLang === 'it') ? 'Azioni' : 'Actions'}</th>
    <th style="cursor:pointer;" onclick="sortAdminUsers('username')">${(currentLang === 'it') ? 'Nome utente' : 'Nickname'}${arrow('username')}</th>
    <th style="cursor:pointer;" onclick="sortAdminUsers('email')">E-mail${arrow('email')}</th>
    <th style="cursor:pointer;" onclick="sortAdminUsers('lastLogin')">${(currentLang === 'it') ? 'Ultima login' : 'Last login'}${arrow('lastLogin')}</th>
    <th style="cursor:pointer;" onclick="sortAdminUsers('joined')">${(currentLang === 'it') ? 'Iscritto dal' : 'Member since'}${arrow('joined')}</th></tr></thead><tbody>
    ${users.map(u => `<tr>
      <td><div style="display:flex;gap:0.3rem;"><button class="tbl-btn" style="background:rgba(181,255,46,0.12);border-color:rgba(181,255,46,0.4);color:var(--accent);" onclick="openEditUserModal('${u.id}')">${currentLang === 'it' ? 'Visualizza' : 'View'}</button>${!u.isAdmin ? `<button class="tbl-btn" style="background:rgba(var(--warn-rgb),0.15);border-color:rgba(var(--warn-rgb),0.4);color:var(--warn);" onclick="impersonateUser('${u.id}')">🎭 ${(currentLang === 'it') ? 'Impersona' : 'Impersonate'}</button>` : ''}</div></td>
      <td>
        <div style="display:flex;align-items:center;gap:0.4rem;">
          <div style="width:24px;height:24px;border-radius:50%;flex-shrink:0;background:${u.avatar ? 'url(' + u.avatar + ') center/cover' : 'var(--card2)'};border:1px solid var(--border);display:flex;align-items:center;justify-content:center;font-size:0.8rem;color:var(--muted);">${u.avatar ? '' : (u.username || '?')[0].toUpperCase()}</div>
          ${u.username || '(senza nickname)'}${u.isAdmin?'<span class="admin-badge">ADMIN</span>':''}${u.nationalityCode ? '<img src="'+flagUrl(u.nationalityCode)+'" title="'+(u.nationalityName||'')+'" style="width:18px;height:12px;object-fit:cover;border-radius:2px;margin-left:4px;">' : ''}
        </div>
      </td>
      <td>${u.email}</td>
      <td style="font-size:0.82rem;">${u.lastLogin ? new Date(u.lastLogin).toLocaleDateString('it-IT') + ' ' + new Date(u.lastLogin).toLocaleTimeString('it-IT',{hour:'2-digit',minute:'2-digit'}) : '<span style="color:var(--muted);font-style:italic;">mai</span>'}</td>
      <td>${new Date(u.joined).toLocaleDateString()}</td>
    </tr>`).join('')}
  </tbody></table>`;
}

let pendingNatCode = '';
let pendingNatName = '';

function openUsernameModal(isFirstTime) {
  if (!currentUser) return;
  document.getElementById('new-username-input').value = currentUser.username || '';
  const errEl = document.getElementById('username-modal-error');
  if (errEl) errEl.style.display = 'none';
  const welcomeEl = document.getElementById('username-modal-welcome');
  if (welcomeEl) welcomeEl.style.display = isFirstTime ? '' : 'none';
  const titleEl = document.getElementById('username-modal-title');
  if (titleEl) titleEl.textContent = isFirstTime
    ? (currentLang === 'it' ? '👋 Benvenuto/a!' : '👋 Welcome!')
    : t('profile.changeUsername.title');
  document.getElementById('username-modal').classList.remove('hidden');
}

async function saveNewUsername() {
  if (!currentUser) return;
  const errEl = document.getElementById('username-modal-error');
  const raw = (document.getElementById('new-username-input').value || '').trim();
  const clean = raw.replace(/[^a-zA-Z0-9_]/g, '');
  if (!clean) {
    if (errEl) { errEl.style.display = ''; errEl.textContent = currentLang === 'it' ? 'Il nome utente non può essere vuoto' : 'Username cannot be empty'; }
    return;
  }
  if (clean !== raw) {
    if (errEl) { errEl.style.display = ''; errEl.textContent = currentLang === 'it' ? 'Solo lettere, numeri e underscore sono ammessi' : 'Only letters, numbers and underscores are allowed'; }
    return;
  }
  if (clean === currentUser.username) { closeModal('username-modal'); maybeAskNewsletterConsent(); return; }
  const profiles = getData('public_profiles', []);
  if (profiles.find(x => x.username === clean && x.id !== currentUser.id)) {
    if (errEl) { errEl.style.display = ''; errEl.textContent = currentLang === 'it' ? 'Questo nome utente è già in uso' : 'This username is already taken'; }
    return;
  }
  currentUser.username = clean;
  LOCAL.set('currentUser', currentUser);
  try {
    await fsSave('users', currentUser);
    await _syncPublicProfile(currentUser);
  } catch(e) {
    console.error('saveNewUsername', e);
    if (errEl) { errEl.style.display = ''; errEl.textContent = currentLang === 'it' ? 'Salvataggio non riuscito, riprova' : 'Save failed, please retry'; }
    return;
  }
  const users = getData('users', []);
  const idx = users.findIndex(u => u.id === currentUser.id);
  if (idx >= 0) { users[idx] = currentUser; _cache.users = users; }
  if (Array.isArray(_cache.public_profiles)) {
    const pIdx = _cache.public_profiles.findIndex(p => p.id === currentUser.id);
    if (pIdx >= 0) _cache.public_profiles[pIdx] = { ..._cache.public_profiles[pIdx], username: clean };
  }
  closeModal('username-modal');
  renderProfile();
  toast(currentLang === 'it' ? 'Nome utente aggiornato! ✏️' : 'Username updated! ✏️', 'success');
  maybeAskNewsletterConsent(); // nuovo utente Google: subito dopo il nome, il consenso
}

function openNationalityModal() {
  if (!currentUser) return;
  pendingNatCode = currentUser.nationalityCode || '';
  pendingNatName = currentUser.nationalityName || '';
  document.getElementById('profile-nationality-search').value = pendingNatName;
  document.getElementById('nationality-dropdown-2').style.display = 'none';
  const preview = document.getElementById('profile-nationality-preview-2');
  if (pendingNatCode) {
    preview.style.display = 'flex';
    preview.innerHTML = `<img src="${flagUrl(pendingNatCode)}" style="width:24px;height:16px;object-fit:cover;border-radius:2px;"> ${pendingNatName}`;
  } else {
    preview.style.display = 'none';
  }
  document.getElementById('nationality-modal').classList.remove('hidden');
}

function filterNationalities2() {
  const q = document.getElementById('profile-nationality-search').value.toLowerCase().trim();
  const dd = document.getElementById('nationality-dropdown-2');
  if (!q) { dd.style.display = 'none'; return; }
  const filtered = COUNTRIES.filter(([code, name]) => name.toLowerCase().includes(q));
  if (!filtered.length) { dd.style.display = 'none'; return; }
  dd.style.display = '';
  dd.innerHTML = filtered.map(([code, name]) =>
    `<div onclick="selectNationality2('${code}','${name}')" style="display:flex;align-items:center;gap:8px;padding:8px 12px;cursor:pointer;" onmouseover="this.style.background='var(--bg3)'" onmouseout="this.style.background=''">
      <img src="${flagUrl(code)}" style="width:24px;height:16px;object-fit:cover;border-radius:2px;">
      <span style="font-size:0.9rem;">${name}</span>
    </div>`
  ).join('');
}

function selectNationality2(code, name) {
  pendingNatCode = code;
  pendingNatName = name;
  document.getElementById('profile-nationality-search').value = name;
  document.getElementById('nationality-dropdown-2').style.display = 'none';
  const preview = document.getElementById('profile-nationality-preview-2');
  preview.style.display = 'flex';
  preview.innerHTML = `<img src="${flagUrl(code)}" style="width:24px;height:16px;object-fit:cover;border-radius:2px;"> ${name}`;
}

async function saveNationality() {
  if (!currentUser) return;
  currentUser.nationalityCode = pendingNatCode;
  currentUser.nationalityName = pendingNatName;
  LOCAL.set('currentUser', currentUser);
  await fsSave('users', currentUser);
  const users = getData('users', []);
  const idx = users.findIndex(u => u.id === currentUser.id);
  if (idx >= 0) {
    users[idx] = currentUser;
    _cache.users = users;
  }
  closeModal('nationality-modal');
  renderProfile();
  toast(currentLang === 'it' ? 'Nazionalità aggiornata! 🌍' : 'Nationality updated! 🌍', 'success');
}

// ============================================================
//  PUNTEGGI / LIVELLI
// ============================================================
function getUserLevel(score) {
  const levels = getData('levels', []).sort((a,b) => b.minScore - a.minScore);
  for (const lv of levels) {
    if (score >= lv.minScore) return lv;
  }
  // Punteggio sotto la soglia del livello più basso definito
  if (levels.length) {
    return { id: '__unqualified__', name: 'Non qualificabile', nameEn: 'Not qualified', minScore: 0 };
  }
  return null;
}

function renderAdminPunteggi() {
  const el = document.getElementById('admin-levels-list');
  if (!el) return;
  const levels = getData('levels', []).sort((a,b) => a.minScore - b.minScore);
  if (!levels.length) {
    el.innerHTML = '<p style="color:var(--muted);font-style:italic;">Nessun livello definito ancora.</p>';
    return;
  }
  el.innerHTML = `<table class="data-table compact"><thead><tr>
    <th>${(currentLang === 'it') ? 'Nome livello' : 'Level name'}</th><th>${(currentLang === 'it') ? 'Punteggio minimo' : 'Min. score'}</th><th></th>
  </tr></thead><tbody>
  ${levels.map(lv => `<tr>
    <td><strong>${lv.name}</strong>${lv.nameEn ? ' / ' + lv.nameEn : ''}</td>
    <td>${lv.minScore.toLocaleString('it-IT')} pt</td>
    <td>
      <button class="tbl-btn tbl-btn-edit" onclick="editLevel('${lv.id}')">${(currentLang === 'it') ? 'Modifica' : 'Edit'}</button>
      <button class="tbl-btn tbl-btn-del" onclick="deleteLevel('${lv.id}')" title="${(currentLang === 'it') ? 'Elimina questo livello' : 'Delete this level'}">🗑️</button>
    </td>
  </tr>`).join('')}
  </tbody></table>`;
}

function editLevel(id) {
  const lv = getData('levels', []).find(l => l.id === id);
  if (!lv) return;
  document.getElementById('level-edit-id').value = id;
  document.getElementById('level-name-input').value = lv.name;
  document.getElementById('level-name-en-input').value = lv.nameEn || '';
  document.getElementById('level-score-input').value = lv.minScore;
}

async function saveLevel() {
  const name = document.getElementById('level-name-input').value.trim();
  const nameEn = document.getElementById('level-name-en-input')?.value.trim() || '';
  const minScore = parseInt(document.getElementById('level-score-input').value);
  const editId = document.getElementById('level-edit-id').value;
  if (!name || isNaN(minScore)) { toast((currentLang === 'it' ? 'Compila nome e punteggio minimo' : 'Fill in name and minimum score'), 'error'); return; }

  let levels = getData('levels', []);
  if (editId) {
    const idx = levels.findIndex(l => l.id === editId);
    if (idx >= 0) {
      levels[idx] = { ...levels[idx], name, nameEn, minScore };
      await fsSave('levels', levels[idx]);
    }
  } else {
    const newLevel = { name, nameEn, minScore };
    const saved = await fsSave('levels', newLevel);
    levels.push(saved);
  }
  _cache.levels = levels;
  document.getElementById('level-edit-id').value = '';
  document.getElementById('level-name-input').value = '';
  document.getElementById('level-name-en-input').value = '';
  document.getElementById('level-score-input').value = '';
  renderAdminPunteggi();
  toast((currentLang === 'it' ? 'Livello salvato!' : 'Level saved!'), 'success');
}

async function deleteLevel(id) {
  if (!confirm(currentLang === 'it' ? 'Eliminare questo livello?' : 'Delete this level?')) return;
  let levels = getData('levels', []);
  levels = levels.filter(l => l.id !== id);
  _cache.levels = levels;
  await fsDelete('levels', id);
  renderAdminPunteggi();
}

// ============================================================
//  RISORSE
// ============================================================
// Scrive il contatore del mese corrente. ATTENZIONE: prima scriveva su
// email_stats/monthly campo "count", mentre TUTTI i lettori leggono
// email_stats/counter campo months[<anno-mese>]. Due documenti diversi: il
// pulsante "Correggi contatore" non ha quindi mai avuto alcun effetto — il
// toast diceva "aggiornato" e il numero a schermo restava identico.
// L'argomento, quando c'è, è sempre il numero di e-mail INVIATE (è così che lo
// passa recalcEmailCounterFromLog). Il campo dell'interfaccia invece contiene le
// e-mail RIMANENTI, per corrispondere al numero che mostra il pannello EmailJS:
// la conversione avviene qui, al confine, e la logica interna continua a
// ragionare in "inviate" — l'unità in cui il contatore è memorizzato.
async function saveEmailCounter(explicitSent) {
  let val;
  if (explicitSent !== undefined) {
    val = explicitSent;
  } else {
    const remaining = parseInt(document.getElementById('email-count-edit').value);
    if (isNaN(remaining) || remaining < 0 || remaining > EMAILJS_MONTHLY_LIMIT) {
      toast(currentLang === 'it'
        ? `Inserisci un numero fra 0 e ${EMAILJS_MONTHLY_LIMIT}`
        : `Enter a number between 0 and ${EMAILJS_MONTHLY_LIMIT}`, 'error');
      return;
    }
    val = EMAILJS_MONTHLY_LIMIT - remaining; // rimanenti → inviate
  }
  if (isNaN(val) || val < 0) { toast(currentLang === 'it' ? 'Valore non valido' : 'Invalid value', 'error'); return; }
  try {
    const now = new Date();
    const monthKey = now.getFullYear() + '-' + String(now.getMonth()+1).padStart(2,'0');
    const { doc, getDoc, setDoc } = window._fb;
    const ref = doc(db, 'email_stats', 'counter');
    // Qui la lettura è lecita: saveEmailCounter è raggiungibile solo dall'admin,
    // e l'admin è l'unico che può leggere email_stats.
    let data = { total: 0, months: {} };
    const snap = await getDoc(ref);
    if (snap.exists()) data = snap.data();
    const prev = (data.months && data.months[monthKey]) || 0;
    const newTotal = Math.max(0, (data.total || 0) + (val - prev)); // il totale segue la correzione del mese
    await setDoc(ref, { total: newTotal, months: { ...(data.months || {}), [monthKey]: val } }, { merge: true });
    await refreshEmailCountWidgets();
    const remainingNow = EMAILJS_MONTHLY_LIMIT - val;
    toast(currentLang === 'it'
      ? `Contatore aggiornato: ${val} inviate, ${remainingNow} rimanenti`
      : `Counter updated: ${val} sent, ${remainingNow} remaining`, 'success');
  } catch(e) {
    console.error('saveEmailCounter', e);
    toast(currentLang === 'it' ? 'Aggiornamento non riuscito' : 'Update failed', 'error');
  }
}

// Ricalcola il contatore del mese contando le e-mail effettivamente registrate
// in email_log (stato "sent", data nel mese corrente). Utile per rimettere in
// riga un contatore corrotto senza doverlo contare a mano.
// LIMITE, dichiarato anche nella conferma: email_log viene sfoltito a 200 voci
// più recenti. Finché le e-mail del mese sono tutte ancora nel log il conteggio
// è esatto; se il log fosse già stato tagliato oltre il confine del mese,
// sottostimerebbe. Meglio comunque di un valore palesemente sbagliato.
async function recalcEmailCounterFromLog() {
  const L = currentLang === 'it';
  const btn = document.getElementById('email-recalc-btn');
  try {
    if (btn) { btn.disabled = true; btn.textContent = L ? 'Conteggio…' : 'Counting…'; }
    const now = new Date();
    const monthKey = now.getFullYear() + '-' + String(now.getMonth()+1).padStart(2,'0');
    const logs = await fsGetAll('email_log');
    const sentThisMonth = logs.filter(e =>
      e.status === 'sent' && typeof e.date === 'string' && e.date.slice(0, 7) === monthKey
    ).length;
    const msg = L
      ? `Nel log risultano ${sentThisMonth} e-mail inviate in questo mese (${monthKey}).\n\nImpostare il contatore su questo valore?\n\nNota: il log conserva le 200 voci più recenti — se ne fossero già state eliminate di questo mese, il conteggio sarebbe per difetto.`
      : `The log shows ${sentThisMonth} e-mails sent this month (${monthKey}).\n\nSet the counter to this value?\n\nNote: the log keeps the 200 most recent entries — if any from this month were already trimmed, the count would be an underestimate.`;
    if (!confirm(msg)) return;
    await saveEmailCounter(sentThisMonth);
  } catch(e) {
    console.error('recalcEmailCounterFromLog', e);
    toast(L ? 'Ricalcolo non riuscito' : 'Recalculation failed', 'error');
  } finally {
    if (btn) { btn.disabled = false; btn.textContent = L ? '🔄 Ricalcola dal log' : '🔄 Recalculate from log'; }
  }
}

// Legge il conteggio e-mail del mese corrente e aggiorna qualsiasi widget
// presente in pagina — sia quello nella sezione Risorse (con modifica
// manuale) sia quello, identico ma in sola lettura, nella sezione E-mail
async function refreshEmailCountWidgets() {
  try {
    const now = new Date();
    const monthKey = now.getFullYear() + '-' + String(now.getMonth()+1).padStart(2,'0');
    const { doc, getDoc } = window._fb;
    const ref = doc(db, 'email_stats', 'counter');
    let count = 0;
    try {
      const snap = await getDoc(ref);
      if (snap.exists()) {
        const data = snap.data();
        count = (data.months && data.months[monthKey]) || 0;
      }
    } catch(e) {}
    const pct = Math.min(Math.round(count / EMAILJS_MONTHLY_LIMIT * 100), 100);
    const remaining = Math.max(0, EMAILJS_MONTHLY_LIMIT - count);
    const color = pct >= 90 ? 'var(--danger)' : pct >= 70 ? 'var(--warn)' : 'var(--accent)';
    ['', '-2'].forEach(suffix => {
      const el = document.getElementById('email-count-display' + suffix);
      if (el) el.textContent = count;
      // Il campo di correzione è in RIMANENTI (come il pannello EmailJS), a
      // differenza di tutto il resto del riquadro che è in INVIATE.
      const editEl = document.getElementById('email-count-edit' + suffix);
      if (editEl) editEl.value = remaining;
      const label = document.getElementById('email-count-label' + suffix);
      if (label) label.textContent = count + ' / ' + EMAILJS_MONTHLY_LIMIT;
      const pctEl = document.getElementById('email-count-pct' + suffix);
      if (pctEl) pctEl.textContent = pct + '%';
      const bar = document.getElementById('email-count-bar' + suffix);
      if (bar) { bar.style.width = pct + '%'; bar.style.background = color; }
    });
  } catch(e) { console.error('Email stats error', e); }
}

async function renderAdminRisorse() {
  // Email counter — reads from same source as Mail tab
  await refreshEmailCountWidgets();
  await refreshPwdResetCountWidget();

  // Selettore serie del "Ricalcola i Nomi completi" — stesso stile dei select degli import (v5.773)
  const rcSel = document.getElementById('recompute-fullnames-series-select');
  if (rcSel) {
    const rcSeries = getData('series', []).slice().sort((a, b) => (a.order || 0) - (b.order || 0) || (a.name || '').localeCompare(b.name || '', 'it'));
    const cur = rcSel.value;
    rcSel.innerHTML = '<option value="">-- ' + (currentLang === 'it' ? 'Seleziona una serie' : 'Select a series') + ' --</option>' +
      rcSeries.map(s => `<option value="${s.id}" data-name="${esc(s.name)}">${esc(s.name)}</option>`).join('');
    if (cur) rcSel.value = cur;
  }

  // Firebase doc count
  try {
    const collections = ['users', 'figurines', 'series', 'posts', 'segnalazioni', 'eventi'];
    let total = 0;
    for (const col of collections) {
      const docs = _cache[col] || [];
      total += docs.length;
    }
    const el = document.getElementById('firebase-docs-count');
    if (el) el.textContent = total.toLocaleString('it-IT');
  } catch(e) { console.error('Firebase stats error', e); }

  // Letture fsGetAll misurate oggi
  const readsEl = document.getElementById('firebase-reads-count');
  if (readsEl) {
    const reads = getReadCount();
    const pct = Math.round(reads / 50000 * 100);
    const color = pct >= 90 ? 'var(--danger)' : pct >= 60 ? 'var(--warn)' : 'var(--accent)';
    readsEl.innerHTML = `<span style="color:${color};">${reads.toLocaleString('it-IT')}</span> <span style="font-size:0.72rem;color:var(--muted);">(${pct}% del limite)</span>`;
  }

  // Cloudinary upload counter
  const clUploads = document.getElementById('cloudinary-uploads-count');
  const clCredits = document.getElementById('cloudinary-credits-count');
  if (clUploads || clCredits) {
    const uploads = getCloudinaryUploadCount();
    const credits = (uploads * 0.01).toFixed(2);
    const pct = Math.round(uploads * 0.01 / 25 * 100);
    const color = pct >= 90 ? 'var(--danger)' : pct >= 60 ? 'var(--warn)' : 'var(--accent)';
    if (clUploads) clUploads.innerHTML = `<span style="color:${color};">${uploads.toLocaleString('it-IT')}</span>`;
    if (clCredits) clCredits.innerHTML = `<span style="color:${color};">~${credits}</span> <span style="font-size:0.72rem;color:var(--muted);">(${pct}% del limite)</span>`;
  }

  // Storico letture ultimi 30 giorni
  const histEl = document.getElementById('firebase-reads-history');
  if (histEl) {
    const history = getReadHistory();
    if (!history.length) {
      histEl.innerHTML = '<p style="font-size:0.78rem;color:var(--muted);font-style:italic;">Nessuno storico ancora — si accumula giorno per giorno.</p>';
    } else {
      const fmtDate = d => {
        const [y, m, day] = d.split('-');
        return day + '/' + m + '/' + y;
      };
      histEl.innerHTML = '<div style="font-size:0.78rem;font-weight:600;color:var(--muted);margin-bottom:0.4rem;">📅 Storico letture (ultimi ' + history.length + ' giorni)</div>' +
        '<table class="data-table compact"><thead><tr><th>Data (PT)</th><th>Letture fsGetAll</th><th>% limite</th></tr></thead><tbody>' +
        history.map(r => {
          const pct = Math.round(r.count / 50000 * 100);
          const color = pct >= 90 ? 'var(--danger)' : pct >= 60 ? 'var(--warn)' : 'var(--accent)';
          return '<tr><td>' + fmtDate(r.date) + '</td><td style="color:' + color + ';font-weight:600;">' + r.count.toLocaleString('it-IT') + '</td><td style="color:' + color + ';">' + pct + '%</td></tr>';
        }).join('') +
        '</tbody></table>';
    }
  }
}

// ============================================================
//  EVENTI
// ============================================================
// Le descrizioni degli eventi vengono rese con innerHTML nella tabella admin
// (renderAdminEventi). Alcune contengono testo scritto dagli utenti — il titolo
// di un post, per esempio — quindi vanno neutralizzate: senza, un utente potrebbe
// intitolare un post "<img src=x onerror=...>" e farlo eseguire nel pannello
// dell'admin. Da qui in avanti l'HTML nelle descrizioni lo mettiamo NOI
// (il <strong> attorno al nome), e tutto ciò che arriva dall'utente passa da esc().
function esc(str) {
  return String(str ?? '').replace(/[&<>"']/g, c =>
    ({ '&':'&amp;', '<':'&lt;', '>':'&gt;', '"':'&quot;', "'":'&#39;' }[c]));
}
// Nome utente in grassetto: uniforme in tutti i log, come da richiesta di Franco.
function bold(str) { return '<strong>' + esc(str) + '</strong>'; }

// EVENTI_RETENTION_MONTHS: scadenza del registro eventi. Il registro sopravvive
// alla cancellazione dell'account (scelta di Franco: e' un registro di sicurezza,
// e sapere CHI se n'e' andato e' proprio il motivo per cui esiste), ma non
// sopravvive al tempo.
const EVENTI_RETENTION_MONTHS = 6;

async function logEvent(type, description, extra = {}) {
  const event = {
    type,
    description,
    date: new Date().toISOString(),
    read: false,
    // authUid rende gli eventi RITROVABILI per utente: finora la descrizione era
    // testo libero, e cercarci dentro il nome sarebbe stato fragile e sbagliato
    // (basta un utente che si chiami "login" o "admin").
    // Resta null per gli eventi generati da chi NON e' autenticato — in pratica
    // solo 'reset_pwd', che parte dal form di login: li' non c'e' nessuna sessione
    // da cui prenderlo, e quell'evento non sara' mai riconducibile a un utente.
    // Un chiamante puo' passarlo esplicitamente in extra (es. registrazione, dove
    // currentUser non e' ancora impostato).
    authUid: currentUser?.authUid || null,
    ...extra
  };
  try {
    const saved = await fsSave('eventi', event);
    if (!_cache.eventi) _cache.eventi = [];
    _cache.eventi.push(saved);
    updateBellBadge();
  } catch(e) { console.error('logEvent error:', e); }
}

function renderAdminEventi() {
  const el = document.getElementById('admin-eventi-table');
  if (!el) return;
  const eventi = (_cache.eventi || []).sort((a,b) => new Date(b.date) - new Date(a.date));
  if (!eventi.length) {
    el.innerHTML = '<p style="color:var(--muted);">' + (currentLang === 'it' ? 'Nessun evento ancora.' : 'No events yet.') + '</p>';
    return;
  }
  const typeIcon = { 'new_user': '👤', 'new_post': '📝', 'reset_pwd': '🔑', 'login': '🔓', 'newsletter_off': '📭', 'account_deleted': '🗑️' };
  const noBellEvTypes = ['login'];
  el.innerHTML = `<table class="data-table compact"><thead><tr>
    <th>${(currentLang === 'it') ? 'Data' : 'Date'}</th><th>${(currentLang === 'it') ? 'Tipo' : 'Type'}</th><th>${(currentLang === 'it') ? 'Descrizione' : 'Description'}</th><th></th>
  </tr></thead><tbody>
  ${eventi.map(e => `<tr style="${e.read ? '' : 'background:rgba(181,255,46,0.05);'}">
    <td style="white-space:nowrap;font-size:0.78rem;">${new Date(e.date).toLocaleDateString('it-IT')} ${new Date(e.date).toLocaleTimeString('it-IT', {hour:'2-digit',minute:'2-digit'})}</td>
    <td>${typeIcon[e.type] || '📌'}</td>
    <td>${e.description}</td>
    <td style="white-space:nowrap;">
      <button class="tbl-btn tbl-btn-edit" onclick="markEventRead('${e.id}')">${e.read ? '✓' : (currentLang === 'it' ? 'Segna come letto' : 'Mark as read')}</button>
      <button class="tbl-btn tbl-btn-del" style="margin-left:0.35rem;" onclick="deleteEvento('${e.id}')" title="${currentLang === 'it' ? 'Elimina questo evento' : 'Delete this event'}">🗑️</button>
    </td>
  </tr>`).join('')}
  </tbody></table>`;
}

// Cancellazione di un singolo evento. Serve soprattutto a ripulire i dati di
// prova: il registro si sfoltisce da solo a 6 mesi (purgeOldEventi), ma per
// ripartire puliti quel tempo e' troppo.
async function deleteEvento(id) {
  if (!confirm(currentLang === 'it'
    ? 'Eliminare questo evento dal registro?'
    : 'Delete this event from the log?')) return;
  try {
    await fsDelete('eventi', id);
    _cache.eventi = getData('eventi', []).filter(e => e.id !== id);
    updateBellBadge(); // l'evento poteva essere non letto: il contatore va rifatto
    renderAdminEventi();
    toast(currentLang === 'it' ? 'Evento eliminato' : 'Event deleted', 'success');
  } catch(e) {
    console.error('deleteEvento', e);
    toast(currentLang === 'it' ? 'Eliminazione non riuscita' : 'Delete failed', 'error');
  }
}

async function markEventRead(id) {
  const idx = (_cache.eventi || []).findIndex(e => e.id === id);
  if (idx < 0) return;
  _cache.eventi[idx].read = true;
  await fsSave('eventi', _cache.eventi[idx]);
  updateBellBadge();
  renderAdminEventi();
}

// ============================================================
//  SEGNALAZIONI
// ============================================================
function isImpersonating() {
  return !!(_realAdmin);
}

function impersonateUser(userId) {
  const user = getData('users', []).find(u => u.id === userId);
  if (!user || user.isAdmin) return;
  const msg = (currentLang === 'it' ? 'Impersonare ' : 'Impersonate ') + user.username + '?';
  if (!confirm(msg)) return;
  _realAdmin = { ...currentUser };
  currentUser = { ...user };
  _showImpersonateBanner();
  showPage('home');
  renderAll();
  updateNavUser();
  toast('🎭 ' + (currentLang === 'it' ? 'Impersonando: ' : 'Impersonating: ') + user.username, 'success');
}

function stopImpersonation() {
  if (!_realAdmin) return;
  currentUser = { ..._realAdmin };
  _realAdmin = null;
  _hideImpersonateBanner();
  showPage('profile');
  setTimeout(() => adminTab('users'), 200);
  renderAll();
  updateNavUser();
  toast(currentLang === 'it' ? '✅ Tornato admin' : '✅ Back to admin', 'success');
}

function _showImpersonateBanner() {
  let banner = document.getElementById('impersonate-banner');
  if (!banner) {
    banner = document.createElement('div');
    banner.id = 'impersonate-banner';
    banner.style.cssText = 'position:fixed;top:64px;left:1rem;z-index:99999;background:var(--warn);color:#0e0a1a;padding:0.3rem 0.75rem;display:flex;align-items:center;gap:0.75rem;font-family:var(--font-ui);font-size:0.82rem;font-weight:700;box-shadow:0 2px 8px rgba(0,0,0,0.3);border-radius:8px;max-width:33vw;';
    document.body.prepend(banner);
  }
  banner.innerHTML = '<span>🎭 ' + (currentLang === 'it' ? 'Stai impersonando' : 'Impersonating') + ': <strong>' + currentUser.username + '</strong> — ' + (currentLang === 'it' ? 'WRITE MODE' : 'WRITE MODE') + '</span><button onclick="stopImpersonation()" style="background:#0e0a1a;color:var(--warn);border:none;border-radius:6px;padding:4px 14px;cursor:pointer;font-weight:700;">' + (currentLang === 'it' ? '✕ Torna admin' : '✕ Back to admin') + '</button>';
  banner.style.display = 'flex';
}

function _hideImpersonateBanner() {
  const banner = document.getElementById('impersonate-banner');
  if (banner) banner.remove();

}

// ============================================================
//  WISHLIST FUNCTIONS
// ============================================================
let _wishlist = [];

function getWishlist() { return _wishlist; }

function updateWishlistBadge() {
  const badge = document.getElementById('nav-wishlist-badge');
  if (!badge) return;
  const count = (_wishlist || []).length;
  if (count > 0) {
    badge.textContent = count > 99 ? '99+' : count;
    badge.style.display = '';
  } else {
    badge.style.display = 'none';
  }
}

async function loadWishlist() {
  if (!currentUser) { _wishlist = []; return; }
  try {
    const doc = await fsGet('wishlists', currentUser.id);
    _wishlist = doc?.items || [];
  } catch(e) { _wishlist = []; }
  updateWishlistBadge();
}

async function saveWishlist() {
  if (!currentUser) return;
  try {
    await fsSave('wishlists', { id: currentUser.id, userId: currentUser.id, authUid: currentUser.authUid || null, items: _wishlist });
  } catch(e) { console.error('saveWishlist error', e); }
  updateWishlistBadge();
}

async function toggleWishlist(figId) {
  if (!currentUser) { openAuth('register'); return; }
  if (_wishlist.includes(figId)) {
    _wishlist = _wishlist.filter(id => id !== figId);
  } else {
    _wishlist.push(figId);
  }
  // Aggiorna visivamente tutti i pulsanti cuore corrispondenti (griglia e/o tabella), senza re-render completo
  const inWishlist = _wishlist.includes(figId);
  document.querySelectorAll(`.wishlist-heart-btn[data-wishlist-id="${figId}"]`).forEach(btn => {
    btn.textContent = inWishlist ? '❤️' : '♡';
    btn.style.background = inWishlist ? 'rgba(var(--danger-rgb),0.15)' : 'transparent';
    btn.style.borderColor = inWishlist ? 'var(--danger)' : 'rgba(255,255,255,0.15)';
    btn.style.color = inWishlist ? 'var(--danger)' : 'var(--muted)';
    btn.title = currentLang === 'it' ? (inWishlist ? 'Togli da "Ciò che cerco"' : 'Aggiungi a "Ciò che cerco"') : (inWishlist ? 'Remove from "What I\'m looking for"' : 'Add to "What I\'m looking for"');
  });
  saveWishlist(); // fire-and-forget, non blocchiamo il thread UI
  if (document.getElementById('page-wishlist')?.classList.contains('active')) renderWishlist();
  if (bulkEditActive) renderBulkEditView();
}

function updateMsgBadge() {
  const badge = document.getElementById('nav-msg-badge');
  const btn = document.getElementById('nav-msg-btn');
  if (!badge || !btn) return;
  const contacts = _cache.contact_messages || [];
  const unread = contacts.filter(m => !m.read).length;
  if (unread > 0) {
    badge.style.display = '';
    badge.textContent = unread > 9 ? '9+' : unread;
  } else {
    badge.style.display = 'none';
  }
}

function updateBellBadge() {
  const badge = document.getElementById('nav-bell-badge');
  if (!badge) return;
  const segnalazioni = _cache.segnalazioni || [];
  const eventi = _cache.eventi || [];
  const noBellTypes = ['login'];
  const unread = segnalazioni.filter(s => !s.read).length + eventi.filter(e => !e.read && !noBellTypes.includes(e.type)).length;
  if (unread > 0) {
    badge.style.display = '';
    badge.textContent = unread > 9 ? '9+' : unread;
  } else {
    badge.style.display = 'none';
  }
}

function switchFigDetailTab(tab) {
  const genDiv = document.getElementById('figdetail-tab-generale');
  const ebayDiv = document.getElementById('figdetail-tab-ebay');
  const genBtn = document.getElementById('figdetail-tab-btn-generale');
  const ebayBtn = document.getElementById('figdetail-tab-btn-ebay');
  if (genDiv) genDiv.style.display = tab === 'generale' ? '' : 'none';
  if (ebayDiv) ebayDiv.style.display = tab === 'ebay' ? '' : 'none';
  if (genBtn) { genBtn.style.borderBottomColor = tab === 'generale' ? 'var(--accent)' : 'transparent'; genBtn.style.color = tab === 'generale' ? 'var(--accent)' : 'var(--muted)'; }
  if (ebayBtn) { ebayBtn.style.borderBottomColor = tab === 'ebay' ? 'var(--accent)' : 'transparent'; ebayBtn.style.color = tab === 'ebay' ? 'var(--accent)' : 'var(--muted)'; }
}

function openFigDetail(figId) {
  _figEditImgData = null; // reset immagine editing precedente
  _currentDetailFigId = figId;
  const allFigs = getData('figurines', []);
  const f = allFigs.find(x => x.id === figId);
  if (!f) return;
  const owned = getOwned();
  const isOwned = owned.includes(f.id);
  const isAdmin = currentUser?.isAdmin;
  const figSeries = getData('series', []).find(s => s.id === f.seriesId);

  // Frecce di navigazione avanti/indietro (solo se la figurina fa parte dell'elenco attualmente in griglia)
  const navIdx = _gridOrderedIds.indexOf(figId);
  const prevBtn = document.getElementById('fig-detail-prev-btn');
  const nextBtn = document.getElementById('fig-detail-next-btn');
  if (prevBtn && nextBtn) {
    prevBtn.title = currentLang === 'it' ? 'Precedente' : 'Previous';
    nextBtn.title = currentLang === 'it' ? 'Successivo' : 'Next';
    if (navIdx === -1) {
      prevBtn.style.visibility = 'hidden';
      nextBtn.style.visibility = 'hidden';
    } else {
      prevBtn.style.visibility = '';
      nextBtn.style.visibility = '';
      prevBtn.disabled = navIdx <= 0;
      prevBtn.style.opacity = navIdx <= 0 ? '0.3' : '1';
      nextBtn.disabled = navIdx >= _gridOrderedIds.length - 1;
      nextBtn.style.opacity = navIdx >= _gridOrderedIds.length - 1 ? '0.3' : '1';
    }
  }

  // Title
  const titleEl = document.getElementById('fig-detail-title');
  const displayNameForTitle = f.fullName || f.name;
  if (titleEl) titleEl.textContent = f.number ? ('#' + f.number + ' - ' + displayNameForTitle) : displayNameForTitle;
  // v5.849 — su telefono il titolo del modale sparisce: ripete Numero e Nome, che sono le prime
  // due righe della scheda. Il testo resta comunque impostato, cosi' se la finestra torna larga
  // (o per i lettori di schermo) c'e'. Nascosto via CSS, vedi .modal-title in sezione mobile.

  // Reset contenuto modal (evita residui da aperture precedenti)
  document.getElementById('fig-detail-content').innerHTML = '';
  document.getElementById('fig-detail-photo').innerHTML = '';

  // Build content
  const rows = [];
  // v5.834 — SOLO TELEFONO: l'ordine della scheda diventa Numero, Nome, FOTO, Punteggio, e poi
  // tutto il resto. Numero e Nome finiscono in rowsTop (contenitore #fig-detail-top, che il CSS
  // mette prima del box foto); il Punteggio viene messo da parte e rimesso in testa a rows, cioe'
  // subito SOTTO le foto. Sul desktop rowsTop resta vuoto e l'ordine e' quello di sempre.
  const _mobileDetail = _isMobileViewport();
  const rowsTop = [];
  let _rowScoreMobile = '';

  // Serie (prima informazione, sempre visibile, utile arrivando da una ricerca)
  (_mobileDetail ? rowsTop : rows).push(`<div class="detail-row"><span class="detail-label">${(currentLang === 'it' ? 'Serie' : 'Series')}</span><span class="detail-value" style="font-weight:600;">${figSeries?.name || ''}</span></div>`);

  // v5.841 — la riga "Retro collegato" NON si stampa piu' (ne' su telefono ne' su desktop):
  // sotto la foto del Retro c'e' gia' lo STESSO link (retroCaption, piu' in basso in questa
  // funzione), che compare ogni volta che il Retro esiste — anche quando non ha foto, perche'
  // la didascalia dipende dall'esistenza del Retro, non dell'immagine. Era lo stesso
  // collegamento due volte nella stessa schermata.
  // Resta il caso GUASTO: se retroId punta a un record che non esiste piu', il box foto non ha
  // nessun Retro da mostrare, quindi questa e' l'unica sede in cui il problema si vede.
  if (f.retroId && !getData('figurines', []).find(x => x.id === f.retroId)) {
    rows.push(`<div class="detail-row"><span class="detail-label">${(currentLang === 'it' ? 'Retro collegato' : 'Linked retro')}</span><span class="detail-value" style="color:var(--danger);">${(currentLang === 'it' ? 'ID collegato non trovato: ' : 'Linked ID not found: ')}${f.retroId}</span></div>`);
  }

  // v5.782 — Franco: "la vista e la modifica devono coincidere (a parte i campi vuoti, che in vista
  // si nascondono)". Numero e Nome mancavano come righe nella vista (per le figurine comparivano
  // solo nel titolo, v5.764): ora ci sono, quando presenti. Numero: i Retro non sono numerati, quindi
  // per loro la riga resta assente. Nome: tutte le sezioni (prima solo Retro).
  if (f.number) {
    const _rowNumero = `<div class="detail-row"><span class="detail-label">${(currentLang === 'it' ? 'Numero' : 'Number')}</span><span class="detail-value">#${f.number}</span></div>`;
    (_mobileDetail ? rowsTop : rows).push(_rowNumero);
  }
  // Categoria (sempre visibile per i Retro), Sottocategoria (solo se popolata).
  if (f.section === 'retros') {
    rows.push(`<div class="detail-row"><span class="detail-label">${(currentLang === 'it' ? 'Categoria' : 'Category')}</span><span class="detail-value">${f.category || '<span style="color:var(--muted);font-style:italic;">' + (currentLang === 'it' ? 'non impostata' : 'not set') + '</span>'}</span></div>`);
    if (f.subcategory) {
      rows.push(`<div class="detail-row"><span class="detail-label">${(currentLang === 'it' ? 'Sottocategoria' : 'Subcategory')}</span><span class="detail-value">${f.subcategory}</span></div>`);
    }
  }
  // Nome — tutte le sezioni, quando presente (hide-empty).
  if (f.name) {
    const _rowNome = `<div class="detail-row"><span class="detail-label">${(currentLang === 'it' ? 'Nome' : 'Name')}</span><span class="detail-value">${esc(f.name)}</span></div>`;
    (_mobileDetail ? rowsTop : rows).push(_rowNome);
  }

  // Sottoserie - show only if populated (admin sees it always in edit modal, not here)
  if (f.subseries) {
    rows.push(`<div class="detail-row"><span class="detail-label">${(currentLang === 'it' ? 'Sottoserie' : 'Subseries')}</span><span class="detail-value">${f.subseries}</span></div>`);
  }

  // Punteggio
  if (f.score > 0 || isAdmin) {
    (_mobileDetail ? { push: v => { _rowScoreMobile = v; } } : rows).push(`<div class="detail-row"><span class="detail-label">${currentLang === 'it' ? 'Punteggio' : 'Score'}</span><span class="detail-value">${f.score > 0 ? '⭐ ' + f.score + ' pt' : '<span style="color:var(--muted);font-style:italic;">' + (currentLang === 'it' ? 'non assegnato' : 'not assigned') + '</span>'}</span></div>`);
  }

  // Da vendere: spostato nel tab Ebay, vedi sotto

  // Flag Variazione ufficiale / non ufficiale / Change (solo se attivi, come frase)
  if (f.isVariation) {
    rows.push(`<div class="detail-row" style="border-bottom:none;"><span class="detail-value" style="font-style:italic;color:var(--accent);">${currentLang === 'it' ? 'Questa figurina è una variazione ufficiale' : 'This sticker is an official variation'}</span></div>`);
  }
  if (f.isUnofficialVariation) {
    rows.push(`<div class="detail-row" style="border-bottom:none;"><span class="detail-value" style="font-style:italic;color:var(--accent);">${currentLang === 'it' ? 'Questa figurina è una variazione non ufficiale' : 'This sticker is an unofficial variation'}</span></div>`);
  }
  if (f.isChange) {
    const changeLabel = f.section === 'retros'
      ? (currentLang === 'it' ? 'Questo retro è un Change' : 'This retro is a Change')
      : (currentLang === 'it' ? 'Questa figurina è un Change' : 'This sticker is a Change');
    rows.push(`<div class="detail-row" style="border-bottom:none;"><span class="detail-value" style="font-style:italic;color:var(--accent);">${changeLabel}</span></div>`);
  }
  // Simmetrico al Change (v5.769): la frase "Questo … è un errore di stampa"
  if (f.isPrintError) {
    const peLabel = f.section === 'retros'
      ? (currentLang === 'it' ? 'Questo retro è un errore di stampa' : 'This retro is a print error')
      : (currentLang === 'it' ? 'Questa figurina è un errore di stampa' : 'This sticker is a print error');
    rows.push(`<div class="detail-row" style="border-bottom:none;"><span class="detail-value" style="font-style:italic;color:var(--accent);">${peLabel}</span></div>`);
  }
  // v5.849 — su telefono la riga che QUALIFICA la variante (tipo di change, tipo di errore di
  // stampa, oppure il retro della variazione) sale in cima, subito dopo il Nome: e' quella che
  // distingue questa figurina dalla sua base, quindi va letta insieme al nome, non in fondo.
  if (f.isChange && f.changeType) {
    (_mobileDetail ? rowsTop : rows).push(`<div class="detail-row"><span class="detail-label">${currentLang === 'it' ? 'Tipo di change' : 'Change type'}</span><span class="detail-value">${f.changeType}</span></div>`);
  }
  // Tipo di errore di stampa (testo libero, tutte le sezioni) — per gli Errori di stampa la riga
  // e' SEMPRE mostrata (v5.770): il tipo e' facoltativo, quindi quando vuoto si scrive "non
  // impostato" invece di nascondere la riga (a differenza del changeType, che e' obbligatorio).
  if (f.isPrintError) {
    (_mobileDetail ? rowsTop : rows).push(`<div class="detail-row"><span class="detail-label">${currentLang === 'it' ? 'Tipo di errore di stampa' : 'Print error type'}</span><span class="detail-value">${f.printErrorType ? esc(f.printErrorType) : '<span style="color:var(--muted);font-style:italic;">' + (currentLang === 'it' ? 'non impostato' : 'not set') + '</span>'}</span></div>`);
  }

  // v5.849 — su telefono, per una VARIAZIONE (ufficiale o non ufficiale) la riga che la qualifica
  // e' il RETRO: e' proprio il retro a distinguerla dalla base. Sale in cima come fanno il tipo di
  // change e il tipo di errore di stampa; sul desktop resta la didascalia sotto la foto.
  if (_mobileDetail && (f.isVariation || f.isUnofficialVariation) && !f.isChange && !f.isPrintError && f.retroId) {
    const _varRetro = getData('figurines', []).find(x => x.id === f.retroId);
    if (_varRetro) {
      const _vp = [_varRetro.category, _varRetro.subcategory].map(v => (v||'').trim()).filter(Boolean);
      rowsTop.push(`<div class="detail-row"><span class="detail-label">${currentLang === 'it' ? 'Retro' : 'Back'}</span><span class="detail-value"><a href="#" onclick="openFigDetail('${_varRetro.id}');return false;" style="color:var(--accent);text-decoration:underline;">${_vp.length ? _vp.join(' · ') + ' — ' : ''}${esc(_varRetro.name || '')} ↗</a></span></div>`);
    }
  }
  if ((f.isVariation || f.isUnofficialVariation || f.isChange || f.isPrintError) && f.baseFigurineId) {
    const baseFig = getData('figurines', []).find(x => x.id === f.baseFigurineId);
    if (baseFig) {
      // v5.769 — per un Errore di stampa il collegamento dice "Errore di stampa di" (prima il
      // ramo mancava e per gli errori di stampa il link alla base non compariva affatto).
      const relationLabel = f.isPrintError
        ? (currentLang === 'it' ? 'Errore di stampa di' : 'Print error of')
        : (f.section === 'retros'
            ? (currentLang === 'it' ? 'Change di' : 'Change of')
            : (currentLang === 'it' ? 'Variazione di' : 'Variation of'));
      rows.push(`<div class="detail-row" style="border-bottom:none;"><span class="detail-value" style="font-style:italic;color:var(--muted);">${relationLabel}: <a href="#" onclick="openFigDetail('${baseFig.id}');return false;" style="color:var(--accent);text-decoration:underline;">${baseFig.number ? '#' + baseFig.number + ' ' : ''}${baseFig.name}</a></span></div>`);
    }
  }

  // Descrizione
  if (f.desc) {
    rows.push(`<div class="detail-row" style="align-items:flex-start;"><span class="detail-label">${currentLang === 'it' ? 'Descrizione' : 'Description'}</span><span class="detail-value" style="font-size:0.88rem;line-height:1.5;">${f.desc}</span></div>`);
  }

  // Taglia (only for series with hasSizes)
  if (figSeries?.hasSizes || (isAdmin && figSeries?.hasSizes)) {
    if (f.size || isAdmin) {
      rows.push(`<div class="detail-row"><span class="detail-label">${(currentLang === 'it' ? 'Taglia' : 'Size')}</span><span class="detail-value">${f.size || '<span style="color:var(--muted);font-style:italic;">' + (currentLang === 'it' ? 'non impostata' : 'not set') + '</span>'}</span></div>`);
    }
  }

  // Numero di variazioni esistenti - always show (default 1)

  // Foto (shown in separate right column)
  const photoEl = document.getElementById('fig-detail-photo');
  if (photoEl) {
    // v5.786 — anche i Change usano il FRONTE della figurina base; il retro è quello proprio del Change
    // se presente, altrimenti quello della base (come sulla card).
    const isVar = f.isVariation || f.isUnofficialVariation || f.isChange;
    const _detBase = (isVar && f.baseFigurineId) ? getData('figurines', []).find(x => x.id === f.baseFigurineId) : null;
    const _detEffRetroId = f.isChange ? (f.retroId || _detBase?.retroId || null) : f.retroId;
    if (_detEffRetroId || (isVar && f.baseFigurineId)) {
      // Variazione/Change o figurina base con Retro collegato: mostra Fronte (sx) + Retro (dx) affiancati
      const baseFig = _detBase;
      const frontImg = baseFig ? baseFig.img : f.img;
      const retroFig = _detEffRetroId ? getData('figurines', []).find(x => x.id === _detEffRetroId) : null;
      const noPhotoBox = '<div style="width:100%;height:200px;background:var(--card2);border-radius:8px;display:flex;align-items:center;justify-content:center;color:var(--muted);font-size:0.75rem;text-align:center;padding:8px;">' + (currentLang === 'it' ? 'Foto non disponibile' : 'Photo not available') + '</div>';
      const baseHTML = frontImg
        ? `<img src="${cloudinaryUrl(frontImg, 'w_400,h_400,c_fit,q_auto,f_auto')}" style="width:100%;object-fit:contain;border-radius:8px;background:var(--card2);padding:6px;">`
        : noPhotoBox;
      const retroHTML = retroFig?.img
        ? `<img src="${cloudinaryUrl(retroFig.img, 'w_400,h_400,c_fit,q_auto,f_auto')}" style="width:100%;object-fit:contain;border-radius:8px;background:var(--card2);padding:6px;">`
        : noPhotoBox;
      const retroCaption = retroFig
        ? (() => { const parts = [retroFig.category, retroFig.subcategory].map(v => (v||'').trim()).filter(Boolean); return `<div style="font-size:0.72rem;text-align:center;margin-top:4px;"><a href="#" onclick="openFigDetail('${retroFig.id}');return false;" style="color:var(--accent);text-decoration:underline;">${parts.length ? parts.join(' · ') + ' — ' : ''}${retroFig.name} ↗</a></div>`; })()
        : '';
      photoEl.innerHTML = `
        <div style="display:grid;grid-template-columns:1fr 1fr;gap:0.5rem;">
          <div>
            <div style="font-size:0.7rem;color:var(--muted);text-align:center;margin-bottom:4px;">${currentLang === 'it' ? 'Fronte' : 'Front'}</div>
            ${baseHTML}
          </div>
          <div>
            <div style="font-size:0.7rem;color:var(--muted);text-align:center;margin-bottom:4px;">${currentLang === 'it' ? 'Retro' : 'Back'}</div>
            ${retroHTML}
            ${retroCaption}
          </div>
        </div>`;
    } else {
      photoEl.innerHTML = f.img ? `<img src="${cloudinaryUrl(f.img, 'w_640,h_640,c_fit,q_auto,f_auto')}" style="width:100%;object-fit:contain;border-radius:8px;background:var(--card2);padding:6px;">` : '<div style="width:100%;height:280px;background:var(--card2);border-radius:8px;display:flex;align-items:center;justify-content:center;color:var(--muted);font-size:0.75rem;text-align:center;padding:8px;">' + (currentLang === 'it' ? 'Foto non ancora disponibile' : 'Photo not yet available') + '</div>';
    }
  }

  // Mia lista toggle
  if (currentUser) {
    rows.push(`<div class="detail-row detail-row-mylist" style="align-items:center;">
      <span class="detail-label">${currentLang === 'it' ? "Mia lista" : 'My list'}</span>
      <button class="owned-btn ${isOwned ? 'on' : ''}" id="fig-detail-toggle" title="${isOwned ? (currentLang==='it'?'\u00c8 nella tua lista':'In your list') : (currentLang==='it'?'Aggiungi alla tua lista':'Add to your list')}" onclick="toggleOwnedFromDetail('${f.id}')">\u2713</button>
    </div>`);
  }

  // Cuore "Ciò che cerco" (solo per utenti non-admin)
  if (currentUser && !isAdmin) {
    const inWishlist = _wishlist.includes(f.id);
    rows.push(`<div class="detail-row detail-row-wishlist" style="align-items:center;">
      <span class="detail-label">${currentLang === 'it' ? 'Ciò che cerco' : "What I'm looking for"}</span>
      <button id="fig-detail-wishlist-btn" data-fig-id="${f.id}" onclick="event.stopPropagation();toggleWishlistFromDetail('${f.id}')" title="${currentLang === 'it' ? (inWishlist ? 'Togli da &quot;Ciò che cerco&quot;' : 'Aggiungi a &quot;Ciò che cerco&quot;') : (inWishlist ? 'Remove from &quot;What I\'m looking for&quot;' : 'Add to &quot;What I\'m looking for&quot;')}" style="background:${inWishlist ? 'rgba(var(--danger-rgb),0.15)' : 'transparent'};border:1px solid ${inWishlist ? 'var(--danger)' : 'rgba(255,255,255,0.15)'};color:${inWishlist ? 'var(--danger)' : 'var(--muted)'};border-radius:8px;padding:3px 10px;cursor:pointer;font-size:1.1rem;line-height:1;position:relative;z-index:2;">${inWishlist ? '❤️' : '♡'}</button>
    </div>`);
  }

  // Figurine collegate (variazioni/change di cui questa è la base) — tab
  rows.push(buildLinkedFiguresTabsHTML(f.id));

  // Bottom buttons (tenuti fuori dai tab, sempre visibili)
  let bottomButtons = '';
  if (isAdmin) {
    bottomButtons = `<div style="margin-top:1rem;display:flex;gap:0.5rem;justify-content:flex-end;">
      <button class="tbl-btn tbl-btn-edit" style="font-size:0.92rem;padding:6px 14px;" onclick="switchToEditMode('${f.id}')">&#9998; ${(currentLang === 'it') ? 'Modifica' : 'Edit'}</button>
      <button class="tbl-btn tbl-btn-edit" style="font-size:0.92rem;padding:6px 14px;" onclick="cloneFigurine('${f.id}')">&#10697; ${(currentLang === 'it') ? 'Clona' : 'Clone'}</button>
      <button class="tbl-btn tbl-btn-del" style="font-size:0.92rem;padding:6px 14px;" onclick="deleteItemFromDetail('${f.id}')">🗑️ ${(currentLang === 'it') ? 'Elimina' : 'Delete'}</button>
    </div>`;
  } else if (currentUser) {
    bottomButtons = `<div style="margin-top:1rem;text-align:right;">
      <button onclick="closeModal('fig-detail-modal');openSegnalazioneModal('${f.id}')" style="font-size:0.82rem;padding:4px 12px;border-radius:8px;border:1px solid rgba(255,255,255,0.15);background:transparent;color:var(--muted);cursor:pointer;">🚩 ${currentLang === 'it' ? 'Segnala errore' : 'Report an error'}</button>
    </div>`;
  }

  // v5.832 — la sezione Ebay del dettaglio (tab "Ebay" + foto Ebay) e' roba da admin: su telefono
  // non si fa amministrazione, quindi qui si prende il ramo dell'utente normale e i tab non
  // vengono nemmeno costruiti. Sul desktop l'admin li vede come sempre.
  // v5.834 — telefono: Punteggio subito sotto le foto (in testa alle righe), Numero e Nome sopra.
  if (_mobileDetail && _rowScoreMobile) rows.unshift(_rowScoreMobile);
  const topEl = document.getElementById('fig-detail-top');
  if (topEl) topEl.innerHTML = _mobileDetail ? rowsTop.join('') : '';

  if (isAdmin && !_isMobileViewport()) {
    const conditionLabel = f.condition === 'used' ? (currentLang === 'it' ? 'Usato' : 'Used') : (currentLang === 'it' ? 'Nuovo' : 'New');
    const ebayRows = [];
    ebayRows.push(`<div class="detail-row"><span class="detail-label">${currentLang === 'it' ? 'Ebay' : 'For sale'}</span><span class="detail-value">${f.forSale ? `<span style="color:var(--success);">✓ €${(f.price||0).toFixed(2)} · ${currentLang === 'it' ? 'Q.tà' : 'Qty'} ${f.quantity||1} · ${conditionLabel}</span>` : '<span style="color:var(--muted);font-style:italic;">' + (currentLang === 'it' ? 'no' : 'no') + '</span>'}</span></div>`);
    if (f.section === 'figurines' || f.section === 'retros') {
      ebayRows.push(`<div class="detail-row" style="align-items:flex-start;"><span class="detail-label">📷 ${currentLang === 'it' ? 'Foto Ebay' : 'Ebay photo'}</span><span class="detail-value">${f.ebayImg ? `<img src="${cloudinaryUrl(f.ebayImg,'w_200,h_200,c_fit,q_auto,f_auto')}" style="max-width:140px;object-fit:contain;border-radius:8px;background:var(--card2);padding:6px;">` : '<span style="color:var(--muted);font-style:italic;">' + (currentLang === 'it' ? 'nessuna foto' : 'no photo') + '</span>'}</span></div>`);
    }
    const tabNav = `<div style="display:flex;gap:0.5rem;border-bottom:1px solid var(--border);margin-bottom:1rem;">
      <button type="button" id="figdetail-tab-btn-generale" onclick="switchFigDetailTab('generale')" style="padding:0.4rem 0.9rem;border:none;border-bottom:2px solid var(--accent);background:transparent;color:var(--accent);font-weight:600;font-size:0.85rem;cursor:pointer;">📋 Generale</button>
      <button type="button" id="figdetail-tab-btn-ebay" onclick="switchFigDetailTab('ebay')" style="padding:0.4rem 0.9rem;border:none;border-bottom:2px solid transparent;background:transparent;color:var(--muted);font-size:0.85rem;cursor:pointer;">🏷️ Ebay</button>
    </div>`;
    document.getElementById('fig-detail-content').innerHTML = tabNav +
      '<div id="figdetail-tab-generale">' + rows.join('') + '</div>' +
      '<div id="figdetail-tab-ebay" style="display:none;">' + ebayRows.join('') + '</div>' +
      bottomButtons;
  } else {
    document.getElementById('fig-detail-content').innerHTML = rows.join('') + bottomButtons;
  }
  document.getElementById('fig-detail-modal').classList.remove('hidden');
}

// Costruisce l'HTML con i tab delle figurine collegate (variazioni/change)
// di cui la figurina "baseId" è la base. Restituisce '' se non ce ne sono.
function buildLinkedFiguresTabsHTML(baseId) {
  const linked = getData('figurines', []).filter(x => x.baseFigurineId === baseId);
  if (!linked.length) return '';

  const groups = [
    { key: 'variation', label: currentLang === 'it' ? 'Variazioni ufficiali' : 'Official variations', icon: '🎨', items: linked.filter(x => x.isVariation) },
    { key: 'unofficialVariation', label: currentLang === 'it' ? 'Variazioni non ufficiali' : 'Unofficial variations', icon: '🎨', items: linked.filter(x => x.isUnofficialVariation) },
    { key: 'change', label: 'Change', icon: '🔄', items: linked.filter(x => x.isChange) },
  ].filter(g => g.items.length > 0);

  if (!groups.length) return '';

  const firstKey = groups[0].key;
  let html = '<div style="margin-top:1.2rem;">';
  html += '<div style="display:flex;gap:0.4rem;border-bottom:1px solid var(--border);margin-bottom:0.75rem;flex-wrap:wrap;">';
  groups.forEach((g, i) => {
    html += `<button class="linked-fig-tab-btn" data-tab="${g.key}" onclick="switchLinkedFigTab('${g.key}')" style="font-size:0.8rem;padding:6px 12px;border:none;border-bottom:2px solid ${i===0?'var(--accent)':'transparent'};background:transparent;color:${i===0?'var(--accent)':'var(--muted)'};cursor:pointer;font-weight:${i===0?'600':'400'};">${g.icon} ${g.label} (${g.items.length})</button>`;
  });
  html += '</div>';

  groups.forEach((g, i) => {
    html += `<div class="linked-fig-tab-panel" data-tab="${g.key}" style="${i===0?'':'display:none;'}">`;
    html += '<div style="display:flex;flex-direction:column;gap:0.4rem;">';
    g.items.forEach(item => {
      let label;
      if (g.key === 'change') {
        // Mostriamo il Tipo di change (più utile del Nome, che coincide con quello della base).
        // v5.779 — vale ora sia per i Change di Retro sia per quelli di figurina, entrambi con Tipo.
        label = item.changeType || item.name;
      } else {
        // Per le Variazioni il Nome coincide sempre con quello della figurina base: inutile
        // ripeterlo. Mostriamo invece il Retro collegato (Categoria + Nome), la vera chiave
        const retroFig = item.retroId ? getData('figurines', []).find(x => x.id === item.retroId) : null;
        label = retroFig
        ? (() => { const parts = [retroFig.category, retroFig.subcategory].map(v => (v||'').trim()).filter(Boolean); return parts.length ? parts.join(' · ') + ' — ' + retroFig.name : retroFig.name; })()
          : (currentLang === 'it' ? 'Nessun Retro collegato' : 'No Retro linked');
      }
      html += `<a href="#" onclick="openFigDetail('${item.id}');return false;" style="display:flex;align-items:center;gap:0.6rem;padding:0.4rem 0.6rem;border-radius:8px;background:var(--card2);text-decoration:none;color:var(--text);font-size:0.85rem;">
        ${item.img ? `<img src="${cloudinaryUrl(item.img,'w_60,h_60,c_fit,q_auto,f_auto')}" style="width:32px;height:32px;object-fit:contain;border-radius:4px;background:var(--card);">` : '<span style="width:32px;height:32px;display:flex;align-items:center;justify-content:center;">🖼️</span>'}
        <span>${label}</span>
      </a>`;
    });
    html += '</div></div>';
  });

  html += '</div>';
  return html;
}

function switchLinkedFigTab(key) {
  document.querySelectorAll('.linked-fig-tab-btn').forEach(btn => {
    const active = btn.getAttribute('data-tab') === key;
    btn.style.borderBottomColor = active ? 'var(--accent)' : 'transparent';
    btn.style.color = active ? 'var(--accent)' : 'var(--muted)';
    btn.style.fontWeight = active ? '600' : '400';
  });
  document.querySelectorAll('.linked-fig-tab-panel').forEach(panel => {
    panel.style.display = panel.getAttribute('data-tab') === key ? '' : 'none';
  });
}

function editItemFromDetail(itemId) {
  switchToEditMode(itemId);
}

let editingFeEbayImgFileSave = null;

function switchFeTab(tab) {
  const genDiv = document.getElementById('fe-tab-generale');
  const ebayDiv = document.getElementById('fe-tab-ebay');
  const genBtn = document.getElementById('fe-tab-btn-generale');
  const ebayBtn = document.getElementById('fe-tab-btn-ebay');
  if (genDiv) genDiv.style.display = tab === 'generale' ? '' : 'none';
  if (ebayDiv) ebayDiv.style.display = tab === 'ebay' ? '' : 'none';
  if (genBtn) { genBtn.style.borderBottomColor = tab === 'generale' ? 'var(--accent)' : 'transparent'; genBtn.style.color = tab === 'generale' ? 'var(--accent)' : 'var(--muted)'; }
  if (ebayBtn) { ebayBtn.style.borderBottomColor = tab === 'ebay' ? 'var(--accent)' : 'transparent'; ebayBtn.style.color = tab === 'ebay' ? 'var(--accent)' : 'var(--muted)'; }
}

function handleFeEbayImg(e) {
  const file = e.target.files[0]; if (!file) return;
  editingFeEbayImgFileSave = file;
  const reader = new FileReader();
  reader.onload = ev => {
    const pr = document.getElementById('fe-ebay-img-preview');
    if (pr.tagName === 'IMG') { pr.src = ev.target.result; }
    else {
      const img = document.createElement('img');
      img.id = 'fe-ebay-img-preview';
      img.src = ev.target.result;
      img.style.cssText = 'max-width:160px;object-fit:contain;border-radius:8px;background:var(--card2);padding:6px;display:block;margin-bottom:0.5rem;';
      pr.replaceWith(img);
    }
  };
  reader.readAsDataURL(file);
}

function toggleFeForSaleFields() {
  const checked = document.getElementById('fe-for-sale').checked;
  document.getElementById('fe-for-sale-fields').style.display = checked ? 'grid' : 'none';
}

function toggleFeBaseFigurineGroup(appenaSpuntata) {
  // esclusivita' fra i quattro tipi, come nell'altra maschera (v5.711): un oggetto e'
  // una cosa sola
  if (appenaSpuntata) {
    const _el = document.getElementById(appenaSpuntata);
    if (_el && _el.checked) {
      ['fe-is-variation', 'fe-is-unofficial-variation', 'fe-is-change', 'fe-is-printerror']
        .filter(c => c !== appenaSpuntata)
        .forEach(c => { const x = document.getElementById(c); if (x) x.checked = false; });
    }
  }
  const group = document.getElementById('fe-base-figurine-group');
  const retroGroup = document.getElementById('fe-retro-group');
  const numberGroup = document.getElementById('fe-number-group');
  const changeTypeGroup = document.getElementById('fe-retro-change-type-group');
  if (!group) return;
  const isVar = document.getElementById('fe-is-variation')?.checked;
  const isUnoff = document.getElementById('fe-is-unofficial-variation')?.checked;
  const isChg = document.getElementById('fe-is-change')?.checked;
  // ERRORE MIO (v5.711): qui leggevo 'fig-is-printerror-input', l'id dell'ALTRA
  // maschera. La mia sostituzione aveva colpito ENTRAMBE le funzioni, e questa usa il
  // prefisso 'fe-'. node --check non poteva vederlo: getElementById su un id
  // inesistente non e' un errore di sintassi — restituisce null, in silenzio.
  const isPE = document.getElementById('fe-is-printerror')?.checked;
  // un errore di stampa, come le variazioni e i Change, e' collegato a un oggetto base
  const showBase = isVar || isUnoff || isChg || isPE;
  group.style.display = showBase ? '' : 'none';
  // v5.786 — Retro visibile anche per i Change; per i Change ripopolo il selettore con TUTTE le serie.
  if (retroGroup) {
    retroGroup.style.display = '';
    if (_feItemSeriesId) _populateFeRetroOptions(_feItemSeriesId, isChg);
  }
  // Il Numero si nasconde per Variazioni/Change: eredita quello della figurina base collegata
  if (numberGroup) numberGroup.style.display = showBase ? 'none' : '';
  if (changeTypeGroup) changeTypeGroup.style.display = isChg ? '' : 'none';
  const printErrorTypeGroup = document.getElementById('fe-print-error-type-group');
  if (printErrorTypeGroup) printErrorTypeGroup.style.display = isPE ? '' : 'none';
  // v5.774 — Nome nascosto per Change/Errore di stampa di RETRO. Un item e' un retro se e' stato
  // costruito il gruppo Tipo di change (esiste solo per i retro); il Nome verra' derivato dal base.
  const feNameGroup = document.getElementById('fe-name-group');
  // v5.790 — il Nome si nasconde per QUALUNQUE Change o Errore di stampa (retro o figurina): in tutti
  // il Nome eredita dalla base.
  if (feNameGroup) feNameGroup.style.display = (isChg || isPE) ? 'none' : '';
}

// v5.779 — la form inline serve tutte le sezioni; il gruppo "Tipo di change" ora esiste anche
// per le FIGURINE, quindi la sua sola presenza non identifica più un Retro. Questo marcatore,
// impostato al momento del render, dice se l'oggetto in modifica è un Retro (per le regole di
// nascondimento del Nome nel toggle).
let _feIsRetro = false;
let _feBaseFigurineLinkOptions = [];
function filterFeBaseFigurineLink() {
  const q = document.getElementById('fe-base-figurine-search').value.toLowerCase().trim();
  const dd = document.getElementById('fe-base-figurine-dropdown');
  if (!dd) return;
  // v5.785 — come nel selettore modale: ricerca sull'etichetta mostrata (_baseFigurineLinkLabel:
  // Nome completo per i Retro, "#numero Nome" per le Figurine) + numero, e nessun limite di 50.
  const filtered = q
    ? _feBaseFigurineLinkOptions.filter(f => _baseFigurineLinkLabel(f).toLowerCase().includes(q) || String(f.number||'').includes(q))
    : _feBaseFigurineLinkOptions;
  if (!filtered.length) { dd.innerHTML = '<div style="padding:10px 12px;color:var(--muted);font-size:0.85rem;">' + (currentLang==='it'?'Nessun risultato':'No results') + '</div>'; dd.style.display = ''; return; }
  dd.style.display = '';
  dd.innerHTML = filtered.map(f => {
    return `<div onclick="selectFeBaseFigurineLink('${f.id}')" style="padding:8px 12px;cursor:pointer;border-bottom:1px solid var(--border);" onmouseover="this.style.background='var(--bg3)'" onmouseout="this.style.background=''">
      <div style="font-size:0.9rem;">${esc(_baseFigurineLinkLabel(f))}</div>
    </div>`;
  }).join('');
}

function selectFeBaseFigurineLink(id) {
  const f = _feBaseFigurineLinkOptions.find(x => x.id === id);
  if (!f) return;
  document.getElementById('fe-base-figurine').value = id;
  document.getElementById('fe-base-figurine-search').value = _baseFigurineLinkLabel(f);
  document.getElementById('fe-base-figurine-dropdown').style.display = 'none';
}

function clearFeBaseFigurineLinkIfEmpty() {
  setTimeout(() => {
    const dd = document.getElementById('fe-base-figurine-dropdown');
    if (dd) dd.style.display = 'none';
    const search = document.getElementById('fe-base-figurine-search');
    const hidden = document.getElementById('fe-base-figurine');
    if (search && hidden && !search.value.trim()) hidden.value = '';
  }, 200);
}

let _feRetroLinkOptions = [];
let _feItemSeriesId = null; // v5.786 — serie dell'oggetto in modifica inline (per ripopolare il selettore Retro al toggle)
// v5.786 — popola le opzioni del selettore Retro inline: allSeries=true (Change) pesca da tutte le serie.
function _populateFeRetroOptions(seriesId, allSeries) {
  _retroLinkAllSeries = !!allSeries;
  // v5.791 — (revert v5.787) in modalità Change (allSeries) TUTTI i retro, non solo i base.
  _feRetroLinkOptions = getData('figurines', [])
    .filter(x => x.section === 'retros' && (allSeries || x.seriesId === seriesId))
    .sort((a,b) => allSeries
      ? _retroLinkLabel(a).localeCompare(_retroLinkLabel(b), 'it', {sensitivity:'base'})
      : ((a.category||'').localeCompare(b.category||'', 'it') || (a.subcategory||'').localeCompare(b.subcategory||'', 'it') || (a.name||'').localeCompare(b.name||'', 'it')));
}
function filterFeRetroLink() {
  const q = document.getElementById('fe-retro-search').value.toLowerCase().trim();
  const dd = document.getElementById('fe-retro-dropdown');
  if (!dd) return;
  const filtered = q
    ? _feRetroLinkOptions.filter(r => _retroLinkLabel(r).toLowerCase().includes(q) || (r.category||'').toLowerCase().includes(q) || (r.subcategory||'').toLowerCase().includes(q))
    : _feRetroLinkOptions;
  if (!filtered.length) { dd.innerHTML = '<div style="padding:10px 12px;color:var(--muted);font-size:0.85rem;">' + (currentLang==='it'?'Nessun risultato':'No results') + '</div>'; dd.style.display = ''; return; }
  dd.style.display = '';
  dd.innerHTML = filtered.map(r => {
    const sub = [r.category, r.subcategory].map(v => (v||'').trim()).filter(Boolean).join(' · ');
    return `<div onclick="selectFeRetroLink('${r.id}')" style="padding:8px 12px;cursor:pointer;border-bottom:1px solid var(--border);" onmouseover="this.style.background='var(--bg3)'" onmouseout="this.style.background=''">
      <div style="font-size:0.9rem;">${esc(_retroLinkLabel(r))}</div>
      ${sub ? `<div style="font-size:0.75rem;color:var(--muted);">${sub}</div>` : ''}
    </div>`;
  }).join('');
}

function selectFeRetroLink(id) {
  const r = _feRetroLinkOptions.find(x => x.id === id);
  if (!r) return;
  document.getElementById('fe-retro').value = id;
  document.getElementById('fe-retro-search').value = _retroLinkLabel(r);
  document.getElementById('fe-retro-dropdown').style.display = 'none';
}

function clearFeRetroLinkIfEmpty() {
  setTimeout(() => {
    const dd = document.getElementById('fe-retro-dropdown');
    if (dd) dd.style.display = 'none';
    const search = document.getElementById('fe-retro-search');
    const hidden = document.getElementById('fe-retro');
    if (search && hidden && !search.value.trim()) hidden.value = '';
  }, 200);
}

function switchToEditMode(figId) {
  const f = getData('figurines', []).find(x => x.id === figId);
  if (!f) return;
  editingFeEbayImgFileSave = null;
  const figSeries = getData('series', []).find(s => s.id === f.seriesId);
  const content = document.getElementById('fig-detail-content');
  const photo = document.getElementById('fig-detail-photo');

  // Aggiorna titolo modal
  const titleEl = document.getElementById('fig-detail-title');
  const displayNameForTitle = f.fullName || f.name;
  if (titleEl) titleEl.textContent = f.number ? ('# ' + f.number + ' - ' + displayNameForTitle) : displayNameForTitle;

  // Foto con pulsante cambio immagine
  if (photo) {
    photo.innerHTML = (f.img
      ? '<img id="fig-edit-img-preview" src="' + cloudinaryUrl(f.img,'w_640,h_640,c_fit,q_auto,f_auto') + '" style="width:100%;object-fit:contain;border-radius:8px;background:var(--card2);padding:6px;display:block;margin-bottom:0.5rem;">'
      : '<div id="fig-edit-img-preview" style="width:100%;height:240px;background:var(--card2);border-radius:8px;display:flex;align-items:center;justify-content:center;color:var(--muted);font-size:0.75rem;text-align:center;padding:8px;margin-bottom:0.5rem;">Nessuna foto</div>') +
      '<div style="display:flex;gap:0.4rem;margin-top:0.3rem;">' +
      '<label style="flex:1;cursor:pointer;text-align:center;">' +
      '<span style="display:block;font-size:0.72rem;color:var(--accent);border:1px solid var(--accent);border-radius:6px;padding:2px 8px;white-space:nowrap;">📷 ' + (currentLang==='it'?'Cambia foto':'Change photo') + '</span>' +
      '<input type="file" id="fig-edit-img-file" accept="image/*" style="display:none;" onchange="handleFigEditImg(event)">' +
      '</label>' +
      (f.img ? '<button onclick="removeFigPhoto()" style="flex:1;font-size:0.72rem;color:var(--danger);border:1px solid rgba(var(--danger-rgb),0.4);background:transparent;border-radius:6px;padding:2px 8px;cursor:pointer;white-space:nowrap;">🗑️ ' + (currentLang==='it'?'Rimuovi foto':'Remove photo') + '</button>' : '') +
      '</div>';
  }

  // Build edit form
  let html = '';

  // v5.784 — i tab PRIMA, poi (dentro il tab Generale) il campo Serie: così la posizione coincide
  // con la vista di visualizzazione, dove Serie sta SOTTO i tab. Prima qui stava sopra i tab.
  html += '<div style="display:flex;gap:0.5rem;border-bottom:1px solid var(--border);margin:0.75rem 0 1rem;">' +
    '<button type="button" id="fe-tab-btn-generale" onclick="switchFeTab(\'generale\')" style="padding:0.4rem 0.9rem;border:none;border-bottom:2px solid var(--accent);background:transparent;color:var(--accent);font-weight:600;font-size:0.85rem;cursor:pointer;">📋 Generale</button>' +
    '<button type="button" id="fe-tab-btn-ebay" onclick="switchFeTab(\'ebay\')" style="padding:0.4rem 0.9rem;border:none;border-bottom:2px solid transparent;background:transparent;color:var(--muted);font-size:0.85rem;cursor:pointer;">🏷️ Ebay</button>' +
    '</div>';
  html += '<div id="fe-tab-generale">';

  // Serie (prima informazione del tab Generale, sempre visibile, non modificabile qui)
  html += '<div class="detail-row"><span class="detail-label">' + (currentLang==='it'?'Serie':'Series') + '</span><span class="detail-value" style="font-weight:600;">' + (figSeries?.name||'') + '</span></div>';

  const isRetrosItem = f.section === 'retros';
  _feIsRetro = isRetrosItem; // v5.779 — usato da toggleFeBaseFigurineGroup per le regole del Nome

  // Categoria (solo per i Retro, prima del Nome)
  if (isRetrosItem) {
    html += '<div class="detail-row"><span class="detail-label">' + (currentLang==='it'?'Categoria':'Category') + '</span><span class="detail-value"><input class="form-input" type="text" id="fe-category" value="' + (f.category||'') + '" style="padding:0.3rem 0.5rem;font-size:0.9rem;border:none;background:transparent;"></span></div>';
    html += '<div class="detail-row"><span class="detail-label">' + (currentLang==='it'?'Sottocategoria':'Subcategory') + '</span><span class="detail-value"><input class="form-input" type="text" id="fe-subcategory" value="' + (f.subcategory||'') + '" style="padding:0.3rem 0.5rem;font-size:0.9rem;border:none;background:transparent;"></span></div>';
  }

  // Sottoserie (solo se la serie ha hasSubseries)
  if (figSeries?.hasSubseries) {
    html += '<div class="detail-row"><span class="detail-label">' + (currentLang==='it'?'Sottoserie':'Subseries') + '</span><span class="detail-value"><input class="form-input" type="text" id="fe-subseries" value="' + (f.subseries||'') + '" placeholder="es. OLO" style="padding:0.3rem 0.5rem;font-size:0.9rem;border:none;background:transparent;"></span></div>';
  }

  // Numero (i Retro non sono numerati; le Variazioni/Change ereditano quello della figurina base)
  html += '<div class="detail-row" id="fe-number-group" style="' + ((f.section === 'figurines' && !f.isVariation && !f.isUnofficialVariation && !f.isChange) ? '' : 'display:none;') + '"><span class="detail-label">N.</span><span class="detail-value" style="display:flex;align-items:center;gap:0.6rem;"><input class="form-input" type="number" id="fe-number" value="' + (f.number||'') + '" placeholder="01" style="padding:0.3rem 0.5rem;font-size:0.9rem;width:80px;border:none;background:transparent;"><label style="display:flex;align-items:center;gap:0.3rem;cursor:pointer;font-size:0.75rem;color:var(--muted);white-space:nowrap;"><input type="checkbox" id="fe-no-number" ' + (f.noNumber?'checked':'') + ' style="width:14px;height:14px;cursor:pointer;">' + (currentLang==='it'?'Non ha numero':'Does not have a number') + '</label></span></div>';

  // Nome
  // v5.774/779/790 — Nome nascosto per Change ED Errori di stampa, sia Retro sia figurine (eredita
  // dalla base; derivato al salvataggio).
  const _feNameHidden = (f.isChange || f.isPrintError) && (f.section === 'retros' || f.section === 'figurines');
  html += '<div class="detail-row" id="fe-name-group" style="' + (_feNameHidden ? 'display:none;' : '') + '"><span class="detail-label">' + (currentLang==='it'?'Nome':'Name') + '</span><span class="detail-value"><input class="form-input" type="text" id="fe-name" value="' + (f.name||'') + '" style="padding:0.3rem 0.5rem;font-size:0.9rem;border:none;background:transparent;"></span></div>';

  // Punteggio
  html += '<div class="detail-row"><span class="detail-label">' + (currentLang==='it'?'Punteggio':'Score') + '</span><span class="detail-value"><input class="form-input" type="number" id="fe-score" value="' + (f.score||0) + '" min="0" style="padding:0.3rem 0.5rem;font-size:0.9rem;width:80px;border:none;background:transparent;"></span></div>';

  // Taglia (solo se la serie ha taglie)
  if (figSeries?.hasSizes) {
    html += '<div class="detail-row"><span class="detail-label">' + (currentLang==='it'?'Taglia':'Size') + '</span><span class="detail-value"><input class="form-input" type="text" id="fe-size" value="' + (f.size||'') + '" placeholder="S/M/L/XL" style="padding:0.3rem 0.5rem;font-size:0.9rem;width:100px;border:none;background:transparent;"></span></div>';
  }

  // Flag Variazione ufficiale / non ufficiale (solo Figurine/Album/Altro) e Change (anche Retro)
  if (!isRetrosItem) {
    html += '<div class="detail-row"><span class="detail-label">' + (currentLang==='it'?'Variazione ufficiale':'Official variation') + '</span><span class="detail-value"><input type="checkbox" id="fe-is-variation" onchange="toggleFeBaseFigurineGroup(\'fe-is-variation\')" ' + (f.isVariation?'checked':'') + ' style="width:18px;height:18px;cursor:pointer;"></span></div>';
    html += '<div class="detail-row"><span class="detail-label">' + (currentLang==='it'?'Variazione non ufficiale':'Unofficial variation') + '</span><span class="detail-value"><input type="checkbox" id="fe-is-unofficial-variation" onchange="toggleFeBaseFigurineGroup(\'fe-is-unofficial-variation\')" ' + (f.isUnofficialVariation?'checked':'') + ' style="width:18px;height:18px;cursor:pointer;"></span></div>';
  }
  html += '<div class="detail-row"><span class="detail-label">Change</span><span class="detail-value"><input type="checkbox" id="fe-is-change" onchange="toggleFeBaseFigurineGroup(\'fe-is-change\')" ' + (f.isChange?'checked':'') + ' style="width:18px;height:18px;cursor:pointer;"></span></div>';
  // ERRORE DI STAMPA (v5.714): la quinta casella, in TUTTE E QUATTRO le sezioni, come
  // Change. Franco: "deve esserci in tutte e 4 le form di modifica". Nella v5.711
  // l'avevo messa SOLO nella maschera "aggiungi oggetto" (#add-fig-modal), senza
  // accorgermi che la maschera di MODIFICA e' un'altra funzione, con i propri id 'fe-'.
  html += '<div class="detail-row"><span class="detail-label">' + (currentLang === 'it' ? 'Errore di stampa' : 'Print error') + '</span><span class="detail-value"><input type="checkbox" id="fe-is-printerror" onchange="toggleFeBaseFigurineGroup(\'fe-is-printerror\')" ' + (f.isPrintError?'checked':'') + ' style="width:18px;height:18px;cursor:pointer;"></span></div>';
  if (isRetrosItem || f.section === 'figurines') {
    const showChangeType = !!f.isChange;
    const retroTypes = changeTypesDiSerie(f.seriesId);
    html += '<div class="detail-row" id="fe-retro-change-type-group" style="' + (showChangeType ? '' : 'display:none;') + '">' +
      '<span class="detail-label">' + (currentLang==='it'?'Tipo di change':'Change type') + '</span>' +
      '<select class="form-input" id="fe-retro-change-type" style="padding:0.3rem 0.5rem;font-size:0.9rem;">' +
      '<option value="">' + (currentLang==='it'?'— scegli —':'— choose —') + '</option>' +
      retroTypes.map(t => '<option value="' + t + '"' + (f.changeType === t ? ' selected' : '') + '>' + t + '</option>').join('') +
      '</select></div>';
  }
  // Tipo di errore di stampa (testo libero) — TUTTE le sezioni, mostrato quando e' un Errore di
  // stampa. Stessa posizione del Tipo di change, con cui e' mutuamente esclusivo (v5.767).
  html += '<div class="detail-row" id="fe-print-error-type-group" style="' + (f.isPrintError ? '' : 'display:none;') + '">' +
    '<span class="detail-label">' + (currentLang==='it'?'Tipo di errore di stampa':'Print error type') + '</span>' +
    '<input class="form-input" type="text" id="fe-print-error-type" value="' + esc(f.printErrorType||'') + '" style="padding:0.3rem 0.5rem;font-size:0.9rem;border:none;background:transparent;"></div>';

  // Figurina/Retro base — ricerca in digitazione (stesso pattern del Retro associato)
  _feBaseFigurineLinkOptions = getData('figurines', [])
    .filter(x => x.seriesId === f.seriesId && x.section === f.section && x.id !== f.id && !x.isVariation && !x.isUnofficialVariation && !x.isChange)
    .sort(_baseFigurineLinkSort); // v5.785 — Retro per Nome completo, Figurine per Numero
  const selectedBaseFig = f.baseFigurineId ? _feBaseFigurineLinkOptions.find(x => x.id === f.baseFigurineId) : null;
  const showBaseGroup = f.isVariation || f.isUnofficialVariation || f.isChange || f.isPrintError;
  const baseLabel = isRetrosItem ? (currentLang==='it'?'Retro base':'Base Retro') : (currentLang==='it'?'Figurina base':'Base sticker');
  html += '<div class="detail-row" id="fe-base-figurine-group" style="' + (showBaseGroup ? '' : 'display:none;') + 'flex-direction:column;align-items:stretch;position:relative;">' +
    '<span class="detail-label">' + baseLabel + '</span>' +
    '<input class="form-input" type="text" id="fe-base-figurine-search" placeholder="' + (currentLang==='it'?'Cerca per numero o nome...':'Search by number or name...') + '" autocomplete="off" value="' + (selectedBaseFig ? esc(_baseFigurineLinkLabel(selectedBaseFig)) : '') + '" oninput="filterFeBaseFigurineLink()" onfocus="filterFeBaseFigurineLink()" onblur="clearFeBaseFigurineLinkIfEmpty()" style="padding:0.3rem 0.5rem;font-size:0.9rem;">' +
    '<input type="hidden" id="fe-base-figurine" value="' + (f.baseFigurineId || '') + '">' +
    '<div id="fe-base-figurine-dropdown" style="display:none;position:absolute;z-index:20;top:100%;left:0;right:0;background:var(--card);border:1px solid var(--border);border-radius:var(--radius);max-height:220px;overflow-y:auto;margin-top:2px;box-shadow:0 8px 24px rgba(0,0,0,0.4);"></div>' +
    '</div>';

  // Selettore Retro associato (non applicabile ai Retro stessi) — ricerca in digitazione (247+ retro in alcune serie)
  if (!isRetrosItem) {
    // v5.786 — il selettore Retro ora si applica anche ai Change (facoltativo). Per i Change pesca da
    // TUTTE le serie; per gli altri tipi resta la serie dell'oggetto. _feItemSeriesId serve al toggle.
    _feItemSeriesId = f.seriesId;
    _populateFeRetroOptions(f.seriesId, !!f.isChange);
    const selectedRetro = f.retroId ? _feRetroLinkOptions.find(r => r.id === f.retroId) : null;
    const showRetroGroup = true; // visibile per base/variazioni/change/errori di stampa (il toggle lo gestisce dinamicamente)
    html += '<div class="detail-row" id="fe-retro-group" style="' + (showRetroGroup ? '' : 'display:none;') + 'flex-direction:column;align-items:stretch;position:relative;">' +
      '<span class="detail-label">' + (currentLang==='it'?'Retro associato':'Associated retro') + '</span>' +
      '<input class="form-input" type="text" id="fe-retro-search" placeholder="' + (currentLang==='it'?'Cerca per nome, categoria o sottocategoria...':'Search by name, category or subcategory...') + '" autocomplete="off" value="' + (selectedRetro ? esc(_retroLinkLabel(selectedRetro)) : '') + '" oninput="filterFeRetroLink()" onfocus="filterFeRetroLink()" onblur="clearFeRetroLinkIfEmpty()" style="padding:0.3rem 0.5rem;font-size:0.9rem;">' +
      '<input type="hidden" id="fe-retro" value="' + (f.retroId || '') + '">' +
    '<div id="fe-retro-dropdown" style="display:none;position:absolute;z-index:20;top:100%;left:0;right:0;background:var(--card);border:1px solid var(--border);border-radius:var(--radius);max-height:220px;overflow-y:auto;margin-top:2px;box-shadow:0 8px 24px rgba(0,0,0,0.4);"></div>' +
    '</div>';
  }

  // Descrizione (in fondo, campo più grande)
  html += '<div class="detail-row" style="align-items:flex-start;"><span class="detail-label">' + (currentLang==='it'?'Descrizione':'Description') + '</span><span class="detail-value"><textarea id="fe-desc" class="form-textarea" rows="2" style="padding:0.3rem 0.5rem;font-size:0.9rem;resize:vertical;border:none;background:transparent;">' + (f.desc||'') + '</textarea></span></div>';

  // Figurine collegate (variazioni/change di cui questa è la base) — tab
  html += buildLinkedFiguresTabsHTML(f.id);

  html += '</div>'; // chiude fe-tab-generale

  // Tab Ebay: Vendita (Da vendere / Prezzo / Quantità / Condizione) + foto dedicata
  html += '<div id="fe-tab-ebay" style="display:none;">';
  html += '<div style="background:var(--card2);border-radius:10px;padding:0.75rem 0.9rem;margin-bottom:0.75rem;">' +
    '<label style="display:flex;align-items:center;gap:0.5rem;cursor:pointer;font-size:0.88rem;font-weight:600;margin-bottom:' + (f.forSale ? '0.6rem' : '0') + ';">' +
    '<input type="checkbox" id="fe-for-sale" onchange="toggleFeForSaleFields()" ' + (f.forSale ? 'checked' : '') + ' style="width:16px;height:16px;cursor:pointer;flex-shrink:0;">' +
    '<span>🏷️ ' + (currentLang==='it'?'Ebay':'For sale on Ebay') + '</span></label>' +
    '<div id="fe-for-sale-fields" style="display:' + (f.forSale ? 'grid' : 'none') + ';grid-template-columns:1fr 1fr 1fr;gap:0.6rem;">' +
    '<div><label style="font-size:0.72rem;color:var(--muted);display:block;margin-bottom:2px;">' + (currentLang==='it'?'Prezzo (€)':'Price (€)') + '</label><input class="form-input" type="number" id="fe-price" value="' + (f.price||'') + '" min="0" step="0.01" style="padding:0.3rem 0.5rem;font-size:0.85rem;"></div>' +
    '<div><label style="font-size:0.72rem;color:var(--muted);display:block;margin-bottom:2px;">' + (currentLang==='it'?'Quantità':'Quantity') + '</label><input class="form-input" type="number" id="fe-quantity" value="' + (f.quantity||1) + '" min="1" style="padding:0.3rem 0.5rem;font-size:0.85rem;"></div>' +
    '<div><label style="font-size:0.72rem;color:var(--muted);display:block;margin-bottom:2px;">' + (currentLang==='it'?'Condizione':'Condition') + '</label><select class="form-input" id="fe-condition" style="padding:0.3rem 0.5rem;font-size:0.85rem;">' +
    '<option value="new"' + (f.condition!=='used'?' selected':'') + '>' + (currentLang==='it'?'Nuovo':'New') + '</option>' +
    '<option value="used"' + (f.condition==='used'?' selected':'') + '>' + (currentLang==='it'?'Usato':'Used') + '</option>' +
    '</select></div></div></div>';
  html += '<div style="margin-bottom:0.75rem;' + ((f.section === 'figurines' || f.section === 'retros') ? '' : 'display:none;') + '">' +
    '<label class="detail-label" style="display:block;margin-bottom:0.4rem;">📷 ' + (currentLang==='it'?'Foto per Ebay':'Ebay photo') + '</label>' +
    '<div style="font-size:0.72rem;color:var(--muted);margin-bottom:0.5rem;">' + (currentLang==='it'?'Foto dedicata da usare per l\'annuncio Ebay, indipendente da quella del catalogo':'Dedicated photo for the Ebay listing, separate from the catalog one') + '</div>' +
    (f.ebayImg
      ? '<img id="fe-ebay-img-preview" src="' + cloudinaryUrl(f.ebayImg,'w_320,h_320,c_fit,q_auto,f_auto') + '" style="max-width:160px;object-fit:contain;border-radius:8px;background:var(--card2);padding:6px;display:block;margin-bottom:0.5rem;">'
      : '<div id="fe-ebay-img-preview" style="width:160px;height:120px;background:var(--card2);border-radius:8px;display:flex;align-items:center;justify-content:center;color:var(--muted);font-size:0.72rem;text-align:center;padding:8px;margin-bottom:0.5rem;">' + (currentLang==='it'?'Nessuna foto':'No photo') + '</div>') +
    '<label style="cursor:pointer;display:inline-block;">' +
    '<span style="display:inline-block;font-size:0.72rem;color:var(--accent);border:1px solid var(--accent);border-radius:6px;padding:2px 8px;">📷 ' + (currentLang==='it'?'Carica foto':'Upload photo') + '</span>' +
    '<input type="file" id="fe-ebay-img-file" accept="image/*" style="display:none;" onchange="handleFeEbayImg(event)">' +
    '</label></div>';
  html += '</div>'; // chiude fe-tab-ebay

  // Pulsanti
  html += '<div style="margin-top:1rem;display:flex;gap:0.5rem;justify-content:flex-end;">';
  html += '<button onclick="closeModal(\'fig-detail-modal\')" style="font-size:0.82rem;padding:4px 12px;border-radius:8px;border:1px solid var(--border);background:transparent;color:var(--muted);cursor:pointer;">' + (currentLang==='it'?'Annulla':'Cancel') + '</button>';
  html += '<button id="fig-edit-save-btn" data-fig-id="' + f.id + '" style="font-size:0.82rem;padding:4px 12px;border-radius:8px;border:none;background:var(--action-admin);color:#ffffff;cursor:pointer;font-weight:600;">💾 ' + (currentLang==='it'?'Salva':'Save') + '</button>';
  html += '</div>';

  content.innerHTML = html;

  // Listener sul pulsante Salva (evita problemi con onclick inline)
  const saveBtn = document.getElementById('fig-edit-save-btn');
  if (saveBtn) saveBtn.addEventListener('click', function() {
    saveFigFromDetail(saveBtn.getAttribute('data-fig-id'));
  });
}

let _figEditImgData = null;

// Carica libreria rimozione sfondo in background all'avvio
(async function loadRemoveBgLib() {
  try {
    const mod = await import('https://esm.sh/@imgly/background-removal');
    window._removeBackground = mod.removeBackground;
    console.log('Background removal library loaded');
  } catch(e) {
    console.warn('Background removal library not available:', e.message);
  }
})();

async function removeBgFromEdit() {
  const btn = document.getElementById('fig-edit-remove-bg-btn');
  const preview = document.getElementById('fig-edit-img-preview');

  if (!preview || !preview.src || preview.src === window.location.href) {
    toast(currentLang === 'it' ? 'Carica prima una foto' : 'Upload a photo first', 'error');
    return;
  }

  // Stato loading
  if (btn) { btn.disabled = true; btn.textContent = currentLang === 'it' ? '⏳ Elaborazione...' : '⏳ Processing...'; }

  try {
    let removeBackground = window._removeBackground;
    if (!removeBackground) {
      if (btn) btn.textContent = currentLang === 'it' ? '⏳ Caricamento libreria...' : '⏳ Loading library...';
      // Aspetta fino a 30 secondi che la libreria si carichi
      for (let i = 0; i < 30; i++) {
        await new Promise(r => setTimeout(r, 1000));
        if (window._removeBackground) { removeBackground = window._removeBackground; break; }
      }
      if (!removeBackground) {
        toast(currentLang === 'it' ? '❌ Libreria non disponibile, ricarica la pagina' : '❌ Library unavailable, reload the page', 'error');
        if (btn) { btn.disabled = false; btn.textContent = currentLang === 'it' ? '✨ Rimuovi sfondo' : '✨ Remove background'; }
        return;
      }
    }

    // Ottieni il blob dalla src corrente
    const srcRes = await fetch(preview.src);
    const blob = await srcRes.blob();

    // Rimuovi sfondo
    const resultBlob = await removeBackground(blob, {
      model: 'isnet', // v5.793 — modello PIENO (qualità migliore su soggetti chiari a basso contrasto, es. retro bianchi) invece del default isnet_fp16
      progress: (key, current, total) => {
        if (btn) btn.textContent = currentLang === 'it'
          ? '⏳ ' + Math.round((current/total)*100) + '%'
          : '⏳ ' + Math.round((current/total)*100) + '%';
      }
    });

    // Crop automatico per rimuovere trasparenza residua
    const cropCanvas = document.createElement('canvas');
    const cropImg = new Image();
    const tmpUrl = URL.createObjectURL(resultBlob);
    await new Promise(res => { cropImg.onload = res; cropImg.src = tmpUrl; });
    URL.revokeObjectURL(tmpUrl);
    cropCanvas.width = cropImg.naturalWidth; cropCanvas.height = cropImg.naturalHeight;
    const cropCtx = cropCanvas.getContext('2d');
    cropCtx.drawImage(cropImg, 0, 0);
    const pd = cropCtx.getImageData(0, 0, cropCanvas.width, cropCanvas.height).data;
    let mnX = cropCanvas.width, mnY = cropCanvas.height, mxX = 0, mxY = 0;
    for (let y = 0; y < cropCanvas.height; y++) for (let x = 0; x < cropCanvas.width; x++) {
      if (pd[(y * cropCanvas.width + x) * 4 + 3] > 10) { if (x < mnX) mnX=x; if (x > mxX) mxX=x; if (y < mnY) mnY=y; if (y > mxY) mxY=y; }
    }
    const pad = 4, cw = mxX-mnX+1+pad*2, ch = mxY-mnY+1+pad*2;
    const finalCanvas = document.createElement('canvas');
    finalCanvas.width = cw; finalCanvas.height = ch;
    finalCanvas.getContext('2d').drawImage(cropCanvas, Math.max(0,mnX-pad), Math.max(0,mnY-pad), cw, ch, 0, 0, cw, ch);
    const croppedBlob = await new Promise(res => finalCanvas.toBlob(res, 'image/png'));

    // Converti in base64 e aggiorna la preview
    const reader = new FileReader();
    reader.onload = e => {
      _figEditImgData = e.target.result;
      preview.src = _figEditImgData;
      if (btn) { btn.disabled = false; btn.textContent = currentLang === 'it' ? '✨ Rimuovi sfondo' : '✨ Remove background'; }
      toast(currentLang === 'it' ? '✅ Sfondo rimosso!' : '✅ Background removed!', 'success');
    };
    reader.readAsDataURL(croppedBlob);

  } catch(e) {
    console.error('removeBg error', e);
    toast(currentLang === 'it' ? '❌ Errore nella rimozione sfondo' : '❌ Error removing background', 'error');
    if (btn) { btn.disabled = false; btn.textContent = currentLang === 'it' ? '✨ Rimuovi sfondo' : '✨ Remove background'; }
  }
}
function removeFigPhoto() {
  if (!confirm(currentLang === 'it' ? 'Rimuovere la foto da questa figurina?' : 'Remove the photo from this sticker?')) return;
  _figEditImgData = '__remove__'; // segnale speciale per saveFigFromDetail
  const preview = document.getElementById('fig-edit-img-preview');
  if (preview) {
    preview.src = '';
    preview.style.display = 'none';
    // Mostra placeholder
    const placeholder = document.createElement('div');
    placeholder.id = 'fig-edit-img-preview';
    placeholder.style.cssText = 'width:160px;height:200px;background:var(--card2);border-radius:8px;display:flex;align-items:center;justify-content:center;color:var(--muted);font-size:0.75rem;text-align:center;padding:8px;margin-bottom:0.5rem;';
    placeholder.textContent = currentLang === 'it' ? 'Nessuna foto' : 'No photo';
    preview.replaceWith(placeholder);
  }
  toast(currentLang === 'it' ? 'Foto rimossa — premi Salva per confermare' : 'Photo removed — press Save to confirm', 'success');
}

function handleFigEditImg(event) {
  const file = event.target.files[0];
  if (!file) return;
  const reader = new FileReader();
  reader.onload = e => {
    _figEditImgData = e.target.result;
    const container = document.getElementById('fig-detail-photo');
    let preview = document.getElementById('fig-edit-img-preview');
    // Se il preview è un div placeholder, lo sostituiamo con un img
    if (preview && preview.tagName === 'DIV') {
      const img = document.createElement('img');
      img.id = 'fig-edit-img-preview';
      img.style.cssText = 'width:160px;height:200px;object-fit:contain;border-radius:8px;background:var(--card2);padding:4px;display:block;margin-bottom:0.5rem;';
      preview.replaceWith(img);
      preview = img;
    }
    if (preview) preview.src = _figEditImgData;
  };
  reader.readAsDataURL(file);
}

async function saveFigFromDetail(figId) {
  let name = document.getElementById('fe-name')?.value.trim();
  const existingForCheck = getData('figurines', []).find(x => x.id === figId);
  // v5.774 — per un Change/Errore di stampa di RETRO il Nome eredita quello del retro base (campo
  // nascosto). Se il base manca, il controllo apposito piu' sotto blocca; qui si salta "Nome obbligatorio".
  const _isChgChk = !!document.getElementById('fe-is-change')?.checked;
  const _isPEChk = !!document.getElementById('fe-is-printerror')?.checked;
  // v5.779/790 — Nome ereditato dalla base per Change ED Errori di stampa, sia Retro sia figurine.
  const _nameInherited = (_isChgChk || _isPEChk) &&
    (existingForCheck?.section === 'retros' || existingForCheck?.section === 'figurines');
  if (_nameInherited) {
    const _baseId = document.getElementById('fe-base-figurine')?.value || null;
    const _bR = _baseId ? getData('figurines', []).find(x => x.id === _baseId) : null;
    if (_bR) name = _bR.name || '';
  }
  if (!name && !_nameInherited) { toast(currentLang==='it'?'Il nome è obbligatorio':'Name is required','error'); return; }
  if (existingForCheck?.section === 'retros') {
    const category = document.getElementById('fe-category')?.value.trim() || '';
    const changeTypeVal = document.getElementById('fe-retro-change-type')?.value || '';
      // stessa correzione del controllo gemello (v5.717): la chiave comprende il TIPO
      const tipoNuovo = tipoDiOggetto({
        isVariation: document.getElementById('fe-is-variation')?.checked || false,
        isUnofficialVariation: document.getElementById('fe-is-unofficial-variation')?.checked || false,
        isChange: document.getElementById('fe-is-change')?.checked || false,
        isPrintError: document.getElementById('fe-is-printerror')?.checked || false
      });
      const dup = getData('figurines', []).find(f =>
        f.id !== figId &&
        f.seriesId === existingForCheck.seriesId &&
        f.section === 'retros' &&
        (f.name||'').toLowerCase() === name.toLowerCase() &&
        (f.category||'').toLowerCase() === category.toLowerCase() &&
        tipoDiOggetto(f) === tipoNuovo &&
        (tipoNuovo !== 'change' ||
          (f.changeType||'').toLowerCase().trim() === changeTypeVal.toLowerCase().trim())
      );
    if (dup) {
      toast((currentLang === 'it' ? 'Esiste già un Retro con la stessa Categoria, lo stesso Nome e lo stesso Tipo di change in questa serie' : 'A Retro with the same Category, Name and Change type already exists in this series'), 'error');
      return;
    }
  }
  const updates = {
    id: figId,
    name,
    number: document.getElementById('fe-number')?.value ? +document.getElementById('fe-number').value : null,
    noNumber: document.getElementById('fe-no-number')?.checked || false,
    subseries: document.getElementById('fe-subseries')?.value.trim() || '',
    desc: document.getElementById('fe-desc')?.value.trim() || '',
    score: +(document.getElementById('fe-score')?.value || 0),
    size: document.getElementById('fe-size')?.value.trim() || '',
    category: document.getElementById('fe-category')?.value.trim() || '',
    subcategory: document.getElementById('fe-subcategory')?.value.trim() || '',
    isVariation: document.getElementById('fe-is-variation')?.checked || false,
    isUnofficialVariation: document.getElementById('fe-is-unofficial-variation')?.checked || false,
    isChange: document.getElementById('fe-is-change')?.checked || false,
    isPrintError: document.getElementById('fe-is-printerror')?.checked || false,
    changeType: document.getElementById('fe-retro-change-type')?.value || null,
    printErrorType: document.getElementById('fe-print-error-type')?.value.trim() || null,
    forSale: document.getElementById('fe-for-sale')?.checked || false,
    price: document.getElementById('fe-for-sale')?.checked ? (parseFloat(document.getElementById('fe-price').value) || 0) : null,
    quantity: document.getElementById('fe-for-sale')?.checked ? (parseInt(document.getElementById('fe-quantity').value) || 1) : null,
    condition: document.getElementById('fe-for-sale')?.checked ? document.getElementById('fe-condition').value : null,
  };

  if ([updates.isVariation, updates.isUnofficialVariation, updates.isChange, updates.isPrintError].filter(Boolean).length > 1) {
    toast(currentLang === 'it' ? 'Variazione ufficiale, non ufficiale, Change ed Errore di stampa sono mutuamente esclusivi: spunta solo una opzione' : 'Official variation, unofficial variation, Change and Print error are mutually exclusive: check only one', 'error');
    return;
  }

  updates.baseFigurineId = (updates.isVariation || updates.isUnofficialVariation || updates.isChange || updates.isPrintError)
    ? (document.getElementById('fe-base-figurine')?.value || null)
    : null;

  // Un Errore di stampa non ha changeType (dalla v5.711 e' un tipo a se'): azzeriamo un
  // eventuale valore residuo del select, coerente con l'import.
  if (updates.isPrintError) updates.changeType = '';
  // ...e simmetricamente il Tipo di errore di stampa vale solo per gli Errori di stampa.
  if (!updates.isPrintError) updates.printErrorType = null;
  // Il Tipo di errore di stampa e' OBBLIGATORIO quando "Errore di stampa" e' selezionato (v5.771)
  if (updates.isPrintError && !updates.printErrorType) {
    toast((currentLang === 'it' ? 'Il campo "Tipo di errore di stampa" è obbligatorio quando è selezionato "Errore di stampa"' : 'The "Print error type" field is required when "Print error" is selected'), 'error');
    return;
  }
  // v5.779 — Il Tipo di change e' OBBLIGATORIO per un Change (Retro o figurina)
  if (updates.isChange && !updates.changeType) {
    toast((currentLang === 'it' ? 'Il campo "Tipo di change" è obbligatorio per un Change' : 'The "Change type" field is required for a Change'), 'error');
    return;
  }

  // Per Variazioni/Change/Errore di stampa il Numero eredita quello della figurina base collegata
  if ((updates.isVariation || updates.isUnofficialVariation || updates.isChange || updates.isPrintError) && updates.baseFigurineId) {
    const baseFigForNum = getData('figurines', []).find(x => x.id === updates.baseFigurineId);
    updates.number = baseFigForNum ? baseFigForNum.number : null;
  }

  if ((updates.isVariation || updates.isUnofficialVariation || updates.isChange || updates.isPrintError) && !updates.baseFigurineId) {
    const label = existingForCheck?.section === 'retros' ? (currentLang === 'it' ? 'Retro base' : 'Base Retro') : (currentLang === 'it' ? 'Figurina base' : 'Base sticker');
    toast((currentLang === 'it' ? `Il campo "${label}" è obbligatorio quando è selezionata una Variazione, un Change o un Errore di stampa` : `The "${label}" field is required when a Variation, Change or Print error is selected`), 'error');
    return;
  }
  if (existingForCheck?.section !== 'retros' && (updates.isVariation || updates.isUnofficialVariation) && !document.getElementById('fe-retro')?.value) {
    toast((currentLang === 'it' ? 'Il campo "Retro associato" è obbligatorio quando è selezionata una Variazione ufficiale o non ufficiale' : 'The "Associated retro" field is required when an official or unofficial Variation is selected'), 'error');
    return;
  }
  // v5.786 — retro anche per i Change (facoltativo). Solo i Retro (section) non hanno il campo.
  updates.retroId = (existingForCheck?.section !== 'retros')
    ? (document.getElementById('fe-retro')?.value || null)
    : null;

  // Gestione immagine
  if (_figEditImgData === '__remove__') {
    updates.img = '';
  } else if (_figEditImgData) {
    try {
      const res = await fetch(_figEditImgData);
      const blob = await res.blob();
      const uploaded = await uploadToCloudinary(blob);
      if (uploaded) updates.img = uploaded;
    } catch(e) { console.error('Upload img error', e); }
  }
  _figEditImgData = null;

  // Gestione foto Ebay
  if (editingFeEbayImgFileSave) {
    try {
      const uploadedEbay = await uploadToCloudinary(editingFeEbayImgFileSave);
      if (uploadedEbay) updates.ebayImg = uploadedEbay;
    } catch(e) { console.error('Upload ebayImg error', e); toast((currentLang === 'it' ? 'Caricamento foto Ebay fallito' : 'Ebay photo upload failed'), 'error'); }
  }
  editingFeEbayImgFileSave = null;

  // Mantieni i campi esistenti non modificati
  const existing = getData('figurines', []).find(x => x.id === figId);
  const merged = { ...existing, ...updates };
  // Rimuovi campi null/vuoti solo se non erano popolati
  if (!merged.number) delete merged.number;
  if (!merged.subseries) delete merged.subseries;
  if (!merged.size) delete merged.size;
  merged.fullName = computeFullName(merged, getData('figurines', []));

  try {
    await fsSave('figurines', merged);
  } catch(e) {
    console.error('saveFigFromDetail', e);
    toast((currentLang === 'it' ? '❌ Salvataggio fallito, riprova (controlla la connessione)' : '❌ Save failed, please retry (check your connection)'), 'error');
    return;
  }
  if (_cache.figurines) {
    const idx = _cache.figurines.findIndex(x => x.id === figId);
    if (idx >= 0) _cache.figurines[idx] = merged;
  }
  const savedLabel = getSectionLabelSingular(merged.section || 'figurines');
  toast(currentLang==='it'?`✅ ${savedLabel.charAt(0).toUpperCase()+savedLabel.slice(1)} salvat${savedLabel.endsWith('a')?'a':'o'}!`:`✅ ${savedLabel.charAt(0).toUpperCase()+savedLabel.slice(1)} saved!`,'success');
  closeModal('fig-detail-modal');
  renderItems();
}

async function deleteItemFromDetail(itemId) {
  if (!confirm(currentLang === 'it' ? 'Eliminare questa figurina?' : 'Delete this sticker?')) return;
  try {
    await fsDelete('figurines', itemId);
  } catch(e) {
    console.error('deleteItemFromDetail', e);
    toast((currentLang === 'it' ? '❌ Eliminazione fallita, riprova' : '❌ Delete failed, please retry'), 'error');
    return;
  }
  _cache.figurines = (_cache.figurines || []).filter(x => x.id !== itemId);
  closeModal('fig-detail-modal');
  renderItems();
  toast(currentLang === 'it' ? 'Eliminata! 🗑️' : 'Deleted! 🗑️', 'success');
}

function toggleOwnedFromDetail(figId) {
  toggleOwned(figId);
  const owned = getOwned();
  const isNowOwned = owned.includes(figId);
  // Update toggle button in modal
  const btn = document.getElementById('fig-detail-toggle');
  if (btn) btn.className = 'owned-btn ' + (isNowOwned ? 'on' : '');   // v5.720: BOTTONE, non interruttore
  // Il cuore "Ciò che cerco" non dipende più dallo stato di "Mia lista":
  // resta sempre visibile e non viene toccato da questo toggle
  // Update the card in the grid without closing the modal
  const card = document.querySelector(`.fig-card[onclick*="${figId}"]`);
  if (card) {
    const toggleBtn = card.querySelector('.owned-btn');
    if (toggleBtn) toggleBtn.className = 'owned-btn ' + (isNowOwned ? 'on' : '');
    const badge = card.querySelector('.owned-badge');
    if (badge) badge.style.display = isNowOwned ? '' : 'none';
  }
  // (Qui toggleOwned aggiornava barra ed etichetta a ogni spunta. Entrambe non
  //  esistono piu' dalla v5.689: il calcolo restava, e girava a vuoto a ogni clic.
  //  Codice morto che consuma e non produce — via.)
}

function openSegnalazioneModal(figId) {
  if (!currentUser) { openAuth('login'); return; }
  document.getElementById('segnalazione-fig-id').value = figId;
  document.getElementById('segnalazione-commento').value = '';
  const fb = document.getElementById('segnalazione-feedback');
  fb.style.display = 'none';
  document.getElementById('segnalazione-modal').classList.remove('hidden');
}

async function inviaSegnalazione() {
  const figId = document.getElementById('segnalazione-fig-id').value;
  const commento = document.getElementById('segnalazione-commento').value.trim();
  if (!commento) { toast(currentLang === 'it' ? 'Inserisci un commento' : 'Please enter a comment', 'error'); return; }
  const allFigs = getData('figurines', []);
  const fig = allFigs.find(f => f.id === figId);
  const series = getData('series', []);
  const serie = fig ? series.find(s => s.id === fig.seriesId) : null;
  const segnalazione = {
    figId,
    figName: fig ? fig.name : 'Sconosciuta',
    figNumber: fig ? fig.number : null,
    serieName: serie ? serie.name : 'Sconosciuta',
    userId: currentUser.id,
    // authUid serve alle REGOLE Firestore: isOwner() confronta request.auth.uid con
    // un campo del documento, e userId (l'id applicativo) non e' quello. Senza
    // questo campo l'utente non potrebbe cancellare le proprie segnalazioni quando
    // elimina l'account, e resterebbero li' con il suo nome e le sue parole.
    authUid: currentUser.authUid || null,
    username: currentUser.username,
    commento,
    date: new Date().toISOString(),
    read: false
  };
  const saved = await fsSave('segnalazioni', segnalazione);
  if (!_cache.segnalazioni) _cache.segnalazioni = [];
  _cache.segnalazioni.push(saved);
  const fb = document.getElementById('segnalazione-feedback');
  fb.style.display = '';
  fb.style.cssText = 'display:block;background:rgba(181,255,46,0.1);border:1px solid rgba(181,255,46,0.2);color:var(--accent);padding:0.6rem;border-radius:8px;font-size:0.88rem;margin-bottom:0.75rem;';
  fb.textContent = currentLang === 'it' ? '✅ Segnalazione inviata! Grazie.' : '✅ Report sent. Thank you!';
  setTimeout(() => closeModal('segnalazione-modal'), 1500);
  updateBellBadge();
  updateMsgBadge();
  await loadWishlist();
  updateWishlistBadge();
}

function renderAdminSegnalazioni() {
  const el = document.getElementById('admin-segnalazioni-table');
  const segnalazioni = (_cache.segnalazioni || []).sort((a,b) => new Date(b.date) - new Date(a.date));
  if (!segnalazioni.length) {
    el.innerHTML = '<p style="color:var(--muted);">' + (currentLang === 'it' ? 'Nessuna segnalazione ancora.' : 'No comments yet.') + '</p>';
    return;
  }
  // L'utente si ritrova una volta sola, non a ogni riga: prima la ricerca era
  // dentro il .map(), quindi rifatta su tutto l'elenco utenti per OGNI segnalazione.
  const perId = new Map(getData('users', []).map(u => [String(u.id), u]));

  el.innerHTML = `<table class="data-table compact"><thead><tr>
    <th>${(currentLang === 'it') ? 'Data' : 'Date'}</th><th>${(currentLang === 'it') ? 'Utente' : 'User'}</th><th>${(currentLang === 'it') ? 'E-mail' : 'E-mail'}</th><th>${(currentLang === 'it') ? 'Figurina' : 'Sticker'}</th><th>${(currentLang === 'it') ? 'Commento' : 'Comment'}</th><th></th>
  </tr></thead><tbody>
  ${segnalazioni.map(s => { const u = perId.get(String(s.userId)); return `<tr style="${s.read ? '' : 'background:rgba(181,255,46,0.05);'}">
    <td style="white-space:nowrap;font-size:0.78rem;">${new Date(s.date).toLocaleDateString('it-IT')}</td>
    <td style="display:flex;align-items:center;gap:6px;">${esc(s.username || '—')}${u?.nationalityCode ? `<img src="${flagUrl(u.nationalityCode)}" title="${esc(u.nationalityName || '')}" style="width:18px;height:12px;object-fit:cover;border-radius:2px;">` : ''}</td>
    <td style="font-size:0.8rem;color:var(--muted);">${u?.email ? esc(u.email) : '—'}</td>
    <td style="font-size:0.82rem;">${esc(s.serieName || '')}<br><span style="color:var(--muted);">${s.figNumber ? '#'+esc(String(s.figNumber))+' ' : ''}${esc(s.figName || '')}</span></td>
    <td style="white-space:pre-wrap;">${esc(s.commento || '')}</td>
    <td style="display:flex;gap:0.4rem;"><button class="tbl-btn tbl-btn-edit" onclick="markSegnalazioneRead('${s.id}')">${s.read ? '✓' : (currentLang === 'it' ? 'Segna come letta' : 'Mark as read')}</button><button class="tbl-btn tbl-btn-del" onclick="deleteSegnalazione('${s.id}')" title="${(currentLang === 'it') ? 'Elimina questa segnalazione' : 'Delete this report'}">🗑️</button></td>
  </tr>`; }).join('')}
  </tbody></table>`;
}

async function deleteSegnalazione(id) {
  if (!confirm(currentLang === 'it' ? 'Eliminare questa segnalazione?' : 'Delete this comment?')) return;
  await fsDelete('segnalazioni', id);
  _cache.segnalazioni = (_cache.segnalazioni || []).filter(s => s.id !== id);
  updateBellBadge();
  renderAdminSegnalazioni();
  toast(currentLang === 'it' ? 'Segnalazione eliminata' : 'Comment deleted', 'success');
}

async function markSegnalazioneRead(id) {
  const idx = _cache.segnalazioni.findIndex(s => s.id === id);
  if (idx < 0) return;
  _cache.segnalazioni[idx].read = true;
  await fsSave('segnalazioni', _cache.segnalazioni[idx]);
  updateBellBadge();
  renderAdminSegnalazioni();
}

async function markAllSegnalazioniRead() {
  for (const s of _cache.segnalazioni.filter(s => !s.read)) {
    s.read = true;
    await fsSave('segnalazioni', s);
  }
  updateBellBadge();
  renderAdminSegnalazioni();
  toast((currentLang === 'it' ? 'Tutte le segnalazioni segnate come lette' : 'All reports marked as read'), 'success');
}

function openViewUserModal(userId) {
  const user = getData('users', []).find(u => u.id === userId);
  if (!user) return;
  const joined = user.joined ? new Date(user.joined).toLocaleDateString('it-IT') : '—';
  const lastLogin = user.lastLogin ? new Date(user.lastLogin).toLocaleDateString('it-IT') + ' ' + new Date(user.lastLogin).toLocaleTimeString('it-IT',{hour:'2-digit',minute:'2-digit'}) : 'mai';
  const role = user.isAdmin ? 'Admin' : 'Collezionista';
  const flag = user.nationalityCode ? `<img src="${flagUrl(user.nationalityCode)}" style="width:20px;height:14px;object-fit:cover;border-radius:2px;vertical-align:middle;margin-left:4px;">` : '';

  const modal = document.createElement('div');
  modal.className = 'modal-overlay';
  modal.style.cssText = 'position:fixed;inset:0;background:rgba(0,0,0,0.7);display:flex;align-items:center;justify-content:center;z-index:9999;';
  modal.innerHTML = `
    <div class="modal" style="max-width:600px;width:95%;">
      <div class="modal-header">
        <h2 class="modal-title">👤 ${user.username}</h2>
        <button class="modal-close" onclick="this.closest('.modal-overlay').remove()">✕</button>
      </div>
      <div style="display:grid;gap:0.75rem;">
        <div class="detail-row"><span class="detail-label">${(currentLang === 'it') ? 'Nome utente' : 'Nickname'}</span><span class="detail-value">${user.username} ${flag}</span></div>
        <div class="detail-row"><span class="detail-label">E-mail</span><span class="detail-value">${user.email}</span></div>
        <div class="detail-row"><span class="detail-label">Tipologia</span><span class="detail-value">${role}</span></div>
        <div class="detail-row"><span class="detail-label">Iscritto dal</span><span class="detail-value">${joined}</span></div>
        <div class="detail-row"><span class="detail-label">Ultima login</span><span class="detail-value">${lastLogin}</span></div>
      </div>
    </div>`;
  modal.addEventListener('click', e => { if (e.target === modal) modal.remove(); });
  document.body.appendChild(modal);
}

async function deleteUserFromModal() {
  const userId = document.getElementById('edit-user-id').value;
  const users = getData('users', []);
  const user = users.find(u => u.id === userId);
  if (!user) return;
  if (!confirm('Eliminare definitivamente l\'utente ' + user.username + '?\n\n⚠️ Promemoria: dopo la cancellazione, ricordati di eliminare a mano anche il suo account da Firebase Console → Authentication — non possiamo farlo automaticamente dal sito.')) return;
  await deleteUser(userId);
  closeModal('edit-user-modal');
}

function openEditUserModal(userId) {
  const user = getData('users', []).find(u => u.id === userId);
  if (!user) return;
  document.getElementById('edit-user-id').value = userId;
  document.getElementById('edit-user-username').value = user.username;
  document.getElementById('edit-user-email').value = user.email;
  document.getElementById('edit-user-role').value = user.isAdmin ? 'admin' : 'collector';
  // Update modal title
  const titleEl = document.getElementById('edit-user-modal-title');
  if (titleEl) titleEl.textContent = '👤 ' + user.username;

  // Read-only fields
  const joinedEl = document.getElementById('edit-user-joined');
  if (joinedEl) joinedEl.textContent = user.joined ? new Date(user.joined).toLocaleDateString('it-IT') : '—';
  const lastLoginEl = document.getElementById('edit-user-lastlogin');
  if (lastLoginEl) lastLoginEl.textContent = user.lastLogin ? new Date(user.lastLogin).toLocaleDateString('it-IT') + ' ' + new Date(user.lastLogin).toLocaleTimeString('it-IT',{hour:'2-digit',minute:'2-digit'}) : 'mai';
  const levelEl = document.getElementById('edit-user-level');
  if (levelEl) {
    const owned = (_cache.ownedMap && _cache.ownedMap[user.id]) || [];
    const allFigs = getData('figurines', []);
    const score = allFigs.filter(f => owned.includes(f.id)).reduce((s, f) => s + (f.score || 0), 0);
    // Ensure levels are loaded
    if (!_cache.levels || !_cache.levels.length) {
      fsGetAll('levels').then(lvs => {
        _cache.levels = lvs;
        const lv = getUserLevel(score);
        levelEl.textContent = lv ? lv.name + ' (' + score.toLocaleString('it-IT') + ' pt)' : '— (' + score.toLocaleString('it-IT') + ' pt)';
      });
    } else {
      const lv = getUserLevel(score);
      levelEl.textContent = lv ? lv.name + ' (' + score.toLocaleString('it-IT') + ' pt)' : '— (' + score.toLocaleString('it-IT') + ' pt)';
    }
  }
  const deleteBtn = document.getElementById('edit-user-delete-btn');
  // Mai per un admin: nessuno cancella un amministratore da qui.
  if (deleteBtn) deleteBtn.style.display = user.isAdmin ? 'none' : 'block';
  document.getElementById('edit-user-modal').classList.remove('hidden');
}

async function adminResetPassword() {
  const userId = document.getElementById('edit-user-id').value;
  const users = getData('users', []);
  const user = users.find(u => u.id === userId);
  if (!user) return;
  if (!user.email) { toast('Utente senza e-mail associata: reset non possibile', 'error'); return; }
  if (!confirm('Inviare a ' + user.username + ' (' + user.email + ') un\'e-mail per reimpostare la password?')) return;

  const fb = document.getElementById('admin-reset-pwd-feedback');
  try {
    const { sendPasswordResetEmail } = window._fbAuth;
    await sendPasswordResetEmail(fbAuth, user.email);
    incrementPwdResetCounter();
    logPwdResetEmail(user.email);
    if (fb) {
      fb.style.cssText = 'display:block;background:rgba(181,255,46,0.1);border:1px solid rgba(181,255,46,0.2);color:var(--accent);padding:0.6rem 1rem;border-radius:8px;font-size:0.88rem;margin-top:0.5rem;';
      fb.textContent = '✅ E-mail di reset inviata a ' + user.email;
    }
    setTimeout(() => closeModal('edit-user-modal'), 3000);
  } catch(err) {
    console.error('adminResetPassword', err);
    if (fb) {
      fb.style.cssText = 'display:block;background:rgba(var(--danger-rgb),0.1);border:1px solid rgba(var(--danger-rgb),0.3);color:var(--danger);padding:0.6rem 1rem;border-radius:8px;font-size:0.88rem;margin-top:0.5rem;';
      fb.textContent = '❌ Invio non riuscito: ' + (err.code || err.message);
    }
  }
}

async function saveEditUser() {
  const userId = document.getElementById('edit-user-id').value;
  const username = document.getElementById('edit-user-username').value.trim();
  const email = document.getElementById('edit-user-email').value.trim();
  const isAdmin = document.getElementById('edit-user-role').value === 'admin';
  if (!username || !email) { toast((currentLang === 'it' ? 'Compila tutti i campi' : 'Please fill in all fields'), 'error'); return; }
  const users = getData('users', []);
  const idx = users.findIndex(u => u.id === userId);
  if (idx < 0) return;
  users[idx].username = username;
  users[idx].email = email;
  await fsSave('users', users[idx]);
  _cache.users = users;
  closeModal('edit-user-modal');
  renderAdminUsers();
  toast('Utente aggiornato!', 'success');
}

async function deleteUser(userId) {
  // L'utente va letto PRIMA di cancellarlo: servono la sua e-mail e il suo authUid
  // per ritrovare le tracce, e dopo fsDelete('users') non li avremmo piu'.
  const target = getData('users', []).find(u => String(u.id) === String(userId));

  // Le stesse cose che fa l'auto-eliminazione. Fino alla v5.642 la cancellazione
  // fatta dall'ADMIN era piu' incompleta di quella fatta dall'utente: non
  // anonimizzava nemmeno i post, e non toccava contact_messages, email_log e
  // segnalazioni. Il risultato dipendeva quindi da CHI premeva il pulsante — il
  // che non ha alcun senso: l'esito dev'essere lo stesso, e cancellare un utente
  // dal pannello e' anzi il modo in cui si evade una richiesta di cancellazione
  // arrivata per iscritto (art. 17 GDPR).
  await _anonymizeUserContent(userId);
  if (target) await _deleteUserTraces(target);

  // Anche la cancellazione fatta dall'admin lascia traccia, ma con una causale
  // DIVERSA: sono due fatti diversi. Un utente che se ne va da solo e un utente
  // rimosso dal pannello non vanno confusi nel registro — e se la rimozione
  // evade una richiesta scritta di cancellazione, questa riga e' la prova di
  // averla onorata.
  // authUid del BERSAGLIO, non dell'admin che sta eseguendo: altrimenti l'evento
  // risulterebbe di chi ha premuto il pulsante.
  if (target) logEvent('account_deleted', "L'utente " + bold(target.username) + " è stato eliminato dall'amministratore", { authUid: target.authUid || null });

  await fsDelete('users', userId);
  // Cancella anche i dati collegati, altrimenti restano "orfani" nel database
  // (è esattamente il problema dei profili pubblici extra scoperto oggi)
  try { await fsDelete('public_profiles', userId); } catch(e) { console.warn('delete public_profiles', e.message); }
  try { await fsDelete('owned', userId); } catch(e) { console.warn('delete owned', e.message); }
  try { await fsDelete('wishlists', userId); } catch(e) { console.warn('delete wishlists', e.message); }
  _cache.users = _cache.users.filter(u => u.id !== userId);
  if (_cache.public_profiles) _cache.public_profiles = _cache.public_profiles.filter(p => p.id !== userId);
  if (_cache.ownedMap) delete _cache.ownedMap[userId];
  renderAdminUsers();
  // Le tabelle delle raccolte ripulite vanno RIDISEGNATE: la cache e' aggiornata,
  // ma cio' che e' gia' a schermo resterebbe li' finche' non si cambia scheda.
  // (Ogni render esce da sola se la sua scheda non e' aperta.)
  renderAdminContacts();
  renderAdminSegnalazioni();
  renderAdminEventi();
  updateMsgBadge();
  updateBellBadge();
  toast(currentLang === 'it' ? '✅ Utente eliminato dal sito.<br><span style="font-size:0.85em;opacity:0.85;">⚠️ Ricordati di eliminarlo anche da Firebase Console → Authentication.</span>' : '✅ User deleted from the site.<br><span style="font-size:0.85em;opacity:0.85;">⚠️ Remember to also delete it from Firebase Console → Authentication.</span>', 'success', null, 7000);
}

// ============================================================
//  STATS
// ============================================================
function animateCount(el, target) {
  let current = 0;
  const step = Math.ceil(target / 30);
  const interval = setInterval(() => {
    current = Math.min(current + step, target);
    el.textContent = current;
    if (current >= target) clearInterval(interval);
  }, 40);
}
function renderHomeStats() {
  const series = getData('series', []);
  const figs = getData('figurines', []);
  const users = getData('public_profiles', []);
  const onlyFigs = figs.filter(f => f.section !== 'retros' && f.section !== 'albums' && f.section !== 'extras' && f.section !== 'bustine');
  const retros = figs.filter(f => f.section === 'retros');
  const bustine = figs.filter(f => f.section === 'bustine');
  const albums = figs.filter(f => f.section === 'albums');
  const extras = figs.filter(f => f.section === 'extras');
  animateCount(document.getElementById('stat-series'), series.length);
  animateCount(document.getElementById('stat-figs'), onlyFigs.length);
  animateCount(document.getElementById('stat-retros'), retros.length);
  animateCount(document.getElementById('stat-bustine'), bustine.length);
  animateCount(document.getElementById('stat-albums'), albums.length);
  animateCount(document.getElementById('stat-extras'), extras.length);
  animateCount(document.getElementById('stat-users'), users.length);
  updateOwnedCounter();
}

function updateOwnedCounter() {
  const figs = getData('figurines', []);
  const owned = getOwned();
  const ownedCount = figs.filter(f => owned.includes(f.id)).length;
  const total = figs.length;

  // Hero stat
  const wrap = document.getElementById('stat-owned-wrap');
  const heroEl = document.getElementById('stat-owned-hero');
  if (wrap && heroEl) {
    if (currentUser) {
      wrap.style.display = '';
      heroEl.textContent = ownedCount + ' / ' + total;
    } else {
      wrap.style.display = 'none';
    }
  }

  // Navbar counter
  const navEl = document.getElementById('nav-owned-counter');
  if (navEl) {
    if (currentUser && !currentUser.isAdmin) {
      navEl.style.display = '';
      navEl.innerHTML = '<div style="font-size:0.7rem;opacity:0.75;line-height:1.2;">' + (currentLang === 'it' ? 'Figurine nella tua lista' : "My list's stickers") + '</div><div style="font-size:0.7rem;line-height:1.2;">' + ownedCount + ' / ' + total + '</div>';
    } else {
      navEl.style.display = 'none';
    }
  }

  // Profile stats
  const profileOwned = document.getElementById('profile-owned');
  if (profileOwned) profileOwned.textContent = ownedCount + ' / ' + total;
}

