// Caricamento massivo foto per figurine senza numero e Retro (base e Change):
// nessuno di questi ha un Numero, quindi l'abbinamento file→oggetto avviene
// per Nome esatto (case-insensitive) invece che per numero. Se più di un
// oggetto della serie condivide lo stesso Nome, il file è ambiguo e viene
// saltato con un avviso, invece di indovinare quale sia quello giusto.
async function startAdminFotoNoNumberUpload() {
  const seriesId = document.getElementById('fotonn-series-select').value;
  if (!seriesId) { toast(currentLang==='it'?'Seleziona una serie':'Select a series', 'error'); return; }
  const scope = document.getElementById('fotonn-scope-select').value; // '' | 'figurine' | 'retro'
  if (!scope) { toast(currentLang==='it'?'Seleziona cosa stai caricando (Figurine o Retro)':'Select what you are uploading (Stickers or Retro)', 'error'); return; }
  const files = Array.from(document.getElementById('fotonn-file-input').files);
  if (!files.length) { toast(currentLang==='it'?'Seleziona almeno una foto':'Select at least one photo', 'error'); return; }
  const doRemoveBg = document.getElementById('fotonn-remove-bg').checked;
  const overwrite = document.getElementById('fotonn-overwrite').checked;

  if (doRemoveBg) {
    let tries = 0;
    while (!window._removeBackground && tries < 30) {
      fotoNnStatus(currentLang==='it'?'⏳ Caricamento libreria AI...':'⏳ Loading AI library...', 0);
      await new Promise(r => setTimeout(r, 1000));
      tries++;
    }
    if (!window._removeBackground) {
      toast(currentLang==='it'?'❌ Libreria AI non disponibile, deseleziona "Rimuovi sfondo"':'❌ AI library unavailable, uncheck "Remove background"', 'error');
      return;
    }
  }

  document.getElementById('fotonn-start-btn').disabled = true;
  document.getElementById('fotonn-progress-wrap').style.display = 'block';
  document.getElementById('fotonn-log').innerHTML = '';
  fotoNnLog('--- ' + (currentLang==='it'?'Avvio':'Start') + ': ' + files.length + ' foto (' + scope + ') ---', 'info');

  // Candidati in base allo scope scelto. Per il Retro (v5.756) la chiave di
  // riconciliazione è il NOME COMPLETO (fullName), non più il solo Nome: il
  // fullName include già Categoria, Nome e — per i Change — il Tipo in MAIUSCOLO
  // (vedi computeFullName/_retroFullName), quindi disambigua da solo sia un Change
  // dal proprio Retro base sia due Retro con lo stesso Nome in Categorie diverse.
  // Si usa il fullName SALVATO — quello mostrato nella colonna "Nome Completo"
  // della Vista tabellare — così l'utente nomina i file esattamente come li vede;
  // se per un record non fosse popolato, lo si ricalcola al volo come ripiego.
  // Le Figurine senza numero restano sul solo Nome (per una base fullName = Nome).
  const allFigs = getData('figurines', []);
  const candidates = allFigs
    .filter(f => f.seriesId === seriesId && (scope === 'retro' ? f.section === 'retros' : (f.section === 'figurines' && !f.number && !f.isVariation && !f.isUnofficialVariation && !f.isChange)))
    .map(f => ({ item: f, key: (scope === 'retro') ? (f.fullName || computeFullName(f, allFigs)) : f.name }));
  fotoNnLog((currentLang==='it'?'Oggetti candidati nella serie:':'Candidate items in series:') + ' ' + candidates.length, 'info');

  let ok = 0, skip = 0, errors = 0;

  // Vedi startImportVar: gli scarti si raccolgono, per poterli ripetere in fondo.
  const erroriRighe = [];
  const errRiga = (msg, lvl) => { fotoNnLog(msg, lvl || 'warn'); erroriRighe.push(msg); errors++; };

  // Normalizzazione per il confronto nome-file ⇄ chiave (v5.757). Il "?" è ammesso
  // nel Nome (e quindi nel Nome completo) dentro al DB, ma NON in un nome di file su
  // Windows: e' un carattere vietato dal file system, quindi chi esporta le foto lo
  // deve per forza omettere. Lo si ignora quindi da ENTRAMBI i lati del confronto.
  // Si azzerano anche gli spazi multipli che la rimozione del "?" puo' lasciare, e le
  // maiuscole/minuscole. Vale per tutte le chiavi (Nome completo dei Retro e Nome
  // delle Figurine senza numero): un file non puo' contenere "?" in nessun caso.
  const normKey = s => (s || '').toLowerCase().replace(/\?/g, '').replace(/\s+/g, ' ').trim();

  for (let i = 0; i < files.length; i++) {
    const file = files[i];
    const name = file.name.replace(/\.[^.]+$/, '').trim();
    fotoNnStatus(file.name + ' (' + (i+1) + '/' + files.length + ')', Math.round((i/files.length)*100));

    if (!name) { errRiga('⚠️ Nome file non valido: ' + file.name, 'warn');  continue; }
    const matches = candidates.filter(c => normKey(c.key) === normKey(name));
    if (!matches.length) { errRiga('⚠️ Nessun oggetto trovato con ' + (scope === 'retro' ? 'Nome completo' : 'Nome') + ' "' + name + '"', 'warn');  continue; }
    if (matches.length > 1) {
      errRiga('⚠️ "' + name + '" è ambiguo: ' + matches.length + ' oggetti nella serie corrispondono — controlla eventuali duplicati nel database', 'warn');
       continue;
    }
    const fig = matches[0].item;
    if (fig.img && !overwrite) { fotoNnLog('⏭️ "' + name + '" — saltata (ha già foto)', 'info'); skip++; continue; }

    try {
      let blob = file;

      if (doRemoveBg) {
        fotoNnLog('🎨 Rimozione sfondo "' + name + '"...', 'info');
        blob = await window._removeBackground(blob, {
          model: 'isnet', // v5.793 — modello pieno (vedi removeBgFromEdit)
          progress: (key, cur, tot) => fotoNnStatus('Sfondo "' + name + '": ' + Math.round((cur/tot)*100) + '%', Math.round((i/files.length)*100))
        });
        blob = await fotoCrop(blob);
      }

      fotoNnLog('☁️ Caricamento ' + (i+1) + '/' + files.length + ' — "' + name + '"...', 'info');
      const url = await uploadToCloudinary(blob);
      const updated = { ...fig, img: url };
      await fsSave('figurines', updated);
      if (_cache.figurines) {
        const idx = _cache.figurines.findIndex(x => x.id === fig.id);
        if (idx >= 0) _cache.figurines[idx] = updated;
      }
      fotoNnLog('✅ "' + name + '" — completato', 'ok');
      ok++;
    } catch(e) {
      errRiga('❌ "' + name + '" — ' + e.message, 'err');
      
    }
  }

  fotoNnStatus('✅ Fine: ' + ok + ' ok · ' + skip + ' saltate · ' + errors + ' errori', 100);
  fotoNnLog('--- FINE: ' + ok + ' ok · ' + skip + ' saltate · ' + errors + ' errori ---', errors === 0 ? 'ok' : 'warn');

  if (erroriRighe.length) {
    fotoNnLog('', 'info');
    fotoNnLog('--- ' + (currentLang === 'it'
      ? 'ELENCO COMPLETO DEI FILE NON CARICATI (' + erroriRighe.length + ') ---'
      : 'COMPLETE LIST OF FILES NOT UPLOADED (' + erroriRighe.length + ') ---'), 'white');
    erroriRighe.forEach(msg => fotoNnLog(msg, 'warn'));
  }
  document.getElementById('fotonn-start-btn').disabled = false;
}

// ============================================================
//  TOAST
// ============================================================
function toast(msg, type = 'success', anchorEl = null, duration = 3500) {
  const t = document.createElement('div');
  t.className = 'toast ' + type;
  if (msg.includes('<br>')) { t.innerHTML = msg; } else { t.textContent = msg; }
  if (anchorEl) {
    // Position near the anchor element
    const rect = anchorEl.getBoundingClientRect();
    t.style.position = 'fixed';
    t.style.zIndex = '9999';
    t.style.left = Math.min(rect.left, window.innerWidth - 320) + 'px';
    t.style.top = (rect.bottom + 8) + 'px';
    t.style.transform = 'none';
    document.body.appendChild(t);
  } else {
    const tc = document.getElementById('toast-container');
    tc.appendChild(t);
  }
  setTimeout(() => t.remove(), duration);
}

// ============================================================
//  PARTICLES
// ============================================================
function createParticles() {
  const container = document.getElementById('particles');
  const colors = ['#b5ff2e','#ff6b1a','#c84bff','#2effb5'];
  for (let i = 0; i < 18; i++) {
    const p = document.createElement('div');
    p.className = 'particle';
    const size = Math.random() * 80 + 20;
    p.style.cssText = `width:${size}px;height:${size}px;left:${Math.random()*100}%;background:${colors[Math.floor(Math.random()*colors.length)]};animation-duration:${Math.random()*20+15}s;animation-delay:-${Math.random()*20}s;`;
    container.appendChild(p);
  }
}
createParticles();

// ============================================================
//  SCROLL REVEAL
// ============================================================
function initReveal() {
  const obs = new IntersectionObserver((entries) => {
    entries.forEach(e => { if (e.isIntersecting) { e.target.classList.add('visible'); obs.unobserve(e.target); } });
  }, { threshold: 0.1 });
  document.querySelectorAll('.reveal').forEach(el => { el.classList.remove('visible'); obs.observe(el); });
}

// ============================================================
//  RENDER ALL
// ============================================================
function renderAll() {
  applyI18n();
  renderHomeSeries();
  renderHomeStats();
  updateSectionCounts();

  // Re-render active page
  if (document.getElementById('page-catalog')?.classList.contains('active')) renderCatalog();
  if (document.getElementById('page-blog')?.classList.contains('active')) renderBlog();
  if (document.getElementById('page-classifica')?.classList.contains('active')) renderClassifica();
  if (document.getElementById('page-wantlist')?.classList.contains('active')) renderWantlist();
  if (document.getElementById('page-wishlist')?.classList.contains('active')) renderWishlist();
  if (document.getElementById('page-newsletter')?.classList.contains('active')) { renderNewsletterUsers(); renderEmailLog(); }

  // Re-render items section if open
  if (document.getElementById('items-section')?.style.display !== 'none') {
    const titleEl = document.getElementById('items-section-title');
    if (titleEl && currentSection) titleEl.textContent = getSectionLabel(currentSection);
    // Aggiorna testo pulsanti toolbar figurine (Vista tabellare / Solo senza foto)
    const bulkBtn = document.getElementById('bulk-edit-toggle-btn');
    if (bulkBtn) {
      bulkBtn.textContent = bulkEditActive
        ? (currentLang === 'it' ? '🔲 Vista griglia' : '🔲 Grid view')
        : (currentLang === 'it' ? '📋 Vista tabellare' : '📋 Table view');
    }
    renderItems();
  }

  // Re-render admin if open — preserve active tab
  if (document.getElementById('admin-panel')?.style.display === 'block') {
    const activeTab = document.querySelector('.admin-tab.active');
    const tab = activeTab?.getAttribute('onclick')?.match(/adminTab\('(\w+)'\)/)?.[1];
    if (tab) adminTab(tab);
  }

  // Only render profile if admin panel is NOT showing (admin panel lives inside page-profile)
  const _adminPanelOpen = document.getElementById('admin-panel')?.style.display === 'block';
  if (document.getElementById('page-profile')?.classList.contains('active') && !_adminPanelOpen) renderProfile();
}

// ============================================================
//  EMAIL COUNTER
// ============================================================
async function logEmail(toEmail, subject, source = 'other', body = '', status = 'sent') {
  try {
    await fsSave('email_log', {
      to: toEmail,
      subject: subject,
      source: source,
      body: body,
      status: status,
      date: new Date().toISOString()
    });
    // Sfoltimento a 200 voci più recenti — solo per l'admin, dato che leggere
    // l'intera collezione email_log richiede permessi di amministratore (le
    // regole Firestore riservano la lettura solo all'admin); per un utente
    // normale (es. la propria email di benvenuto) questo controllo va
    // semplicemente saltato, è comunque una manutenzione periodica, non
    // serve farla ad ogni singolo invio
    if (currentUser?.isAdmin) {
      try {
        const allLogs = await fsGetAll('email_log');
        if (allLogs.length > 200) {
          allLogs.sort((a,b) => new Date(a.date) - new Date(b.date));
          const toDelete = allLogs.slice(0, allLogs.length - 200);
          for (const log of toDelete) await fsDelete('email_log', log.id);
        }
      } catch(e) { console.error('email_log trim error', e); }
    }
    // Refresh log if Mail tab is open
    if (typeof renderEmailLog === 'function') {
      const mailTab = document.getElementById('admin-email-log');
      if (mailTab && mailTab.offsetParent !== null) renderEmailLog();
    }
  } catch(e) { console.error('logEmail error', e); }
}

async function incrementEmailCounter(count) {
  if (!count || !db || !window._fb) return;
  try {
    const now = new Date();
    const monthKey = now.getFullYear() + '-' + String(now.getMonth()+1).padStart(2,'0');
    const { doc, getDoc, setDoc, increment } = window._fb;
    const ref = doc(db, 'email_stats', 'counter');
    // INCREMENTO ATOMICO lato server (FieldValue.increment), senza rileggere il
    // documento. È il punto centrale della correzione: email_stats è SCRIVIBILE
    // da tutti (serve anche ai non-admin, es. la propria e-mail di benvenuto) ma
    // LEGGIBILE solo dall'admin. La versione precedente faceva
    // leggi → somma → riscrivi-tutto: per un utente non-admin la lettura falliva,
    // l'errore veniva ingoiato da un catch vuoto, e il setDoc finale
    // SOVRASCRIVEVA il documento reale con { total: 1 }. Ogni registrazione non
    // incrementava il contatore: lo azzerava. Con increment() non c'è nessuna
    // lettura da fare, e il valore non può essere sovrascritto.
    await setDoc(ref, { total: increment(count), months: { [monthKey]: increment(count) } }, { merge: true });
    // Il riquadro del contatore lo vede solo l'admin — ed è anche l'unico che ha
    // il permesso di rileggere il documento per aggiornarlo a schermo.
    if (currentUser?.isAdmin) {
      try { await refreshEmailCountWidgets(); }
      catch(e) { console.warn('Contatore e-mail: aggiornamento a schermo non riuscito', e.message); }
    }
  } catch(e) { console.error('Email counter error', e); }
}



// Alimentava renderEmailCounter(), che scriveva su elementi inesistenti:
// era quindi un lettore che non produceva alcun effetto visibile. Delega a
// refreshEmailCountWidgets(), che legge lo stesso documento e aggiorna i widget
// realmente presenti in pagina. Mantenuta come funzione perché richiamata
// altrove: rimuoverla avrebbe richiesto di rincorrerne i chiamanti.
async function loadEmailCounter() {
  await refreshEmailCountWidgets();
}


// ============================================================
//  AVATAR UPLOAD
// ============================================================
async function uploadAvatar(e) {
  const file = e.target.files[0];
  if (!file) return;
  toast((currentLang === 'it' ? 'Caricamento avatar...' : 'Uploading avatar...'), 'success');
  try {
    const url = await uploadToCloudinary(file);
    // Update user in cache and localStorage
    currentUser.avatar = url;
    LOCAL.set('currentUser', currentUser);
    // Update in Firebase
    await fsSave('users', currentUser);
    let users = getData('users', []);
    const idx = users.findIndex(u => u.id === currentUser.id);
    if (idx >= 0) {
      users[idx] = currentUser;
      _cache.users = users;
    }
    updateNavUser();
    renderProfile();
    toast('Avatar aggiornato! 🎉', 'success');
  } catch(e) {
    toast((currentLang === 'it' ? 'Errore nel caricamento' : 'Upload error'), 'error');
  }
}

// ============================================================
//  BULK OWNED
// ============================================================
async function setAllOwned(ownAll) {
  if (!currentUser) return;
  // Agisce su cio' che il filtro ha SELEZIONATO, non sull'intera sezione.
  // Fino alla v5.669 questa riga prendeva tutte le figurine della sezione,
  // ignorando ricerca, filtro tipo, "senza variazione ufficiale" e "da vendere".
  // I pulsanti dicevano "tutti gli oggetti VISUALIZZATI" e ne toccavano molti di
  // piu': con un filtro attivo su 12 variazioni, "Rimuovi" svuotava dalla lista
  // l'INTERA sezione — centinaia di oggetti — dopo una conferma che aveva
  // promesso altro. Distruttivo e silenzioso.
  // getCurrentlyFilteredItems() e' la funzione condivisa che gia' usano renderItems
  // e altri cinque punti: restituisce gli elementi filtrati di TUTTE le pagine
  // (l'impaginazione avviene dopo). Era l'unico posto rimasto fuori.
  const items = getCurrentlyFilteredItems();
  if (!items.length) return;
  // La conferma dice QUANTI oggetti verranno toccati. Un "tutti gli oggetti
  // visualizzati?" e' vero ma astratto: con un filtro attivo si vedono 12 righe e
  // ce ne possono essere 300 nelle pagine successive. Il numero rende concreto
  // cio' che si sta per fare — e questa, in rimozione, e' un'azione che butta via
  // il lavoro di mesi.
  const n = items.length;
  const msg = ownAll
    ? (currentLang === 'it'
        ? `Aggiungere alla tua lista ${n} ${n === 1 ? 'oggetto' : 'oggetti'}?`
        : `Add ${n} ${n === 1 ? 'item' : 'items'} to your list?`)
    : (currentLang === 'it'
        ? `Rimuovere dalla tua lista ${n} ${n === 1 ? 'oggetto' : 'oggetti'}?`
        : `Remove ${n} ${n === 1 ? 'item' : 'items'} from your list?`);
  if (!confirm(msg)) return;
  let owned = getOwned();
  if (ownAll) {
    items.forEach(f => { if (!owned.includes(f.id)) owned.push(f.id); });
  } else {
    const ids = items.map(f => f.id);
    owned = owned.filter(id => !ids.includes(id));
  }
  if (!_cache.ownedMap) _cache.ownedMap = {};
  _cache.ownedMap[currentUser.id] = owned;
  LOCAL.set('owned_' + currentUser.id, owned);
  await saveOwnedToFirebase(currentUser.id, owned);
  renderItems();
  updateOwnedCounter();
  refreshSeriesMeta();   // idem per l'aggiunta/rimozione massiva (v5.709)
  // Punti guadagnati con QUESTA azione, e punteggio complessivo della lista.
  // I punti nuovi si contano solo sugli oggetti che l'utente NON aveva: chi aveva
  // gia' mezza serie non deve vedersi accreditare anche quella meta'.
  // Il totale invece si ricalcola su TUTTA la lista, non solo su questa serie.
  let puntiAggiunti = 0, punteggioTotale = 0;
  if (ownAll) {
    puntiAggiunti = items
      .filter(f => !giaAveva.has(f.id))
      .reduce((somma, f) => somma + (f.score || 0), 0);
    punteggioTotale = getData('figurines', [])
      .filter(f => owned.includes(f.id))
      .reduce((somma, f) => somma + (f.score || 0), 0);
  }

  // La finestra si mostra solo se c'e' davvero qualcosa da festeggiare. Se
  // l'utente aveva gia' tutto, i punti nuovi sono ZERO: "Complimenti, hai aggiunto
  // 0 punti" sarebbe una presa in giro. In quel caso resta il messaggino di sempre.
  if (ownAll && puntiAggiunti > 0) {
    mostraPunteggioGuadagnato(puntiAggiunti, punteggioTotale);
    return;
  }

  const setAllMsgEl = document.getElementById('set-all-msg');
  if (setAllMsgEl) {
    setAllMsgEl.textContent = ownAll ? (currentLang === 'it' ? 'Tutti aggiunti!' : 'All added!') : (currentLang === 'it' ? 'Tutti rimossi!' : 'All removed!');
    setAllMsgEl.style.display = '';
    setTimeout(() => { setAllMsgEl.style.display = 'none'; }, 3000);
  }
}

// Finestra "Complimenti": quanti punti ha appena guadagnato e a quanto e' arrivato.
// I numeri usano il separatore delle migliaia della lingua in uso (1.234 in
// italiano, 1,234 in inglese): un punteggio a quattro cifre scritto di fila si
// legge male.
// Singolare e plurale sono gestiti a mano ("1 punto" / "2 punti", "1 point" /
// "2 points"): scrivere "1 punti" e' il dettaglio che fa sembrare tradotto male
// tutto il resto.
function mostraPunteggioGuadagnato(aggiunti, totale) {
  const it = currentLang === 'it';
  const loc = it ? 'it-IT' : 'en-US';
  const nA = aggiunti.toLocaleString(loc);
  const nT = totale.toLocaleString(loc);
  const pA = it ? (aggiunti === 1 ? 'punto' : 'punti') : (aggiunti === 1 ? 'point' : 'points');
  const pT = it ? (totale === 1 ? 'punto' : 'punti') : (totale === 1 ? 'point' : 'points');

  const elA = document.getElementById('score-boost-added');
  const elT = document.getElementById('score-boost-total');
  if (elA) elA.textContent = it
    ? 'Hai aggiunto ' + nA + ' ' + pA + ' alla classifica della tua lista.'
    : 'You added ' + nA + ' ' + pA + " to your list's ranking.";
  if (elT) elT.textContent = it
    ? 'La tua lista ha ora un punteggio di ' + nT + ' ' + pT + '!'
    : 'Your list now has a score of ' + nT + ' ' + pT + '!';
  document.getElementById('score-boost-modal')?.classList.remove('hidden');
}

// ============================================================
//  BULK EDIT VIEW
// ============================================================
let bulkEditActive = false;

function toggleBulkEditView() {
  bulkEditActive = !bulkEditActive;
  const grid = document.getElementById('items-grid');
  const pagination = document.getElementById('items-pagination');
  const paginationTop = document.getElementById('items-pagination-top');
  const bulkView = document.getElementById('bulk-edit-view');
  const btn = document.getElementById('bulk-edit-toggle-btn');

  if (bulkEditActive) {
    if (grid) grid.style.display = 'none';
    if (pagination) pagination.style.display = 'none';
    if (paginationTop) paginationTop.style.display = 'none';
    if (bulkView) bulkView.style.display = '';
    if (btn) btn.textContent = currentLang === 'it' ? '🔲 Vista griglia' : '🔲 Grid view';
    renderBulkEditView();
  } else {
    if (grid) grid.style.display = 'grid';
    if (pagination) pagination.style.display = '';
    if (paginationTop) paginationTop.style.display = '';
    if (bulkView) { bulkView.style.display = 'none'; bulkView.innerHTML = ''; }
    if (btn) btn.textContent = currentLang === 'it' ? '📋 Vista tabellare' : '📋 Table view';
  }
}

function renderBulkEditView() {
  const bulkView = document.getElementById('bulk-edit-view');
  if (!bulkView) return;
  bulkView.style.width = 'min(1800px, 96vw)';
  bulkView.style.maxWidth = '1800px';
  bulkView.style.marginLeft = '50%';
  bulkView.style.marginRight = '0';
  bulkView.style.transform = 'translateX(-50%)';
  const isAdmin = !!currentUser?.isAdmin;
  const owned = getOwned();
  const currentSeries = getData('series', []).find(s => s.id === currentSeriesId);
  const currentSeriesHasSizes = currentSeries?.hasSizes || false;
  const currentSeriesHasSubseries = currentSeries?.hasSubseries || false;
  const allItems = getCurrentlyFilteredItems()
    .sort((a,b) => {
      if (currentSection === 'retros') {
        const catCmp = (a.category||'').localeCompare(b.category||'', 'it');
        if (catCmp !== 0) return catCmp;
        const subcatCmp = (a.subcategory||'').localeCompare(b.subcategory||'', 'it');
        if (subcatCmp !== 0) return subcatCmp;
        const nameCmp = (a.name||'').localeCompare(b.name||'', 'it');
        if (nameCmp !== 0) return nameCmp;
        return (a.changeType||'').localeCompare(b.changeType||'', 'it');
      }
      if (currentSection === 'figurines') {
        const subCmp = (a.subseries||'').localeCompare(b.subseries||'', 'it');
        if (subCmp !== 0) return subCmp;
        if (!a.number && !b.number) {
          const nameCmp = (a.name||'').localeCompare(b.name||'', 'it');
          if (nameCmp !== 0) return nameCmp;
        } else if (!a.number) { return 1; }
        else if (!b.number) { return -1; }
        else {
          const numCmp = a.number - b.number;
          if (numCmp !== 0) return numCmp;
        }
        const allFigsForSort2 = getData('figurines', []);
        const fnA = a.fullName || computeFullName(a, allFigsForSort2);
        const fnB = b.fullName || computeFullName(b, allFigsForSort2);
        return fnA.localeCompare(fnB, 'it');
      }
      if (!a.number && !b.number) return (a.subseries||'').localeCompare(b.subseries||'');
      if (!a.number) return 1;
      if (!b.number) return -1;
      return a.number - b.number;
    });
  updateItemsCountDisplay(allItems);

  if (!allItems.length) { bulkView.innerHTML = `<p style="color:var(--muted);">${currentLang === 'it' ? 'Nessun oggetto trovato con i filtri attuali.' : 'No items found with the current filters.'}</p>`; return; }

  // Cella di sola lettura per l'utente non-admin (niente input editabile)
  const readCell = (val, width) => `<td style="padding:4px 8px;color:var(--text);text-align:left;${width ? 'min-width:'+width+'px;' : ''}">${val ?? ''}</td>`;

  bulkView.innerHTML = `
    ${isAdmin ? `<p style="font-size:0.8rem;color:var(--muted);margin-bottom:0.75rem;">${(currentLang === 'it') ? 'Modifica direttamente nelle celle. Le modifiche vengono salvate automaticamente.' : 'Edit directly in the cells. Changes are saved automatically.'}</p>
    <div style="display:flex;align-items:center;gap:0.75rem;margin-bottom:0.75rem;">
      <button class="btn-danger" id="bulk-delete-btn" onclick="deleteBulkSelected()" disabled style="opacity:0.5;font-size:0.9rem;padding:0.5rem 1rem;">🗑️ ${(currentLang === 'it') ? 'Elimina selezionati' : 'Delete selected'} (<span id="bulk-delete-count">0</span>)</button>
    </div>` : ''}
    <table style="width:100%;border-collapse:collapse;font-size:0.82rem;">
      <thead>
        <tr style="background:var(--card2);">
          <th style="padding:8px;text-align:center;border-bottom:1px solid var(--border);color:var(--muted);width:36px;">#</th>
          <th style="padding:8px;text-align:center;border-bottom:1px solid var(--border);color:var(--muted);width:48px;">${(currentLang === 'it') ? 'Foto' : 'Photo'}</th>
          ${isAdmin ? `<th style="padding:8px;text-align:left;border-bottom:1px solid var(--border);color:var(--muted);">${(currentLang === 'it') ? 'Modifica' : 'Edit'}</th>` : ''}
          ${isAdmin ? '<th style="padding:8px;text-align:center;border-bottom:1px solid var(--border);width:30px;"><input type="checkbox" id="bulk-select-all" onchange="toggleBulkSelectAll(this)"></th>' : ''}
          ${currentSeriesHasSubseries ? '<th style="padding:8px;text-align:left;border-bottom:1px solid var(--border);color:var(--muted);">Sottoserie</th>' : ''}
          ${currentSection === 'retros' ? '<th style="padding:8px;text-align:left;border-bottom:1px solid var(--border);color:var(--muted);">Categoria</th><th style="padding:8px;text-align:left;border-bottom:1px solid var(--border);color:var(--muted);">Sottocategoria</th>' : ''}
          ${currentSection !== 'retros' ? '<th style="padding:8px;text-align:left;border-bottom:1px solid var(--border);color:var(--muted);">N.</th>' : ''}
          ${currentSection === 'figurines' ? `<th style="padding:8px;text-align:left;border-bottom:1px solid var(--border);color:var(--muted);">${currentLang === 'it' ? 'Tipo' : 'Type'}</th>` : ''}
          <th style="padding:8px;text-align:left;border-bottom:1px solid var(--border);color:var(--muted);">${currentSection === 'figurines' ? (currentLang === 'it' ? 'Nome Completo' : 'Full Name') : 'Nome'}</th>
          ${currentSection === 'retros' ? `<th style="padding:8px;text-align:left;border-bottom:1px solid var(--border);color:var(--muted);">${currentLang === 'it' ? 'Tipo di change' : 'Change type'}</th>` : ''}
          <th style="padding:8px;text-align:left;border-bottom:1px solid var(--border);color:var(--muted);">${(currentLang === 'it') ? 'Punteggio' : 'Score'}</th>
          ${currentSeriesHasSizes ? '<th style="padding:8px;text-align:left;border-bottom:1px solid var(--border);color:var(--muted);">Taglia</th>' : ''}
          ${!isAdmin ? `
          <th style="padding:8px;text-align:center;border-bottom:1px solid var(--border);color:var(--muted);">${currentLang === 'it' ? 'Mia lista' : 'My list'}</th>
          <th style="padding:8px;text-align:center;border-bottom:1px solid var(--border);color:var(--muted);">${currentLang === 'it' ? 'Ciò che cerco' : "What I'm looking for"}</th>` : ''}
        </tr>
      </thead>
      <tbody>
        ${allItems.map((f, rowIdx) => {
          const isOwned = owned.includes(f.id);
          const inWishlist = _wishlist.includes(f.id);
          return `<tr id="bulk-row-${f.id}" style="border-bottom:1px solid var(--border);">
          <td style="padding:4px 8px;text-align:center;color:var(--muted);font-size:0.78rem;">${rowIdx + 1}</td>
          <td style="padding:4px;text-align:center;">${f.img
            ? `<img src="${f.img}" alt="" loading="lazy" style="width:38px;height:38px;object-fit:cover;border-radius:5px;background:var(--card2);border:1px solid var(--border2);vertical-align:middle;">`
            : `<span style="display:inline-flex;width:38px;height:38px;border-radius:5px;background:var(--card2);border:1px solid var(--border2);align-items:center;justify-content:center;color:var(--muted);font-size:0.95rem;">${currentSection === 'retros' ? '📇' : '🃏'}</span>`}</td>
          ${isAdmin ? `<td style="padding:4px;white-space:nowrap;"><button class="tbl-btn tbl-btn-edit" style="font-size:1.05rem;font-weight:bold;line-height:1;padding:3px 8px;" title="${currentLang === 'it' ? 'Modifica' : 'Edit'}" onclick="openAddItemModal('${f.id}')">&#9998;</button> <button class="tbl-btn tbl-btn-edit" style="font-size:1.05rem;font-weight:bold;line-height:1;padding:3px 8px;" title="${currentLang === 'it' ? 'Clona' : 'Clone'}" onclick="cloneFigurine('${f.id}')">&#10697;</button></td>` : ''}
          ${isAdmin ? `<td style="padding:4px;text-align:center;"><input type="checkbox" class="bulk-select-row" data-id="${f.id}" onchange="updateBulkDeleteCount()"></td>` : ''}
          ${currentSeriesHasSubseries ? (isAdmin ? '<td style="padding:4px;"><input data-field="subseries" data-id="'+f.id+'" value="'+(f.subseries||'')+'" style="width:90px;background:var(--card);border:1px solid var(--border);color:var(--text);padding:3px 6px;border-radius:4px;font-size:0.8rem;" onchange="saveBulkCell(this)"></td>' : readCell(f.subseries)) : ''}
          ${currentSection === 'retros' ? (isAdmin ? '<td style="padding:4px;"><input data-field="category" data-id="'+f.id+'" value="'+(f.category||'')+'" style="width:120px;background:var(--card);border:1px solid var(--border);color:var(--text);padding:3px 6px;border-radius:4px;font-size:0.8rem;" onchange="saveBulkCell(this)"></td><td style="padding:4px;"><input data-field="subcategory" data-id="'+f.id+'" value="'+(f.subcategory||'')+'" style="width:120px;background:var(--card);border:1px solid var(--border);color:var(--text);padding:3px 6px;border-radius:4px;font-size:0.8rem;" onchange="saveBulkCell(this)"></td>' : readCell(f.category) + readCell(f.subcategory)) : ''}
          ${currentSection !== 'retros' ? (isAdmin ? '<td style="padding:4px;"><input data-field="number" data-id="'+f.id+'" value="'+(f.number||'')+'" type="number" style="width:60px;background:var(--card);border:1px solid var(--border);color:var(--text);padding:3px 6px;border-radius:4px;font-size:0.8rem;" onchange="saveBulkCell(this)"></td>' : readCell(f.number ? '#'+f.number : '')) : ''}
          ${currentSection === 'figurines' ? (() => {
            const typeLabel = f.isVariation ? (currentLang === 'it' ? 'Variazione ufficiale' : 'Official variation')
              : f.isUnofficialVariation ? (currentLang === 'it' ? 'Variazione non ufficiale' : 'Unofficial variation')
              : f.isChange ? 'Change'
              : (currentLang === 'it' ? 'Base' : 'Base');
            return readCell(typeLabel, 160);
          })() : ''}
          ${(() => {
            if (currentSection === 'figurines') {
              const fullName = f.fullName || computeFullName(f, getData('figurines', []));
              return readCell(fullName, 300);
            }
            return isAdmin
              ? `<td style="padding:4px;width:99%;"><input data-field="name" data-id="${f.id}" value="${f.name||''}" style="width:100%;min-width:280px;background:var(--card);border:1px solid var(--border);color:var(--text);padding:3px 6px;border-radius:4px;font-size:0.8rem;" onchange="saveBulkCell(this)"></td>`
              : readCell(f.name, 300);
          })()}
          ${currentSection === 'retros' ? (isAdmin ? `<td style="padding:4px;"><input data-field="changeType" data-id="${f.id}" value="${f.changeType||''}" style="width:140px;background:var(--card);border:1px solid var(--border);color:var(--text);padding:3px 6px;border-radius:4px;font-size:0.8rem;" onchange="saveBulkCell(this)"></td>` : readCell(f.changeType, 140)) : ''}
          ${isAdmin ? `<td style="padding:4px;"><input data-field="score" data-id="${f.id}" value="${f.score||0}" type="number" style="width:60px;background:var(--card);border:1px solid var(--border);color:var(--text);padding:3px 6px;border-radius:4px;font-size:0.8rem;" onchange="saveBulkCell(this)"></td>` : readCell(f.score||0)}
          ${currentSeriesHasSizes ? (isAdmin ? '<td style="padding:4px;"><input data-field="size" data-id="'+f.id+'" value="'+(f.size||'')+'" style="width:80px;background:var(--card);border:1px solid var(--border);color:var(--text);padding:3px 6px;border-radius:4px;font-size:0.8rem;" onchange="saveBulkCell(this)"></td>' : readCell(f.size)) : ''}
          ${!isAdmin ? `
          <td style="padding:4px;text-align:center;"><button class="owned-btn ${isOwned?'on':''}" title="${isOwned ? (currentLang==='it'?'\u00c8 nella tua lista':'In your list') : (currentLang==='it'?'Aggiungi alla tua lista':'Add to your list')}" onclick="toggleOwned('${f.id}')">\u2713</button></td>
          <td style="padding:4px;text-align:center;"><button class="wishlist-heart-btn" data-wishlist-id="${f.id}" onclick="toggleWishlist('${f.id}')" title="${currentLang==='it'?(inWishlist?'Togli da &quot;Ciò che cerco&quot;':'Aggiungi a &quot;Ciò che cerco&quot;'):(inWishlist?'Remove from &quot;What I\'m looking for&quot;':'Add to &quot;What I\'m looking for&quot;')}" style="background:${inWishlist?'rgba(var(--danger-rgb),0.15)':'transparent'};border:1px solid ${inWishlist?'var(--danger)':'rgba(255,255,255,0.15)'};color:${inWishlist?'var(--danger)':'var(--muted)'};border-radius:8px;padding:3px 8px;cursor:pointer;font-size:1rem;line-height:1;">${inWishlist?'❤️':'♡'}</button></td>` : ''}
        </tr>`;
        }).join('')}
      </tbody>
    </table>`;
}

function toggleBulkSelectAll(checkbox) {
  document.querySelectorAll('.bulk-select-row').forEach(cb => cb.checked = checkbox.checked);
  updateBulkDeleteCount();
}

function updateBulkDeleteCount() {
  const count = document.querySelectorAll('.bulk-select-row:checked').length;
  const countEl = document.getElementById('bulk-delete-count');
  const btn = document.getElementById('bulk-delete-btn');
  if (countEl) countEl.textContent = count;
  if (btn) { btn.disabled = count === 0; btn.style.opacity = count === 0 ? '0.5' : '1'; }
}

async function deleteBulkSelected() {
  const ids = Array.from(document.querySelectorAll('.bulk-select-row:checked')).map(cb => cb.dataset.id);
  if (!ids.length) return;
  if (!confirm((currentLang === 'it' ? 'Eliminare definitivamente ' : 'Permanently delete ') + ids.length + (currentLang === 'it' ? ' oggetti selezionati? L\u2019operazione non è reversibile.' : ' selected items? This cannot be undone.'))) return;

  const btn = document.getElementById('bulk-delete-btn');
  if (btn) btn.disabled = true;
  let done = 0;
  for (const id of ids) {
    try {
      await fsDelete('figurines', id);
      done++;
    } catch(e) {
      console.error('deleteBulkSelected', id, e);
    }
  }
  toast(done + (currentLang === 'it' ? ' oggetti eliminati' : ' items deleted'), 'success');
  renderBulkEditView();
  renderItems(); renderHomeStats(); updateSectionCounts();
}

async function saveBulkCell(input) {
  const figId = input.dataset.id;
  const field = input.dataset.field;
  let value = input.value.trim();

  // Type conversion
  if (field === 'number') value = value ? parseInt(value) : null;
  if (field === 'score') value = parseInt(value) || 0;

  const figs = getData('figurines', []);
  const idx = figs.findIndex(f => f.id === figId);
  if (idx < 0) return;
  figs[idx][field] = value;
  if (field === 'name' && figs[idx].section === 'figurines') {
    figs[idx].fullName = computeFullName(figs[idx], figs);
  }
  _cache.figurines = figs;
  await fsSave('figurines', figs[idx]);

  // Visual feedback
  input.style.borderColor = 'var(--accent)';
  setTimeout(() => { input.style.borderColor = 'var(--border)'; }, 800);
}

// ============================================================
//  BULK SCORE
// ============================================================
function openBulkScoreModal() {
  if (!currentUser?.isAdmin) return;
  document.getElementById('bulk-score-input').value = '';
  document.getElementById('bulk-score-modal').classList.remove('hidden');
}

async function saveBulkScore() {
  const score = parseInt(document.getElementById('bulk-score-input').value);
  if (isNaN(score) || score < 0) { toast('Inserisci un punteggio valido', 'error'); return; }
  const items = getCurrentlyFilteredItems();
  if (!items.length) { toast(currentLang === 'it' ? 'Nessun oggetto visibile con i filtri attuali' : 'No items visible with the current filters', 'error'); return; }
  if (!confirm((currentLang === 'it' ? 'Assegnare ' + score + ' punti a tutti i ' + items.length + ' oggetti attualmente visibili (non nascosti dai filtri)?' : 'Assign ' + score + ' points to all ' + items.length + ' currently visible items (not hidden by filters)?'))) return;
  const fb = document.getElementById('bulk-score-feedback');
  const btn = document.querySelector('#bulk-score-modal .btn-primary');
  if (btn) btn.disabled = true;
  if (fb) { fb.style.display = ''; fb.textContent = (currentLang === 'it' ? '⏳ Salvataggio in corso...' : '⏳ Saving...') + ' 0 / ' + items.length; }
  let saved = 0;
  for (const item of items) {
    item.score = score;
    await fsSave('figurines', item);
    saved++;
    if (fb) fb.textContent = (currentLang === 'it' ? '⏳ Salvataggio in corso...' : '⏳ Saving...') + ' ' + saved + ' / ' + items.length;
  }
  const updatedIds = new Set(items.map(f => f.id));
  _cache.figurines = getData('figurines', []).map(f => {
    if (updatedIds.has(f.id)) f.score = score;
    return f;
  });
  if (fb) fb.textContent = currentLang === 'it' ? '✅ Punteggio assegnato a ' + items.length + ' oggetti!' : '✅ Score assigned to ' + items.length + ' items!';
  if (btn) btn.disabled = false;
  renderItems();
  setTimeout(() => {
    closeModal('bulk-score-modal');
    if (fb) { fb.style.display = 'none'; fb.textContent = ''; }
  }, 1000);
}

// ============================================================
//  CLASSIFICA
// ============================================================
function renderClassificaLevels(el) {
  const levels = getData('levels', []).sort((a,b) => a.minScore - b.minScore);
  const isAdmin = currentUser?.isAdmin;

  let html = '';
  if (levels.length) {
    html += '<table class="data-table compact"><thead><tr>';
    html += '<th>' + (currentLang === 'it' ? 'Livello' : 'Level') + '</th>';
    html += '<th>' + (currentLang === 'it' ? 'Da' : 'From') + '</th>';
    if (isAdmin) html += '<th></th>';
    html += '</tr></thead><tbody>';
    html += levels.map(lv => {
      let row = '<tr><td><strong>' + ((currentLang !== 'it' && lv.nameEn) ? lv.nameEn : lv.name) + '</strong></td>';
      row += '<td>' + lv.minScore.toLocaleString('it-IT') + ' pt</td>';
      if (isAdmin) {
        row += '<td style="display:flex;gap:0.3rem;">';
        row += '<button class="tbl-btn tbl-btn-edit cl-edit-btn" data-id="' + lv.id + '">' + (currentLang === 'it' ? 'Modifica' : 'Edit') + '</button>';
        row += '<button class="tbl-btn tbl-btn-del cl-del-btn" data-id="' + lv.id + '" title="' + (currentLang === 'it' ? 'Elimina questo livello' : 'Delete this level') + '">🗑️</button>';
        row += '</td>';
      }
      row += '</tr>';
      return row;
    }).join('');
    html += '</tbody></table>';
  } else {
    html = '<p style="color:var(--muted);font-size:0.85rem;font-style:italic;">' + (currentLang === 'it' ? 'Nessun livello definito.' : 'No levels defined.') + '</p>';
  }

  // Form aggiunta/modifica per admin
  if (isAdmin) {
    html += '<hr style="border-color:var(--border);margin:1rem 0;">';
    html += '<div id="classifica-level-form" style="background:var(--card2);border-radius:var(--radius);padding:0.75rem;">';
    html += '<div style="font-size:0.8rem;font-weight:600;color:var(--accent);margin-bottom:0.5rem;" id="classifica-level-form-title">' + (currentLang === 'it' ? '+ Aggiungi livello' : '+ Add level') + '</div>';
    html += '<input type="hidden" id="cl-edit-id">';
    html += '<div style="display:flex;gap:0.5rem;flex-wrap:wrap;">';
    html += '<input class="form-input" type="text" id="cl-name-it" placeholder="' + (currentLang === 'it' ? 'Nome IT' : 'Name IT') + '" style="flex:1;min-width:100px;">';
    html += '<input class="form-input" type="text" id="cl-name-en" placeholder="Name EN" style="flex:1;min-width:100px;">';
    html += '<input class="form-input" type="number" id="cl-score" placeholder="Min pt" style="width:80px;">';
    html += '<button class="btn-primary btn-admin" style="padding:0.4rem 0.75rem;font-size:0.82rem;" onclick="saveLevelClassifica()">💾</button>';
    html += '<button style="padding:0.4rem 0.75rem;font-size:0.82rem;background:transparent;border:1px solid var(--border);color:var(--muted);border-radius:var(--radius);cursor:pointer;" onclick="resetLevelClassifica()">✕</button>';
    html += '</div></div>';
  }

  el.innerHTML = html;

  // Event delegation per modifica/elimina livelli
  el.querySelectorAll('.cl-edit-btn').forEach(btn => {
    btn.addEventListener('click', () => editLevelClassifica(btn.getAttribute('data-id')));
  });
  el.querySelectorAll('.cl-del-btn').forEach(btn => {
    btn.addEventListener('click', () => deleteLevelClassifica(btn.getAttribute('data-id')));
  });
}

function editLevelClassifica(id) {
  const lv = getData('levels', []).find(l => l.id === id);
  if (!lv) return;
  document.getElementById('cl-edit-id').value = id;
  document.getElementById('cl-name-it').value = lv.name;
  document.getElementById('cl-name-en').value = lv.nameEn || '';
  document.getElementById('cl-score').value = lv.minScore;
  const title = document.getElementById('classifica-level-form-title');
  if (title) title.textContent = currentLang === 'it' ? '✏️ Modifica livello' : '✏️ Edit level';
}

function resetLevelClassifica() {
  document.getElementById('cl-edit-id').value = '';
  document.getElementById('cl-name-it').value = '';
  document.getElementById('cl-name-en').value = '';
  document.getElementById('cl-score').value = '';
  const title = document.getElementById('classifica-level-form-title');
  if (title) title.textContent = currentLang === 'it' ? '+ Aggiungi livello' : '+ Add level';
}

async function saveLevelClassifica() {
  const name = document.getElementById('cl-name-it')?.value.trim();
  const nameEn = document.getElementById('cl-name-en')?.value.trim() || '';
  const minScore = parseInt(document.getElementById('cl-score')?.value);
  const editId = document.getElementById('cl-edit-id')?.value;
  if (!name || isNaN(minScore)) { toast(currentLang === 'it' ? 'Compila nome e punteggio' : 'Fill in name and score', 'error'); return; }
  let levels = getData('levels', []);
  if (editId) {
    const idx = levels.findIndex(l => l.id === editId);
    if (idx >= 0) { levels[idx] = { ...levels[idx], name, nameEn, minScore }; await fsSave('levels', levels[idx]); }
  } else {
    const saved = await fsSave('levels', { name, nameEn, minScore });
    levels.push(saved);
  }
  _cache.levels = levels;
  resetLevelClassifica();
  const levelsEl = document.getElementById('classifica-levels-table');
  if (levelsEl) renderClassificaLevels(levelsEl);
  toast(currentLang === 'it' ? '✅ Livello salvato!' : '✅ Level saved!', 'success');
}

async function deleteLevelClassifica(id) {
  if (!confirm(currentLang === 'it' ? 'Eliminare questo livello?' : 'Delete this level?')) return;
  await fsDelete('levels', id);
  _cache.levels = (_cache.levels || []).filter(l => l.id !== id);
  const levelsEl = document.getElementById('classifica-levels-table');
  if (levelsEl) renderClassificaLevels(levelsEl);
  toast(currentLang === 'it' ? '✅ Livello eliminato' : '✅ Level deleted', 'success');
}

async function renderClassifica() {
  const el = document.getElementById('classifica-list');
  if (!el) return;
  el.innerHTML = '<div class="empty-state"><div class="empty-icon">⏳</div><p class="empty-title">' + (currentLang === 'it' ? 'Caricamento...' : 'Loading...') + '</p></div>';
  // Show anon info banner for logged-in non-admin users
  const anonBanner = document.getElementById('classifica-anon-banner');
  if (anonBanner) anonBanner.style.display = (currentUser && !currentUser.isAdmin) ? '' : 'none';

  // Pannello di ricalcolo punteggi: visibile solo all'admin
  const backfillPanel = document.getElementById('classifica-admin-backfill');
  if (backfillPanel) backfillPanel.style.display = currentUser?.isAdmin ? '' : 'none';

  // Render levels table on the right
  const levelsEl = document.getElementById('classifica-levels-table');
  if (levelsEl) {
    renderClassificaLevels(levelsEl);
  }

  const users = getData('public_profiles', []).filter(u => u && u.id && u.username);

  // Calculate score for each user (già pre-calcolato e pubblicato in
  // public_profiles da _updatePublicScore, non serve più leggere i dettagli
  // di "owned" — che restano privati)
  const ranking = [];
  for (const user of users) {
    const score = user.score || 0;
    const countFigurines = user.countFigurines || 0;
    const countAlbums = user.countAlbums || 0;
    const countExtras = user.countExtras || 0;
    ranking.push({ user, score, countFigurines, countAlbums, countExtras });
  }

  ranking.sort((a, b) => b.score - a.score);

  if (!ranking.length) {
    el.innerHTML = '<div class="empty-state"><div class="empty-icon">👤</div><p class="empty-title">' + (currentLang === 'it' ? 'Nessun collezionista ancora!' : 'No collectors yet!') + '</p></div>';
    return;
  }

  const medals = ['🥇', '🥈', '🥉', '🏅', '🏅', '🏅', '🏅', '🏅', '🏅', '🏅'];
  const trophies = [
    '<span style="font-size:2rem;">🏆</span>',
    '<span style="font-size:2rem;filter:grayscale(1) brightness(1.8);">🏆</span>',
    '<span style="font-size:2rem;filter:sepia(1) saturate(0.5) brightness(0.8);">🏆</span>'
  ];

  // Count anon users for stable numbering
  let anonCount = 0;
  el.innerHTML = ranking.map((entry, idx) => {
    const { user, score, countFigurines, countAlbums, countExtras } = entry;
    const position = idx + 1;
    const medal = position <= 10 ? medals[idx] : '';
    const isTop3 = position <= 3;
    const isMe = currentUser && user.id === currentUser.id;
    const isAnon = user.isAnonymous && !currentUser?.isAdmin && !isMe;
    if (user.isAnonymous && !isMe) anonCount++;
    const myAnonIdx = isMe && user.isAnonymous ? ranking.slice(0, idx+1).filter(e => e.user.isAnonymous).length : 0;

    const displayName = isAnon
      ? (currentLang === 'it' ? 'Collezionista Anonimo ' + anonCount : 'Anonymous Collector ' + anonCount)
      : user.username;
    const avatarHTML = user.avatar
      ? `<div style="width:40px;height:40px;border-radius:50%;background:url('${user.avatar}') center/cover;border:2px solid ${isTop3 ? 'var(--accent)' : 'var(--border)'};flex-shrink:0;"></div>`
      : `<div style="width:40px;height:40px;border-radius:50%;background:var(--card2);border:2px solid ${isTop3 ? 'var(--accent)' : 'var(--border)'};display:flex;align-items:center;justify-content:center;font-size:1.1rem;color:var(--muted);flex-shrink:0;">${(user.username || '?')[0].toUpperCase()}</div>`;
    const displayAvatar = isAnon
      ? `<div style="width:40px;height:40px;border-radius:50%;background:var(--card2);border:2px solid ${isTop3 ? 'var(--accent)' : 'var(--border)'};display:flex;align-items:center;justify-content:center;font-size:1.1rem;flex-shrink:0;">🕵️</div>`
      : avatarHTML;
    const adminNote = user.isAnonymous && currentUser?.isAdmin ? ` <span style="font-size:0.75rem;color:var(--warn);">🕵️ ${currentLang === 'it' ? 'anonimo' : 'anonymous'}</span>` : '';
    const meNote = isMe && user.isAnonymous
      ? ` <span style="font-size:0.78rem;color:var(--warn);font-family:var(--font-ui);">${currentLang === 'it' ? '(tu 🕵️ — nome anonimizzato)' : '(you 🕵️ — anonymous name)'}</span>`
      : isMe ? ` <span style="font-size:0.78rem;color:var(--accent);font-family:var(--font-ui);">${currentLang === 'it' ? '(tu)' : '(you)'}</span>` : '';
    const rowBg = isMe
      ? (isTop3 ? 'rgba(181,255,46,0.1)' : 'rgba(181,255,46,0.04)')
      : (isTop3 ? 'rgba(181,255,46,0.05)' : 'var(--card)');
    const rowBorder = isMe
      ? 'rgba(181,255,46,0.5)'
      : (isTop3 ? 'rgba(181,255,46,0.2)' : 'var(--border)');

    return `<div class="cl-row" style="background:${rowBg};border:1px solid ${rowBorder};border-radius:var(--radius-lg);padding:0.4rem 1rem;margin-bottom:0.3rem;display:flex;align-items:center;gap:1rem;">
      <div class="cl-pos" style="font-size:1.1rem;width:40px;text-align:center;flex-shrink:0;font-family:var(--font-ui);color:${isTop3 ? 'var(--accent)' : 'var(--muted)'};">#${position}</div>
      <div class="cl-avatar">${displayAvatar}</div>
      <div style="flex:1;">
        <div style="font-family:var(--font-ui);font-size:1.15rem;color:var(--text);display:flex;align-items:center;gap:6px;flex-wrap:wrap;">${displayName}${adminNote}${meNote}${!isAnon && user.nationalityCode ? `<img src="${flagUrl(user.nationalityCode)}" title="${user.nationalityName||''}" style="width:22px;height:15px;object-fit:cover;border-radius:2px;">` : ''}${!isAnon ? `<span style="font-size:0.92rem;color:var(--muted);font-family:var(--font-body);font-weight:400;">(${(currentLang === 'it') ? 'utente dal' : 'member since'} ${user.joined ? new Date(user.joined).toLocaleDateString((currentLang === 'it') ? 'it-IT' : 'en-GB') : '—'})</span>` : ''}</div>
        <div style="font-size:0.82rem;color:var(--muted);margin-top:2px;">${countFigurines} ${(currentLang === 'it') ? 'figurine' : 'stickers'} · ${countAlbums} album · ${countExtras} ${(currentLang === 'it') ? 'altri articoli' : 'extras'}</div>
      </div>
      <div style="display:flex;align-items:center;gap:0.75rem;">
        <div style="text-align:center;">
          <div style="font-family:var(--font-ui);font-size:1.1rem;color:var(--accent);">${score.toLocaleString('it-IT')} pt</div>
          ${(() => { const lv = getUserLevel(score); if (!lv) return ''; const lvName = (currentLang !== 'it' && lv.nameEn) ? lv.nameEn : lv.name; return `<div style="font-size:0.72rem;color:var(--accent);opacity:0.8;font-family:var(--font-ui);">🏅 ${lvName}</div>`; })()}
        </div>
        ${isTop3 ? trophies[idx] : (medal ? `<span style="font-size:1.5rem;">${medal}</span>` : '')}
      </div>
    </div>`;
  }).join('');
}

// ============================================================
//  WANTLIST
// ============================================================
// ============================================================
//  WISHLIST
// ============================================================
function renderWishlist() {
  const el = document.getElementById('wishlist-content');
  if (!el) return;

  // Vista admin: mostra tutte le liste desiderati ricevute
  if (currentUser?.isAdmin) {
    renderWishlistAdmin(el);
    return;
  }

  const allFigs = getData('figurines', []);
  const series = getData('series', []);
  const items = _wishlist.map(id => allFigs.find(f => f.id === id)).filter(Boolean);

  if (!items.length) {
    el.innerHTML = `<div class="empty-state"><div class="empty-icon">❤️</div><p class="empty-title">${currentLang === 'it' ? 'Il tuo \"Ciò che cerco\" è vuoto' : 'Your \"What I\'m looking for\" is empty'}</p><p class="empty-sub">${currentLang === 'it' ? 'Naviga l\'Inventario e premi ❤️ sulle figurine che ti interessano.' : 'Browse the Inventory and press ❤️ on stickers you are interested in.'}</p></div>`;
    renderWishlistHistory();
    return;
  }

  // Group by series
  const bySeries = {};
  items.forEach(f => {
    if (!bySeries[f.seriesId]) bySeries[f.seriesId] = [];
    bySeries[f.seriesId].push(f);
  });

  const seriesSorted = series.filter(s => bySeries[s.id]).sort((a,b) => (a.order??9999)-(b.order??9999));

  const totalItems = items.length;

  el.innerHTML = seriesSorted.map(s => {
    const figs = bySeries[s.id].sort((a,b) => (a.number||0)-(b.number||0));
    const chipHtml = f => `<span style="background:rgba(var(--danger-rgb),0.08);border:1px solid rgba(var(--danger-rgb),0.25);color:var(--text);font-size:0.72rem;padding:2px 8px;border-radius:10px;display:inline-flex;align-items:center;gap:4px;">
      ${f.number ? '#'+f.number+' ' : ''}${f.name}
      <button onclick="toggleWishlist('${f.id}')" style="background:none;border:none;color:var(--danger);cursor:pointer;padding:0;font-size:0.9rem;line-height:1;" title="${currentLang === 'it' ? 'Rimuovi' : 'Remove'}">×</button>
    </span>`;
    // Prima si raggruppa per tipo di oggetto (Figurine/Retro/Album/Altri
    // oggetti), altrimenti non si capisce cosa si sta guardando quando una
    // serie ha in lista più tipi diversi mescolati insieme
    const typeLabels = { figurines: currentLang === 'it' ? 'Figurine' : 'Stickers', retros: 'Retro', albums: 'Album', extras: currentLang === 'it' ? 'Altri oggetti' : 'Other items', bustine: currentLang === 'it' ? 'Bustine' : 'Packs' };
    const typeOrder = ['figurines', 'retros', 'albums', 'extras', 'bustine'];
    const byType = {};
    figs.forEach(f => {
      const sec = f.section || 'figurines';
      if (!byType[sec]) byType[sec] = [];
      byType[sec].push(f);
    });
    const itemsHtml = Object.entries(byType).sort(([a],[b]) => typeOrder.indexOf(a) - typeOrder.indexOf(b)).map(([sec, secFigs]) => {
      // All'interno di ogni tipo, si raggruppa ulteriormente per Categoria
      // (Retro) o Sottoserie (Figurine), con l'etichetta scritta una sola
      // volta prima del suo elenco. Gli oggetti senza nessuno dei due campi
      // restano in un unico elenco
      const groupLabel = f => f.category || f.subseries || null;
      const withoutGroup = secFigs.filter(f => !groupLabel(f));
      const byGroup = {};
      secFigs.filter(f => groupLabel(f)).forEach(f => {
        const key = groupLabel(f);
        if (!byGroup[key]) byGroup[key] = [];
        byGroup[key].push(f);
      });
      let groupsHtml = withoutGroup.length ? `<div style="display:flex;flex-wrap:wrap;gap:0.3rem;">${withoutGroup.map(chipHtml).join('')}</div>` : '';
      groupsHtml += Object.entries(byGroup).sort(([a],[b]) => a.localeCompare(b)).map(([label, groupFigs]) =>
        `<div style="margin-top:0.3rem;"><div style="font-size:0.78rem;font-weight:700;color:var(--accent3);margin-bottom:0.25rem;">${label}</div><div style="display:flex;flex-wrap:wrap;gap:0.3rem;">${groupFigs.map(chipHtml).join('')}</div></div>`
      ).join('');
      return `<div style="margin-top:0.5rem;"><div style="font-family:var(--font-ui);font-size:0.9rem;color:var(--muted);margin-bottom:0.3rem;">${typeLabels[sec] || sec}</div>${groupsHtml}</div>`;
    }).join('');
    return `<div style="background:var(--card);border:1px solid var(--border);border-radius:var(--radius-lg);padding:0.75rem 1rem;margin-bottom:0.75rem;">
      <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:0.5rem;">
        <span style="font-family:var(--font-display);font-size:1.1rem;">${s.name}</span>
        <span class="card-badge">${currentLang === 'it' ? 'N. figurine: ' : 'Items: '}${figs.length}</span>
      </div>
      ${itemsHtml}
    </div>`;
  }).join('');

  // Totale in fondo alla lista
  el.innerHTML += `<p style="text-align:center;color:var(--muted);font-size:0.9rem;margin:1rem 0 0.25rem;">
    ${currentLang === 'it'
      ? 'La tua lista "Ciò che cerco" conta <strong style="color:var(--text);">' + totalItems + '</strong> figurine.'
      : 'Your "What I\'m looking for" list contains <strong style="color:var(--text);">' + totalItems + '</strong> items.'}
  </p>`;

  // Storico liste inviate
  renderWishlistHistory();
}

function _wlMsgBody(msg) {
  var lines = msg.split('\n');
  var i = lines.findIndex(function(l) { return l.trim() === ''; });
  return i > -1 ? lines.slice(i + 1).join('\n') : msg;
}

function renderWishlistAdmin(el) {
  var allMsgs = getData('contact_messages', [])
    .filter(function(m) { return m.type === 'wishlist'; })
    .sort(function(a, b) { return new Date(b.date) - new Date(a.date); });

  if (!allMsgs.length) {
    el.innerHTML = '<div class="empty-state"><div class="empty-icon">❤️</div><p class="empty-title">' +
      (currentLang === 'it' ? 'Nessuna lista "Ciò che cerco" ricevuta' : 'No "What I\'m looking for" lists received yet') + '</p></div>';
    return;
  }

  var histEl = document.getElementById('wishlist-history');
  if (histEl) histEl.innerHTML = '';

  var fmt = function(d) {
    return new Date(d).toLocaleDateString(currentLang === 'it' ? 'it-IT' : 'en-GB',
      { day:'2-digit', month:'2-digit', year:'numeric', hour:'2-digit', minute:'2-digit' });
  };

  var html = '<p style="color:var(--muted);font-size:0.88rem;margin-bottom:1rem;">' +
    (currentLang === 'it' ? allMsgs.length + ' liste ricevute' : allMsgs.length + ' lists received') + '</p>';

  allMsgs.forEach(function(m) {
    html += '<div style="background:var(--card);border:1px solid var(--border);border-radius:var(--radius-lg);padding:0.75rem 1rem;margin-bottom:0.75rem;">';
    html += '<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:0.5rem;">';
    html += '<span style="font-weight:600;">👤 ' + esc(m.name || m.email || '—') + '</span>';
    html += '<div style="display:flex;align-items:center;gap:0.5rem;">';
    html += '<span style="font-size:0.78rem;color:var(--muted);">📨 ' + fmt(m.date) + '</span>';
    html += '<button class="wl-delete-btn" data-msg-id="' + m.id + '" style="font-size:0.75rem;padding:2px 8px;border-radius:6px;border:1px solid rgba(var(--danger-rgb),0.4);background:rgba(var(--danger-rgb),0.08);color:var(--danger);cursor:pointer;" title="' + (currentLang === 'it' ? 'Elimina' : 'Delete') + '">🗑️</button>';
    html += '</div>';
    html += '</div>';
    if (m.email) {
      html += '<div style="font-size:0.78rem;color:var(--muted);margin-bottom:0.4rem;">✉️ ' + m.email + '</div>';
    }
    html += '<div style="font-size:0.82rem;color:var(--text);white-space:pre-line;line-height:1.6;background:var(--card2);border-radius:8px;padding:0.5rem 0.75rem;">' +
      _wlMsgBody(m.message) + '</div>';
    if (m.comment) {
      html += '<div style="margin-top:0.4rem;font-size:0.8rem;color:var(--text);background:rgba(181,255,46,0.07);border:1px solid rgba(181,255,46,0.2);border-radius:8px;padding:0.4rem 0.75rem;">' +
        '<span style="font-size:0.7rem;color:var(--accent);font-weight:600;display:block;margin-bottom:2px;">💬 ' + (currentLang === 'it' ? 'Commento utente' : 'User comment') + '</span>' +
        m.comment + '</div>';
    }
    html += '</div>';
  });

  el.innerHTML = html;

  // Event delegation per i pulsanti elimina wishlist
  el.querySelectorAll('.wl-delete-btn').forEach(function(btn) {
    btn.addEventListener('click', function() {
      deleteWishlistMsg(btn.getAttribute('data-msg-id'));
    });
  });
}


async function deleteWishlistMsg(msgId) {
  if (!confirm(currentLang === 'it' ? 'Eliminare questa lista "Ciò che cerco"?' : 'Delete this "What I\'m looking for" list?')) return;
  await fsDelete('contact_messages', msgId);
  // Rimuovi dalla cache
  if (_cache.contact_messages) {
    _cache.contact_messages = _cache.contact_messages.filter(m => m.id !== msgId);
  }
  // Re-render
  const el = document.getElementById('wishlist-content');
  if (el) renderWishlistAdmin(el);
  updateMsgBadge();
}

function renderWishlistHistory() {
  // Cerca o crea il contenitore storico
  let histEl = document.getElementById('wishlist-history');
  if (!histEl) {
    histEl = document.createElement('div');
    histEl.id = 'wishlist-history';
    const page = document.getElementById('page-wishlist');
    const inner = page?.querySelector('.section-inner') || page;
    if (inner) inner.appendChild(histEl);
  }

  const msgs = (getData('contact_messages', []))
    .filter(m => m.type === 'wishlist' && m.userId === currentUser?.id)
    .sort((a,b) => new Date(b.date) - new Date(a.date));

  if (!msgs.length) { histEl.innerHTML = ''; return; }

  const fmt = d => new Date(d).toLocaleDateString(currentLang === 'it' ? 'it-IT' : 'en-GB', { day:'2-digit', month:'2-digit', year:'numeric', hour:'2-digit', minute:'2-digit' });

  histEl.innerHTML = `
    <hr style="border-color:var(--border);margin:2rem 0 1.25rem;">
    <h3 style="font-family:var(--font-ui);font-size:1.2rem;margin-bottom:0.75rem;">
      📋 ${currentLang === 'it' ? 'Storico "Ciò che cerco" inviate' : 'Sent "What I\'m looking for" history'}
    </h3>
    ${msgs.map((m,i) => `
      <div style="background:var(--card);border:1px solid var(--border);border-radius:var(--radius-lg);padding:0.75rem 1rem;margin-bottom:0.6rem;">
        <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:0.4rem;">
          <span style="font-size:0.82rem;color:var(--muted);">📨 ${fmt(m.date)}</span>
          <span class="card-badge" style="font-size:0.7rem;">#${msgs.length - i}</span>
        </div>
        <div style="font-size:0.78rem;color:var(--text);white-space:pre-line;line-height:1.5;">${(function(msg){var p=msg.indexOf('\n\n');return p>-1?msg.slice(p+2):msg;})(m.message)}</div>
        ${m.comment ? `<div style="margin-top:0.35rem;font-size:0.76rem;color:var(--text);background:rgba(181,255,46,0.07);border:1px solid rgba(181,255,46,0.2);border-radius:8px;padding:0.35rem 0.65rem;"><span style="font-size:0.68rem;color:var(--accent);font-weight:600;display:block;margin-bottom:2px;">💬 ${currentLang === 'it' ? 'Il tuo commento' : 'Your comment'}</span>${m.comment}</div>` : ''}
      </div>
    `).join('')}
  `;
}

function promptMultiline(labelText) {
  return new Promise(resolve => {
    // Crea overlay
    const overlay = document.createElement('div');
    overlay.style.cssText = 'position:fixed;inset:0;background:rgba(5,2,15,0.85);z-index:3000;display:flex;align-items:center;justify-content:center;';
    overlay.innerHTML = `
      <div style="background:var(--card);border:1px solid var(--border);border-radius:var(--radius-lg);padding:1.5rem;width:min(480px,90vw);display:flex;flex-direction:column;gap:1rem;">
        <div style="font-family:var(--font-ui);font-size:1rem;font-weight:600;">${labelText}</div>
        <textarea id="multiline-comment-input" rows="5" style="width:100%;background:var(--card2);border:1px solid var(--border);border-radius:var(--radius);color:var(--text);font-size:0.9rem;padding:0.6rem 0.75rem;resize:vertical;font-family:inherit;box-sizing:border-box;" placeholder="${currentLang === 'it' ? 'Scrivi qui il tuo commento...' : 'Write your comment here...'}"></textarea>
        <div style="display:flex;gap:0.75rem;justify-content:flex-end;">
          <button id="multiline-cancel" style="padding:0.45rem 1.1rem;border-radius:var(--radius);border:1px solid var(--border);background:transparent;color:var(--muted);cursor:pointer;font-size:0.88rem;">${currentLang === 'it' ? 'Annulla' : 'Cancel'}</button>
          <button id="multiline-confirm" class="btn-primary" style="padding:0.45rem 1.1rem;font-size:0.88rem;">${currentLang === 'it' ? 'Conferma' : 'Confirm'}</button>
        </div>
      </div>`;
    document.body.appendChild(overlay);
    const textarea = overlay.querySelector('#multiline-comment-input');
    textarea.focus();
    overlay.querySelector('#multiline-confirm').onclick = () => {
      const val = textarea.value.trim();
      overlay.remove();
      resolve(val);
    };
    overlay.querySelector('#multiline-cancel').onclick = () => {
      overlay.remove();
      resolve('');
    };
    // Ctrl+Enter conferma
    textarea.addEventListener('keydown', e => {
      if (e.key === 'Enter' && e.ctrlKey) {
        overlay.querySelector('#multiline-confirm').click();
      }
    });
  });
}

async function submitWishlist() {
  if (!currentUser || !_wishlist.length) return;
  if (!confirm(currentLang === 'it' ? 'Confermi di inviare allo staff la tua lista "Ciò che cerco"?' : 'Do you confirm sending your "What I\'m looking for" list to the staff?')) return;

  // Chiede se aggiungere un commento
  let userComment = '';
  if (confirm(currentLang === 'it' ? 'Vuoi aggiungere un commento per lo staff prima di inviare?' : 'Do you want to add a comment for the staff before sending?')) {
    userComment = await promptMultiline(
      currentLang === 'it' ? 'Scrivi il tuo commento per lo staff:' : 'Write your comment for the staff:'
    );
  }

  const allFigs = getData('figurines', []);
  const series = getData('series', []);
  const items = _wishlist.map(id => allFigs.find(f => f.id === id)).filter(Boolean);

  // Build message
  const bySeries = {};
  items.forEach(f => {
    const s = series.find(x => x.id === f.seriesId);
    const sName = s?.name || f.seriesId;
    if (!bySeries[sName]) bySeries[sName] = [];
    bySeries[sName].push((f.number ? '#'+f.number+' ' : '') + f.name);
  });
  const listText = Object.entries(bySeries).map(([s, figs]) => s + ': ' + figs.join(', ')).join('\n');
  const commentSection = userComment ? '\n\n--- Commento utente ---\n' + userComment : '';
  const msg = (currentLang === 'it' ? 'Ciao! Ecco la mia lista "Ciò che cerco":\n\n' : 'Hi! Here is my "What I\'m looking for" list:\n\n') + listText + commentSection;

  // Save as contact message
  const saved = await fsSave('contact_messages', {
    name: currentUser.username,
    email: currentUser.email || '',
    subject: currentLang === 'it' ? '🎁 Ciò che cerco' : '🎁 What I\'m looking for',
    message: msg,
    comment: userComment,
    date: new Date().toISOString(),
    read: false,
    type: 'wishlist',
    userId: currentUser.id
  });
  if (saved) {
    _cache.contact_messages = _cache.contact_messages || [];
    _cache.contact_messages.unshift(saved);
    updateMsgBadge();
    toast(currentLang === 'it' ? '✅ Lista inviata!<br><span style="font-size:0.85em;opacity:0.85;">Troverai la tua lista nello storico.</span>' : '✅ List sent!<br><span style="font-size:0.85em;opacity:0.85;">You will find it in the history.</span>', 'success', null, 5000);
    _wishlist = [];
    await saveWishlist();
    renderWishlist();
  }
}

// Wantlist display mode per group: 'both' | 'numbers' | 'names'
const _wantlistCollapsed = {}; // seriesId -> bool

function toggleWantlistCollapse(sId) {
  // v5.860 — default CHIUSO: una serie e' considerata aperta solo se _wantlistCollapsed[sId]
  // vale esplicitamente false. Undefined (mai toccata) e true contano entrambi come "chiusa".
  _wantlistCollapsed[sId] = (_wantlistCollapsed[sId] === false) ? true : false;
  renderWantlist();
}
const wantlistMode = {};

function toggleWantlistMode(key, mode) {
  wantlistMode[key] = mode;
  renderWantlist();
}

// Figurina "base": non è una variazione ufficiale/non ufficiale né un Change
function isBaseFigurine(f) {
  return !f.isVariation && !f.isUnofficialVariation && !f.isChange;
}

function renderWantlist() {
  if (!currentUser) { showPage('home'); return; }
  const el = document.getElementById('wantlist-content');
  const allFigs = getData('figurines', []);
  const owned = getOwned();
  // Le numeriche di default considerano solo le figurine base (non variazioni/change);
  // le variazioni/change sono incluse nell'export solo se l'utente attiva l'opzione dedicata
  const isBaseItem = isBaseFigurine;
  const missing = allFigs.filter(f => !owned.includes(f.id) && isBaseItem(f));
  const series = getData('series', []);

  // Series where user has everything (or has items but none missing)
  const completeSeries = series.slice().sort((a,b) => (a.order ?? 9999) - (b.order ?? 9999)).filter(s => {
    const seriesFigs = allFigs.filter(f => f.seriesId === s.id && f.section === 'figurines' && isBaseItem(f));
    const missingInSeries = seriesFigs.filter(f => !owned.includes(f.id));
    if (!seriesFigs.length) return false;
    return missingInSeries.length === 0;
  });

  if (!missing.length) {
    const prefs = getWantlistPrefs();
    const completeBoxes = completeSeries.map(s => {
      const incOwned = prefs[s.id]?.includeOwned !== false;
      return `<div style="background:var(--card);border:1px solid var(--border);border-radius:var(--radius-lg);padding:0.5rem 0.9rem;margin-bottom:0.5rem;display:flex;align-items:center;justify-content:space-between;flex-wrap:wrap;gap:0.4rem;">
        <span style="font-family:var(--font-display);font-size:1.1rem;">${s.name} <span style="font-size:0.8rem;color:var(--success);">✓ (${(() => { const figs = getData('figurines',[]).filter(f=>f.seriesId===s.id&&f.section==='figurines'&&!f.isVariation&&!f.isUnofficialVariation&&!f.isChange); return figs.length; })()}&nbsp;${currentLang==='it'?'figurine':'stickers'})</span></span>
        <button onclick="toggleOwnedInclude('${s.id}')" style="font-size:0.72rem;padding:2px 8px;border-radius:8px;border:1px solid ${!incOwned ? 'var(--info)' : 'var(--border)'};background:${!incOwned ? 'rgba(var(--info-rgb),0.15)' : 'var(--card2)'};color:${!incOwned ? 'var(--info)' : 'var(--muted)'};cursor:pointer;">
          ${!incOwned ? '✓ ' : ''}${(currentLang === 'it') ? 'Escludi da export figurine della tua lista' : 'Exclude from owned stickers export'}
        </button>
      </div>`;
    }).join('');
    el.innerHTML = '<div class="empty-state"><div class="empty-icon">🎉</div><p class="empty-title">' + (currentLang === 'it' ? 'Complimenti! La tua lista comprende tutti gli oggetti dell\'inventario Sgorbions!' : 'Congrats! Your list includes every item in the Sgorbions inventory!') + '</p><p class="empty-sub">' + (currentLang === 'it' ? 'Non ti manca nessuna figurina.' : 'You are not missing any sticker.') + '</p></div>' + (completeBoxes ? '<hr style="border-color:var(--border);margin:1rem 0;"><h2 style="font-family:var(--font-ui);font-size:1.5rem;margin-bottom:0.6rem;">' + (currentLang === 'it' ? 'SEZIONE 2: EXPORT DELLE TUE SERIE COMPLETE' : 'SECTION 2: EXPORT OF YOUR COMPLETE SERIES') + '</h2><p style="font-size:1.05rem;color:var(--muted);margin-bottom:0.5rem;">' + (currentLang === 'it' ? 'Seleziona le serie per le quali esportare l\'elenco delle figurine. Poi premi il tasto <i style="color:#fff;">Esporta lista figurine mie serie complete</i>.' : 'Select the series for which you want to export your stickers. Then press <i style="color:#fff;">Export my complete series stickers</i>.') + '</p><div style="margin-bottom:1rem;"><button class="btn-primary" onclick="exportOwnedList()" style="font-size:0.88rem;">' + (currentLang === 'it' ? 'Esporta lista figurine mie serie complete' : 'Export my complete series stickers') + '</button></div>' + completeBoxes : '');
    return;
  }

  const bySeries = {};
  missing.forEach(f => {
    if (!bySeries[f.seriesId]) bySeries[f.seriesId] = [];
    bySeries[f.seriesId].push(f);
  });

  const sectionLabels = { figurines: currentLang === 'it' ? 'Figurine non nella tua lista' : 'Stickers not in my list', retros: currentLang === 'it' ? 'Retro non nella tua lista' : 'Retros not in my list', albums: currentLang === 'it' ? 'Album non nella tua lista' : 'Albums not in my list', extras: currentLang === 'it' ? 'Altri oggetti non nella tua lista' : 'Other items not in my list', bustine: currentLang === 'it' ? 'Bustine non nella tua lista' : 'Packs not in my list' };

  const sortedEntries = Object.entries(bySeries).sort(([aId], [bId]) => {
    const aS = series.find(x => x.id === aId);
    const bS = series.find(x => x.id === bId);
    return (aS?.order ?? 9999) - (bS?.order ?? 9999);
  });

  // === SEZIONE 1: EXPORT DELLE TUE SERIE INCOMPLETE (titolo generale) ===
  let html = '<h2 style="font-family:var(--font-ui);font-size:1.5rem;margin-bottom:0.6rem;">' + (currentLang === 'it' ? 'SEZIONE 1: EXPORT DELLE TUE SERIE INCOMPLETE' : 'SECTION 1: EXPORT OF YOUR INCOMPLETE SERIES') + '</h2>';
  // === SEZIONE 1a: Lista degli oggetti non nella tua lista ===
  html += '<h3 style="font-family:var(--font-ui);font-size:1.2rem;margin-bottom:0.4rem;">' + (currentLang === 'it' ? 'SEZIONE 1a: LISTA DEGLI OGGETTI NON NELLA TUA LISTA' : 'SECTION 1a: LIST OF ITEMS NOT IN MY LIST') + '</h3><p style="color:var(--muted);font-size:0.88rem;margin-bottom:0.75rem;">' + (currentLang === 'it' ? 'Seleziona le serie per cui esportare l\'elenco degli oggetti non presenti nella tua lista. Poi premi il tasto <i style="color:#fff;">Esporta lista oggetti non nella tua lista</i>.' : 'Select the series for which to export the list of items not in your list. Then press <i style="color:#fff;">Export items not in my list</i>.') + '</p><div style="margin-bottom:1rem;"><button class="btn-primary" onclick="exportWantlist(this)">' + (currentLang === 'it' ? 'Esporta lista oggetti non nella tua lista' : 'Export items not in my list') + '</button></div>';

  html += sortedEntries.map(([sId, figs]) => {
    const s = series.find(x => x.id === sId);
    const seriesPrefs = getWantlistPrefs();
    const seriesIncVariations = seriesPrefs[sId]?.includeVariations || false;
    const figurinesOnlyMissing = allFigs.filter(f => f.seriesId === sId && (f.section || 'figurines') === 'figurines' && !owned.includes(f.id) && (seriesIncVariations || isBaseItem(f))).length;
    const figurinesOnlyTotal = allFigs.filter(f => f.seriesId === sId && (f.section || 'figurines') === 'figurines' && (seriesIncVariations || isBaseItem(f))).length;
    const ownedCount = figurinesOnlyTotal - figurinesOnlyMissing;
    const bySection = {};
    figs.forEach(f => {
      const sec = f.section || 'figurines';
      if (!bySection[sec]) bySection[sec] = [];
      bySection[sec].push(f);
    });

    return `<div style="background:var(--card);border:1px solid var(--border);border-radius:var(--radius-lg);padding:0.5rem 0.9rem;margin-bottom:0.5rem;">
      ${(() => {
        const prefs = getWantlistPrefs();
        const excMissing = prefs[sId]?.excludeMissing || false;
        const incVariations = prefs[sId]?.includeVariations || false; // default false
        return `
        <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:0.4rem;flex-wrap:wrap;gap:0.4rem;">
          <div style="display:flex;align-items:center;gap:0.5rem;flex-wrap:wrap;">
            <span style="display:flex;align-items:center;gap:0.5rem;flex-wrap:wrap;cursor:pointer;" onclick="toggleWantlistCollapse('${sId}')">
              <span style="font-size:0.8rem;color:var(--muted);user-select:none;">${_wantlistCollapsed[sId] === false ? '▼' : '▶'}</span>
              <span style="font-family:var(--font-display);font-size:1.2rem;">${s ? s.name : (currentLang === 'it' ? 'Serie sconosciuta' : 'Unknown series')}</span>
              <span class="card-badge" style="color:#5ec8f0;">${figurinesOnlyMissing} ${currentLang === 'it' ? 'figurine non nella tua lista su' : 'stickers not in my list out of'} ${figurinesOnlyTotal}</span>
            </span>
            <label style="display:flex;align-items:center;gap:0.4rem;cursor:pointer;font-size:0.82rem;">
              <input type="checkbox" onchange="toggleIncludeVariations('${sId}')" ${incVariations ? 'checked' : ''} style="width:16px;height:16px;cursor:pointer;flex-shrink:0;">
              <span style="color:${incVariations ? 'var(--accent)' : 'var(--muted)'};">${currentLang === 'it' ? 'Includere variazioni/change' : 'Include variations/change'}</span>
            </label>
          </div>
          <label style="display:flex;align-items:center;gap:0.4rem;cursor:pointer;font-size:0.82rem;">
            <input type="checkbox" onchange="toggleWantlistExclude('${sId}')" ${excMissing ? 'checked' : ''} style="width:16px;height:16px;cursor:pointer;flex-shrink:0;">
            <span style="color:${excMissing ? 'var(--info)' : 'var(--muted)'};">${currentLang === 'it' ? 'Escludi da export "Oggetti non nella tua lista"' : 'Exclude from export "Items not in my list"'}</span>
          </label>
        </div>
        ${!excMissing ? '<div class="progress-bar" style="margin-bottom:0.5rem;"><div class="progress-fill" style="width:' + Math.round(ownedCount/figurinesOnlyTotal*100) + '%"></div></div>' : ''}
        `;
      })()}
      ${(() => { if (_wantlistCollapsed[sId] !== false) return ''; const prefs = getWantlistPrefs(); if (prefs[sId]?.excludeMissing) return '<p style="color:var(--muted);font-size:0.82rem;font-style:italic;">' + (currentLang === 'it' ? 'Esclusa dalla mancolista.' : 'Excluded from missing list.') + '</p>'; const sectionOrder = ['figurines', 'retros', 'albums', 'extras', 'bustine']; return Object.entries(bySection).sort(([secA], [secB]) => sectionOrder.indexOf(secA) - sectionOrder.indexOf(secB)).map(([sec, items]) => {
        const groupKey = sId + '_' + sec;
        const mode = wantlistMode[groupKey] || 'both';
        const hasNumbers = items.some(f => f.number);
        const hasNames = true;
        const modeSelector = `
          <div style="display:flex;gap:0.4rem;margin-bottom:0.3rem;align-items:center;flex-wrap:wrap;">
            <span style="font-family:var(--font-ui);font-size:0.85rem;color:var(--accent3);">${sectionLabels[sec] || sec}</span>
            <div style="margin-left:auto;display:flex;gap:1rem;flex-wrap:wrap;align-items:center;">
              ${hasNumbers ? `<div style="display:flex;align-items:center;gap:0.35rem;"><button class="toggle-btn-blue ${mode==='numbers'?'on':''}" onclick="toggleWantlistMode('${groupKey}','numbers')" title="${currentLang === 'it' ? 'Mostra solo numeri' : 'Show numbers only'}"></button><span style="font-size:0.78rem;color:var(--muted);">${currentLang === 'it' ? 'Mostra solo numeri' : 'Show numbers only'}</span></div>` : ''}
              ${hasNumbers ? `<div style="display:flex;align-items:center;gap:0.35rem;"><button class="toggle-btn-blue ${mode==='names'?'on':''}" onclick="toggleWantlistMode('${groupKey}','names')" title="${currentLang === 'it' ? 'Mostra solo nomi' : 'Show names only'}"></button><span style="font-size:0.78rem;color:var(--muted);">${currentLang === 'it' ? 'Mostra solo nomi' : 'Show names only'}</span></div>` : ''}
              ${hasNumbers ? `<div style="display:flex;align-items:center;gap:0.35rem;"><button class="toggle-btn-blue ${mode==='both'?'on':''}" onclick="toggleWantlistMode('${groupKey}','both')" title="${currentLang === 'it' ? 'Mostra numeri e nomi' : 'Show numbers and names'}"></button><span style="font-size:0.78rem;color:var(--muted);">${currentLang === 'it' ? 'Mostra numeri e nomi' : 'Show numbers and names'}</span></div>` : ''}
            </div>
          </div>`;
        // If all items in this section are missing, show a simple message
        const allSectionFigs = allFigs.filter(f => f.seriesId === sId && f.section === sec);
        if (items.length === allSectionFigs.length) {
          return `<div style="margin-bottom:0.4rem;">${modeSelector}<div style="color:var(--muted);font-size:0.88rem;font-style:italic;">${currentLang === 'it' ? 'Nella tua lista manca tutta la serie!' : 'Your list is missing the entire series!'}</div></div>`;
        }
        const sorted = items.sort((a,b) => {
          // Sort by subseries first, then by number, then by name
          const aSub = a.subseries || '';
          const bSub = b.subseries || '';
          if (aSub !== bSub) return aSub.localeCompare(bSub);
          if (a.number && b.number) return a.number - b.number;
          if (a.number) return -1;
          if (b.number) return 1;
          return (a.name || '').localeCompare(b.name || '');
        });
        // Check if items have subseries
        const hasSubseries = items.some(f => f.subseries);
        let chipsHtml = '';
        if (hasSubseries) {
          // Group by subseries
          const bySubseries = {};
          sorted.forEach(f => {
            const key = f.subseries || (currentLang === 'it' ? 'Senza sottoserie' : 'No subseries');
            if (!bySubseries[key]) bySubseries[key] = [];
            bySubseries[key].push(f);
          });
          chipsHtml = Object.entries(bySubseries).map(([sub, subItems]) => {
            subItems.sort((a, b) => {
              if (a.number && b.number) return a.number - b.number;
              if (a.number) return -1;
              if (b.number) return 1;
              return (a.name || '').localeCompare(b.name || '');
            });
            const subChips = subItems.map(f => {
              let label = '';
              if (mode === 'numbers') label = f.number ? '#' + f.number : f.name;
              else if (mode === 'names') label = f.name;
              else label = (f.number ? '#' + f.number + ' ' : '') + f.name;
              return `<span style="background:rgba(255,255,255,0.06);border:1px solid rgba(255,255,255,0.15);color:var(--text);font-size:0.64rem;padding:1px 5px;border-radius:8px;">${label}</span>`;
            }).join('');
            return `<div style="margin-bottom:0.3rem;"><span style="font-size:0.72rem;font-weight:700;color:var(--accent3);margin-right:0.4rem;">(${(currentLang === 'it') ? 'Sottoserie' : 'Subseries'}: ${sub}):</span><span style="display:inline-flex;flex-wrap:wrap;gap:0.3rem;">${subChips}</span></div>`;
          }).join('');
        } else {
          const chips = sorted.map(f => {
            let label = '';
            if (mode === 'numbers') label = f.number ? '#' + f.number : f.name;
            else if (mode === 'names') label = f.name;
            else label = (f.number ? '#' + f.number + ' ' : '') + f.name;
            return `<span style="background:rgba(255,255,255,0.06);border:1px solid rgba(255,255,255,0.15);color:var(--text);font-size:0.64rem;padding:1px 5px;border-radius:8px;">${label}</span>`;
          }).join('');
          chipsHtml = `<div style="display:flex;flex-wrap:wrap;gap:0.3rem;">${chips}</div>`;
        }
        return `<div style="margin-bottom:0.4rem;">${modeSelector}${chipsHtml}</div>`;
      }).join(''); })()}
    </div>`;
  }).join('');

  // === SEZIONE 1b: Lista figurine nella mia lista (serie incomplete) ===
  html += '<hr style="border-color:var(--border);margin:1.5rem 0;"><h3 style="font-family:var(--font-ui);font-size:1.2rem;margin-bottom:0.4rem;">' + (currentLang === 'it' ? 'SEZIONE 1b: LISTA FIGURINE NELLA TUA LISTA' : 'SECTION 1b: LIST OF STICKERS IN MY LIST') + '</h3><p style="color:var(--muted);font-size:0.88rem;margin-bottom:0.75rem;">' + (currentLang === 'it' ? 'Seleziona le serie per cui esportare l\'elenco delle figurine nella tua lista. Poi premi il tasto <i style="color:#fff;">Esporta la tua lista di figurine (solo serie incomplete)</i>.' : 'Select the series for which to export the list of stickers in your list. Then press <i style="color:#fff;">Export my sticker list (incomplete series only)</i>.') + '</p><div style="margin-bottom:1.5rem;"><button class="btn-primary" onclick="exportOwnedIncomplete(this)">' + (currentLang === 'it' ? 'Esporta figurine serie incomplete' : 'Export my sticker list (incomplete series only)') + '</button></div>';

  html += sortedEntries.map(([sId]) => {
    const s = series.find(x => x.id === sId);
    const prefs = getWantlistPrefs();
    const incOwned = prefs[sId]?.includeOwned !== false;
    const seriesIncVariations = prefs[sId]?.includeVariations || false;
    const figurinesOnlyTotal = allFigs.filter(f => f.seriesId === sId && (f.section || 'figurines') === 'figurines' && (seriesIncVariations || isBaseItem(f))).length;
    const figurinesOnlyMissing = allFigs.filter(f => f.seriesId === sId && (f.section || 'figurines') === 'figurines' && !owned.includes(f.id) && (seriesIncVariations || isBaseItem(f))).length;
    const ownedCount = figurinesOnlyTotal - figurinesOnlyMissing;
    return `<div style="background:var(--card);border:1px solid var(--border);border-radius:var(--radius-lg);padding:0.5rem 0.9rem;margin-bottom:0.5rem;display:flex;align-items:center;justify-content:space-between;flex-wrap:wrap;gap:0.4rem;">
      <span style="font-family:var(--font-display);font-size:1.1rem;">${s ? s.name : (currentLang === 'it' ? 'Serie sconosciuta' : 'Unknown series')} <span style="font-size:0.8rem;color:var(--accent);">(${ownedCount}&nbsp;/&nbsp;${figurinesOnlyTotal}&nbsp;${currentLang==='it'?'nella tua lista':'in my list'})</span></span>
      <button onclick="toggleOwnedInclude('${sId}')" style="font-size:0.72rem;padding:2px 8px;border-radius:8px;border:1px solid ${!incOwned ? 'var(--info)' : 'var(--border)'};background:${!incOwned ? 'rgba(var(--info-rgb),0.15)' : 'var(--card2)'};color:${!incOwned ? 'var(--info)' : 'var(--muted)'};cursor:pointer;">
        ${!incOwned ? '✓ ' : ''}${(currentLang === 'it') ? 'Escludi da export figurine della tua lista' : 'Exclude from owned stickers export'}
      </button>
    </div>`;
  }).join('');

  el.innerHTML = html;

  // Append complete series section at the bottom
  if (completeSeries.length) {
    const prefs = getWantlistPrefs();
    const completeBoxes = completeSeries.map(s => {
      const incOwned = prefs[s.id]?.includeOwned !== false;
      return `<div style="background:var(--card);border:1px solid var(--border);border-radius:var(--radius-lg);padding:0.5rem 0.9rem;margin-bottom:0.5rem;display:flex;align-items:center;justify-content:space-between;flex-wrap:wrap;gap:0.4rem;">
        <span style="font-family:var(--font-display);font-size:1.1rem;">${s.name} <span style="font-size:0.8rem;color:var(--success);">✓ (${(() => { const figs = getData('figurines',[]).filter(f=>f.seriesId===s.id&&f.section==='figurines'&&!f.isVariation&&!f.isUnofficialVariation&&!f.isChange); return figs.length; })()}&nbsp;${currentLang==='it'?'figurine':'stickers'})</span></span>
        <button onclick="toggleOwnedInclude('${s.id}')" style="font-size:0.72rem;padding:2px 8px;border-radius:8px;border:1px solid ${!incOwned ? 'var(--info)' : 'var(--border)'};background:${!incOwned ? 'rgba(var(--info-rgb),0.15)' : 'var(--card2)'};color:${!incOwned ? 'var(--info)' : 'var(--muted)'};cursor:pointer;">
          ${!incOwned ? '✓ ' : ''}${(currentLang === 'it') ? 'Escludi da export figurine della tua lista' : 'Exclude from owned stickers export'}
        </button>
      </div>`;
    }).join('');
    el.innerHTML += '<hr style="border-color:var(--border);margin:1.5rem 0;"><h2 style="font-family:var(--font-ui);font-size:1.5rem;margin-bottom:0.6rem;">' + (currentLang === 'it' ? 'SEZIONE 2: EXPORT DELLE TUE SERIE COMPLETE' : 'SECTION 2: EXPORT OF YOUR COMPLETE SERIES') + '</h2><p style="font-size:1.05rem;color:var(--muted);margin-bottom:0.5rem;">' + (currentLang === 'it' ? 'Seleziona le serie per le quali esportare l\'elenco delle figurine. Poi premi il tasto <i style="color:#fff;">Esporta lista figurine mie serie complete</i>.' : 'Select the series for which you want to export your stickers. Then press <i style="color:#fff;">Export my complete series stickers</i>.') + '</p><div style="margin-bottom:1rem;"><button class="btn-primary" onclick="exportOwnedList()" style="font-size:0.88rem;">' + (currentLang === 'it' ? 'Esporta lista figurine mie serie complete' : 'Export my complete series stickers') + '</button></div>' + completeBoxes;
  }
}

// Wantlist preferences stored on user profile
function getWantlistPrefs() {
  return currentUser?.wantlistPrefs || {};
}

async function toggleWantlistExclude(seriesId) {
  if (!currentUser) return;
  const prefs = getWantlistPrefs();
  prefs[seriesId] = prefs[seriesId] || {};
  prefs[seriesId].excludeMissing = !prefs[seriesId].excludeMissing;
  currentUser.wantlistPrefs = prefs;
  LOCAL.set('currentUser', currentUser);
  await fsSave('users', currentUser);
  renderWantlist();
}

async function toggleOwnedInclude(seriesId) {
  if (!currentUser) return;
  const prefs = getWantlistPrefs();
  prefs[seriesId] = prefs[seriesId] || {};
  prefs[seriesId].includeOwned = !prefs[seriesId].includeOwned;
  currentUser.wantlistPrefs = prefs;
  LOCAL.set('currentUser', currentUser);
  await fsSave('users', currentUser);
  renderWantlist();
}

async function toggleIncludeVariations(seriesId) {
  if (!currentUser) return;
  const prefs = getWantlistPrefs();
  prefs[seriesId] = prefs[seriesId] || {};
  prefs[seriesId].includeVariations = !prefs[seriesId].includeVariations;
  currentUser.wantlistPrefs = prefs;
  LOCAL.set('currentUser', currentUser);
  await fsSave('users', currentUser);
  renderWantlist();
}

async function exportOwnedIncomplete(btn) {
  // Export owned figs only for series where user does NOT have all stickers
  const allFigs = getData('figurines', []);
  const series = getData('series', []);
  const owned = getOwned();
  const prefs = getWantlistPrefs();

  const rows = [[(currentLang === 'it' ? 'Serie' : 'Series'), (currentLang === 'it' ? 'Tipo di oggetto' : 'Item type'), (currentLang === 'it' ? 'Sottoserie' : 'Subseries'), (currentLang === 'it' ? 'Numero' : 'Number'), (currentLang === 'it' ? 'Nome' : 'Name')]];

  // Get incomplete series (has missing figs) and not excluded
  const incompleteSeries = series.filter(s => {
    if (prefs[s.id]?.includeOwned === false) return false;
    const seriesFigs = allFigs.filter(f => f.seriesId === s.id && f.section === 'figurines' && isBaseFigurine(f));
    const missing = seriesFigs.filter(f => !owned.includes(f.id));
    return missing.length > 0 && missing.length < seriesFigs.length;
  }).sort((a,b) => (a.order ?? 9999) - (b.order ?? 9999));

  incompleteSeries.forEach(s => {
    const ownedFigs = allFigs.filter(f => f.seriesId === s.id && f.section === 'figurines' && isBaseFigurine(f) && owned.includes(f.id))
      .sort((a,b) => (a.number||0) - (b.number||0));
    ownedFigs.forEach(f => {
      rows.push([s.name, (currentLang === 'it' ? 'Figurina' : 'Sticker'), f.subseries || '', f.number || '', f.name]);
    });
  });

  if (rows.length <= 1) { toast(currentLang === 'it' ? 'Non ti manca nessuna figurina! 🎉' : 'You are not missing any sticker! 🎉', 'success', btn); return; }

  const XLSX = await loadXLSX();
  const ws = XLSX.utils.aoa_to_sheet(rows);
  const wb = XLSX.utils.book_new();
  XLSX.utils.book_append_sheet(wb, ws, currentLang === 'it' ? 'Serie incomplete' : 'Incomplete series');
  XLSX.writeFile(wb, (currentLang === 'it' ? 'sgorbions_serie_incomplete_possedute' : 'sgorbions_incomplete_series_owned') + '_' + currentUser.username + '.xlsx');
  toast(currentLang === 'it' ? 'Esportato! 📊' : 'Exported! 📊', 'success');
}

async function exportOwnedList() {
  if (!currentUser) return;
  const allFigs = getData('figurines', []);
  const owned = getOwned();
  const ownedFigs = allFigs.filter(f => owned.includes(f.id) && f.section === 'figurines' && isBaseFigurine(f));
  const series = getData('series', []);
  const sectionLabels = { figurines: currentLang === 'it' ? 'Figurina' : 'Sticker', retros: 'Retro', albums: 'Album', extras: currentLang === 'it' ? 'Altri oggetti' : 'Other items', bustine: currentLang === 'it' ? 'Bustina' : 'Pack' };

  const rows = [[(currentLang === 'it' ? 'Serie' : 'Series'), (currentLang === 'it' ? 'Tipo di oggetto' : 'Item type'), (currentLang === 'it' ? 'Sottoserie' : 'Subseries'), (currentLang === 'it' ? 'Numero' : 'Number'), (currentLang === 'it' ? 'Nome' : 'Name')]];

  const prefs = getWantlistPrefs();
  const bySeries = {};
  ownedFigs.forEach(f => {
    if (prefs[f.seriesId]?.includeOwned === false) return; // excluded
    if (!bySeries[f.seriesId]) bySeries[f.seriesId] = [];
    bySeries[f.seriesId].push(f);
  });

  const sortedEntries = Object.entries(bySeries).sort(([aId], [bId]) => {
    const aS = series.find(x => x.id === aId);
    const bS = series.find(x => x.id === bId);
    return (aS?.order ?? 9999) - (bS?.order ?? 9999);
  });

  sortedEntries.forEach(([sId, figs]) => {
    const s = series.find(x => x.id === sId);
    const sName = s ? s.name : (currentLang === 'it' ? 'Serie sconosciuta' : 'Unknown series');
    figs.sort((a,b) => (a.number||0) - (b.number||0)).forEach(f => {
      rows.push([
        sName,
        sectionLabels[f.section] || sectionLabels.figurines,
        f.subseries || '',
        f.number ? String(f.number) : '',
        f.name
      ]);
    });
  });

  try {
    const XLSX = await loadXLSX();
    const ws = XLSX.utils.aoa_to_sheet(rows);
    ws['!cols'] = [{ wch: 25 }, { wch: 15 }, { wch: 12 }, { wch: 8 }, { wch: 35 }];
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, 'La tua lista');
    XLSX.writeFile(wb, (currentLang === 'it' ? 'mia_lista_' : 'my_list_') + currentUser.username + '_' + new Date().toLocaleDateString('it-IT').replace(/\//g,'-') + '.xlsx');
    toast('Lista esportata in Excel! 📊', 'success');
  } catch(e) {
    console.error('SheetJS error:', e);
    toast('Errore esportazione', 'error');
  }
}

async function exportWantlist(btn) {
  const allFigs = getData('figurines', []).filter(f => f.section === 'figurines');
  const owned = getOwned();
  const missing = allFigs.filter(f => !owned.includes(f.id));
  if (!missing.length) {
    toast(currentLang === 'it' ? 'Non ti manca nessuna figurina! 🎉' : 'You are not missing any sticker! 🎉', 'success', btn);
    return;
  }
  // continue with original logic
  return _exportWantlistImpl();
}
async function _exportWantlistImpl() {
  if (!currentUser) return;
  const allFigs = getData('figurines', []);
  const owned = getOwned();
  const missing = allFigs.filter(f => !owned.includes(f.id));
  const series = getData('series', []);
  const sectionLabels = { figurines: currentLang === 'it' ? 'Figurina' : 'Sticker', retros: 'Retro', albums: 'Album', extras: currentLang === 'it' ? 'Altri oggetti' : 'Other items', bustine: currentLang === 'it' ? 'Bustina' : 'Pack' };

  const rows = [[(currentLang === 'it' ? 'Serie' : 'Series'), (currentLang === 'it' ? 'Tipo di oggetto' : 'Item type'), (currentLang === 'it' ? 'Sottoserie' : 'Subseries'), (currentLang === 'it' ? 'Numero' : 'Number'), (currentLang === 'it' ? 'Nome' : 'Name')]];

  const prefs2 = getWantlistPrefs();
  const bySeries = {};
  missing.forEach(f => {
    if (prefs2[f.seriesId]?.excludeMissing) return; // excluded
    const isVariant = f.isVariation || f.isUnofficialVariation || f.isChange;
    if (isVariant && !prefs2[f.seriesId]?.includeVariations) return; // variazioni/change escluse per default
    if (!bySeries[f.seriesId]) bySeries[f.seriesId] = [];
    bySeries[f.seriesId].push(f);
  });

  const sortedEntries = Object.entries(bySeries).sort(([aId], [bId]) => {
    const aS = series.find(x => x.id === aId);
    const bS = series.find(x => x.id === bId);
    return (aS?.order ?? 9999) - (bS?.order ?? 9999);
  });

  sortedEntries.forEach(([sId, figs]) => {
    const s = series.find(x => x.id === sId);
    const sName = s ? s.name : (currentLang === 'it' ? 'Serie sconosciuta' : 'Unknown series');
    figs.sort((a,b) => (a.number||0) - (b.number||0)).forEach(f => {
      rows.push([
        sName,
        sectionLabels[f.section] || sectionLabels.figurines,
        f.subseries || '',
        f.number ? String(f.number) : '',
        f.name
      ]);
    });
  });

  // Load SheetJS and generate real .xlsx
  try {
    const XLSX = await loadXLSX();
    const ws = XLSX.utils.aoa_to_sheet(rows);
    // Set column widths
    ws['!cols'] = [{ wch: 25 }, { wch: 15 }, { wch: 12 }, { wch: 8 }, { wch: 35 }];
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, (currentLang === 'it' ? 'Mancolista' : 'Missing list'));
    XLSX.writeFile(wb, (currentLang === 'it' ? 'mancolista_' : 'missing_list_') + currentUser.username + '_' + new Date().toLocaleDateString('it-IT').replace(/\//g,'-') + '.xlsx');
    toast((currentLang === 'it' ? 'Mancolista esportata in Excel! 📊' : 'Missing list exported to Excel! 📊'), 'success');
  } catch(e) {
    console.error('SheetJS error:', e);
    toast('Errore esportazione', 'error');
  }
}

